fn terminal_now_ms() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_millis().min(u128::from(u64::MAX)) as u64)
        .unwrap_or(0)
}

const TERMINAL_STARTING_IDLE_BUFFER_MS: u64 = 5_000;
const TERMINAL_ACTIVITY_IDLE_QUIESCE_MS: u64 = 1_750;
const TERMINAL_PROMPT_READY_BUSY_DEBOUNCE_MS: u64 = 750;
const TERMINAL_STARTING_WATCHDOG_MS: u64 = 30_000;
const TERMINAL_MCP_STARTUP_DEGRADED_MS: u64 = 30_000;
const TERMINAL_WATCHDOG_OUTPUT_QUIET_MS: u64 = 2_500;
const TERMINAL_HOT_STALE_WATCHDOG_MS: u64 = 10 * 60_000;
/// A WAITING session (turn parked on live background shells/subagents) that
/// sees no hook or output activity for this long is force-released to idle so
/// a silently-dead background task can never hold receipts hostage forever.
const TERMINAL_WAITING_RELEASE_WATCHDOG_MS: u64 = 30 * 60_000;
const TERMINAL_STARTUP_READY_SCAN_BYTES: usize = 16 * 1024;
const TERMINAL_CONTROL_AUTOMATION_GUARD_TTL_MS: u64 = 60_000;
const TERMINAL_CONTROL_PROMPT_ANSWER_GUARD_TTL_MS: u64 = 10_000;
const TERMINAL_CONTROL_AUTOMATION_WAIT_POLL_MS: u64 = 25;
const TERMINAL_CODEX_APP_SERVER_READY_TIMEOUT_MS: u64 = 8_000;
const TERMINAL_CODEX_APP_SERVER_READY_POLL_MS: u64 = 80;
const TERMINAL_CODEX_APP_SERVER_CONNECT_ATTEMPTS: usize = 50;
const TERMINAL_CODEX_APP_SERVER_CONNECT_RETRY_MS: u64 = 100;
const TERMINAL_CODEX_AUTH_RELOAD_MAX_ATTEMPTS: usize = 3;
const TERMINAL_CODEX_AUTH_RELOAD_BACKOFF_BASE_MS: u64 = 100;
const TERMINAL_CODEX_AUTH_RELOAD_JITTER_MAX_MS: u64 = 75;
const TERMINAL_CODEX_AUTH_EXHAUSTED_FLUSH_TIMEOUT_MS: u64 = 2_000;
const TERMINAL_CODEX_AUTH_RECOVERY_DOWNSTREAM_QUEUE_MAX: usize = 128;
const TERMINAL_CODEX_APP_SERVER_STARTUP_JITTER_MIN_MS: u64 = 20;
const TERMINAL_CODEX_APP_SERVER_STARTUP_JITTER_SPAN_MS: u64 = 131;
const TERMINAL_CODEX_HOOK_TRUST_RESPONSE_TIMEOUT_MS: u64 = 10_000;
const TERMINAL_RESTART_INTENT_DEFAULT_DEADLINE_MS: u64 = 120_000;
const TERMINAL_RESTART_INTENT_MIN_DEADLINE_MS: u64 = 5_000;
const TERMINAL_RESTART_INTENT_MAX_DEADLINE_MS: u64 = 15 * 60_000;
const TERMINAL_RESTART_INTENT_EVENT: &str = "forge-terminal-restart-intent";
// A resume binding is captured before a busy restart is queued. Keep it past
// the longest admission deadline so the ready event can still reopen against
// the pane's frozen account instead of falling back to the mutable active one.
const TERMINAL_FROZEN_RESUME_BINDING_TTL_MS: u64 =
    TERMINAL_RESTART_INTENT_MAX_DEADLINE_MS + 2 * 60_000;
// Agent-start commands must never hang the frontend launch pipeline: a
// wedged lifecycle holder (slow terminal_open, close teardown) or a stuck
// pane future previously left the invoke pending forever, so panes sat at
// "starting" with no retry and no error. Bound both waits and let the
// frontend's retry/backoff loop recover.
const TERMINAL_AGENT_START_LIFECYCLE_LOCK_TIMEOUT_SECS: u64 = 60;
const TERMINAL_AGENT_START_PANE_TIMEOUT_SECS: u64 = 120;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum TerminalCodexHookTrustDiscoveryState {
    Pending,
    Open,
    FailedClosed,
    Resolved,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct TerminalCodexHookTrustDiscoveryEntry {
    generation: u64,
    state: TerminalCodexHookTrustDiscoveryState,
}

static TERMINAL_CODEX_HOOK_TRUST_DISCOVERY_GENERATION: AtomicU64 = AtomicU64::new(0);
static TERMINAL_CODEX_HOOK_TRUST_DISCOVERY_STATES: OnceLock<
    StdMutex<HashMap<(String, u64), TerminalCodexHookTrustDiscoveryEntry>>,
> = OnceLock::new();

fn terminal_codex_hook_trust_discovery_states(
) -> &'static StdMutex<HashMap<(String, u64), TerminalCodexHookTrustDiscoveryEntry>> {
    TERMINAL_CODEX_HOOK_TRUST_DISCOVERY_STATES.get_or_init(|| StdMutex::new(HashMap::new()))
}

fn terminal_codex_hook_trust_discovery_begin(pane_id: &str, instance_id: u64) -> u64 {
    let generation = TERMINAL_CODEX_HOOK_TRUST_DISCOVERY_GENERATION
        .fetch_add(1, Ordering::SeqCst)
        .saturating_add(1);
    if let Ok(mut states) = terminal_codex_hook_trust_discovery_states().lock() {
        states.retain(|(candidate_pane_id, _), _| candidate_pane_id != pane_id);
        states.insert(
            (pane_id.to_string(), instance_id),
            TerminalCodexHookTrustDiscoveryEntry {
                generation,
                state: TerminalCodexHookTrustDiscoveryState::Pending,
            },
        );
    }
    generation
}

fn terminal_codex_hook_trust_discovery_set(
    pane_id: &str,
    instance_id: u64,
    state: TerminalCodexHookTrustDiscoveryState,
) {
    if state == TerminalCodexHookTrustDiscoveryState::Pending {
        terminal_codex_hook_trust_discovery_begin(pane_id, instance_id);
        return;
    }
    if let Ok(mut states) = terminal_codex_hook_trust_discovery_states().lock() {
        if let Some(entry) = states.get_mut(&(pane_id.to_string(), instance_id)) {
            if matches!(
                entry.state,
                TerminalCodexHookTrustDiscoveryState::FailedClosed
            ) && state == TerminalCodexHookTrustDiscoveryState::Resolved
            {
                return;
            }
            entry.state = state;
        }
    }
}

fn terminal_codex_hook_trust_discovery_snapshot(
    pane_id: &str,
    instance_id: u64,
) -> Option<TerminalCodexHookTrustDiscoveryEntry> {
    terminal_codex_hook_trust_discovery_states()
        .lock()
        .ok()
        .and_then(|states| states.get(&(pane_id.to_string(), instance_id)).copied())
}

fn terminal_codex_hook_trust_discovery_transition(
    pane_id: &str,
    instance_id: u64,
    generation: u64,
    expected: &[TerminalCodexHookTrustDiscoveryState],
    state: TerminalCodexHookTrustDiscoveryState,
) -> bool {
    let Ok(mut states) = terminal_codex_hook_trust_discovery_states().lock() else {
        return false;
    };
    let Some(entry) = states.get_mut(&(pane_id.to_string(), instance_id)) else {
        return false;
    };
    if entry.generation != generation || !expected.contains(&entry.state) {
        return false;
    }
    entry.state = state;
    true
}

fn terminal_codex_hook_trust_discovery_blocks_idle(pane_id: &str, instance_id: u64) -> bool {
    terminal_codex_hook_trust_discovery_state(pane_id, instance_id).is_some_and(|state| {
        matches!(
            state,
            TerminalCodexHookTrustDiscoveryState::Pending
                | TerminalCodexHookTrustDiscoveryState::Open
                | TerminalCodexHookTrustDiscoveryState::FailedClosed
        )
    })
}

fn terminal_codex_hook_trust_discovery_state(
    pane_id: &str,
    instance_id: u64,
) -> Option<TerminalCodexHookTrustDiscoveryState> {
    terminal_codex_hook_trust_discovery_snapshot(pane_id, instance_id).map(|entry| entry.state)
}

fn terminal_codex_hook_trust_discovery_clear(pane_id: &str, instance_id: u64) {
    if let Ok(mut states) = terminal_codex_hook_trust_discovery_states().lock() {
        states.remove(&(pane_id.to_string(), instance_id));
    }
}

fn terminal_codex_hook_trust_discovery_clear_generation(
    pane_id: &str,
    instance_id: u64,
    generation: u64,
) {
    if let Ok(mut states) = terminal_codex_hook_trust_discovery_states().lock() {
        let key = (pane_id.to_string(), instance_id);
        if states
            .get(&key)
            .is_some_and(|entry| entry.generation == generation)
        {
            states.remove(&key);
        }
    }
}

fn terminal_output_latest_working_indicator_index(text: &str) -> Option<usize> {
    let lower = text.to_ascii_lowercase();
    ["Working (", "Working("]
        .into_iter()
        .flat_map(|needle| text.match_indices(needle).map(|(index, _)| index))
        .filter(|index| {
            *index == 0
                || text[..*index]
                    .chars()
                    .next_back()
                    .is_none_or(|character| !character.is_ascii_alphanumeric() && character != '_')
        })
        .filter_map(|index| {
            lower[index..]
                .find("esc to interrupt")
                .filter(|suffix_index| *suffix_index <= 160)
                .map(|_| index)
        })
        .max()
}

fn terminal_output_latest_mcp_startup_indicator_index(text: &str) -> Option<usize> {
    let lower = text.to_ascii_lowercase();
    let startup = ["booting mcp server", "starting mcp server"]
        .into_iter()
        .filter_map(|needle| lower.rfind(needle))
        .max();
    let failed = (lower.contains("mcp client for") && lower.contains("failed to start"))
        .then(|| lower.rfind("mcp client for"))
        .flatten();
    startup.max(failed)
}

fn terminal_output_latest_readiness_blocker_index(text: &str) -> Option<usize> {
    terminal_output_latest_working_indicator_index(text)
        .max(terminal_output_latest_mcp_startup_indicator_index(text))
}

fn terminal_output_latest_prompt_marker_index(text: &str) -> Option<usize> {
    let lower = text.to_ascii_lowercase();
    let mut latest = ["›", "❯", "❱"]
        .into_iter()
        .filter_map(|needle| text.rfind(needle))
        .max();

    if (lower.contains("opencode") || lower.contains("build ")) && lower.contains("ctrl+p commands")
    {
        latest = latest.max(lower.rfind("ctrl+p commands"));
    }

    let mut offset = 0;
    for line in text.split_inclusive('\n') {
        let line_without_newline = line.trim_end_matches(|ch| ch == '\r' || ch == '\n');
        let trimmed_start = line_without_newline.trim_start();
        if trimmed_start == ">" || trimmed_start.starts_with("> ") {
            latest = latest.max(Some(
                offset + (line_without_newline.len() - trimmed_start.len()),
            ));
        }
        offset += line.len();
    }

    latest
}

fn terminal_output_prompt_marker_after_working_indicator(text: &str) -> bool {
    let Some(prompt_index) = terminal_output_latest_prompt_marker_index(text) else {
        return false;
    };
    terminal_output_latest_readiness_blocker_index(text)
        .map(|working_index| prompt_index > working_index)
        .unwrap_or(true)
}

fn terminal_output_current_mcp_startup_marker(text: &str) -> bool {
    let current_in_text = |value: &str| {
        let Some(startup_index) = terminal_output_latest_mcp_startup_indicator_index(value) else {
            return false;
        };
        terminal_output_latest_prompt_marker_index(value)
            .max(terminal_output_latest_working_indicator_index(value))
            .map(|newer_activity_index| startup_index > newer_activity_index)
            .unwrap_or(true)
    };
    let cleaned = terminal_activity_strip_terminal_sequences(text);
    current_in_text(&cleaned)
}

fn terminal_output_current_prompt_marker(text: &str) -> bool {
    let cleaned = cloud_mcp_clean_terminal_state_text(text);
    if cleaned.is_empty() {
        return false;
    }
    terminal_output_prompt_marker_after_working_indicator(text)
        || terminal_output_prompt_marker_after_working_indicator(&cleaned)
}

#[derive(Clone, Debug)]
struct TerminalControlOperation {
    operation_id: String,
    operation_kind: String,
    automation_owned: bool,
    expires_at_ms: u64,
}

static TERMINAL_CONTROL_OPERATIONS: OnceLock<StdMutex<HashMap<String, TerminalControlOperation>>> =
    OnceLock::new();

fn terminal_control_operation_registry(
) -> &'static StdMutex<HashMap<String, TerminalControlOperation>> {
    TERMINAL_CONTROL_OPERATIONS.get_or_init(|| StdMutex::new(HashMap::new()))
}

fn terminal_control_operation_prune_expired(
    operations: &mut HashMap<String, TerminalControlOperation>,
    now_ms: u64,
) {
    operations.retain(|_, operation| operation.expires_at_ms > now_ms);
}

#[cfg(test)]
fn terminal_control_automation_owned(pane_id: &str) -> bool {
    let now_ms = terminal_now_ms();
    let Ok(mut operations) = terminal_control_operation_registry().lock() else {
        return true;
    };
    terminal_control_operation_prune_expired(&mut operations, now_ms);
    operations
        .get(pane_id)
        .is_some_and(|operation| operation.automation_owned)
}

fn terminal_control_operation_end_if_owner(pane_id: &str, operation_id: &str) -> bool {
    let Ok(mut operations) = terminal_control_operation_registry().lock() else {
        return false;
    };
    if operations
        .get(pane_id)
        .is_some_and(|operation| operation.operation_id == operation_id)
    {
        operations.remove(pane_id);
        true
    } else {
        false
    }
}

#[derive(Debug)]
struct TerminalControlPromptAnswerGuard {
    pane_id: String,
    operation_id: String,
}

impl Drop for TerminalControlPromptAnswerGuard {
    fn drop(&mut self) {
        terminal_control_operation_end_if_owner(&self.pane_id, &self.operation_id);
    }
}

fn terminal_control_prompt_answer_begin(
    pane_id: &str,
) -> Result<TerminalControlPromptAnswerGuard, String> {
    let now_ms = terminal_now_ms();
    let operation_id = format!("prompt-answer-{}", uuid::Uuid::new_v4());
    let mut operations = terminal_control_operation_registry()
        .lock()
        .map_err(|_| "Terminal control operation state is unavailable.".to_string())?;
    terminal_control_operation_prune_expired(&mut operations, now_ms);
    if let Some(active) = operations.get(pane_id) {
        return Err(if active.automation_owned {
            format!(
                "Terminal control automation ({}) owns this pane; prompt answer injection was rejected.",
                active.operation_kind
            )
        } else {
            "Another prompt answer is already being applied to this pane.".to_string()
        });
    }
    operations.insert(
        pane_id.to_string(),
        TerminalControlOperation {
            operation_id: operation_id.clone(),
            operation_kind: "prompt_answer".to_string(),
            automation_owned: false,
            expires_at_ms: now_ms.saturating_add(TERMINAL_CONTROL_PROMPT_ANSWER_GUARD_TTL_MS),
        },
    );
    Ok(TerminalControlPromptAnswerGuard {
        pane_id: pane_id.to_string(),
        operation_id,
    })
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_control_automation_begin(
    pane_id: String,
    operation_id: String,
    operation_kind: String,
    timeout_ms: Option<u64>,
) -> Result<(), String> {
    validate_terminal_pane_id(&pane_id)?;
    let operation_id = operation_id.trim();
    if operation_id.is_empty() || operation_id.len() > 200 {
        return Err("Terminal control automation requires a valid operation id.".to_string());
    }
    let operation_kind = terminal_projection_text(&operation_kind, "");
    if !matches!(operation_kind.as_str(), "model" | "effort" | "permission") {
        return Err("Unsupported terminal control automation kind.".to_string());
    }
    let wait_ms = timeout_ms.unwrap_or(20_000).clamp(100, 20_000);
    let started_at_ms = terminal_now_ms();
    loop {
        let now_ms = terminal_now_ms();
        let acquired = {
            let mut operations = terminal_control_operation_registry()
                .lock()
                .map_err(|_| "Terminal control operation state is unavailable.".to_string())?;
            terminal_control_operation_prune_expired(&mut operations, now_ms);
            match operations.get_mut(&pane_id) {
                Some(active) if active.operation_id == operation_id => {
                    active.expires_at_ms =
                        now_ms.saturating_add(TERMINAL_CONTROL_AUTOMATION_GUARD_TTL_MS);
                    true
                }
                Some(_) => false,
                None => {
                    operations.insert(
                        pane_id.clone(),
                        TerminalControlOperation {
                            operation_id: operation_id.to_string(),
                            operation_kind: operation_kind.clone(),
                            automation_owned: true,
                            expires_at_ms: now_ms
                                .saturating_add(TERMINAL_CONTROL_AUTOMATION_GUARD_TTL_MS),
                        },
                    );
                    true
                }
            }
        };
        if acquired {
            return Ok(());
        }
        if now_ms.saturating_sub(started_at_ms) >= wait_ms {
            return Err("Timed out waiting for this pane's control operation queue.".to_string());
        }
        sleep(Duration::from_millis(
            TERMINAL_CONTROL_AUTOMATION_WAIT_POLL_MS,
        ))
        .await;
    }
}

#[tauri::command(rename_all = "snake_case")]
fn terminal_control_automation_end(pane_id: String, operation_id: String) -> Result<bool, String> {
    validate_terminal_pane_id(&pane_id)?;
    Ok(terminal_control_operation_end_if_owner(
        &pane_id,
        operation_id.trim(),
    ))
}

fn terminal_activity_payload_is_non_prompting_lifecycle(
    payload: &TerminalActivityHookPayload,
) -> bool {
    if payload.terminal_is_prompting_user {
        return false;
    }
    [
        payload.status.as_str(),
        payload.activity_status.as_str(),
        payload.command_phase.as_str(),
        payload.execution_phase.as_str(),
        payload.native_rail_state.as_str(),
        payload.terminal_status.as_str(),
        payload.terminal_work_state.as_str(),
        payload.turn_status.as_str(),
    ]
    .into_iter()
    .map(|value| terminal_projection_text(value, ""))
    .any(|value| {
        matches!(
            value.as_str(),
            "idle" | "running" | "completed" | "complete" | "done"
        )
    })
}

fn terminal_activity_payload_clear_prompt_state(payload: &mut TerminalActivityHookPayload) {
    payload.prompt_id = Some(String::new());
    payload.prompt_kind = None;
    payload.prompt_default_option = None;
    payload.prompt_ttl_ms = None;
    payload.prompt_options.clear();
    payload.prompt_questions = None;
    payload.prompt_schema = None;
    payload.prompt_url = None;
    payload.provider_payload = None;
    payload.allows_free_text = false;
    payload.manual_prompt_source = None;
    payload.manual_approval_required = false;
    payload.provider_blocked_for_user = false;
    payload.terminal_is_prompting_user = false;
    payload.prompting_user_kind = None;
    payload.prompting_user_source = None;
    payload.prompting_user_confidence = None;
    payload.prompting_user_text = None;
}

fn terminal_activity_payload_clear_interaction_state(payload: &mut TerminalActivityHookPayload) {
    terminal_activity_payload_clear_prompt_state(payload);
    payload.approval_id = None;
    payload.permission_prompt_id = None;
    payload.permission_request_id = None;
    payload.permission_mode = None;
    payload.prompt_answer_option = None;
    payload.interaction_id = None;
    payload.interaction_revision = None;
    payload.interaction_source = None;
    payload.interaction_response_mode = None;
    payload.provider_request_id = None;
}

fn terminal_activity_payload_has_prompt_signal(payload: &TerminalActivityHookPayload) -> bool {
    payload.provider_blocked_for_user || payload.terminal_is_prompting_user
}

fn terminal_activity_hook_reconcile_prompt_state(payload: &mut TerminalActivityHookPayload) {
    if payload.terminal_is_prompting_user {
        if payload.prompt_id.is_none() {
            payload.prompt_id = Some(String::new());
        }
        return;
    }

    if terminal_activity_payload_is_non_prompting_lifecycle(payload) {
        terminal_activity_payload_clear_prompt_state(payload);
        return;
    }

    // PTY content is observability only. A terminal screen that resembles a
    // menu must never manufacture actionable UIR state; only provider hooks
    // or provider control protocols may set terminal_is_prompting_user.
    terminal_activity_payload_clear_prompt_state(payload);
}

#[cfg(windows)]
fn terminal_windows_build_number() -> Option<u32> {
    use windows_sys::Wdk::System::SystemServices::RtlGetVersion;
    use windows_sys::Win32::System::SystemInformation::OSVERSIONINFOW;

    let mut info = OSVERSIONINFOW {
        dwOSVersionInfoSize: std::mem::size_of::<OSVERSIONINFOW>() as u32,
        ..Default::default()
    };
    let status = unsafe { RtlGetVersion(&mut info) };

    if status >= 0 && info.dwBuildNumber > 0 {
        Some(info.dwBuildNumber)
    } else {
        None
    }
}

#[cfg(not(windows))]
fn terminal_windows_build_number() -> Option<u32> {
    None
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_windows_pty_info() -> Result<Value, String> {
    Ok(json!({
        "backend": if cfg!(windows) { "conpty" } else { "native" },
        "build_number": terminal_windows_build_number(),
        "term": TERMINAL_EMULATION_TERM,
        "term_program": TERMINAL_EMULATION_PROGRAM,
    }))
}

fn clean_terminal_telemetry_text(value: &str) -> String {
    value
        .replace(|character: char| character.is_control(), " ")
        .trim()
        .chars()
        .take(TERMINAL_TELEMETRY_MAX_TEXT)
        .collect()
}

fn validate_terminal_size(cols: u16, rows: u16) -> Result<PtySize, String> {
    if !(TERMINAL_MIN_COLS..=TERMINAL_MAX_COLS).contains(&cols) {
        return Err(format!(
            "Terminal columns must be between {TERMINAL_MIN_COLS} and {TERMINAL_MAX_COLS}."
        ));
    }

    if !(TERMINAL_MIN_ROWS..=TERMINAL_MAX_ROWS).contains(&rows) {
        return Err(format!(
            "Terminal rows must be between {TERMINAL_MIN_ROWS} and {TERMINAL_MAX_ROWS}."
        ));
    }

    Ok(PtySize {
        rows,
        cols,
        pixel_width: 0,
        pixel_height: 0,
    })
}

fn terminal_size_from_request(cols: Option<u16>, rows: Option<u16>) -> Result<PtySize, String> {
    validate_terminal_size(
        cols.unwrap_or(TERMINAL_DEFAULT_COLS),
        rows.unwrap_or(TERMINAL_DEFAULT_ROWS),
    )
}

fn terminal_launch_provider(kind: &str, provider: Option<&str>) -> Result<AgentProvider, String> {
    Ok(match kind {
        "console" => provider
            .map(parse_agent_provider)
            .transpose()?
            .unwrap_or(AgentProvider::Codex),
        "codex" => AgentProvider::Codex,
        "claude" => AgentProvider::Claude,
        "opencode" => AgentProvider::OpenCode,
        _ => {
            if let Some(provider) = provider {
                parse_agent_provider(provider)?
            } else {
                return Err("Terminal kind is invalid.".to_string());
            }
        }
    })
}

fn terminal_normalize_agent_kind(value: Option<&str>) -> Option<String> {
    let normalized = value?.trim().to_ascii_lowercase();
    if normalized.is_empty() {
        return None;
    }
    if normalized.contains("claude") {
        return Some("claude".to_string());
    }
    if normalized.contains("opencode") || normalized.contains("open-code") {
        return Some("opencode".to_string());
    }
    if normalized.contains("codex") || normalized == "console" {
        return Some("codex".to_string());
    }
    if matches!(
        normalized.as_str(),
        "generic"
            | "shell"
            | "terminal"
            | "plain-shell"
            | "plain_shell"
            | "generic-shell"
            | "generic_shell"
    ) {
        return Some("generic".to_string());
    }
    None
}

fn terminal_clean_provider_session_id(value: Option<&str>) -> Option<String> {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

fn terminal_provider_session_exists_on_device(
    agent_id: &str,
    provider_session_id: &str,
    working_directory: &str,
    account_binding: Option<&TerminalProviderLaunchAccountBinding>,
) -> Result<bool, String> {
    let Some(provider_session_id) = terminal_clean_provider_session_id(Some(provider_session_id))
    else {
        return Ok(false);
    };
    let provider = terminal_launch_provider(agent_id, Some(agent_id))?;
    if let Some(account_binding) = account_binding {
        account_binding.validate_frozen_account(provider, true)?;
        return Ok(terminal_resolve_provider_resume_session_for_binding(
            provider,
            Some(provider_session_id),
            working_directory,
            account_binding,
        )
        .0
        .is_some());
    }
    Ok(match provider {
        AgentProvider::Codex => {
            resolve_codex_resume_session(&provider_session_id, working_directory).is_ok()
        }
        AgentProvider::Claude => {
            resolve_claude_resume_session(&provider_session_id, working_directory).is_ok()
        }
        AgentProvider::OpenCode => {
            resolve_opencode_resume_session(&provider_session_id, working_directory).is_ok()
        }
    })
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_provider_session_exists(
    state: State<'_, TerminalState>,
    agent_id: String,
    provider_session_id: String,
    working_directory: String,
    pane_id: Option<String>,
    instance_id: Option<u64>,
) -> Result<bool, String> {
    let provider = terminal_launch_provider(&agent_id, Some(&agent_id))?;
    let pane_id = pane_id
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    if let Some(pane_id) = pane_id.as_deref() {
        validate_terminal_pane_id(pane_id)?;
    }
    let (frozen_binding, frozen_instance_id) = if let Some(pane_id) = pane_id.as_deref() {
        let live_instance = {
            let terminals = state.terminals.read().await;
            terminals.get(pane_id).cloned()
        };
        if let Some(instance) = live_instance {
            if instance_id.is_some_and(|expected| expected != instance.id) {
                return Err("The provider session probe targets a stale terminal instance.".to_string());
            }
            let binding = instance
                .launch_account_binding
                .as_ref()
                .filter(|binding| binding.matches_provider_id(agent_definition(provider).id))
                .cloned()
                .ok_or_else(|| {
                    "The terminal has no frozen provider account binding for this session probe."
                        .to_string()
                })?;
            (binding, instance.id)
        } else {
            let binding = terminal_frozen_resume_binding(
                pane_id,
                instance_id,
                provider,
                &provider_session_id,
                false,
            )
            .ok_or_else(|| {
                "The frozen provider account binding is no longer available for this session probe."
                    .to_string()
            })?;
            (binding, instance_id.unwrap_or_default())
        }
    } else {
        (TerminalProviderLaunchAccountBinding::default(), 0)
    };
    let has_frozen_binding = pane_id.is_some();
    let binding_for_probe = has_frozen_binding.then_some(frozen_binding.clone());
    let agent_id_for_probe = agent_id.clone();
    let provider_session_id_for_probe = provider_session_id.clone();
    let exists = tauri::async_runtime::spawn_blocking(move || {
        terminal_provider_session_exists_on_device(
            &agent_id_for_probe,
            &provider_session_id_for_probe,
            &working_directory,
            binding_for_probe.as_ref(),
        )
    })
    .await
    .map_err(|error| format!("Provider session existence check failed: {error}"))??;
    if let Some(pane_id) = pane_id.as_deref() {
        if exists {
            terminal_store_frozen_resume_binding(
                pane_id,
                frozen_instance_id,
                provider,
                &provider_session_id,
                &frozen_binding,
            );
        } else {
            terminal_clear_frozen_resume_binding(pane_id);
        }
    }
    Ok(exists)
}

fn terminal_provider_session_id_is_recordable_for_agent(
    agent_id: &str,
    agent_kind: &str,
    provider_session_id: &str,
) -> bool {
    let provider_session_id = provider_session_id.trim();
    if provider_session_id.is_empty() {
        return false;
    }
    let normalized_agent = terminal_normalize_agent_kind(Some(agent_kind))
        .or_else(|| terminal_normalize_agent_kind(Some(agent_id)));
    if normalized_agent.as_deref() == Some("opencode") {
        return provider_session_id.starts_with("ses_");
    }
    true
}

fn terminal_recordable_provider_session_id_for_metadata(
    metadata: &TerminalInstanceMetadata,
    provider_session_id: Option<&str>,
) -> Option<String> {
    let provider_session_id = terminal_clean_provider_session_id(provider_session_id)?;
    terminal_provider_session_id_is_recordable_for_agent(
        &metadata.agent_id,
        &metadata.agent_kind,
        &provider_session_id,
    )
    .then_some(provider_session_id)
}

fn terminal_provider_resume_args(
    provider: AgentProvider,
    provider_session_id: Option<&str>,
) -> Vec<String> {
    let Some(session_id) = terminal_clean_provider_session_id(provider_session_id) else {
        return Vec::new();
    };

    match provider {
        AgentProvider::Codex => vec!["resume".to_string(), session_id],
        AgentProvider::Claude => vec!["--resume".to_string(), session_id],
        AgentProvider::OpenCode => vec!["--session".to_string(), session_id],
    }
}

fn terminal_provider_fork_args(
    provider: AgentProvider,
    provider_session_id: Option<&str>,
) -> Vec<String> {
    let Some(session_id) = terminal_clean_provider_session_id(provider_session_id) else {
        return Vec::new();
    };

    match provider {
        AgentProvider::Codex => vec!["fork".to_string(), session_id],
        AgentProvider::Claude => {
            vec![
                "--resume".to_string(),
                session_id,
                "--fork-session".to_string(),
            ]
        }
        AgentProvider::OpenCode => vec!["--session".to_string(), session_id, "--fork".to_string()],
    }
}

fn terminal_provider_session_fork_error(provider: AgentProvider) -> String {
    format!(
        "Unable to fork this {} session because it is not available locally.",
        agent_definition(provider).label
    )
}

fn terminal_claude_resume_unavailable_message() -> String {
    "This Claude session was created on another device and isn't available to resume here."
        .to_string()
}

#[derive(Clone)]
enum TerminalProviderLaunchAccountBinding {
    Claude {
        home: Option<PathBuf>,
        account: Option<AgentAccountsLaunchAccountBinding>,
    },
    OpenCode {
        data_home: Option<PathBuf>,
        db_path: Option<PathBuf>,
        account: Option<AgentAccountsLaunchAccountBinding>,
    },
    Unmanaged {
        account: Option<AgentAccountsLaunchAccountBinding>,
    },
}

#[derive(Clone)]
struct TerminalFrozenResumeBinding {
    account_binding: TerminalProviderLaunchAccountBinding,
    captured_at_ms: u64,
    instance_id: u64,
    provider_id: String,
    provider_session_id: String,
}

static TERMINAL_FROZEN_RESUME_BINDINGS: OnceLock<
    StdMutex<HashMap<String, TerminalFrozenResumeBinding>>,
> = OnceLock::new();

fn terminal_frozen_resume_bindings(
) -> &'static StdMutex<HashMap<String, TerminalFrozenResumeBinding>> {
    TERMINAL_FROZEN_RESUME_BINDINGS.get_or_init(|| StdMutex::new(HashMap::new()))
}

fn terminal_store_frozen_resume_binding(
    pane_id: &str,
    instance_id: u64,
    provider: AgentProvider,
    provider_session_id: &str,
    account_binding: &TerminalProviderLaunchAccountBinding,
) {
    let provider_id = agent_definition(provider).id;
    if let Ok(mut bindings) = terminal_frozen_resume_bindings().lock() {
        let now_ms = terminal_now_ms();
        bindings.retain(|_, binding| {
            now_ms.saturating_sub(binding.captured_at_ms)
                <= TERMINAL_FROZEN_RESUME_BINDING_TTL_MS
        });
        bindings.insert(
            pane_id.to_string(),
            TerminalFrozenResumeBinding {
                account_binding: account_binding.clone(),
                captured_at_ms: now_ms,
                instance_id,
                provider_id: provider_id.to_string(),
                provider_session_id: provider_session_id.to_string(),
            },
        );
    }
}

fn terminal_frozen_resume_binding(
    pane_id: &str,
    instance_id: Option<u64>,
    provider: AgentProvider,
    provider_session_id: &str,
    take: bool,
) -> Option<TerminalProviderLaunchAccountBinding> {
    let provider_id = agent_definition(provider).id;
    let mut bindings = terminal_frozen_resume_bindings().lock().ok()?;
    let now_ms = terminal_now_ms();
    bindings.retain(|_, binding| {
        now_ms.saturating_sub(binding.captured_at_ms)
            <= TERMINAL_FROZEN_RESUME_BINDING_TTL_MS
    });
    let matches = bindings.get(pane_id).is_some_and(|binding| {
        binding.provider_id == provider_id
            && binding.provider_session_id == provider_session_id
            && instance_id.is_none_or(|instance_id| binding.instance_id == instance_id)
    });
    if !matches {
        return None;
    }
    if take {
        bindings.remove(pane_id).map(|binding| binding.account_binding)
    } else {
        bindings
            .get(pane_id)
            .map(|binding| binding.account_binding.clone())
    }
}

fn terminal_clear_frozen_resume_binding(pane_id: &str) {
    if let Ok(mut bindings) = terminal_frozen_resume_bindings().lock() {
        bindings.remove(pane_id);
    }
}

impl Default for TerminalProviderLaunchAccountBinding {
    fn default() -> Self {
        Self::Unmanaged { account: None }
    }
}

fn terminal_opencode_launch_data_home(
    selected_data_home: Option<PathBuf>,
    native_data_home: Option<&Path>,
) -> Option<PathBuf> {
    selected_data_home
        .or_else(|| {
            native_data_home
                .and_then(Path::parent)
                .map(Path::to_path_buf)
        })
}

impl TerminalProviderLaunchAccountBinding {
    fn capture(provider: AgentProvider) -> Self {
        match provider {
            AgentProvider::Claude => {
                let account = agent_accounts_capture_launch_account_binding("claude");
                let home = account
                    .as_ref()
                    .and_then(|binding| binding.profile_home.clone())
                    .or_else(|| {
                        account
                            .as_ref()
                            .is_some_and(|binding| {
                                binding.profile_id == AGENT_ACCOUNTS_DEFAULT_PROFILE_ID
                            })
                            .then(claude_home_dir)
                            .flatten()
                    });
                Self::Claude { home, account }
            }
            AgentProvider::OpenCode => {
                let account = agent_accounts_capture_launch_account_binding("opencode");
                if account.is_none() {
                    // Keep the provider boundary fail-closed if account
                    // binding is ever unavailable: no DB may be resolved from
                    // an identity that the spawn cannot also carry.
                    return Self::OpenCode {
                        data_home: None,
                        db_path: None,
                        account: None,
                    };
                }
                let selected_data_home = account
                    .as_ref()
                    .and_then(|binding| binding.selected_profile_dir.clone());
                if let Some(profile_dir) = selected_data_home.as_deref() {
                    let _ = agent_accounts_migrate_opencode_profile_layout(profile_dir);
                }
                let native_data_homes = opencode_native_data_home();
                let native_data_home =
                    opencode_native_data_home_for_launch(&native_data_homes);
                let db_path = opencode_db_path_for_launch_roots(
                    selected_data_home.clone(),
                    native_data_homes,
                );
                let data_home = terminal_opencode_launch_data_home(
                    selected_data_home,
                    native_data_home.as_deref(),
                );
                Self::OpenCode {
                    data_home,
                    db_path,
                    account,
                }
            }
            AgentProvider::Codex => Self::Unmanaged {
                account: agent_accounts_capture_launch_account_binding("codex"),
            },
        }
    }

    fn captured_account(&self) -> Option<&AgentAccountsLaunchAccountBinding> {
        match self {
            Self::Claude { account, .. }
            | Self::OpenCode { account, .. }
            | Self::Unmanaged { account } => account.as_ref(),
        }
    }

    fn provider_kind(&self) -> Option<&'static str> {
        self.captured_account().map(|account| account.kind)
    }

    fn matches_provider_id(&self, provider_id: &str) -> bool {
        agent_accounts_supported_kind(provider_id)
            .zip(self.provider_kind())
            .is_some_and(|(provider, captured)| provider == captured)
    }

    fn codex_auth_home(&self) -> Option<&Path> {
        match self {
            Self::Unmanaged { account } => account
                .as_ref()
                .and_then(|account| account.profile_home.as_deref()),
            _ => None,
        }
    }

    fn validate_frozen_account(
        &self,
        provider: AgentProvider,
        resume_requires_auth_store: bool,
    ) -> Result<(), String> {
        if !resume_requires_auth_store {
            return Ok(());
        }
        let definition = agent_definition(provider);
        let account = self
            .captured_account()
            .filter(|account| account.kind == definition.id)
            .ok_or_else(|| {
                format!(
                    "Unable to freeze the active {} account for launch.",
                    definition.label
                )
            })?;
        if account.auth_revision.trim().is_empty() {
            return Err(format!(
                "The frozen {} account has no stable authentication revision.",
                definition.label
            ));
        }
        let auth_path = match provider {
            AgentProvider::Claude => account
                .profile_home
                .as_deref()
                .map(|home| home.join(".credentials.json")),
            AgentProvider::Codex => account
                .profile_home
                .as_deref()
                .map(|home| home.join("auth.json")),
            AgentProvider::OpenCode => account
                .selected_profile_dir
                .as_deref()
                .map(|home| home.join("opencode").join("auth.json")),
        }
        .ok_or_else(|| {
            format!(
                "The frozen {} account has no isolated authentication home.",
                definition.label
            )
        })?;
        if !auth_path.is_file() {
            return Err(format!(
                "The frozen {} authentication store is unavailable.",
                definition.label
            ));
        }
        Ok(())
    }

    fn apply_to_env(&self, env_vars: &mut Vec<(String, String)>) {
        match self {
            Self::Claude { home, .. } => {
                env_vars.retain(|(key, _)| key != "CLAUDE_CONFIG_DIR");
                if let Some(home) = home {
                    env_vars.push((
                        "CLAUDE_CONFIG_DIR".to_string(),
                        home.to_string_lossy().to_string(),
                    ));
                }
            }
            Self::OpenCode { data_home, .. } => {
                env_vars.retain(|(key, _)| key != "OPENCODE_DATA_DIR" && key != "XDG_DATA_HOME");
                // Deferred launches run inside an already-open warm shell.
                // Empty overrides are required when the captured launch is
                // the native/default profile; merely removing vector entries
                // would leave a previously selected profile exported in that
                // shell. OpenCode treats empty XDG overrides as unset/default.
                if let Some(data_home) = data_home {
                    env_vars.push((
                        "XDG_DATA_HOME".to_string(),
                        data_home.to_string_lossy().to_string(),
                    ));
                } else {
                    env_vars.push(("XDG_DATA_HOME".to_string(), String::new()));
                }
            }
            // A coordination-managed home remains the process home, but an
            // unmanaged resume source is only a rollout source. The process
            // itself must use the captured account home even when the session
            // was discovered elsewhere.
            Self::Unmanaged { account } => {
                let managed_home = env_vars.iter().rev().find_map(|(key, value)| {
                    (key == "DIFFFORGE_CODEX_HOME")
                        .then_some(value.trim())
                        .filter(|value| !value.is_empty())
                });
                let launch_home = managed_home.map(PathBuf::from).or_else(|| {
                    account
                        .as_ref()
                        .and_then(|binding| binding.profile_home.clone())
                });
                if let Some(home) = launch_home {
                    env_vars.retain(|(key, _)| key != "CODEX_HOME");
                    env_vars.push((
                        "CODEX_HOME".to_string(),
                        home.to_string_lossy().to_string(),
                    ));
                }
            }
        }
    }
}

fn terminal_launch_account_binding_for_instance(
    instance: &TerminalInstance,
    provider: AgentProvider,
) -> TerminalProviderLaunchAccountBinding {
    let provider_id = agent_definition(provider).id;
    instance
        .launch_account_binding
        .as_ref()
        .filter(|binding| binding.matches_provider_id(provider_id))
        .cloned()
        .unwrap_or_else(|| TerminalProviderLaunchAccountBinding::capture(provider))
}

fn terminal_resolve_provider_resume_session_for_binding(
    provider: AgentProvider,
    requested_resume_session_id: Option<String>,
    working_directory: &str,
    account_binding: &TerminalProviderLaunchAccountBinding,
) -> (Option<String>, Option<String>) {
    let Some(requested_session_id) = requested_resume_session_id else {
        return (None, None);
    };

    let resolved = match (provider, account_binding) {
        (AgentProvider::Claude, TerminalProviderLaunchAccountBinding::Claude { home, .. }) => home
            .as_deref()
            .ok_or_else(|| "Unable to locate the active Claude Code home.".to_string())
            .and_then(|home| {
                resolve_claude_resume_session_in_home(
                    &requested_session_id,
                    working_directory,
                    home,
                )
            })
            .map(|session_id| (session_id, None)),
        (
            AgentProvider::OpenCode,
            TerminalProviderLaunchAccountBinding::OpenCode { db_path, .. },
        ) => db_path
            .as_deref()
            .ok_or_else(|| "Unable to locate OpenCode database.".to_string())
            .and_then(|db_path| {
                resolve_opencode_resume_session_in_db(
                    db_path,
                    &requested_session_id,
                    working_directory,
                )
            })
            .map(|session_id| (session_id, None)),
        (AgentProvider::Codex, _) => account_binding
            .codex_auth_home()
            .ok_or_else(|| "Unable to locate the frozen Codex account home.".to_string())
            .and_then(|home| {
                resolve_codex_resume_session_for_auth_home(
                    &requested_session_id,
                    working_directory,
                    home,
                )
            })
            .map(|(session_id, home)| {
                (session_id, Some(home.to_string_lossy().to_string()))
            }),
        _ => Err("Provider launch binding does not match the requested provider.".to_string()),
    };

    match resolved {
        Ok((session_id, home)) => (Some(session_id), home),
        Err(error) => {
            log_terminal_status_event(
                "backend.terminal_provider_session.resume_drop",
                json!({
                    "error": clean_terminal_diagnostic_log_text(&error),
                    "provider": agent_definition(provider).id,
                }),
            );
            (None, None)
        }
    }
}

fn terminal_session_last_model_for_binding(
    provider: AgentProvider,
    session_id: &str,
    codex_source_home: Option<&str>,
    account_binding: &TerminalProviderLaunchAccountBinding,
) -> Option<String> {
    let transcript = match (provider, account_binding) {
        (AgentProvider::Claude, TerminalProviderLaunchAccountBinding::Claude { home, .. }) => {
            claude_session_transcript_path_in_home(home.as_deref()?, session_id)?
        }
        (AgentProvider::Codex, _) => codex_session_transcript_path_in_home(
            Path::new(codex_source_home?.trim()),
            session_id,
        )?,
        (
            AgentProvider::OpenCode,
            TerminalProviderLaunchAccountBinding::OpenCode { db_path, .. },
        ) => return opencode_session_last_model_in_db(session_id, db_path.as_deref()?),
        _ => return None,
    };
    jsonl_tail_last_model(provider, &transcript)
}

#[derive(Clone, Default)]
struct TerminalProviderLaunchOptions {
    model: Option<String>,
    reasoning_effort: Option<String>,
    speed: Option<String>,
    permission_mode: Option<String>,
}

#[derive(Clone, Default)]
struct TerminalProviderResolvedLaunchOptions {
    model: Option<String>,
    model_source: Option<String>,
    reasoning_effort: Option<String>,
    speed: Option<String>,
    permission_mode: Option<String>,
}

fn terminal_launch_runtime_metadata_from_resolved(
    launch: &TerminalProviderResolvedLaunchOptions,
) -> TerminalLaunchRuntimeMetadata {
    TerminalLaunchRuntimeMetadata {
        model: launch.model.clone(),
        model_source: launch.model_source.clone(),
        reasoning_effort: launch.reasoning_effort.clone(),
        speed: launch.speed.clone(),
        permission_mode: launch.permission_mode.clone(),
        provider_error: None,
    }
}

fn terminal_apply_launch_runtime_metadata(
    instance: &TerminalInstance,
    launch: &TerminalProviderResolvedLaunchOptions,
) {
    if let Ok(mut metadata) = instance.launch_metadata.lock() {
        *metadata = terminal_launch_runtime_metadata_from_resolved(launch);
    }
}

fn terminal_normalize_launch_keyword(value: Option<String>) -> Option<String> {
    value
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty() && value != "default")
}

fn terminal_provider_model_supports_codex_fast(model: Option<&str>) -> bool {
    let model = model.unwrap_or_default().trim().to_ascii_lowercase();
    model == "gpt-5.5" || model == "gpt-5.4"
}

fn terminal_provider_model_supports_claude_fast(model: Option<&str>) -> bool {
    let model = model.unwrap_or_default().trim().to_ascii_lowercase();
    model == "opus" || model.contains("opus")
}

fn terminal_normalize_launch_reasoning_effort(
    provider: AgentProvider,
    effort: Option<String>,
) -> Result<Option<String>, String> {
    let Some(effort) = terminal_normalize_launch_keyword(effort) else {
        return Ok(None);
    };

    let valid = match provider {
        AgentProvider::Codex => matches!(effort.as_str(), "low" | "medium" | "high" | "xhigh"),
        AgentProvider::Claude => {
            matches!(effort.as_str(), "low" | "medium" | "high" | "xhigh" | "max")
        }
        AgentProvider::OpenCode => false,
    };

    if valid {
        Ok(Some(effort))
    } else if matches!(provider, AgentProvider::OpenCode) {
        Err(
            "OpenCode launch effort is configured through OpenCode model variants, not a global CLI flag."
                .to_string(),
        )
    } else {
        Err("Launch effort is invalid for this provider.".to_string())
    }
}

fn terminal_normalize_launch_speed(
    provider: AgentProvider,
    model: Option<&str>,
    speed: Option<String>,
) -> Result<Option<String>, String> {
    let Some(speed) = speed.map(|value| value.trim().to_ascii_lowercase()) else {
        return Ok(None);
    };
    if speed.is_empty() || speed == "default" {
        return Ok(None);
    }
    if speed == "standard" {
        return Ok(Some("standard".to_string()));
    }
    if speed != "fast" {
        return Err("Launch speed is invalid.".to_string());
    }

    let supported = match provider {
        AgentProvider::Codex => terminal_provider_model_supports_codex_fast(model),
        AgentProvider::Claude => terminal_provider_model_supports_claude_fast(model),
        AgentProvider::OpenCode => false,
    };

    if supported {
        Ok(Some("fast".to_string()))
    } else {
        Err("Fast launch speed is not supported for this provider/model.".to_string())
    }
}

fn terminal_append_provider_launch_args(
    provider: AgentProvider,
    args: &mut Vec<String>,
    launch: &TerminalProviderResolvedLaunchOptions,
) {
    if matches!(provider, AgentProvider::Codex) {
        args.push("-c".to_string());
        args.push("check_for_update_on_startup=false".to_string());
    }

    if let Some(model) = launch.model.as_ref() {
        args.push("--model".to_string());
        args.push(model.clone());
    }

    match provider {
        AgentProvider::Codex => {
            if let Some(effort) = launch.reasoning_effort.as_ref() {
                args.push("-c".to_string());
                args.push(format!("model_reasoning_effort=\"{effort}\""));
            }
            if launch.speed.as_deref() == Some("fast") {
                args.push("-c".to_string());
                args.push("service_tier=\"fast\"".to_string());
                args.push("--enable".to_string());
                args.push("fast_mode".to_string());
            }
        }
        AgentProvider::Claude => {
            if let Some(effort) = launch.reasoning_effort.as_ref() {
                args.push("--effort".to_string());
                args.push(effort.clone());
            }
            if launch.speed.as_deref() == Some("fast") {
                args.push("--settings".to_string());
                args.push("{\"fastMode\":true}".to_string());
            }
        }
        AgentProvider::OpenCode => {}
    }
}

fn terminal_uuid_session_id_from_text(value: &str) -> Option<String> {
    let bytes = value.as_bytes();
    for window in bytes.windows(36) {
        let Ok(text) = std::str::from_utf8(window) else {
            continue;
        };
        let hyphenated = text
            .chars()
            .enumerate()
            .all(|(index, character)| match index {
                8 | 13 | 18 | 23 => character == '-',
                _ => character.is_ascii_hexdigit(),
            });
        if hyphenated {
            if let Ok(uuid) = uuid::Uuid::parse_str(text) {
                return Some(uuid.to_string());
            }
        }
    }
    for window in bytes.windows(32) {
        let Ok(text) = std::str::from_utf8(window) else {
            continue;
        };
        if text.chars().all(|character| character.is_ascii_hexdigit()) {
            if let Ok(uuid) = uuid::Uuid::parse_str(text) {
                return Some(uuid.to_string());
            }
        }
    }
    None
}

fn terminal_provider_session_id_from_transcript_path(event: &Value) -> Option<String> {
    terminal_activity_hook_string(event, &["transcript_path", "agent_transcript_path"])
        .and_then(|path| terminal_uuid_session_id_from_text(&path))
}

fn terminal_activity_hook_provider_session_id(event: &Value) -> Option<String> {
    terminal_activity_hook_string(
        event,
        &[
            "session_id",
            "provider_session_id",
            "native_session_id",
            "conversation_id",
        ],
    )
    .or_else(|| terminal_provider_session_id_from_transcript_path(event))
}

fn terminal_runtime_snapshot(instance: &TerminalInstance) -> TerminalRuntimeSnapshot {
    instance
        .runtime
        .lock()
        .map(|snapshot| snapshot.clone())
        .unwrap_or_else(|_| TerminalRuntimeSnapshot::opened_idle(None))
}

struct TerminalOperationAdmissionGuard {
    admission: Arc<StdMutex<TerminalOperationAdmissionState>>,
}

impl Drop for TerminalOperationAdmissionGuard {
    fn drop(&mut self) {
        if let Ok(mut admission) = self.admission.lock() {
            admission.active = admission.active.saturating_sub(1);
        }
    }
}

fn terminal_operation_try_admit(
    instance: &TerminalInstance,
) -> Option<TerminalOperationAdmissionGuard> {
    let admission = Arc::clone(&instance.operation_admission);
    {
        let mut state = admission.lock().ok()?;
        if state.closing {
            return None;
        }
        state.active = state.active.saturating_add(1);
    }
    Some(TerminalOperationAdmissionGuard { admission })
}

fn terminal_runtime_apply_opened(
    instance: &TerminalInstance,
    provider_session_id: Option<&str>,
    fork_from_provider_session_id: Option<&str>,
    source: &str,
) -> TerminalRuntimeSnapshot {
    let Some(_operation) = terminal_operation_try_admit(instance) else {
        return terminal_runtime_snapshot(instance);
    };
    let provider_session_id = terminal_recordable_provider_session_id_for_metadata(
        &instance.metadata,
        provider_session_id,
    );
    let fork_from_provider_session_id = terminal_recordable_provider_session_id_for_metadata(
        &instance.metadata,
        fork_from_provider_session_id,
    );
    let snapshot = if cloud_mcp_agent_uses_activity_hooks(&instance.metadata.agent_id)
        || cloud_mcp_agent_uses_activity_hooks(&instance.metadata.agent_kind)
    {
        let mut snapshot = TerminalRuntimeSnapshot::opened_starting(provider_session_id, source);
        snapshot.fork_from_provider_session_id = fork_from_provider_session_id;
        snapshot
    } else {
        let mut snapshot = TerminalRuntimeSnapshot::opened_idle(provider_session_id);
        snapshot.fork_from_provider_session_id = fork_from_provider_session_id;
        snapshot
    };
    if let Ok(mut runtime) = instance.runtime.lock() {
        *runtime = snapshot.clone();
    }
    snapshot
}

fn terminal_runtime_mark_closing(instance: &TerminalInstance, source: &str) {
    let Ok(mut runtime) = instance.runtime.lock() else {
        return;
    };
    if matches!(runtime.canonical_state.as_str(), "closing" | "closed") {
        return;
    }
    runtime.terminal_state_contract_version = 1;
    runtime.canonical_state = "closing".to_string();
    runtime.canonical_badge_label = "closing".to_string();
    runtime.canonical_state_seq = runtime.canonical_state_seq.saturating_add(1);
    runtime.prompt_state_seq = runtime.prompt_state_seq.saturating_add(1);
    runtime.turn_active = false;
    runtime.active_interaction_id = None;
    runtime.active_interaction_revision = None;
    runtime.interaction_actionable = false;
    runtime.status = "closing".to_string();
    runtime.activity_status = "closing".to_string();
    runtime.command_phase = "closing".to_string();
    runtime.input_ready = false;
    runtime.source = source.to_string();
    runtime.event_type = "terminal-closing".to_string();
    runtime.hook_event_name = "Close".to_string();
    runtime.updated_at_ms = terminal_now_ms();
    runtime.waiting_origin_ms = 0;
}

fn terminal_runtime_apply_provider_session_id(
    instance: &TerminalInstance,
    provider_session_id: &str,
    source: &str,
) -> Option<TerminalRuntimeSnapshot> {
    let _operation = terminal_operation_try_admit(instance)?;
    let provider_session_id = terminal_recordable_provider_session_id_for_metadata(
        &instance.metadata,
        Some(provider_session_id),
    )?;
    let mut runtime = instance.runtime.lock().ok()?;
    runtime.provider_session_id = Some(provider_session_id);
    runtime.native_session_id = runtime.provider_session_id.clone();
    runtime.source = source.to_string();
    runtime.updated_at_ms = terminal_now_ms();
    Some(runtime.clone())
}

fn terminal_runtime_apply_activity_payload(
    instance: &TerminalInstance,
    payload: &TerminalActivityHookPayload,
    open_structured_interaction: Option<&TerminalStructuredInteraction>,
    task_parked: bool,
    prompt_state_update: bool,
) -> (TerminalRuntimeSnapshot, TerminalCanonicalProjection) {
    let Some(_operation) = terminal_operation_try_admit(instance) else {
        let runtime = terminal_runtime_snapshot(instance);
        let projection = terminal_canonical_projection_from_runtime(&runtime);
        return (runtime, projection);
    };
    let Ok(mut runtime) = instance.runtime.lock() else {
        let runtime = terminal_runtime_snapshot(instance);
        let projection = terminal_canonical_projection_from_runtime(&runtime);
        return (runtime, projection);
    };
    let previous = runtime.clone();
    let projection = terminal_reduce_canonical_state(
        &previous,
        payload,
        open_structured_interaction,
        task_parked,
        prompt_state_update,
    );
    let completion_rejected = terminal_projection_text(&payload.event_type, "")
        == "provider_turn_completed"
        && !projection.completion_accepted;
    let waiting_rejected = terminal_projection_text(&payload.event_type, "")
        == "provider_turn_waiting"
        && !projection.waiting_accepted;
    let interrupt_rejected = terminal_projection_text(&payload.event_type, "")
        == "provider_turn_interrupted"
        && !projection.interrupt_accepted;
    let error_rejected = (terminal_projection_text(&payload.event_type, "")
        == "provider_turn_error"
        || payload.provider_error.is_some())
        && !projection.error_accepted;
    let prompt_ready_recovery_rejected = matches!(
        terminal_projection_text(&previous.canonical_state, "starting").as_str(),
        "error" | "interrupted"
    ) && terminal_projection_text(&payload.event_type, "") == "terminal_input_ready"
        && !terminal_canonical_prompt_ready_recovery_correlates(
            &previous,
            payload,
            open_structured_interaction,
        );
    let terminal_event_rejected = completion_rejected
        || waiting_rejected
        || interrupt_rejected
        || error_rejected
        || prompt_ready_recovery_rejected;
    let active_state_override = projection.turn_active
        && (payload.input_ready
            || terminal_projection_state_is_idle(&payload.activity_status)
            || terminal_projection_state_is_idle(&payload.command_phase));
    let provider_session_id = if terminal_event_rejected {
        previous.provider_session_id.clone()
    } else {
        terminal_recordable_provider_session_id_for_metadata(
            &instance.metadata,
            payload.provider_session_id.as_deref(),
        )
        .or_else(|| {
            terminal_recordable_provider_session_id_for_metadata(
                &instance.metadata,
                previous.provider_session_id.as_deref(),
            )
        })
    };
    let native_session_id = if terminal_event_rejected {
        previous.native_session_id.clone()
    } else {
        terminal_recordable_provider_session_id_for_metadata(
            &instance.metadata,
            payload.native_session_id.as_deref(),
        )
        .or(provider_session_id.clone())
        .or_else(|| {
            terminal_recordable_provider_session_id_for_metadata(
                &instance.metadata,
                previous.native_session_id.as_deref(),
            )
        })
    };
    let fork_from_provider_session_id = if terminal_event_rejected {
        previous.fork_from_provider_session_id.clone()
    } else {
        terminal_recordable_provider_session_id_for_metadata(
            &instance.metadata,
            payload.fork_from_provider_session_id.as_deref(),
        )
        .or_else(|| previous.fork_from_provider_session_id.clone())
    };
    let snapshot = TerminalRuntimeSnapshot {
        terminal_state_contract_version: 1,
        canonical_state: projection.canonical_state.clone(),
        canonical_badge_label: projection.canonical_badge_label.clone(),
        canonical_state_seq: projection.canonical_state_seq,
        prompt_state_seq: projection.prompt_state_seq,
        turn_generation: projection.turn_generation,
        completed_turn_generation: projection.completed_turn_generation,
        turn_active: projection.turn_active,
        active_interaction_id: projection.active_interaction_id.clone(),
        active_interaction_revision: projection.active_interaction_revision,
        interaction_actionable: projection.interaction_actionable,
        status: if projection.completion_accepted {
            "active".to_string()
        } else if terminal_event_rejected {
            previous.status.clone()
        } else if active_state_override {
            "active".to_string()
        } else {
            payload.status.clone()
        },
        activity_status: if projection.completion_accepted {
            "idle".to_string()
        } else if terminal_event_rejected {
            previous.activity_status.clone()
        } else if active_state_override {
            match projection.canonical_state.as_str() {
                "uir" => "awaiting_input",
                "paused" => "paused",
                _ => "thinking",
            }
            .to_string()
        } else {
            payload.activity_status.clone()
        },
        command_phase: if projection.completion_accepted {
            "completed".to_string()
        } else if terminal_event_rejected {
            previous.command_phase.clone()
        } else if active_state_override {
            match projection.canonical_state.as_str() {
                "uir" | "paused" => "awaiting_input".to_string(),
                _ if terminal_projection_state_is_busy(&previous.command_phase) => {
                    previous.command_phase.clone()
                }
                _ => "running".to_string(),
            }
        } else {
            payload.command_phase.clone()
        },
        input_ready: if terminal_event_rejected {
            previous.input_ready
        } else if projection.turn_active {
            false
        } else {
            projection.completion_accepted || payload.input_ready
        },
        input_ready_at: if projection.completion_accepted {
            payload
                .input_ready_at
                .clone()
                .or_else(|| Some(crate::coordination::kernel::now_rfc3339()))
        } else if terminal_event_rejected {
            previous.input_ready_at.clone()
        } else if active_state_override {
            previous.input_ready_at.clone()
        } else {
            payload.input_ready_at.clone()
        },
        prompt_ready_at: if projection.completion_accepted {
            payload
                .prompt_ready_at
                .clone()
                .or_else(|| Some(crate::coordination::kernel::now_rfc3339()))
        } else if terminal_event_rejected {
            previous.prompt_ready_at.clone()
        } else if active_state_override {
            previous.prompt_ready_at.clone()
        } else {
            payload.prompt_ready_at.clone()
        },
        completed_at: if projection.completion_accepted {
            payload
                .completed_at
                .clone()
                .or_else(|| Some(crate::coordination::kernel::now_rfc3339()))
        } else if terminal_event_rejected {
            previous.completed_at.clone()
        } else if active_state_override {
            previous.completed_at.clone()
        } else {
            payload.completed_at.clone()
        },
        provider_session_id,
        native_session_id,
        fork_from_provider_session_id,
        provider_turn_id: if terminal_event_rejected {
            previous.provider_turn_id.clone()
        } else {
            payload
                .provider_turn_id
                .clone()
                .or_else(|| previous.provider_turn_id.clone())
        },
        turn_id: if terminal_event_rejected {
            previous.turn_id.clone()
        } else {
            payload.turn_id.clone().or_else(|| previous.turn_id.clone())
        },
        source: if terminal_event_rejected {
            previous.source.clone()
        } else {
            payload.source.clone()
        },
        event_type: if projection.completion_accepted {
            "provider-turn-completed".to_string()
        } else if terminal_event_rejected {
            previous.event_type.clone()
        } else {
            payload.event_type.clone()
        },
        hook_event_name: if projection.completion_accepted {
            "Stop".to_string()
        } else if terminal_event_rejected {
            previous.hook_event_name.clone()
        } else {
            payload.hook_event_name.clone()
        },
        updated_at_ms: if terminal_event_rejected {
            previous.updated_at_ms
        } else {
            payload.observed_at_ms
        },
        waiting_origin_ms: terminal_next_waiting_origin_ms(
            &previous,
            payload,
            &projection,
            terminal_event_rejected,
        ),
        background_task_counts: if terminal_event_rejected {
            previous.background_task_counts
        } else if payload.background_task_counts.is_some() {
            payload.background_task_counts
        } else if matches!(
            projection.canonical_state.as_str(),
            "idle" | "interrupted" | "error" | "closing"
        ) {
            // Settled/terminal states owe no background cue.
            None
        } else {
            previous.background_task_counts
        },
    };
    *runtime = snapshot.clone();
    (snapshot, projection)
}

/// Next `waiting_origin_ms` after an event: an accepted park stamps the
/// parking event's ORIGIN (hook fire time; max() keeps a stale re-park from
/// rewinding the ordering identity), rejected events and continued waiting
/// preserve it, and leaving waiting clears it.
fn terminal_next_waiting_origin_ms(
    previous: &TerminalRuntimeSnapshot,
    payload: &TerminalActivityHookPayload,
    projection: &TerminalCanonicalProjection,
    terminal_event_rejected: bool,
) -> u64 {
    if terminal_event_rejected {
        previous.waiting_origin_ms
    } else if projection.waiting_accepted {
        previous.waiting_origin_ms.max(if payload.hook_timestamp_ms > 0 {
            payload.hook_timestamp_ms
        } else {
            payload.observed_at_ms
        })
    } else if projection.canonical_state == "waiting" {
        previous.waiting_origin_ms
    } else {
        0
    }
}

fn terminal_runtime_snapshot_is_starting(runtime: &TerminalRuntimeSnapshot) -> bool {
    matches!(
        terminal_projection_text(&runtime.status, "").as_str(),
        "starting" | "prewarmed"
    ) || matches!(
        terminal_projection_text(&runtime.activity_status, "").as_str(),
        "starting" | "prewarmed"
    ) || terminal_projection_text(&runtime.command_phase, "") == "starting"
}

fn terminal_runtime_snapshot_is_interrupted(runtime: &TerminalRuntimeSnapshot) -> bool {
    terminal_projection_text(&runtime.event_type, "") == "provider_turn_interrupted"
        || matches!(
            terminal_projection_text(&runtime.activity_status, "").as_str(),
            "cancelled" | "canceled" | "interrupted"
        )
        || matches!(
            terminal_projection_text(&runtime.command_phase, "").as_str(),
            "cancelled" | "canceled" | "interrupted"
        )
}

fn terminal_runtime_snapshot_is_recoverable_startup_error(
    runtime: &TerminalRuntimeSnapshot,
) -> bool {
    terminal_projection_text(&runtime.event_type, "") == "provider_startup_error"
}

fn terminal_runtime_snapshot_is_busy_turn(runtime: &TerminalRuntimeSnapshot) -> bool {
    let status = terminal_projection_text(&runtime.status, "");
    let activity = terminal_projection_text(&runtime.activity_status, "");
    let command_phase = terminal_projection_text(&runtime.command_phase, "");
    let event_type = terminal_projection_text(&runtime.event_type, "");
    let hook_event_name = terminal_projection_text(&runtime.hook_event_name, "");

    if runtime.input_ready
        || terminal_projection_state_is_error(&status)
        || terminal_projection_state_is_error(&activity)
        || terminal_projection_state_is_paused(&status)
        || terminal_projection_state_is_paused(&activity)
        || terminal_projection_state_is_closed(&status)
        || terminal_projection_state_is_finished(&activity)
        || matches!(command_phase.as_str(), "completed" | "complete" | "done")
    {
        return false;
    }

    terminal_projection_state_is_busy(&status)
        || terminal_projection_state_is_busy(&activity)
        || terminal_projection_state_is_busy(&command_phase)
        || matches!(
            event_type.as_str(),
            "message_submitted"
                | "message-submitted"
                | "provider_turn_started"
                | "provider-turn-started"
                | "agent_output"
                | "agent-output"
                | "pending_prompt_sent"
                | "pending-prompt-sent"
        )
        || matches!(
            hook_event_name.as_str(),
            "backendpromptsubmit"
                | "userpromptsubmit"
                | "userpromptsubmitted"
                | "promptsubmit"
                | "promptsubmitted"
        )
}

fn terminal_prompt_ready_recovery_allowed(
    metadata: &TerminalInstanceMetadata,
    runtime: &TerminalRuntimeSnapshot,
) -> bool {
    // Startup is the one PTY recovery every hook-managed provider (Claude
    // included) is allowed: this path only runs once a prompt marker is
    // already on screen and a Claude terminal sitting at its composer prompt
    // during startup is genuinely idle/ready. Without it a missed SessionStart
    // hook strands the cloud/web row on "starting" forever, since Claude's
    // busy-turn PTY recovery stays disabled below.
    if terminal_runtime_snapshot_is_starting(runtime) {
        return true;
    }

    // An interrupt is authoritative immediately, but it is not itself proof
    // that the provider has returned to its composer. Likewise, an MCP
    // startup timeout remains recoverable. In both states, a later prompt
    // marker is the explicit provider boundary that may restore input-ready.
    if terminal_runtime_snapshot_is_interrupted(runtime)
        || terminal_runtime_snapshot_is_recoverable_startup_error(runtime)
    {
        return terminal_activity_provider_allows_pty_lifecycle_recovery(metadata);
    }

    // Claude Code exposes deterministic SessionStart/UserPromptSubmit/Stop
    // hooks and keeps its composer prompt on screen while a turn is still
    // reasoning, so a visible prompt glyph mid-turn is not proof input is
    // ready. Outside startup, let provider hooks own Claude's lifecycle.
    if !terminal_activity_provider_allows_pty_lifecycle_recovery(metadata) {
        return false;
    }

    // Provider Stop/session-idle hooks remain the primary completion signal,
    // but running terminals can predate the latest hook install or miss one
    // hook write. A prompt marker after the busy debounce is a recovery signal
    // for hook-managed providers that do not emit reliable turn-end hooks.
    // Codex and Claude have full lifecycle-hook coverage, and prompt-ready
    // recovery can race ahead of their real Stop hook while output is active.
    if terminal_metadata_is_codex(metadata) {
        return false;
    }

    terminal_runtime_snapshot_is_busy_turn(runtime)
}

fn terminal_activity_provider_allows_pty_lifecycle_recovery(
    metadata: &TerminalInstanceMetadata,
) -> bool {
    !terminal_metadata_is_claude(metadata)
}

fn terminal_runtime_startup_idle_fingerprint(runtime: &TerminalRuntimeSnapshot) -> Value {
    json!({
        "status": runtime.status,
        "activity_status": runtime.activity_status,
        "command_phase": runtime.command_phase,
        "input_ready": runtime.input_ready,
        "input_ready_at": runtime.input_ready_at,
        "prompt_ready_at": runtime.prompt_ready_at,
        "completed_at": runtime.completed_at,
        "provider_session_id": runtime.provider_session_id,
        "native_session_id": runtime.native_session_id,
        "fork_from_provider_session_id": runtime.fork_from_provider_session_id,
        "provider_turn_id": runtime.provider_turn_id,
        "turn_id": runtime.turn_id,
        "source": runtime.source,
        "event_type": runtime.event_type,
        "hook_event_name": runtime.hook_event_name,
        "updated_at_ms": runtime.updated_at_ms,
    })
}

fn terminal_projection_text(value: &str, fallback: &str) -> String {
    let normalized = value.trim().to_ascii_lowercase().replace([' ', '-'], "_");
    if normalized.is_empty() {
        fallback.to_string()
    } else {
        normalized
    }
}

fn terminal_projection_state_is_busy(value: &str) -> bool {
    matches!(
        terminal_projection_text(value, "").as_str(),
        "busy"
            | "compacting"
            | "compaction"
            | "delegating"
            | "dispatched"
            | "editing"
            | "implementing"
            | "mcp"
            | "pending"
            | "queued"
            | "reasoning"
            | "resume_requested"
            | "resumed"
            | "running"
            | "shell"
            | "starting"
            | "subagent"
            | "subagent_completed"
            | "subagent_running"
            | "submitted"
            | "thinking"
            | "tool"
            | "tool_completed"
            | "tool_running"
            | "waiting"
            | "working"
    )
}

fn terminal_projection_state_is_idle(value: &str) -> bool {
    matches!(
        terminal_projection_text(value, "").as_str(),
        "complete" | "completed" | "done" | "idle" | "input_ready" | "interrupted" | "ready"
    )
}

fn terminal_projection_state_is_paused(value: &str) -> bool {
    matches!(
        terminal_projection_text(value, "").as_str(),
        "awaiting_input"
            | "awaiting_user"
            | "needs_input"
            | "parked"
            | "paused"
            | "prompting_user"
            | "requires_input"
            | "requires_user_input"
            | "resume_ready"
            | "uir"
            | "user_input_required"
    )
}

fn terminal_projection_state_is_error(value: &str) -> bool {
    matches!(
        terminal_projection_text(value, "").as_str(),
        "error" | "failed" | "failure"
    )
}

fn terminal_projection_state_is_closed(value: &str) -> bool {
    matches!(
        terminal_projection_text(value, "").as_str(),
        "closed" | "closing" | "exited" | "no_session" | "offline" | "stopped" | "terminated"
    )
}

fn terminal_projection_state_is_finished(value: &str) -> bool {
    matches!(
        terminal_projection_text(value, "").as_str(),
        "cancelled" | "canceled" | "complete" | "completed" | "done" | "interrupted"
    )
}

fn terminal_projection_state_is_compacting(value: &str) -> bool {
    matches!(
        terminal_projection_text(value, "").as_str(),
        "compacting" | "compaction"
    )
}

fn terminal_projection_readiness(status: &str) -> &'static str {
    let status = terminal_projection_text(status, "idle");
    if matches!(status.as_str(), "cancelled" | "canceled" | "interrupted") {
        "interrupted"
    } else if terminal_projection_state_is_busy(&status) {
        "busy"
    } else if terminal_projection_state_is_paused(&status) {
        "needs_input"
    } else if terminal_projection_state_is_error(&status) {
        "error"
    } else if status == "closing" {
        "closing"
    } else if terminal_projection_state_is_closed(&status) {
        "closed"
    } else {
        "ready"
    }
}

fn terminal_projection_turn_status(activity_status: &str, status: &str) -> &'static str {
    let activity =
        terminal_projection_text(activity_status, &terminal_projection_text(status, "idle"));
    if matches!(activity.as_str(), "cancelled" | "canceled" | "interrupted") {
        "interrupted"
    } else if terminal_projection_state_is_compacting(&activity) {
        "running"
    } else if terminal_projection_state_is_busy(&activity) {
        "running"
    } else if terminal_projection_state_is_error(&activity) {
        "failed"
    } else if terminal_projection_state_is_paused(&activity) {
        "pending"
    } else if terminal_projection_state_is_closed(&activity) {
        "interrupted"
    } else {
        "completed"
    }
}

fn terminal_projection_execution_phase(
    event_type: &str,
    command_phase: &str,
    activity_status: &str,
    status: &str,
    readiness: &str,
    turn_status: &str,
    terminal_lifecycle: &str,
) -> &'static str {
    let event_type = terminal_projection_text(event_type, "");
    let command_phase = terminal_projection_text(command_phase, "");
    let activity = terminal_projection_text(activity_status, "");
    let status = terminal_projection_text(status, "");
    let readiness = terminal_projection_text(readiness, "");
    let turn = terminal_projection_text(turn_status, "");
    let lifecycle = terminal_projection_text(terminal_lifecycle, "");

    if matches!(activity.as_str(), "starting" | "prewarmed")
        || matches!(status.as_str(), "starting" | "prewarmed")
        || command_phase == "starting"
    {
        return "starting";
    }
    if lifecycle == "offline" || activity == "offline" || status == "offline" {
        return "offline";
    }
    if lifecycle == "exited" || activity == "exited" || status == "exited" {
        return "exited";
    }
    if ["closed", "closing", "terminated"].contains(&lifecycle.as_str())
        || ["closed", "closing", "terminated"].contains(&status.as_str())
    {
        return if lifecycle == "closing" || status == "closing" {
            "closing"
        } else {
            "closed"
        };
    }
    if matches!(
        event_type.as_str(),
        "provider_turn_compacting" | "context_compaction_started"
    ) || terminal_projection_state_is_compacting(&command_phase)
        || terminal_projection_state_is_compacting(&activity)
        || terminal_projection_state_is_compacting(&turn)
    {
        return "compacting";
    }
    if event_type == "provider_turn_interrupted" || turn == "interrupted" {
        return "interrupted";
    }
    if matches!(turn.as_str(), "cancelled" | "canceled")
        || matches!(command_phase.as_str(), "cancelled" | "canceled")
    {
        return "cancelled";
    }
    if matches!(
        event_type.as_str(),
        "provider_turn_error" | "pending_prompt_error"
    ) || matches!(turn.as_str(), "failed" | "error")
        || terminal_projection_state_is_error(&activity)
        || readiness == "error"
        || status == "error"
    {
        return "failed";
    }
    if terminal_projection_state_is_paused(&activity)
        || matches!(readiness.as_str(), "needs_input" | "paused")
    {
        return "needs_input";
    }
    if command_phase == "queued" {
        return "queued";
    }
    if matches!(
        command_phase.as_str(),
        "submitted" | "input_written" | "accepted" | "running"
    ) || matches!(
        event_type.as_str(),
        "message_submitted" | "provider_turn_started" | "agent_output" | "pending_prompt_sent"
    ) || terminal_projection_state_is_busy(&activity)
        || matches!(
            turn.as_str(),
            "queued" | "submitted" | "pending" | "running" | "thinking" | "reasoning" | "working"
        )
        || (readiness == "busy" && !terminal_projection_state_is_finished(&turn))
    {
        return "running";
    }
    if event_type == "provider_turn_completed"
        || matches!(command_phase.as_str(), "completed" | "complete" | "done")
        || terminal_projection_state_is_finished(&turn)
        || terminal_projection_state_is_idle(&activity)
        || matches!(readiness.as_str(), "ready" | "input_ready")
    {
        return "idle";
    }

    "idle"
}

fn terminal_projection_rail_state(execution_phase: &str, fallback: &str) -> String {
    match terminal_projection_text(execution_phase, "").as_str() {
        "starting" | "prewarmed" => "starting".to_string(),
        "offline" | "closed" | "closing" | "exited" => {
            terminal_projection_text(execution_phase, "closed")
        }
        "failed" => "error".to_string(),
        "needs_input" | "paused" | "parked" | "resume_ready" => "paused".to_string(),
        "compacting" | "compaction" => "compacting".to_string(),
        "queued" | "submitted" | "input_written" | "accepted" | "running" | "cancelling" => {
            "thinking".to_string()
        }
        "cancelled" | "canceled" | "interrupted" => "interrupted".to_string(),
        "completed" | "complete" | "done" | "idle" => "idle".to_string(),
        _ => terminal_projection_text(fallback, "idle"),
    }
}

fn terminal_projection_label(value: &str) -> String {
    terminal_projection_text(value, "unknown").replace(['_', '-'], " ")
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct TerminalCanonicalProjection {
    canonical_state: String,
    canonical_badge_label: String,
    canonical_state_seq: u64,
    prompt_state_seq: u64,
    turn_generation: u64,
    completed_turn_generation: u64,
    turn_active: bool,
    active_interaction_id: Option<String>,
    active_interaction_revision: Option<u64>,
    interaction_actionable: bool,
    completion_accepted: bool,
    waiting_accepted: bool,
    interrupt_accepted: bool,
    error_accepted: bool,
}

fn terminal_canonical_projection_from_runtime(
    runtime: &TerminalRuntimeSnapshot,
) -> TerminalCanonicalProjection {
    TerminalCanonicalProjection {
        canonical_state: runtime.canonical_state.clone(),
        canonical_badge_label: runtime.canonical_badge_label.clone(),
        canonical_state_seq: runtime.canonical_state_seq,
        prompt_state_seq: runtime.prompt_state_seq,
        turn_generation: runtime.turn_generation,
        completed_turn_generation: runtime.completed_turn_generation,
        turn_active: runtime.turn_active,
        active_interaction_id: runtime.active_interaction_id.clone(),
        active_interaction_revision: runtime.active_interaction_revision,
        interaction_actionable: runtime.interaction_actionable,
        completion_accepted: false,
        waiting_accepted: false,
        interrupt_accepted: false,
        error_accepted: false,
    }
}

fn terminal_canonical_default_badge_label(state: &str) -> &'static str {
    match state {
        "starting" => "starting",
        "idle" => "idle",
        "thinking" => "thinking",
        "waiting" => "waiting",
        "paused" => "paused",
        "uir" => "input required",
        "interrupted" => "interrupted",
        "error" => "error",
        "closing" => "closing",
        "closed" => "closed",
        "offline" => "offline",
        _ => "thinking",
    }
}

fn terminal_canonical_thinking_badge(payload: &TerminalActivityHookPayload) -> &'static str {
    let values = [
        payload.event_type.as_str(),
        payload.activity_status.as_str(),
        payload.command_phase.as_str(),
        payload.hook_event_name.as_str(),
    ]
    .map(|value| terminal_projection_text(value, ""));
    if values.iter().any(|value| {
        matches!(
            value.as_str(),
            "compacting" | "compaction" | "provider_turn_compacting" | "context_compaction_started"
        )
    }) {
        "compacting"
    } else if values.iter().any(|value| {
        matches!(
            value.as_str(),
            "reasoning" | "reasoningdelta" | "thinkingdelta" | "assistantreasoningdelta"
        )
    }) {
        "reasoning"
    } else if values
        .iter()
        .any(|value| value.contains("tool") || value == "mcp")
    {
        "tooling"
    } else {
        "thinking"
    }
}

fn terminal_canonical_interaction_actionable(
    interaction: Option<&TerminalStructuredInteraction>,
) -> bool {
    interaction.is_some_and(|interaction| {
        !interaction.interaction_id.trim().is_empty()
            && interaction.revision > 0
            && !interaction.provider_request_id.trim().is_empty()
            && !interaction.response_mode.trim().is_empty()
            && (!interaction.options.is_empty()
                || interaction.prompt_questions.is_some()
                || interaction.prompt_schema.is_some()
                || interaction.provider_payload.is_some())
    })
}

fn terminal_canonical_exact_resolution(
    previous: &TerminalRuntimeSnapshot,
    payload: &TerminalActivityHookPayload,
) -> bool {
    let event_type = terminal_projection_text(&payload.event_type, "");
    let hook = terminal_activity_hook_name_key(&payload.hook_event_name);
    let resolution_event = matches!(
        event_type.as_str(),
        "provider_user_prompt_answered" | "provider_user_prompt_completed"
    ) || matches!(
        hook.as_str(),
        "permissiondenied"
            | "permissionresult"
            | "permissionresolved"
            | "elicitationresult"
            | "elicitationresolved"
    );
    resolution_event
        && previous.active_interaction_id.is_some()
        && previous.active_interaction_revision.is_some()
        && previous.active_interaction_id.as_deref() == payload.event_interaction_id.as_deref()
        && previous.active_interaction_revision == payload.event_interaction_revision
}

fn terminal_canonical_stop_correlates(
    previous: &TerminalRuntimeSnapshot,
    payload: &TerminalActivityHookPayload,
) -> bool {
    // Missing control-event generations are bound to the current generation
    // at ingestion. Explicit values are left untouched, so exact equality
    // rejects an old event without confusing it with an absent field.
    let generation_matches = payload.turn_generation == previous.turn_generation;
    let session_matches = match (
        previous
            .provider_session_id
            .as_deref()
            .or(previous.native_session_id.as_deref()),
        payload
            .provider_session_id
            .as_deref()
            .or(payload.native_session_id.as_deref()),
    ) {
        (Some(previous), Some(candidate)) => previous.trim() == candidate.trim(),
        _ => true,
    };
    let previous_turn = previous
        .provider_turn_id
        .as_deref()
        .or(previous.turn_id.as_deref());
    let candidate_turn = payload
        .provider_turn_id
        .as_deref()
        .or(payload.turn_id.as_deref());
    let turn_matches = match (previous_turn, candidate_turn) {
        (Some(previous), Some(candidate)) => previous.trim() == candidate.trim(),
        _ => true,
    };
    // WAITING awaits a FUTURE turn's stop: the background continuation may
    // mint a new turn id with no intermediate event updating the runtime, so
    // a turn-id mismatch alone must not reject the stop. The exemption is
    // deliberately narrow: generation equality stays required AND the session
    // must match EXPLICITLY (both sides present and equal) — a session-less
    // stray can never settle a waiting turn. Residual (accepted): a delayed
    // generationless Stop from an OLDER turn of the SAME session is
    // indistinguishable from the awaited one; hook transport is ordered, so
    // in practice the next same-session Stop after waiting IS the completion.
    let explicit_session_match = matches!(
        (
            previous
                .provider_session_id
                .as_deref()
                .or(previous.native_session_id.as_deref())
                .map(str::trim)
                .filter(|value| !value.is_empty()),
            payload
                .provider_session_id
                .as_deref()
                .or(payload.native_session_id.as_deref())
                .map(str::trim)
                .filter(|value| !value.is_empty()),
        ),
        (Some(previous_session), Some(candidate_session)) if previous_session == candidate_session
    );
    // Durable ordering identity: hook processing is NOT ordered (independent
    // tasks + a polled JSONL fallback), so a delayed Stop from an OLDER turn
    // can arrive after WAITING began. The event's ORIGIN timestamp (stamped
    // by the hook CLI at fire time) discriminates: only a stop that fired
    // at/after the waiting entry's ORIGIN (`waiting_origin_ms`, same clock
    // domain — never ingestion-time `updated_at_ms`) may act. Every
    // legitimate producer stamps fire time, so an unstamped candidate fails.
    let event_origin_ms = if payload.hook_timestamp_ms > 0 {
        payload.hook_timestamp_ms
    } else {
        payload.observed_at_ms
    };
    let ordered_after_waiting =
        terminal_waiting_origin_ordered(event_origin_ms, previous.waiting_origin_ms);
    let waiting_previous = terminal_projection_text(&previous.canonical_state, "") == "waiting";
    if waiting_previous && terminal_projection_text(&payload.event_type, "") == "provider_turn_completed" {
        // Settling WAITING always consults the ordering gate: absent turn ids
        // must not slip through the `turn_matches` missing-field default, and
        // matching ids are no proof against a delayed duplicate. Turn ids are
        // advisory here — session identity plus origin ordering decide.
        return generation_matches && explicit_session_match && ordered_after_waiting;
    }
    let waiting_awaits_future_turn =
        explicit_session_match && ordered_after_waiting && waiting_previous;
    generation_matches && session_matches && (turn_matches || waiting_awaits_future_turn)
}

/// ORIGIN timestamp of a raw hook event: the hook CLI stamps `timestamp_ms`
/// at fire time; `ts_ms`/`observed_at_ms` cover synthetic emitters. Zero
/// means the producer never stamped an origin.
fn terminal_event_origin_ms(event: &Value) -> u64 {
    event
        .get("timestamp_ms")
        .and_then(Value::as_u64)
        .or_else(|| event.get("ts_ms").and_then(Value::as_u64))
        .or_else(|| event.get("observed_at_ms").and_then(Value::as_u64))
        .unwrap_or(0)
}

/// WAITING ordering gate: a candidate may act on a waiting session only when
/// it carries a real origin stamp at/after the waiting entry's origin. An
/// unstamped candidate FAILS closed (all legitimate producers stamp fire
/// time); an unstamped waiting entry cannot discriminate and accepts any
/// stamped candidate.
fn terminal_waiting_origin_ordered(candidate_origin_ms: u64, waiting_origin_ms: u64) -> bool {
    candidate_origin_ms > 0
        && (waiting_origin_ms == 0 || candidate_origin_ms >= waiting_origin_ms)
}

fn terminal_canonical_error_correlates(
    previous: &TerminalRuntimeSnapshot,
    payload: &TerminalActivityHookPayload,
    open_structured_interaction: Option<&TerminalStructuredInteraction>,
) -> bool {
    if payload.event_interaction_id.is_some() || payload.event_interaction_revision.is_some() {
        let current_interaction_id = open_structured_interaction
            .map(|interaction| interaction.interaction_id.as_str())
            .or(previous.active_interaction_id.as_deref());
        let current_interaction_revision = open_structured_interaction
            .map(|interaction| interaction.revision)
            .or(previous.active_interaction_revision);
        return current_interaction_id == payload.event_interaction_id.as_deref()
            && current_interaction_revision == payload.event_interaction_revision;
    }
    if payload.turn_generation_explicit {
        return terminal_canonical_stop_correlates(previous, payload);
    }

    let candidate_turn = payload
        .provider_turn_id
        .as_deref()
        .or(payload.turn_id.as_deref())
        .map(str::trim)
        .filter(|value| !value.is_empty());
    if let Some(candidate_turn) = candidate_turn {
        let current_turn = previous
            .provider_turn_id
            .as_deref()
            .or(previous.turn_id.as_deref())
            .map(str::trim)
            .filter(|value| !value.is_empty());
        if current_turn != Some(candidate_turn) {
            return false;
        }
    }

    // A provider session error often has no turn/interaction identity. It is
    // still authoritative for the current session, including while that
    // session is blocked on UIR. Explicit stale interaction or generation
    // identities were handled above and remain exact-match only.
    match (
        previous
            .provider_session_id
            .as_deref()
            .or(previous.native_session_id.as_deref()),
        payload
            .provider_session_id
            .as_deref()
            .or(payload.native_session_id.as_deref()),
    ) {
        (Some(previous), Some(candidate)) => {
            !previous.trim().is_empty() && previous.trim() == candidate.trim()
        }
        _ => open_structured_interaction.is_none() && previous.active_interaction_id.is_none(),
    }
}

fn terminal_canonical_prompt_ready_recovery_correlates(
    previous: &TerminalRuntimeSnapshot,
    payload: &TerminalActivityHookPayload,
    open_structured_interaction: Option<&TerminalStructuredInteraction>,
) -> bool {
    let previous_state = terminal_projection_text(&previous.canonical_state, "starting");
    if !matches!(previous_state.as_str(), "error" | "interrupted")
        || previous.turn_active
        || previous.active_interaction_id.is_some()
        || open_structured_interaction.is_some()
        || terminal_projection_text(&payload.event_type, "") != "terminal_input_ready"
        || !payload.input_ready
        || !terminal_projection_state_is_idle(&payload.activity_status)
    {
        return false;
    }

    // Prompt-ready recovery is allowed to clear an interrupted/error gate only
    // for the exact turn that observed the prompt. Backend prompt observers
    // freeze this generation on their synthesized event; requiring an explicit
    // generation prevents an older delayed observation from being rebound to
    // whichever turn happens to be current when the event is ingested.
    if !payload.turn_generation_explicit || payload.turn_generation != previous.turn_generation {
        return false;
    }

    let previous_turn = previous
        .provider_turn_id
        .as_deref()
        .or(previous.turn_id.as_deref())
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let candidate_turn = payload
        .provider_turn_id
        .as_deref()
        .or(payload.turn_id.as_deref())
        .map(str::trim)
        .filter(|value| !value.is_empty());
    if match (previous_turn, candidate_turn) {
        (Some(previous_turn), Some(candidate_turn)) => previous_turn != candidate_turn,
        (None, None) => false,
        _ => true,
    } {
        return false;
    }

    let previous_session = previous
        .provider_session_id
        .as_deref()
        .or(previous.native_session_id.as_deref())
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let candidate_session = payload
        .provider_session_id
        .as_deref()
        .or(payload.native_session_id.as_deref())
        .map(str::trim)
        .filter(|value| !value.is_empty());
    match (previous_session, candidate_session) {
        (Some(previous_session), Some(candidate_session)) => {
            previous_session == candidate_session
        }
        (None, None) => true,
        _ => false,
    }
}

fn terminal_canonical_transition_allowed(previous: &str, next: &str) -> bool {
    if previous == next {
        return true;
    }
    matches!(
        (previous, next),
        ("starting", "idle")
            | ("starting", "thinking")
            | ("idle", "thinking")
            | ("thinking", "uir")
            | ("thinking", "paused")
            | ("uir", "thinking")
            | ("paused", "thinking")
            | ("thinking", "idle")
            | ("uir", "idle")
            | ("paused", "idle")
            | ("thinking", "waiting")
            | ("uir", "waiting")
            | ("paused", "waiting")
            | ("waiting", "thinking")
            | ("waiting", "idle")
            | ("waiting", "uir")
            | ("waiting", "interrupted")
            | ("waiting", "error")
            | ("waiting", "closing")
            | ("interrupted", "idle")
            | ("error", "idle")
            | ("thinking", "interrupted")
            | ("uir", "interrupted")
            | ("paused", "interrupted")
            | ("thinking", "error")
            | ("uir", "error")
            | ("paused", "error")
            | ("starting", "error")
            | ("idle", "error")
            | ("starting", "closing")
            | ("idle", "closing")
            | ("thinking", "closing")
            | ("uir", "closing")
            | ("paused", "closing")
            | ("interrupted", "closing")
            | ("error", "closing")
            | ("offline", "closing")
            | ("closing", "closed")
            | ("closed", "starting")
    )
}

fn terminal_reduce_canonical_state(
    previous_runtime: &TerminalRuntimeSnapshot,
    authoritative_event: &TerminalActivityHookPayload,
    open_structured_interaction: Option<&TerminalStructuredInteraction>,
    task_parked: bool,
    prompt_state_update: bool,
) -> TerminalCanonicalProjection {
    let event_type = terminal_projection_text(&authoritative_event.event_type, "");
    let previous_state = terminal_projection_text(&previous_runtime.canonical_state, "starting");
    let turn_started = matches!(
        event_type.as_str(),
        "provider_turn_started" | "message_submitted" | "pending_prompt_sent"
    );
    let completion_event = event_type == "provider_turn_completed";
    let waiting_event = event_type == "provider_turn_waiting";
    let interrupt_event = event_type == "provider_turn_interrupted";
    let error_event =
        event_type == "provider_turn_error" || authoritative_event.provider_error.is_some();
    let close_event = matches!(
        event_type.as_str(),
        "remote_control_close" | "terminal_closed" | "closed" | "closing"
    );
    let prompt_event = terminal_activity_payload_has_prompt_signal(authoritative_event);
    let prompt_accepts_missing_turn = prompt_event
        && !previous_runtime.turn_active
        && matches!(previous_state.as_str(), "starting" | "idle");
    let exact_resolution =
        terminal_canonical_exact_resolution(previous_runtime, authoritative_event);
    let distinct_open_interaction_remains =
        open_structured_interaction.is_some_and(|interaction| {
            authoritative_event.event_interaction_id.as_deref()
                != Some(interaction.interaction_id.as_str())
                || authoritative_event.event_interaction_revision != Some(interaction.revision)
        });
    let stop_correlates = terminal_canonical_stop_correlates(previous_runtime, authoritative_event);
    let generationless_completion_blocked_by_uir = completion_event
        && !authoritative_event.turn_generation_explicit
        && (previous_state == "uir"
            || previous_runtime.active_interaction_id.is_some()
            || open_structured_interaction.is_some());
    let error_accepted = error_event
        && terminal_canonical_error_correlates(
            previous_runtime,
            authoritative_event,
            open_structured_interaction,
        );
    let prompt_ready_recovery = terminal_canonical_prompt_ready_recovery_correlates(
        previous_runtime,
        authoritative_event,
        open_structured_interaction,
    );

    let mut turn_generation = previous_runtime.turn_generation;
    let mut completed_turn_generation = previous_runtime.completed_turn_generation;
    let mut turn_active = previous_runtime.turn_active;
    if (turn_started || prompt_accepts_missing_turn) && !previous_runtime.turn_active {
        turn_generation = turn_generation.saturating_add(1);
        turn_active = true;
    }

    let completion_accepted = completion_event
        && stop_correlates
        && !generationless_completion_blocked_by_uir
        && previous_runtime.turn_active
        && matches!(
            previous_state.as_str(),
            "thinking" | "uir" | "paused" | "waiting"
        );
    // A Stop that arrives while the harness still owns background work
    // (shells/subagents) parks the session in WAITING: the turn stays OPEN —
    // no settlement, no completed generation — until the true final Stop.
    let waiting_accepted = waiting_event
        && stop_correlates
        && previous_runtime.turn_active
        && matches!(
            previous_state.as_str(),
            "thinking" | "uir" | "paused" | "waiting"
        );
    let interrupt_accepted = interrupt_event
        && stop_correlates
        && previous_runtime.turn_active
        && matches!(
            previous_state.as_str(),
            "thinking" | "uir" | "paused" | "waiting"
        );
    if completion_accepted {
        completed_turn_generation = turn_generation;
        turn_active = false;
    }
    if interrupt_accepted {
        completed_turn_generation = turn_generation;
        turn_active = false;
    }
    if error_accepted {
        turn_active = false;
    }
    if prompt_ready_recovery {
        completed_turn_generation = turn_generation;
        turn_active = false;
    }

    let mut next_state = if close_event {
        "closing"
    } else if error_accepted {
        "error"
    } else if interrupt_accepted {
        "interrupted"
    } else if completion_accepted && completed_turn_generation == turn_generation {
        "idle"
    } else if waiting_accepted {
        "waiting"
    } else if (waiting_event || completion_event || interrupt_event)
        && previous_state == "waiting"
    {
        // Any Stop-family event that failed acceptance while WAITING (id
        // drift, stale origin) must hold WAITING — falling through to
        // thinking would flap the state and adopt unverified identifiers.
        "waiting"
    } else if prompt_ready_recovery {
        "idle"
    } else if prompt_event {
        "uir"
    } else if distinct_open_interaction_remains {
        "uir"
    } else if exact_resolution {
        "thinking"
    } else if previous_state == "uir" {
        // An unresolved provider prompt owns the lifecycle state. Passive
        // turn/task evidence cannot resume or park it; only an exact answer
        // or provider resolution may move UIR back to thinking.
        "uir"
    } else if previous_state == "waiting" && !turn_started {
        // Passive/background evidence — SubagentStop, TaskCompleted, tool
        // noise — IS the work the parking Stop awaits. It must not melt the
        // WAITING latch (a flip to thinking clears waiting_origin_ms and
        // drops the settle gate, so the true final Stop can be rejected or
        // a stale one accepted). Only Stop-family outcomes, interrupts,
        // errors, prompts, close, or explicit turn re-entry move waiting.
        "waiting"
    } else if task_parked {
        "paused"
    } else if turn_started {
        "thinking"
    } else if previous_state == "paused" {
        if matches!(
            terminal_projection_text(&authoritative_event.activity_status, "").as_str(),
            "resumed" | "resume_requested" | "thinking" | "running"
        ) {
            "thinking"
        } else {
            "paused"
        }
    } else if turn_active {
        // Missing/unknown/passive evidence during an active turn is thinking,
        // never idle. This is the queue-drain safety invariant.
        "thinking"
    } else if previous_state == "starting"
        && matches!(
            event_type.as_str(),
            "provider_session_ready" | "terminal_input_ready"
        )
    {
        "idle"
    } else {
        previous_state.as_str()
    };

    if turn_active && next_state == "idle" {
        next_state = "thinking";
    }
    let transition_allowed = terminal_canonical_transition_allowed(&previous_state, next_state)
        || (prompt_accepts_missing_turn
            && next_state == "uir"
            && terminal_canonical_transition_allowed(&previous_state, "thinking")
            && terminal_canonical_transition_allowed("thinking", "uir"));
    if !transition_allowed {
        next_state = if previous_state == "waiting" {
            // A vetoed transition out of WAITING must never decay to
            // thinking — that clears the ordering latch. Hold waiting.
            "waiting"
        } else if turn_active {
            "thinking"
        } else {
            previous_state.as_str()
        };
    }

    let clears_interaction =
        completion_accepted || interrupt_accepted || error_accepted || close_event;
    let interaction_clear_boundary = clears_interaction
        && (previous_runtime.active_interaction_id.is_some()
            || open_structured_interaction.is_some()
            || previous_state == "uir");
    let mut prompt_state_seq = previous_runtime.prompt_state_seq;
    // Prompt latches may be overlaid from the currently-open interaction so
    // emitted passive frames keep describing it. Only the pre-overlay provider
    // event is allowed to advance the prompt cohort sequence.
    let prompt_update = prompt_event && prompt_state_update;
    let prompt_resolution = exact_resolution;
    if prompt_update || prompt_resolution || interaction_clear_boundary || close_event {
        prompt_state_seq = prompt_state_seq.saturating_add(1);
    }

    let (active_interaction_id, active_interaction_revision) = if clears_interaction {
        (None, None)
    } else if distinct_open_interaction_remains {
        let interaction = open_structured_interaction.expect("checked distinct open interaction");
        (
            Some(interaction.interaction_id.clone()),
            Some(interaction.revision),
        )
    } else if prompt_resolution {
        (None, None)
    } else if let Some(interaction) = open_structured_interaction {
        (
            Some(interaction.interaction_id.clone()),
            Some(interaction.revision),
        )
    } else if prompt_event {
        (
            authoritative_event.interaction_id.clone(),
            authoritative_event.interaction_revision,
        )
    } else {
        (
            previous_runtime.active_interaction_id.clone(),
            previous_runtime.active_interaction_revision,
        )
    };
    let interaction_actionable = next_state == "uir"
        && terminal_canonical_interaction_actionable(open_structured_interaction);
    let rejected_completion = completion_event && !completion_accepted;
    let rejected_waiting = waiting_event && !waiting_accepted;
    let rejected_interrupt = interrupt_event && !interrupt_accepted;
    let rejected_error = error_event && !error_accepted;
    let badge_label = if rejected_completion || rejected_waiting || rejected_interrupt || rejected_error {
        previous_runtime.canonical_badge_label.clone()
    } else if next_state == "thinking" {
        terminal_canonical_thinking_badge(authoritative_event).to_string()
    } else {
        terminal_canonical_default_badge_label(next_state).to_string()
    };
    let canonical_changed = previous_state != next_state
        || previous_runtime.canonical_badge_label != badge_label
        || previous_runtime.turn_generation != turn_generation
        || previous_runtime.completed_turn_generation != completed_turn_generation
        || previous_runtime.turn_active != turn_active
        || previous_runtime.active_interaction_id != active_interaction_id
        || previous_runtime.active_interaction_revision != active_interaction_revision
        || previous_runtime.interaction_actionable != interaction_actionable;

    TerminalCanonicalProjection {
        canonical_state: next_state.to_string(),
        canonical_badge_label: badge_label,
        canonical_state_seq: if canonical_changed {
            previous_runtime.canonical_state_seq.saturating_add(1)
        } else {
            previous_runtime.canonical_state_seq
        },
        prompt_state_seq,
        turn_generation,
        completed_turn_generation,
        turn_active,
        active_interaction_id,
        active_interaction_revision,
        interaction_actionable,
        completion_accepted,
        waiting_accepted,
        interrupt_accepted,
        error_accepted,
    }
}

fn terminal_apply_canonical_projection_to_payload(
    payload: &mut TerminalActivityHookPayload,
    projection: &TerminalCanonicalProjection,
) {
    payload.terminal_state_contract_version = 1;
    payload.canonical_state = projection.canonical_state.clone();
    payload.canonical_badge_label = projection.canonical_badge_label.clone();
    payload.canonical_state_seq = projection.canonical_state_seq;
    payload.prompt_state_seq = projection.prompt_state_seq;
    payload.turn_generation = projection.turn_generation;
    payload.completed_turn_generation = projection.completed_turn_generation;
    payload.turn_active = projection.turn_active;
    payload.active_interaction_id = projection.active_interaction_id.clone();
    payload.active_interaction_revision = projection.active_interaction_revision;
    payload.interaction_actionable = projection.interaction_actionable;
    payload.turn_settlement_accepted =
        projection.completion_accepted || projection.interrupt_accepted;
    if projection.completion_accepted {
        payload.status = "active".to_string();
        payload.activity_status = "idle".to_string();
        payload.command_phase = "completed".to_string();
        payload.input_ready = true;
        payload.event_type = "provider-turn-completed".to_string();
        payload.hook_event_name = "Stop".to_string();
        let now = crate::coordination::kernel::now_rfc3339();
        payload.input_ready_at.get_or_insert_with(|| now.clone());
        payload.prompt_ready_at.get_or_insert_with(|| now.clone());
        payload.completed_at.get_or_insert(now);
    } else if projection.canonical_state == "waiting" {
        // WAITING is busy on the WIRE too, not just in the stored runtime:
        // a held (rejected) same-turn stale Stop still carries its original
        // completion tuple — emitting input_ready=true would disable Escape
        // in the UI and project remote awaiting_input while the harness
        // still owns background work. The turn is open: no readiness or
        // completion stamps may ride along.
        payload.status = "active".to_string();
        payload.activity_status = "waiting".to_string();
        payload.command_phase = "background_waiting".to_string();
        payload.input_ready = false;
        payload.input_ready_at = None;
        payload.prompt_ready_at = None;
        payload.completed_at = None;
    }
}

fn terminal_apply_projected_runtime_to_payload(
    payload: &mut TerminalActivityHookPayload,
    metadata: &TerminalInstanceMetadata,
    runtime: &TerminalRuntimeSnapshot,
) {
    let projected = terminal_project_runtime(metadata, runtime, false);
    payload.display_name = projected.display_name;
    payload.terminal_name = projected.terminal_name;
    payload.terminal_nickname = projected.terminal_nickname;
    payload.execution_phase = projected.execution_phase;
    payload.native_rail_state = projected.native_rail_state;
    payload.native_rail_label = projected.native_rail_label;
    payload.readiness = projected.readiness;
    payload.terminal_lifecycle = projected.terminal_lifecycle;
    payload.terminal_status = projected.terminal_status;
    payload.terminal_work_state = projected.terminal_work_state;
    payload.turn_status = projected.turn_status;
    payload.session_state = projected.session_state;
    if payload.background_task_counts.is_none() {
        // Passive frames while WAITING carry no task evidence of their own —
        // backfill the latched counts so every emitted frame keeps the cue.
        payload.background_task_counts = runtime.background_task_counts;
    }
}

fn terminal_projection_display_name(metadata: &TerminalInstanceMetadata) -> String {
    [
        metadata.terminal_nickname.as_str(),
        metadata.terminal_name.as_str(),
        metadata.agent_kind.as_str(),
        metadata.agent_id.as_str(),
        "Terminal",
    ]
    .iter()
    .map(|value| value.trim())
    .find(|value| !value.is_empty())
    .unwrap_or("Terminal")
    .to_string()
}

#[derive(Clone)]
struct TerminalProjectedRuntime {
    display_name: String,
    terminal_name: String,
    terminal_nickname: String,
    execution_phase: String,
    native_rail_state: String,
    native_rail_label: String,
    readiness: String,
    terminal_lifecycle: String,
    terminal_status: String,
    terminal_work_state: String,
    turn_status: String,
    session_state: String,
}

fn terminal_project_runtime(
    metadata: &TerminalInstanceMetadata,
    runtime: &TerminalRuntimeSnapshot,
    parked: bool,
) -> TerminalProjectedRuntime {
    let canonical_state = terminal_projection_text(&runtime.canonical_state, "starting");
    let terminal_lifecycle = match canonical_state.as_str() {
        "closing" => "closing",
        "closed" | "offline" => "closed",
        _ => "open",
    };
    let status = canonical_state.clone();
    let readiness = match canonical_state.as_str() {
        "thinking" | "starting" | "waiting" => "busy",
        "uir" | "paused" => "needs_input",
        "error" => "error",
        "closing" => "closing",
        "closed" | "offline" => "closed",
        _ => "ready",
    }
    .to_string();
    let turn_status = match canonical_state.as_str() {
        "thinking" | "waiting" => "running",
        "uir" | "paused" => "pending",
        "error" => "failed",
        "interrupted" | "closing" | "closed" | "offline" => "interrupted",
        _ => "completed",
    }
    .to_string();
    let execution_phase = match canonical_state.as_str() {
        "thinking" if runtime.canonical_badge_label == "compacting" => "compacting",
        "thinking" => "running",
        "uir" => "needs_input",
        state => state,
    }
    .to_string();
    let native_rail_state = canonical_state.clone();
    let native_rail_label = runtime.canonical_badge_label.clone();
    let terminal_work_state = if terminal_lifecycle == "closed" {
        "closed"
    } else if parked || matches!(canonical_state.as_str(), "uir" | "paused") {
        "prompting_user"
    } else if canonical_state == "error" {
        "error"
    } else if matches!(canonical_state.as_str(), "thinking" | "waiting") {
        "running"
    } else {
        "complete"
    }
    .to_string();
    let display_name = terminal_projection_display_name(metadata);
    let terminal_name = metadata
        .terminal_name
        .trim()
        .to_string()
        .if_empty_then(|| display_name.clone());

    TerminalProjectedRuntime {
        display_name,
        terminal_name,
        terminal_nickname: metadata.terminal_nickname.trim().to_string(),
        execution_phase,
        native_rail_state,
        native_rail_label,
        readiness,
        terminal_lifecycle: terminal_lifecycle.to_string(),
        terminal_status: status.clone(),
        terminal_work_state,
        turn_status,
        session_state: if terminal_lifecycle == "closed" {
            "no_session".to_string()
        } else if runtime
            .provider_session_id
            .as_deref()
            .or(runtime.native_session_id.as_deref())
            .is_some_and(|value| !value.trim().is_empty())
        {
            "session_attached".to_string()
        } else if canonical_state == "starting" {
            "session_starting".to_string()
        } else {
            "no_session".to_string()
        },
    }
}

trait TerminalIfEmptyThen {
    fn if_empty_then<F: FnOnce() -> String>(self, fallback: F) -> String;
}

impl TerminalIfEmptyThen for String {
    fn if_empty_then<F: FnOnce() -> String>(self, fallback: F) -> String {
        if self.trim().is_empty() {
            fallback()
        } else {
            self
        }
    }
}

fn terminal_record_coordination_provider_session_id(
    coordination: TerminalCoordinationSession,
    provider_session_id: String,
    source: impl Into<String>,
) {
    let source = source.into();
    if !terminal_provider_session_id_is_recordable_for_agent(
        &coordination.agent_id,
        &coordination.agent_kind,
        &provider_session_id,
    ) {
        log_terminal_status_event(
            "backend.terminal_provider_session.record_skip",
            json!({
                "provider": coordination.agent_kind,
                "reason": "invalid-provider-session-id",
                "source": source.clone(),
            }),
        );
        return;
    }
    tauri::async_runtime::spawn_blocking(
        move || match crate::coordination::CoordinationKernel::open(
            &coordination.repo_path,
            Some(PathBuf::from(&coordination.db_path)),
        ) {
            Ok(kernel) => {
                if let Err(error) = kernel.record_session_provider_session_id(
                    &coordination.session_id,
                    &provider_session_id,
                ) {
                    log_terminal_status_event(
                        "backend.terminal_provider_session.record_error",
                        json!({
                            "error": clean_terminal_diagnostic_log_text(&error),
                            "source": source.clone(),
                        }),
                    );
                }
            }
            Err(error) => log_terminal_status_event(
                "backend.terminal_provider_session.kernel_open_error",
                json!({
                    "error": clean_terminal_diagnostic_log_text(&error),
                    "source": source.clone(),
                }),
            ),
        },
    );
}

fn terminal_provider_session_binding_root(instance: &TerminalInstance) -> String {
    instance
        .coordination
        .as_ref()
        .map(|coordination| coordination.repo_path.clone())
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| instance.working_directory.to_string_lossy().to_string())
}

fn terminal_provider_session_binding_payload(
    instance: &TerminalInstance,
    provider_session_id: &str,
    source: &str,
) -> Option<WorkspaceThreadProviderSessionBinding> {
    let metadata = instance.metadata.clone();
    let provider_session_id =
        terminal_recordable_provider_session_id_for_metadata(&metadata, Some(provider_session_id))?;
    let runtime = terminal_runtime_snapshot(instance);
    let fork_from_provider_session_id = runtime
        .fork_from_provider_session_id
        .clone()
        .unwrap_or_default();
    let shared_history_id = workspace_agent_session_history_shared_history_id(
        &metadata.workspace_id,
        &metadata.agent_kind,
        &provider_session_id,
        &fork_from_provider_session_id,
    );
    Some(WorkspaceThreadProviderSessionBinding {
        workspace_id: metadata.workspace_id,
        thread_id: metadata.thread_id,
        agent_id: metadata.agent_id,
        provider_session_id: provider_session_id.clone(),
        native_session_id: provider_session_id,
        fork_from_provider_session_id,
        shared_history_id,
        native_session_kind: "session".to_string(),
        native_session_source: source.to_string(),
        pane_id: metadata.pane_id,
        instance_id: Some(instance.id),
        terminal_index: metadata.terminal_index.map(i64::from),
        provider: metadata.agent_kind,
        session_title: String::new(),
        model_id: String::new(),
        source: source.to_string(),
        cwd: instance.working_directory.to_string_lossy().to_string(),
        observed_at_ms: terminal_now_ms(),
    })
}

fn terminal_emit_provider_session_binding(
    app: &AppHandle,
    binding: &WorkspaceThreadProviderSessionBinding,
    recorded: Option<bool>,
) {
    let mut payload = serde_json::to_value(binding).unwrap_or_else(|_| json!({}));
    if let Some(object) = payload.as_object_mut() {
        object.insert("type".to_string(), json!("provider-session"));
        object.insert("recorded".to_string(), json!(recorded));
        object.insert(
            "session_id".to_string(),
            json!(binding.provider_session_id.clone()),
        );
        object.insert(
            "provider_session_id".to_string(),
            json!(binding.provider_session_id.clone()),
        );
        object.insert(
            "native_session_id".to_string(),
            json!(binding.native_session_id.clone()),
        );
        object.insert(
            "native_session_kind".to_string(),
            json!(binding.native_session_kind.clone()),
        );
        object.insert(
            "native_session_source".to_string(),
            json!(binding.native_session_source.clone()),
        );
    }
    let _ = app.emit(TERMINAL_PROVIDER_SESSION_BOUND_EVENT, payload);
}

fn terminal_workspace_agent_session_status_requires_input(
    event_type: &str,
    activity_status: &str,
    command_phase: &str,
) -> bool {
    let event_type = terminal_projection_text(event_type, "");
    let activity_status = terminal_projection_text(activity_status, "");
    let command_phase = terminal_projection_text(command_phase, "");
    matches!(
        event_type.as_str(),
        "provider_user_prompt_started" | "provider-user-prompt-started"
    ) || matches!(
        activity_status.as_str(),
        "awaiting_input" | "awaiting_user" | "needs_input" | "prompting_user"
    ) || matches!(
        command_phase.as_str(),
        "awaiting_input"
            | "awaiting_user"
            | "needs_input"
            | "prompting_user"
            | "requires_input"
            | "requires_user_input"
    )
}

fn terminal_workspace_agent_session_status_from_runtime(
    runtime: &TerminalRuntimeSnapshot,
) -> String {
    if terminal_workspace_agent_session_status_requires_input(
        &runtime.event_type,
        &runtime.activity_status,
        &runtime.command_phase,
    ) {
        return "needs_input".to_string();
    }
    terminal_projection_text(
        &runtime.activity_status,
        &terminal_projection_text(&runtime.status, "active"),
    )
}

fn terminal_workspace_agent_session_status_from_payload(
    payload: &TerminalActivityHookPayload,
) -> String {
    if payload.terminal_is_prompting_user
        || terminal_workspace_agent_session_status_requires_input(
            &payload.event_type,
            &payload.activity_status,
            &payload.command_phase,
        )
    {
        return "needs_input".to_string();
    }
    terminal_projection_text(
        &payload.activity_status,
        &terminal_projection_text(&payload.status, "active"),
    )
}

fn terminal_record_workspace_provider_session_binding(
    app: Option<AppHandle>,
    instance: &TerminalInstance,
    provider_session_id: String,
    source: impl Into<String>,
) {
    terminal_record_workspace_provider_session_binding_with_transcript_path(
        app,
        instance,
        provider_session_id,
        source,
        None,
    );
}

fn terminal_register_native_transcript_watch(
    app: &AppHandle,
    instance: &TerminalInstance,
    provider_session_id: &str,
    transcript_path: Option<&str>,
    source: &str,
) {
    let metadata = instance.metadata.clone();
    let agent_id = terminal_normalize_agent_kind(Some(&metadata.agent_kind))
        .or_else(|| terminal_normalize_agent_kind(Some(&metadata.agent_id)))
        .unwrap_or_else(|| metadata.agent_id.clone());
    let request = AgentThreadTranscriptNativeWatchRequest {
        agent_id,
        cwd: instance.working_directory.to_string_lossy().to_string(),
        instance_id: Some(instance.id),
        pane_id: metadata.pane_id,
        provider_session_id: provider_session_id.to_string(),
        source: source.to_string(),
        terminal_index: metadata.terminal_index.map(i64::from),
        thread_id: metadata.thread_id,
        transcript_path: transcript_path
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        workspace_id: metadata.workspace_id,
    };
    if let Err(error) = register_agent_thread_transcript_native_watch(app, &request) {
        log_terminal_status_event(
            "backend.agent_thread_transcript.native_watch_error",
            json!({
                "error": clean_terminal_diagnostic_log_text(&error),
                "instance_id": instance.id,
                "pane_id": clean_terminal_diagnostic_log_text(&request.pane_id),
                "provider_session_id_present": !provider_session_id.trim().is_empty(),
                "source": source,
            }),
        );
    }
}

fn terminal_record_workspace_provider_session_binding_with_transcript_path(
    app: Option<AppHandle>,
    instance: &TerminalInstance,
    provider_session_id: String,
    source: impl Into<String>,
    transcript_path: Option<&str>,
) {
    let source = source.into();
    let Some(binding) =
        terminal_provider_session_binding_payload(instance, &provider_session_id, &source)
    else {
        return;
    };
    if let Some(app) = app.as_ref() {
        terminal_emit_provider_session_binding(app, &binding, None);
    }
    let history_status =
        terminal_workspace_agent_session_status_from_runtime(&terminal_runtime_snapshot(instance));
    terminal_record_workspace_agent_session_history(
        app.clone(),
        instance,
        None,
        None,
        &history_status,
        format!("{source}:provider-session"),
        None,
    );
    let root_directory = terminal_provider_session_binding_root(instance);
    let emit_app = app.clone();
    if let Some(app) = app.as_ref() {
        terminal_register_native_transcript_watch(
            app,
            instance,
            &provider_session_id,
            transcript_path,
            &source,
        );
    }
    tauri::async_runtime::spawn_blocking(move || {
        match workspace_threads_record_provider_session_binding(
            Some(root_directory.as_str()),
            binding.clone(),
        ) {
            Ok(recorded) => {
                if let Some(app) = emit_app.as_ref() {
                    terminal_emit_provider_session_binding(app, &binding, Some(recorded));
                }
            }
            Err(error) => log_terminal_status_event(
                "backend.terminal_provider_session.binding_record_error",
                json!({
                    "error": clean_terminal_diagnostic_log_text(&error),
                    "source": source,
                }),
            ),
        }
    });
}

fn terminal_workspace_agent_session_slot_key(
    instance: &TerminalInstance,
    override_slot_key: Option<&str>,
) -> String {
    override_slot_key
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .or_else(|| {
            instance.coordination.as_ref().and_then(|coordination| {
                terminal_coordination_env_value(coordination, "COORDINATION_SLOT_KEY")
            })
        })
        .unwrap_or_default()
}

fn terminal_workspace_agent_session_title(instance: &TerminalInstance) -> String {
    let metadata = &instance.metadata;
    [
        metadata.terminal_nickname.as_str(),
        metadata.terminal_name.as_str(),
        metadata.agent_kind.as_str(),
        metadata.agent_id.as_str(),
    ]
    .into_iter()
    .map(str::trim)
    .find(|value| !value.is_empty())
    .unwrap_or("Coding agent session")
    .to_string()
}

fn terminal_emit_workspace_agent_session_history_changed(
    app: &AppHandle,
    record: &WorkspaceAgentSessionHistoryRecord,
    recorded: Option<bool>,
) {
    let mut payload = serde_json::to_value(record).unwrap_or_else(|_| json!({}));
    if let Some(object) = payload.as_object_mut() {
        object.insert("type".to_string(), json!("workspace-agent-session-history"));
        object.insert("recorded".to_string(), json!(recorded));
        object.insert(
            "workspace_id".to_string(),
            json!(record.workspace_id.clone()),
        );
        object.insert("session_history_id".to_string(), json!(record.id.clone()));
    }
    let _ = app.emit(WORKSPACE_AGENT_SESSION_HISTORY_CHANGED_EVENT, payload);
}

fn terminal_record_workspace_agent_session_history(
    app: Option<AppHandle>,
    instance: &TerminalInstance,
    model_id: Option<&str>,
    model_source: Option<&str>,
    status: &str,
    source: impl Into<String>,
    slot_key_override: Option<&str>,
) {
    let source = source.into();
    let metadata = instance.metadata.clone();
    if metadata.workspace_id.trim().is_empty() {
        return;
    }
    let launch_metadata = instance
        .launch_metadata
        .lock()
        .map(|metadata| metadata.clone())
        .unwrap_or_default();
    let runtime = terminal_runtime_snapshot(instance);
    let provider_session_id = terminal_recordable_provider_session_id_for_metadata(
        &metadata,
        runtime.provider_session_id.as_deref(),
    );
    let native_session_id = terminal_recordable_provider_session_id_for_metadata(
        &metadata,
        runtime.native_session_id.as_deref(),
    )
    .or(provider_session_id.clone());
    if provider_session_id.is_none() && native_session_id.is_none() {
        return;
    }
    let visible_session_id = provider_session_id
        .as_deref()
        .or(native_session_id.as_deref())
        .unwrap_or_default()
        .to_string();
    let canonical_history_id = workspace_agent_session_history_record_id(
        &metadata.workspace_id,
        &metadata.agent_kind,
        &visible_session_id,
    );
    let coordination_session_id = instance
        .coordination
        .as_ref()
        .map(|coordination| coordination.session_id.clone())
        .unwrap_or_default();
    let record = WorkspaceAgentSessionHistoryRecord {
        id: canonical_history_id,
        workspace_id: metadata.workspace_id.clone(),
        workspace_name: metadata.workspace_name,
        coordination_session_id,
        provider_session_id: provider_session_id.clone().unwrap_or_default(),
        native_session_id: native_session_id.clone().unwrap_or_default(),
        fork_from_provider_session_id: runtime
            .fork_from_provider_session_id
            .clone()
            .unwrap_or_default(),
        shared_history_id: workspace_agent_session_history_shared_history_id(
            &metadata.workspace_id,
            &metadata.agent_kind,
            provider_session_id
                .as_deref()
                .or(native_session_id.as_deref())
                .unwrap_or_default(),
            runtime
                .fork_from_provider_session_id
                .as_deref()
                .unwrap_or_default(),
        ),
        agent_id: metadata.agent_id,
        provider: metadata.agent_kind,
        model_id: model_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .or(launch_metadata.model.as_deref())
            .unwrap_or_default()
            .trim()
            .to_string(),
        model_source: model_source
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .or(launch_metadata.model_source.as_deref())
            .unwrap_or_default()
            .trim()
            .to_string(),
        session_mode: instance.session_mode.as_str().to_string(),
        file_authority: instance.session_mode.file_authority().to_string(),
        coordination_mode: instance
            .coordination
            .as_ref()
            .and_then(|coordination| {
                terminal_coordination_env_value(coordination, "COORDINATION_ENFORCEMENT_MODE")
            })
            .unwrap_or_default(),
        thread_id: metadata.thread_id,
        pane_id: metadata.pane_id,
        terminal_instance_id: Some(instance.id),
        terminal_index: metadata.terminal_index.map(i64::from),
        slot_key: terminal_workspace_agent_session_slot_key(instance, slot_key_override),
        cwd: instance.working_directory.to_string_lossy().to_string(),
        status: status.trim().to_string(),
        title: terminal_workspace_agent_session_title(instance),
        source: source.clone(),
        observed_at_ms: Some(terminal_now_ms()),
        created_at_ms: None,
    };
    let root_directory = terminal_provider_session_binding_root(instance);
    let emit_app = app.clone();
    tauri::async_runtime::spawn_blocking(move || {
        match workspace_agent_session_history_upsert_blocking(
            Some(root_directory.as_str()),
            record.clone(),
        ) {
            Ok(recorded) => {
                if let Some(app) = emit_app.as_ref() {
                    terminal_emit_workspace_agent_session_history_changed(
                        app,
                        &record,
                        Some(recorded),
                    );
                    agent_chat_session_sync_spawn_from_history_record(
                        app.clone(),
                        record.clone(),
                        "terminal_session_history",
                    );
                }
            }
            Err(error) => log_terminal_status_event(
                "backend.workspace_agent_session_history.record_error",
                json!({
                    "error": clean_terminal_diagnostic_log_text(&error),
                    "source": source,
                }),
            ),
        }
    });
}

const TERMINAL_CODEX_SESSION_DISCOVERY_DELAYS_MS: [u64; 6] = [100, 250, 500, 1_000, 2_000, 4_000];
const TERMINAL_PROMPT_SESSION_DISCOVERY_DELAYS_MS: [u64; 8] =
    [50, 150, 300, 600, 1_200, 2_500, 5_000, 10_000];

fn terminal_runtime_has_provider_session(instance: &TerminalInstance) -> bool {
    terminal_runtime_snapshot(instance)
        .provider_session_id
        .as_deref()
        .map(str::trim)
        .is_some_and(|value| !value.is_empty())
}

fn terminal_current_recordable_provider_session_id(instance: &TerminalInstance) -> Option<String> {
    let runtime = terminal_runtime_snapshot(instance);
    runtime
        .provider_session_id
        .or(runtime.native_session_id)
        .and_then(|session_id| {
            terminal_recordable_provider_session_id_for_metadata(
                &instance.metadata,
                Some(&session_id),
            )
        })
}

fn spawn_terminal_codex_session_discovery(
    app: AppHandle,
    terminals: Arc<RwLock<HashMap<String, TerminalInstance>>>,
    pane_id: String,
    instance_id: u64,
    launched_at_ms: u64,
    source: impl Into<String>,
    delays_ms: &'static [u64],
) {
    let source = source.into();
    tauri::async_runtime::spawn(async move {
        for &delay_ms in delays_ms {
            sleep(Duration::from_millis(delay_ms)).await;

            let Some(instance) =
                terminal_activity_hook_current_instance(&terminals, &pane_id, instance_id).await
            else {
                break;
            };
            if !terminal_metadata_is_codex(&instance.metadata) {
                break;
            }
            if terminal_runtime_has_provider_session(&instance) {
                break;
            }

            let cwd = instance.working_directory.to_string_lossy().to_string();
            let Some(auth_home) = instance
                .launch_account_binding
                .as_ref()
                .and_then(TerminalProviderLaunchAccountBinding::codex_auth_home)
                .map(Path::to_path_buf)
            else {
                log_terminal_status_event(
                    "backend.terminal_provider_session.codex_discovery_error",
                    json!({
                        "error": "missing frozen Codex auth home",
                        "instance_id": instance_id,
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "source": source.clone(),
                    }),
                );
                break;
            };
            let discovered = match tauri::async_runtime::spawn_blocking(move || {
                discover_latest_codex_session_for_cwd_in_auth_home(
                    &cwd,
                    launched_at_ms,
                    &auth_home,
                )
            })
            .await
            {
                Ok(Ok(discovered)) => discovered,
                Ok(Err(error)) => {
                    log_terminal_status_event(
                        "backend.terminal_provider_session.codex_discovery_error",
                        json!({
                            "error": clean_terminal_diagnostic_log_text(&error),
                            "instance_id": instance_id,
                            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                            "source": source.clone(),
                        }),
                    );
                    None
                }
                Err(error) => {
                    log_terminal_status_event(
                        "backend.terminal_provider_session.codex_discovery_join_error",
                        json!({
                            "error": clean_terminal_diagnostic_log_text(&error.to_string()),
                            "instance_id": instance_id,
                            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                            "source": source.clone(),
                        }),
                    );
                    None
                }
            };

            let Some(discovered) = discovered else {
                continue;
            };
            let provider_session_id =
                match terminal_clean_provider_session_id(Some(&discovered.session_id)) {
                    Some(provider_session_id) => provider_session_id,
                    None => continue,
                };

            let Some(current_instance) =
                terminal_activity_hook_current_instance(&terminals, &pane_id, instance_id).await
            else {
                break;
            };
            if terminal_runtime_has_provider_session(&current_instance) {
                break;
            }

            terminal_runtime_apply_provider_session_id(
                &current_instance,
                &provider_session_id,
                "codex-transcript-discovery",
            );
            terminal_record_workspace_provider_session_binding_with_transcript_path(
                Some(app.clone()),
                &current_instance,
                provider_session_id.clone(),
                "codex-transcript-discovery",
                Some(discovered.rollout_path.as_str()),
            );
            if let Some(coordination) = current_instance.coordination.clone() {
                terminal_record_coordination_provider_session_id(
                    coordination,
                    provider_session_id.clone(),
                    "codex-transcript-discovery",
                );
            }
            log_terminal_status_event(
                "backend.terminal_provider_session.codex_discovered",
                json!({
                    "cwd": clean_terminal_diagnostic_log_text(&discovered.cwd),
                    "instance_id": instance_id,
                    "latest_timestamp": discovered.latest_timestamp,
                    "modified_at_ms": discovered.modified_at_ms,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "provider_session_id_present": true,
                    "rollout_path": clean_terminal_diagnostic_log_text(&discovered.rollout_path),
                    "session_title_present": !discovered.session_title.trim().is_empty(),
                    "source": source.clone(),
                }),
            );
            break;
        }
    });
}

fn spawn_terminal_non_codex_session_discovery_for_prompt(
    app: AppHandle,
    terminals: Arc<RwLock<HashMap<String, TerminalInstance>>>,
    pane_id: String,
    instance_id: u64,
    prompt: String,
    source: impl Into<String>,
) {
    let source = source.into();
    let prompt = prompt.trim().to_string();
    if prompt.is_empty() {
        return;
    }
    tauri::async_runtime::spawn(async move {
        for (attempt, &delay_ms) in TERMINAL_PROMPT_SESSION_DISCOVERY_DELAYS_MS
            .iter()
            .enumerate()
        {
            sleep(Duration::from_millis(delay_ms)).await;

            let Some(instance) =
                terminal_activity_hook_current_instance(&terminals, &pane_id, instance_id).await
            else {
                return;
            };
            if terminal_runtime_has_provider_session(&instance) {
                return;
            }
            let agent_id = terminal_normalize_agent_kind(Some(&instance.metadata.agent_kind))
                .or_else(|| terminal_normalize_agent_kind(Some(&instance.metadata.agent_id)))
                .unwrap_or_default();
            if !matches!(agent_id.as_str(), "claude" | "opencode") {
                return;
            }

            let cwd = instance.working_directory.to_string_lossy().to_string();
            let prompt_for_discovery = prompt.clone();
            let agent_for_discovery = agent_id.clone();
            let launch_account_binding = instance.launch_account_binding.clone();
            let discovered = tauri::async_runtime::spawn_blocking(move || {
                match (agent_for_discovery.as_str(), launch_account_binding.as_ref()) {
                    (
                        "claude",
                        Some(TerminalProviderLaunchAccountBinding::Claude {
                            home: Some(home),
                            ..
                        }),
                    ) => discover_claude_session_by_prompt_in_home(
                        &prompt_for_discovery,
                        &cwd,
                        CODEX_TRANSCRIPT_DEFAULT_LIMIT,
                        home,
                    ),
                    (
                        "opencode",
                        Some(TerminalProviderLaunchAccountBinding::OpenCode {
                            db_path: Some(db_path),
                            ..
                        }),
                    ) => discover_opencode_session_by_prompt_in_db(
                        &prompt_for_discovery,
                        &cwd,
                        CODEX_TRANSCRIPT_DEFAULT_LIMIT,
                        db_path,
                    ),
                    _ => Err(
                        "The terminal has no frozen provider session store for discovery."
                            .to_string(),
                    ),
                }
            })
            .await
            .ok()
            .and_then(Result::ok);

            let Some(discovered) = discovered else {
                if attempt + 1 == TERMINAL_PROMPT_SESSION_DISCOVERY_DELAYS_MS.len() {
                    log_terminal_status_event(
                        "backend.terminal_provider_session.prompt_discovery_exhausted",
                        json!({
                            "agent_id": agent_id,
                            "attempt_count": attempt + 1,
                            "instance_id": instance_id,
                            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                            "source": source.clone(),
                        }),
                    );
                }
                continue;
            };
            let Some(provider_session_id) =
                terminal_clean_provider_session_id(Some(&discovered.session_id))
            else {
                continue;
            };
            let Some(current_instance) =
                terminal_activity_hook_current_instance(&terminals, &pane_id, instance_id).await
            else {
                return;
            };
            if terminal_runtime_has_provider_session(&current_instance) {
                return;
            }

            terminal_runtime_apply_provider_session_id(
                &current_instance,
                &provider_session_id,
                "prompt-transcript-discovery",
            );
            terminal_record_workspace_provider_session_binding_with_transcript_path(
                Some(app.clone()),
                &current_instance,
                provider_session_id.clone(),
                "prompt-transcript-discovery",
                Some(discovered.rollout_path.as_str()),
            );
            if let Some(coordination) = current_instance.coordination.clone() {
                terminal_record_coordination_provider_session_id(
                    coordination,
                    provider_session_id,
                    "prompt-transcript-discovery",
                );
            }
            log_terminal_status_event(
                "backend.terminal_provider_session.prompt_discovered",
                json!({
                    "agent_id": agent_id,
                    "attempt": attempt + 1,
                    "instance_id": instance_id,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "provider_session_id_present": true,
                    "source": source.clone(),
                }),
            );
            return;
        }
    });
}

type TerminalLaunchResult = (
    Vec<String>,
    Vec<String>,
    String,
    Option<String>,
    TerminalProviderResolvedLaunchOptions,
    Option<String>,
    Option<String>,
    TerminalProviderLaunchAccountBinding,
);

fn terminal_launch(
    kind: &str,
    provider: Option<String>,
    launch_options: TerminalProviderLaunchOptions,
    provider_session_id: Option<String>,
    fork_from_provider_session_id: Option<String>,
    working_directory: &str,
) -> Result<TerminalLaunchResult, String> {
    let provider = terminal_launch_provider(kind, provider.as_deref())?;
    let account_binding = TerminalProviderLaunchAccountBinding::capture(provider);
    terminal_launch_with_account_binding(
        provider,
        launch_options,
        provider_session_id,
        fork_from_provider_session_id,
        working_directory,
        account_binding,
    )
}

fn terminal_launch_with_account_binding(
    provider: AgentProvider,
    launch_options: TerminalProviderLaunchOptions,
    provider_session_id: Option<String>,
    fork_from_provider_session_id: Option<String>,
    working_directory: &str,
    account_binding: TerminalProviderLaunchAccountBinding,
) -> Result<TerminalLaunchResult, String> {
    let definition = agent_definition(provider);
    let requested_resume_session_id = provider_session_id
        .as_deref()
        .and_then(|session_id| terminal_clean_provider_session_id(Some(session_id)));
    let resume_was_requested = requested_resume_session_id.is_some();
    let requested_fork_session_id = fork_from_provider_session_id
        .as_deref()
        .and_then(|session_id| terminal_clean_provider_session_id(Some(session_id)));
    let is_fork_launch = requested_fork_session_id.is_some();
    let (source_session_id, codex_resume_home) = if is_fork_launch {
        let (session_id, codex_resume_home) = terminal_resolve_provider_resume_session_for_binding(
            provider,
            requested_fork_session_id,
            working_directory,
            &account_binding,
        );
        let Some(session_id) = session_id else {
            return Err(terminal_provider_session_fork_error(provider));
        };
        (Some(session_id), codex_resume_home)
    } else {
        terminal_resolve_provider_resume_session_for_binding(
            provider,
            requested_resume_session_id,
            working_directory,
            &account_binding,
        )
    };
    if !is_fork_launch
        && matches!(provider, AgentProvider::Claude)
        && resume_was_requested
        && source_session_id.is_none()
    {
        return Err(terminal_claude_resume_unavailable_message());
    }
    let mut args = if is_fork_launch {
        terminal_provider_fork_args(provider, source_session_id.as_deref())
    } else {
        terminal_provider_resume_args(provider, source_session_id.as_deref())
    };

    // When resuming, the session transcript knows the exact model that was
    // active when the session closed — including in-session `/model`
    // switches the stored binding never saw. Prefer it over the caller's
    // default so a reopened terminal continues on the same model.
    let session_model = source_session_id
        .as_deref()
        .and_then(|session_id| {
            terminal_session_last_model_for_binding(
                provider,
                session_id,
                codex_resume_home.as_deref(),
                &account_binding,
            )
        })
        .and_then(|model| normalize_forge_model(Some(model)).ok().flatten());
    let request_model = normalize_forge_model(launch_options.model)?;
    let mut resolved_launch = match session_model {
        Some(model) => TerminalProviderResolvedLaunchOptions {
            model: Some(model),
            model_source: Some("session-current".to_string()),
            ..Default::default()
        },
        None => {
            let source = if request_model.is_some() {
                Some("request".to_string())
            } else {
                None
            };
            TerminalProviderResolvedLaunchOptions {
                model: request_model,
                model_source: source,
                ..Default::default()
            }
        }
    };
    resolved_launch.reasoning_effort =
        terminal_normalize_launch_reasoning_effort(provider, launch_options.reasoning_effort)?;
    resolved_launch.speed = terminal_normalize_launch_speed(
        provider,
        resolved_launch.model.as_deref(),
        launch_options.speed,
    )?;
    resolved_launch.permission_mode =
        terminal_normalize_permission_mode(launch_options.permission_mode)?;
    terminal_append_provider_launch_args(provider, &mut args, &resolved_launch);

    Ok((
        agent_command_candidates(definition),
        args,
        definition.label.to_string(),
        codex_resume_home,
        resolved_launch,
        source_session_id.clone(),
        if is_fork_launch {
            None
        } else {
            source_session_id
        },
        account_binding,
    ))
}

fn terminal_launch_with_resume_fallback(
    kind: &str,
    provider: Option<String>,
    launch_options: TerminalProviderLaunchOptions,
    provider_session_id: Option<String>,
    fork_from_provider_session_id: Option<String>,
    working_directory: &str,
) -> Result<(TerminalLaunchResult, bool), String> {
    let launch_provider = terminal_launch_provider(kind, provider.as_deref())?;
    let account_binding = TerminalProviderLaunchAccountBinding::capture(launch_provider);
    terminal_launch_with_resume_fallback_for_binding(
        launch_provider,
        kind,
        launch_options,
        provider_session_id,
        fork_from_provider_session_id,
        working_directory,
        account_binding,
    )
}

fn terminal_launch_with_resume_fallback_for_binding(
    launch_provider: AgentProvider,
    kind: &str,
    launch_options: TerminalProviderLaunchOptions,
    provider_session_id: Option<String>,
    fork_from_provider_session_id: Option<String>,
    working_directory: &str,
    account_binding: TerminalProviderLaunchAccountBinding,
) -> Result<(TerminalLaunchResult, bool), String> {
    let resume_was_requested = terminal_clean_provider_session_id(provider_session_id.as_deref())
        .is_some()
        && terminal_clean_provider_session_id(fork_from_provider_session_id.as_deref()).is_none();
    let first_attempt = terminal_launch_with_account_binding(
        launch_provider,
        launch_options.clone(),
        provider_session_id,
        fork_from_provider_session_id.clone(),
        working_directory,
        account_binding.clone(),
    );

    match first_attempt {
        Ok(launch) if resume_was_requested && launch.6.is_none() => {
            log_terminal_status_event(
                "backend.terminal_provider_session.resume_fallback_fresh",
                json!({
                    "provider": clean_terminal_diagnostic_log_text(kind),
                    "reason": "resume_resolution_missing",
                }),
            );
            terminal_launch_with_account_binding(
                launch_provider,
                launch_options,
                None,
                fork_from_provider_session_id,
                working_directory,
                account_binding,
            )
            .map(|fresh_launch| (fresh_launch, true))
        }
        Ok(launch) => Ok((launch, false)),
        Err(error)
            if resume_was_requested && error == terminal_claude_resume_unavailable_message() =>
        {
            log_terminal_status_event(
                "backend.terminal_provider_session.resume_fallback_fresh",
                json!({
                    "provider": clean_terminal_diagnostic_log_text(kind),
                    "reason": "resume_resolution_error",
                }),
            );
            terminal_launch_with_account_binding(
                launch_provider,
                launch_options,
                None,
                fork_from_provider_session_id,
                working_directory,
                account_binding,
            )
            .map(|fresh_launch| (fresh_launch, true))
        }
        Err(error) => Err(error),
    }
}

async fn remove_terminal_instance_if_current(
    terminals: &Arc<RwLock<HashMap<String, TerminalInstance>>>,
    pane_id: &str,
    instance_id: u64,
) -> Option<TerminalInstance> {
    let mut terminals = terminals.write().await;
    let is_current = terminals
        .get(pane_id)
        .map(|instance| instance.id == instance_id)
        .unwrap_or(false);

    if is_current {
        terminals.remove(pane_id)
    } else {
        None
    }
}

async fn get_terminal_instance(
    state: &TerminalState,
    pane_id: &str,
) -> Result<TerminalInstance, String> {
    let terminals = state.terminals.read().await;

    terminals
        .get(pane_id)
        .cloned()
        .ok_or_else(|| "Terminal session is not running.".to_string())
}

async fn get_terminal_instance_if_current(
    state: &TerminalState,
    pane_id: &str,
    instance_id: Option<u64>,
) -> Result<Option<TerminalInstance>, String> {
    let terminals = state.terminals.read().await;
    let Some(instance) = terminals.get(pane_id).cloned() else {
        return if instance_id.is_some() {
            Ok(None)
        } else {
            Err("Terminal session is not running.".to_string())
        };
    };

    if instance_id.is_some_and(|expected_id| expected_id != instance.id) {
        return Ok(None);
    }

    Ok(Some(instance))
}

fn terminal_audio_input_target_matches(
    target: &TerminalAudioInputTarget,
    pane_id: &str,
    instance_id: Option<u64>,
) -> bool {
    target.pane_id == pane_id && target.instance_id == instance_id
}

fn active_terminal_audio_input_target(
    state: &TerminalState,
) -> Result<Option<TerminalAudioInputTarget>, String> {
    state
        .active_audio_input_target
        .lock()
        .map(|target| target.clone())
        .map_err(|_| "Unable to read focused terminal input target.".to_string())
}

fn clear_terminal_audio_input_target_if_matches(
    state: &TerminalState,
    pane_id: &str,
    instance_id: Option<u64>,
) -> Result<(), String> {
    let mut active_target = state
        .active_audio_input_target
        .lock()
        .map_err(|_| "Unable to clear focused terminal input target.".to_string())?;

    if active_target
        .as_ref()
        .is_some_and(|target| terminal_audio_input_target_matches(target, pane_id, instance_id))
    {
        *active_target = None;
    }

    Ok(())
}

fn terminal_audio_route_gate(state: &TerminalState) -> Result<TerminalAudioRouteGate, String> {
    state
        .audio_route_gate
        .lock()
        .map(|gate| gate.clone())
        .map_err(|_| "Unable to read the terminal audio route gate.".to_string())
}

fn set_terminal_audio_route_gate_for(
    state: &TerminalState,
    allow_terminal: bool,
) -> Result<(), String> {
    let mut gate = state
        .audio_route_gate
        .lock()
        .map_err(|_| "Unable to update the terminal audio route gate.".to_string())?;

    if gate.allow_terminal != allow_terminal {
        write_thread_bridge_diagnostic_log_entry(json!({
            "ts_ms": current_time_ms(),
            "phase": "backend.audio_input_target.route_gate",
            "source": "backend",
            "app_pid": std::process::id(),
            "thread": terminal_diagnostic_thread_label(),
            "fields": {
                "allow_terminal": allow_terminal,
            },
        }));
    }
    gate.allow_terminal = allow_terminal;

    Ok(())
}

fn clear_terminal_audio_input_target(state: &TerminalState) -> Result<(), String> {
    let mut active_target = state
        .active_audio_input_target
        .lock()
        .map_err(|_| "Unable to clear focused terminal input target.".to_string())?;

    *active_target = None;

    Ok(())
}

fn set_terminal_audio_input_target_for(
    state: &TerminalState,
    pane_id: String,
    instance_id: Option<u64>,
    active: bool,
) -> Result<(), String> {
    validate_terminal_pane_id(&pane_id)?;
    write_thread_bridge_diagnostic_log_entry(json!({
        "ts_ms": current_time_ms(),
        "phase": "backend.audio_input_target.set_request",
        "source": "backend",
        "app_pid": std::process::id(),
        "thread": terminal_diagnostic_thread_label(),
        "fields": {
            "active": active,
            "instance_id": instance_id,
            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
        },
    }));

    if !active {
        return clear_terminal_audio_input_target_if_matches(state, &pane_id, instance_id);
    }

    let mut active_target = state
        .active_audio_input_target
        .lock()
        .map_err(|_| "Unable to update focused terminal input target.".to_string())?;

    *active_target = Some(TerminalAudioInputTarget {
        pane_id,
        instance_id,
    });

    Ok(())
}

fn emit_terminal_audio_input_refocus(
    app: &AppHandle,
    target: &TerminalAudioInputTarget,
    inserted_text: Option<&str>,
) {
    if let Some(window) = app.get_window("main") {
        let _ = window.show();
        let _ = window.set_focus();
    }

    let _ = app.emit(
        TERMINAL_AUDIO_INPUT_REFOCUS_EVENT,
        TerminalAudioInputRefocusPayload {
            pane_id: target.pane_id.clone(),
            instance_id: target.instance_id,
            inserted_text: inserted_text.map(str::to_string),
        },
    );
}

fn webview_window_is_focused(app: &AppHandle, label: &str) -> bool {
    app.get_webview_window(label)
        .and_then(|window| window.is_focused().ok())
        .unwrap_or(false)
}

/// `is_focused` is key-window status, and the audio widget's hover-focus
/// resigns key WITHOUT keying a successor — so while Diff Forge is the active
/// (frontmost) app, there can be NO key window at the exact moment a
/// transcript lands. Insertion gates must not read that state as "the user is
/// in another app": app-active is the signal that dictation belongs to us.
/// When the user really is in another app this is false, and transcripts still
/// fall through to the focused input there.
#[cfg(target_os = "macos")]
fn app_process_is_active() -> bool {
    // NSRunningApplication is documented thread-safe, unlike NSApplication.
    unsafe { objc2_app_kit::NSRunningApplication::currentApplication().isActive() }
}

#[cfg(not(target_os = "macos"))]
fn app_process_is_active() -> bool {
    false
}

fn app_has_focused_terminal_window(app: &AppHandle) -> bool {
    app.webview_windows().into_iter().any(|(label, window)| {
        label.starts_with(TERMINAL_WINDOW_LABEL_PREFIX) && window.is_focused().unwrap_or(false)
    })
}

fn app_has_focused_audio_input_window(app: &AppHandle) -> bool {
    webview_window_is_focused(app, "main")
        || webview_window_is_focused(app, AUDIO_WIDGET_WINDOW_LABEL)
        || app_has_focused_terminal_window(app)
        || app_process_is_active()
}

fn terminal_audio_input_target_window_is_focused(
    app: &AppHandle,
    target: &TerminalAudioInputTarget,
) -> bool {
    webview_window_is_focused(app, &terminal_window_label(&target.pane_id))
}

fn app_has_focused_audio_input_window_for_target(
    app: &AppHandle,
    target: &TerminalAudioInputTarget,
) -> bool {
    webview_window_is_focused(app, "main")
        || webview_window_is_focused(app, AUDIO_WIDGET_WINDOW_LABEL)
        || terminal_audio_input_target_window_is_focused(app, target)
        || app_process_is_active()
}

fn terminal_audio_target_should_own_insert(
    app: &AppHandle,
    state: &TerminalState,
    target: Option<&TerminalAudioInputTarget>,
) -> Result<bool, String> {
    let Some(target) = target else {
        return Ok(false);
    };

    if terminal_audio_input_target_window_is_focused(app, target) {
        return Ok(true);
    }

    if !terminal_audio_route_gate(state)?.allow_terminal {
        return Ok(false);
    }

    Ok(webview_window_is_focused(app, "main")
        || webview_window_is_focused(app, AUDIO_WIDGET_WINDOW_LABEL)
        || app_process_is_active())
}

async fn write_terminal_input(
    app: Option<&AppHandle>,
    state: &TerminalState,
    pane_id: &str,
    instance_id: Option<u64>,
    data: &str,
    structured_answer: Option<&TerminalStructuredInteraction>,
    _skipped_phase: &str,
) -> Result<bool, String> {
    validate_terminal_pane_id(pane_id)?;

    if data.is_empty() {
        return Ok(true);
    }

    if data.len() > MAX_TERMINAL_WRITE_BYTES {
        return Err("Terminal input chunk is too large.".to_string());
    }

    let instance = {
        let terminals = state.terminals.read().await;
        let Some(instance) = terminals.get(pane_id).cloned() else {
            if let Some(interaction) = structured_answer {
                terminal_structured_interaction_remove_generation(state, interaction);
            }
            return if instance_id.is_some() {
                Ok(false)
            } else {
                Err("Terminal session is not running.".to_string())
            };
        };

        if instance_id.is_some_and(|expected_id| expected_id != instance.id) {
            if let Some(interaction) = structured_answer {
                terminal_structured_interaction_remove_generation(state, interaction);
            }
            return Ok(false);
        }

        instance
    };
    let input_kind = terminal_input_forensics_kind(data);
    if let Some(app) = app {
        let cloud_state = app.state::<CloudMcpState>();
        cloud_mcp_revoke_terminal_io_control_for_local_action(
            cloud_state.inner(),
            &instance.metadata.workspace_id,
            pane_id,
            instance.id,
            "native_input",
        )
        .await;
    }
    log_terminal_crash_forensics_event(
        "backend.terminal_input.write.begin",
        json!({
            "bytes": data.len(),
            "input_kind": input_kind,
            "instance_id": instance.id,
            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
        }),
    );
    let lock_started_at = Instant::now();
    let terminals = state.terminals.read().await;
    let mut writer = instance.writer.lock().await;
    let lock_wait_ms = terminal_diagnostic_elapsed_ms(lock_started_at);
    if terminals
        .get(pane_id)
        .map(|current| current.id != instance.id)
        .unwrap_or(true)
    {
        if let Some(interaction) = structured_answer {
            terminal_structured_interaction_remove_generation(state, interaction);
        }
        return Ok(false);
    }
    let structured_interactions = if let Some(interaction) = structured_answer {
        let interactions = state
            .terminal_structured_interactions
            .lock()
            .map_err(|_| "Structured terminal interaction state is unavailable.".to_string())?;
        let exact_claim_is_open =
            interactions
                .get(&interaction.interaction_id)
                .is_some_and(|current| {
                    terminal_structured_interaction_same_generation(current, interaction)
                        && current.awaiting_provider_confirmation
                });
        if !exact_claim_is_open {
            return Ok(false);
        }
        Some(interactions)
    } else {
        None
    };
    let structured_runtime = if structured_answer.is_some() {
        let runtime = instance
            .runtime
            .lock()
            .map_err(|_| "Terminal runtime state is unavailable.".to_string())?;
        if !terminal_runtime_is_prompting_for_structured_interaction(&runtime) {
            drop(runtime);
            drop(structured_interactions);
            if let Some(interaction) = structured_answer {
                terminal_structured_interaction_remove_generation(state, interaction);
            }
            return Ok(false);
        }
        Some(runtime)
    } else {
        None
    };
    let write_started_at = Instant::now();

    if let Err(error) = writer.write_all(data.as_bytes()) {
        log_terminal_crash_forensics_event(
            "backend.terminal_input.write.error",
            json!({
                "bytes": data.len(),
                "error": clean_terminal_diagnostic_log_text(&error.to_string()),
                "input_kind": input_kind,
                "instance_id": instance.id,
                "lock_wait_ms": lock_wait_ms,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                "stage": "write_all",
            }),
        );
        drop(structured_runtime);
        drop(structured_interactions);
        if let Some(interaction) = structured_answer {
            terminal_structured_interaction_remove_generation(state, interaction);
        }
        return Err(format!("Unable to write terminal input: {error}"));
    }
    if let Err(error) = writer.flush() {
        log_terminal_crash_forensics_event(
            "backend.terminal_input.write.error",
            json!({
                "bytes": data.len(),
                "error": clean_terminal_diagnostic_log_text(&error.to_string()),
                "input_kind": input_kind,
                "instance_id": instance.id,
                "lock_wait_ms": lock_wait_ms,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                "stage": "flush",
            }),
        );
        drop(structured_runtime);
        drop(structured_interactions);
        if let Some(interaction) = structured_answer {
            terminal_structured_interaction_remove_generation(state, interaction);
        }
        return Err(format!("Unable to flush terminal input: {error}"));
    }
    let write_ms = terminal_diagnostic_elapsed_ms(write_started_at);
    let elapsed_ms = lock_wait_ms + write_ms;
    log_terminal_crash_forensics_event(
        "backend.terminal_input.write.done",
        json!({
            "bytes": data.len(),
            "elapsed_ms": elapsed_ms,
            "input_kind": input_kind,
            "instance_id": instance.id,
            "lock_wait_ms": lock_wait_ms,
            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
            "write_ms": write_ms,
        }),
    );

    if elapsed_ms >= TERMINAL_DIAGNOSTIC_SLOW_MS {
        if let Some(app) = app {
            log_terminal_diagnostic_event(
                app,
                "backend.input_write.slow",
                json!({
                    "bytes": data.len(),
                    "elapsed_ms": elapsed_ms,
                    "instance_id": instance.id,
                    "lock_wait_ms": lock_wait_ms,
                    "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                    "write_ms": write_ms,
                }),
            );
        }
    }

    Ok(true)
}

/// Writes an exact byte frame from a remote terminal controller. This is
/// intentionally below the prompt/todo command layer: termio mirrors the PTY
/// and must preserve control bytes and non-UTF-8 input without interpreting it
/// as a chat submission.
async fn write_terminal_input_bytes(
    state: &TerminalState,
    pane_id: &str,
    instance_id: u64,
    data: &[u8],
) -> Result<bool, String> {
    validate_terminal_pane_id(pane_id)?;
    if data.is_empty() {
        return Ok(true);
    }
    if data.len() > MAX_TERMINAL_WRITE_BYTES {
        return Err("Terminal input chunk is too large.".to_string());
    }

    let Some(instance) =
        get_terminal_instance_if_current(state, pane_id, Some(instance_id)).await?
    else {
        return Ok(false);
    };
    let Some(_operation) = terminal_operation_try_admit(&instance) else {
        return Ok(false);
    };
    let _input_guard = instance.input_queue.lock().await;
    let terminals = state.terminals.read().await;
    if terminals
        .get(pane_id)
        .map(|current| current.id != instance_id)
        .unwrap_or(true)
    {
        return Ok(false);
    }
    let mut writer = instance.writer.lock().await;
    writer
        .write_all(data)
        .map_err(|error| format!("Unable to write terminal input: {error}"))?;
    writer
        .flush()
        .map_err(|error| format!("Unable to flush terminal input: {error}"))?;
    Ok(true)
}

fn terminal_output_coalesce_window_ms(remote_controlled: bool) -> u64 {
    if remote_controlled {
        TERMINAL_REMOTE_OUTPUT_COALESCE_WINDOW_MS
    } else {
        TERMINAL_OUTPUT_COALESCE_WINDOW_MS
    }
}

async fn resize_terminal_instance_exact(
    app: &AppHandle,
    state: &TerminalState,
    pane_id: &str,
    instance_id: u64,
    cols: u16,
    rows: u16,
) -> Result<bool, String> {
    validate_terminal_pane_id(pane_id)?;
    let size = validate_terminal_size(cols, rows)?;
    let Some(instance) =
        get_terminal_instance_if_current(state, pane_id, Some(instance_id)).await?
    else {
        return Ok(false);
    };
    resize_terminal_instance(Some(app), &instance, size, false).await?;
    Ok(true)
}

async fn write_to_active_terminal_audio_input_target(
    app: &AppHandle,
    state: &TerminalState,
    cloud_mcp_state: &CloudMcpState,
    data: &str,
) -> Result<bool, String> {
    let Some(target) = active_terminal_audio_input_target(state)? else {
        return Ok(false);
    };

    // The webview gates the terminal route by what the user is actually
    // looking at: another tab in front of the Terminals view, or focus in a
    // non-terminal editable (for example the todo list), routes dictation to
    // that input instead. The pane selection is kept so the terminal becomes
    // the target again once it is back in view.
    let target_terminal_window_focused =
        terminal_audio_input_target_window_is_focused(app, &target);
    if !terminal_audio_route_gate(state)?.allow_terminal && !target_terminal_window_focused {
        write_thread_bridge_diagnostic_log_entry(json!({
            "ts_ms": current_time_ms(),
            "phase": "backend.audio_input_target.write_skip",
            "source": "backend",
            "app_pid": std::process::id(),
            "thread": terminal_diagnostic_thread_label(),
            "fields": {
                "pane_id": clean_terminal_diagnostic_log_text(&target.pane_id),
                "reason": "route_gate_blocked",
            },
        }));
        return Ok(false);
    }

    if !app_has_focused_audio_input_window_for_target(app, &target) {
        clear_terminal_audio_input_target_if_matches(state, &target.pane_id, target.instance_id)?;
        return Ok(false);
    }

    if get_terminal_instance_if_current(state, &target.pane_id, target.instance_id)
        .await?
        .is_none()
    {
        clear_terminal_audio_input_target_if_matches(state, &target.pane_id, target.instance_id)?;
        return Ok(false);
    }

    terminal_write_inner(
        app.clone(),
        state,
        cloud_mcp_state,
        target.pane_id.clone(),
        target.instance_id,
        data.to_string(),
        None,
        None,
        None,
        None,
        None,
        None,
        None,
        None,
        None,
        None,
        None,
        None,
        None,
        true,
        true,
    )
    .await?;
    emit_terminal_audio_input_refocus(app, &target, Some(data));

    Ok(true)
}

fn poll_terminal_child_exit(child: &mut dyn Child) -> bool {
    for _ in 0..TERMINAL_SHUTDOWN_POLL_ATTEMPTS {
        match child.try_wait() {
            Ok(Some(_)) => return true,
            Ok(None) => thread::sleep(Duration::from_millis(TERMINAL_SHUTDOWN_POLL_INTERVAL_MS)),
            Err(_) => return true,
        }
    }

    false
}

#[derive(Default)]
struct TerminalKillReport {
    pid: Option<u32>,
    process_group_id: Option<i32>,
    taskkill_exit_code: Option<i32>,
    taskkill_success: Option<bool>,
    taskkill_error: Option<String>,
    sigterm_process_group_ok: Option<bool>,
    sigterm_process_group_error: Option<String>,
    sigkill_process_group_ok: Option<bool>,
    sigkill_process_group_error: Option<String>,
    exited_after_sigterm: Option<bool>,
    exited_after_sigkill: Option<bool>,
    child_kill_ok: bool,
    child_kill_error: Option<String>,
}

fn terminal_kill_report_json(report: &TerminalKillReport) -> Value {
    json!({
        "child_kill_error": report.child_kill_error.clone(),
        "child_kill_ok": report.child_kill_ok,
        "exited_after_sigkill": report.exited_after_sigkill,
        "exited_after_sigterm": report.exited_after_sigterm,
        "pid": report.pid,
        "process_group_id": report.process_group_id,
        "sigkill_process_group_error": report.sigkill_process_group_error.clone(),
        "sigkill_process_group_ok": report.sigkill_process_group_ok,
        "sigterm_process_group_error": report.sigterm_process_group_error.clone(),
        "sigterm_process_group_ok": report.sigterm_process_group_ok,
        "taskkill_error": report.taskkill_error.clone(),
        "taskkill_exit_code": report.taskkill_exit_code,
        "taskkill_success": report.taskkill_success,
    })
}

fn terminal_metadata_forensics_json(metadata: &TerminalInstanceMetadata) -> Value {
    json!({
        "agent_id": clean_terminal_diagnostic_log_text(&metadata.agent_id),
        "agent_kind": clean_terminal_diagnostic_log_text(&metadata.agent_kind),
        "pane_id": clean_terminal_diagnostic_log_text(&metadata.pane_id),
        "terminal_index": metadata.terminal_index,
        "thread_id": clean_terminal_diagnostic_log_text(&metadata.thread_id),
        "workspace_id": clean_terminal_diagnostic_log_text(&metadata.workspace_id),
        "workspace_name": clean_terminal_diagnostic_log_text(&metadata.workspace_name),
    })
}

fn terminal_input_forensics_kind(data: &str) -> &'static str {
    match data {
        "\r" | "\n" | "\r\n" => "plain_enter",
        TERMINAL_ENTER_SEQUENCE | TERMINAL_ENTER_SEQUENCE_MOD1 => "enhanced_enter_sequence",
        TERMINAL_SHIFT_ENTER_SEQUENCE => "shift_enter_sequence",
        _ if data.chars().any(|character| character.is_control()) => "control_or_escape",
        _ => "text",
    }
}

#[cfg(windows)]
fn kill_terminal_process_tree(
    child: &mut dyn Child,
    _process_group_leader: Option<i32>,
) -> TerminalKillReport {
    use std::os::windows::process::CommandExt;

    const CREATE_NO_WINDOW: u32 = 0x08000000;

    let mut report = TerminalKillReport {
        pid: child.process_id(),
        ..TerminalKillReport::default()
    };

    if let Some(pid) = report.pid {
        let mut taskkill = Command::new("taskkill");
        taskkill.creation_flags(CREATE_NO_WINDOW);

        match taskkill
            .arg("/PID")
            .arg(pid.to_string())
            .arg("/T")
            .arg("/F")
            .current_dir(safe_background_command_working_directory())
            .stdin(Stdio::null())
            .stdout(Stdio::null())
            .stderr(Stdio::null())
            .status()
        {
            Ok(status) => {
                report.taskkill_exit_code = status.code();
                report.taskkill_success = Some(status.success());
            }
            Err(error) => {
                report.taskkill_success = Some(false);
                report.taskkill_error = Some(clean_terminal_telemetry_text(&error.to_string()));
            }
        }
    }

    match child.kill() {
        Ok(()) => report.child_kill_ok = true,
        Err(error) => {
            report.child_kill_error = Some(clean_terminal_telemetry_text(&error.to_string()));
        }
    }

    report
}

fn terminal_metadata_is_opencode(metadata: &TerminalInstanceMetadata) -> bool {
    let agent_id = metadata.agent_id.trim().to_ascii_lowercase();
    let agent_kind = metadata.agent_kind.trim().to_ascii_lowercase();

    agent_id.contains("opencode") || agent_kind.contains("opencode")
}

fn terminal_metadata_is_claude(metadata: &TerminalInstanceMetadata) -> bool {
    let agent_id = metadata.agent_id.trim().to_ascii_lowercase();
    let agent_kind = metadata.agent_kind.trim().to_ascii_lowercase();

    agent_id.contains("claude") || agent_kind.contains("claude")
}

fn terminal_metadata_is_codex(metadata: &TerminalInstanceMetadata) -> bool {
    let agent_id = metadata.agent_id.trim().to_ascii_lowercase();
    let agent_kind = metadata.agent_kind.trim().to_ascii_lowercase();

    agent_id.contains("codex") || agent_kind.contains("codex")
}

#[cfg(not(windows))]
fn terminal_process_matches_opencode(process: &sysinfo::Process) -> bool {
    let name = clean_process_text(&process.name().to_string_lossy()).to_ascii_lowercase();
    let command = process_command_text(process.cmd()).to_ascii_lowercase();
    let executable = process
        .exe()
        .map(process_path_display)
        .unwrap_or_default()
        .to_ascii_lowercase();

    name.contains("opencode") || command.contains("opencode") || executable.contains("opencode")
}

#[cfg(not(windows))]
fn signal_opencode_theme_refresh(root_pid: u32) -> Result<Vec<u32>, String> {
    let mut system = SysSystem::new();
    system.refresh_processes_specifics(
        ProcessesToUpdate::All,
        true,
        developer_process_refresh_kind(true),
    );

    let child_map = developer_child_map(&system);
    let candidates = developer_process_tree_child_first(root_pid, &child_map);
    let mut signaled = Vec::new();
    let mut failed = Vec::new();

    for candidate in candidates {
        let Some(process) = system.process(SysPid::from_u32(candidate)) else {
            continue;
        };
        if !terminal_process_matches_opencode(process) {
            continue;
        }
        match process.kill_with(sysinfo::Signal::User2) {
            Some(true) => signaled.push(candidate),
            _ => failed.push(candidate),
        }
    }

    if signaled.is_empty() && !failed.is_empty() {
        return Err("Unable to refresh OpenCode terminal theme.".to_string());
    }

    Ok(signaled)
}

#[cfg(windows)]
fn signal_opencode_theme_refresh(_root_pid: u32) -> Result<Vec<u32>, String> {
    Ok(Vec::new())
}

#[cfg(not(windows))]
fn signal_terminal_process_group(
    process_group_leader: Option<i32>,
    signal: i32,
) -> Result<bool, String> {
    let Some(process_group_leader) = process_group_leader.filter(|pid| *pid > 0) else {
        return Ok(false);
    };
    let result = unsafe { libc::killpg(process_group_leader, signal) };
    if result == 0 {
        Ok(true)
    } else {
        Err(clean_terminal_telemetry_text(
            &std::io::Error::last_os_error().to_string(),
        ))
    }
}

#[cfg(not(windows))]
fn kill_terminal_process_tree_with_waits<WaitForExit, SignalProcessGroup>(
    child: &mut dyn Child,
    process_group_leader: Option<i32>,
    mut wait_for_exit: WaitForExit,
    mut signal_process_group: SignalProcessGroup,
) -> TerminalKillReport
where
    WaitForExit: FnMut(&mut dyn Child) -> bool,
    SignalProcessGroup: FnMut(Option<i32>, i32) -> Result<bool, String>,
{
    let mut report = TerminalKillReport {
        pid: child.process_id(),
        process_group_id: process_group_leader,
        ..TerminalKillReport::default()
    };

    match signal_process_group(process_group_leader, libc::SIGTERM) {
        Ok(sent) => report.sigterm_process_group_ok = Some(sent),
        Err(error) => {
            report.sigterm_process_group_ok = Some(false);
            report.sigterm_process_group_error = Some(error);
        }
    }
    if report.sigterm_process_group_ok == Some(true) {
        let exited = wait_for_exit(child);
        report.exited_after_sigterm = Some(exited);
        if exited {
            return report;
        }
    }

    match signal_process_group(process_group_leader, libc::SIGKILL) {
        Ok(sent) => report.sigkill_process_group_ok = Some(sent),
        Err(error) => {
            report.sigkill_process_group_ok = Some(false);
            report.sigkill_process_group_error = Some(error);
        }
    }
    if report.sigkill_process_group_ok == Some(true) {
        let exited = wait_for_exit(child);
        report.exited_after_sigkill = Some(exited);
        if exited {
            return report;
        }
    }

    match child.kill() {
        Ok(()) => report.child_kill_ok = true,
        Err(error) => {
            report.child_kill_error = Some(clean_terminal_telemetry_text(&error.to_string()));
        }
    }

    report
}

#[cfg(not(windows))]
fn kill_terminal_process_tree(
    child: &mut dyn Child,
    process_group_leader: Option<i32>,
) -> TerminalKillReport {
    kill_terminal_process_tree_with_waits(
        child,
        process_group_leader,
        poll_terminal_child_exit,
        signal_terminal_process_group,
    )
}

fn interrupt_terminal_coordination_session(
    coordination: &TerminalCoordinationSession,
    reason: &str,
) {
    let kernel = match crate::coordination::CoordinationKernel::open_for_shutdown_cleanup(
        &coordination.repo_path,
        Some(PathBuf::from(&coordination.db_path)),
    ) {
        Ok(kernel) => kernel,
        Err(_) => return,
    };

    let _ = kernel.interrupt_session_for_terminal_launch(
        &coordination.session_id,
        reason,
        coordination.terminal_launch_epoch.as_deref(),
    );
}

fn terminal_coordination_session_from_context(
    context: &crate::coordination::models::TerminalCoordinationContext,
) -> TerminalCoordinationSession {
    TerminalCoordinationSession {
        repo_path: context.repo_path.clone(),
        db_path: context.db_path.clone(),
        mcp_command: context.mcp_command.clone(),
        agent_id: context.agent_id.clone(),
        agent_kind: context.agent_kind.clone(),
        session_id: context.session_id.clone(),
        terminal_launch_epoch: context.terminal_launch_epoch.clone(),
        env_vars: context.env_vars(),
    }
}

fn clear_terminal_activity_hook_files(
    pane_id: &str,
    instance_id: u64,
    workspace_id: Option<&str>,
) {
    let events_path = terminal_activity_events_path(pane_id, instance_id, workspace_id);
    let _ = fs::remove_file(&events_path);
    let _ = fs::remove_file(terminal_activity_debug_path(
        pane_id,
        instance_id,
        workspace_id,
    ));
    let _ = fs::remove_file(diff_forge_claude_hook_correlation_state_path(&events_path));
    let _ = fs::remove_file(diff_forge_claude_hook_correlation_lock_path(&events_path));
}

fn refresh_codex_activity_hook_profile_for_launch(
    coordination: Option<&TerminalCoordinationSession>,
    provider_id: &str,
    pane_id: &str,
    instance_id: u64,
    workspace_id: Option<&str>,
    terminal_index: Option<u16>,
) -> bool {
    if !provider_id.to_ascii_lowercase().contains("codex") || coordination.is_none() {
        return false;
    }
    match refresh_codex_activity_hook_profile_for_terminal(
        coordination,
        provider_id,
        pane_id,
        instance_id,
        workspace_id,
        terminal_index,
    ) {
        Ok(updated) => {
            log_terminal_status_event(
                "backend.terminal_activity_hook.profile_scoped",
                json!({
                    "activity_debug_path": terminal_activity_debug_path(pane_id, instance_id, workspace_id).to_string_lossy().to_string(),
                    "activity_events_path": terminal_activity_events_path(pane_id, instance_id, workspace_id).to_string_lossy().to_string(),
                    "auto_trusted": true,
                    "instance_id": instance_id,
                    "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                    "provider_id": provider_id,
                    "terminal_index": terminal_index,
                    "updated": updated,
                    "workspace_id": workspace_id.unwrap_or_default(),
                }),
            );
            false
        }
        Err(error) => {
            // A managed terminal must never land on Codex's startup review
            // wall with inert Diff Forge hooks. Persisted per-hook trust is
            // the normal path; the dangerous bypass is a launch-local last
            // resort when the managed home could not be updated.
            log_terminal_status_event(
                "backend.terminal_activity_hook.profile_scope_error",
                json!({
                    "error": clean_terminal_diagnostic_log_text(&error),
                    "fallback": "codex_hook_trust_bypass",
                    "instance_id": instance_id,
                    "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                    "provider_id": provider_id,
                    "terminal_index": terminal_index,
                    "workspace_id": workspace_id.unwrap_or_default(),
                }),
            );
            true
        }
    }
}

fn ensure_terminal_coordination_ready_for_prompt(
    coordination: &TerminalCoordinationSession,
) -> Result<(), String> {
    let kernel = crate::coordination::CoordinationKernel::open_for_shutdown_cleanup(
        &coordination.repo_path,
        Some(PathBuf::from(&coordination.db_path)),
    )?;

    if kernel.heartbeat_session(&coordination.session_id).is_ok() {
        return Ok(());
    }

    match kernel.reactivate_interrupted_session_for_agent(
        &coordination.session_id,
        &coordination.agent_id,
        coordination.terminal_launch_epoch.as_deref(),
        "terminal_prompt_submit_reconnect",
    )? {
        Some(_) => Ok(()),
        None => Err(
            "Coordination session is not active. Reconnect the terminal before sending a prompt."
                .to_string(),
        ),
    }
}

#[derive(Clone, Copy)]
enum TerminalCoordinationCleanupMode {
    InterruptAfterProcess,
    Preserve,
    DeferToShutdownBatch,
}

impl TerminalCoordinationCleanupMode {
    fn as_str(self) -> &'static str {
        match self {
            TerminalCoordinationCleanupMode::InterruptAfterProcess => "interrupt_after_process",
            TerminalCoordinationCleanupMode::Preserve => "preserve",
            TerminalCoordinationCleanupMode::DeferToShutdownBatch => "defer_to_shutdown_batch",
        }
    }
}

#[derive(Clone)]
struct TerminalShutdownCoordinationCleanup {
    repo_path: String,
    db_path: String,
    session_id: String,
    terminal_launch_epoch: Option<String>,
}

fn terminal_shutdown_coordination_cleanup_from_instance(
    instance: &TerminalInstance,
) -> Option<TerminalShutdownCoordinationCleanup> {
    let coordination = instance.coordination.as_ref()?;
    Some(TerminalShutdownCoordinationCleanup {
        repo_path: coordination.repo_path.clone(),
        db_path: coordination.db_path.clone(),
        session_id: coordination.session_id.clone(),
        terminal_launch_epoch: coordination.terminal_launch_epoch.clone(),
    })
}

fn cleanup_terminal_shutdown_coordination_batch_with_timeout(
    cleanups: Vec<TerminalShutdownCoordinationCleanup>,
    reason: &'static str,
    timeout: Duration,
) {
    if cleanups.is_empty() {
        return;
    }

    let (summary_tx, summary_rx) = std::sync::mpsc::channel();
    thread::spawn(move || {
        cleanup_terminal_shutdown_coordination_batch(cleanups, reason);
        let _ = summary_tx.send(());
    });

    let _ = summary_rx.recv_timeout(timeout);
}

fn cleanup_terminal_shutdown_coordination_batch(
    cleanups: Vec<TerminalShutdownCoordinationCleanup>,
    reason: &'static str,
) {
    let mut grouped: HashMap<(String, String), Vec<TerminalShutdownCoordinationCleanup>> =
        HashMap::new();
    for cleanup in cleanups {
        grouped
            .entry((cleanup.repo_path.clone(), cleanup.db_path.clone()))
            .or_default()
            .push(cleanup);
    }

    for ((repo_path, db_path), group) in grouped {
        let kernel = match crate::coordination::CoordinationKernel::open_for_shutdown_cleanup(
            &repo_path,
            Some(PathBuf::from(&db_path)),
        ) {
            Ok(kernel) => kernel,
            Err(_) => continue,
        };

        for cleanup in group {
            let _ = kernel.interrupt_session_for_terminal_launch(
                &cleanup.session_id,
                reason,
                cleanup.terminal_launch_epoch.as_deref(),
            );
        }
    }
}

fn interrupt_terminal_coordination_after_process_cleanup(
    coordination: Option<&TerminalCoordinationSession>,
    reason: &'static str,
    coordination_cleanup_mode: TerminalCoordinationCleanupMode,
) {
    if !matches!(
        coordination_cleanup_mode,
        TerminalCoordinationCleanupMode::InterruptAfterProcess
    ) {
        return;
    }

    let Some(coordination) = coordination else {
        return;
    };

    interrupt_terminal_coordination_session(coordination, reason);
}

fn cleanup_terminal_instance_with_context(
    instance: TerminalInstance,
    kill_first: bool,
    reason: &'static str,
    coordination_cleanup_mode: TerminalCoordinationCleanupMode,
) {
    let TerminalInstance {
        id,
        child,
        master,
        writer,
        size,
        headless_output: _,
        working_directory,
        agent_started,
        input_gate,
        input_queue,
        active_task,
        operation_admission: _,
        coordination,
        session_mode: _,
        metadata,
        runtime: _,
        launch_metadata: _,
        codex_gateway,
        launch_account_binding: _,
        app_control_mcp_requested: _,
    } = instance;
    terminal_codex_hook_trust_discovery_clear(&metadata.pane_id, id);
    terminal_structured_interaction_clear_superseded(&metadata.pane_id, id);
    if let Ok(mut gateway) = codex_gateway.lock() {
        if let Some(gateway) = gateway.take() {
            log_terminal_status_event(
                "backend.codex_app_server_gateway.shutdown",
                json!({
                    "endpoint": clean_terminal_diagnostic_log_text(&gateway.endpoint),
                    "instance_id": id,
                    "pane_id": clean_terminal_diagnostic_log_text(&metadata.pane_id),
                    "reason": reason,
                }),
            );
            gateway.shutdown();
        }
    }
    let metadata_fields = terminal_metadata_forensics_json(&metadata);
    unregister_agent_thread_transcript_native_watch(&metadata.pane_id, Some(id));
    log_terminal_crash_forensics_event(
        "backend.terminal_cleanup.begin",
        json!({
            "coordination_cleanup_mode": coordination_cleanup_mode.as_str(),
            "instance_id": id,
            "kill_first": kill_first,
            "metadata": metadata_fields,
            "reason": reason,
        }),
    );

    let maybe_child = {
        let mut child = child.blocking_lock();
        child.take()
    };
    #[cfg(not(windows))]
    let process_group_leader = {
        let master = master.blocking_lock();
        master.process_group_leader()
    };
    #[cfg(windows)]
    let process_group_leader: Option<i32> = None;
    let Some(mut child) = maybe_child else {
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.no_child",
            json!({
                "instance_id": id,
                "reason": reason,
            }),
        );
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.drop_writer.begin",
            json!({
                "instance_id": id,
                "reason": reason,
            }),
        );
        drop(writer);
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.drop_writer.done",
            json!({
                "instance_id": id,
                "reason": reason,
            }),
        );
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.drop_master.begin",
            json!({
                "instance_id": id,
                "reason": reason,
            }),
        );
        drop(master);
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.drop_master.done",
            json!({
                "instance_id": id,
                "reason": reason,
            }),
        );
        drop(size);
        drop(working_directory);
        drop(agent_started);
        drop(input_gate);
        drop(input_queue);
        drop(active_task);
        drop(metadata);
        interrupt_terminal_coordination_after_process_cleanup(
            coordination.as_ref(),
            reason,
            coordination_cleanup_mode,
        );
        drop(coordination);
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.done",
            json!({
                "instance_id": id,
                "reason": reason,
            }),
        );
        return;
    };
    if kill_first {
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.kill.begin",
            json!({
                "instance_id": id,
                "reason": reason,
                "stage": "initial_kill_first",
            }),
        );
        let report = kill_terminal_process_tree(child.as_mut(), process_group_leader);
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.kill.done",
            json!({
                "instance_id": id,
                "reason": reason,
                "report": terminal_kill_report_json(&report),
                "stage": "initial_kill_first",
            }),
        );
    } else if !poll_terminal_child_exit(child.as_mut()) {
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.kill.begin",
            json!({
                "instance_id": id,
                "reason": reason,
                "stage": "poll_timeout",
            }),
        );
        let report = kill_terminal_process_tree(child.as_mut(), process_group_leader);
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.kill.done",
            json!({
                "instance_id": id,
                "reason": reason,
                "report": terminal_kill_report_json(&report),
                "stage": "poll_timeout",
            }),
        );
    }

    if !poll_terminal_child_exit(child.as_mut()) {
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.kill.begin",
            json!({
                "instance_id": id,
                "reason": reason,
                "stage": "final_poll_timeout",
            }),
        );
        let report = kill_terminal_process_tree(child.as_mut(), process_group_leader);
        log_terminal_crash_forensics_event(
            "backend.terminal_cleanup.kill.done",
            json!({
                "instance_id": id,
                "reason": reason,
                "report": terminal_kill_report_json(&report),
                "stage": "final_poll_timeout",
            }),
        );
        poll_terminal_child_exit(child.as_mut());
    }

    log_terminal_crash_forensics_event(
        "backend.terminal_cleanup.drop_child.begin",
        json!({
            "instance_id": id,
            "reason": reason,
        }),
    );
    drop(child);
    log_terminal_crash_forensics_event(
        "backend.terminal_cleanup.drop_child.done",
        json!({
            "instance_id": id,
            "reason": reason,
        }),
    );
    log_terminal_crash_forensics_event(
        "backend.terminal_cleanup.drop_writer.begin",
        json!({
            "instance_id": id,
            "reason": reason,
        }),
    );
    drop(writer);
    log_terminal_crash_forensics_event(
        "backend.terminal_cleanup.drop_writer.done",
        json!({
            "instance_id": id,
            "reason": reason,
        }),
    );
    log_terminal_crash_forensics_event(
        "backend.terminal_cleanup.drop_master.begin",
        json!({
            "instance_id": id,
            "reason": reason,
        }),
    );
    drop(master);
    log_terminal_crash_forensics_event(
        "backend.terminal_cleanup.drop_master.done",
        json!({
            "instance_id": id,
            "reason": reason,
        }),
    );
    drop(size);
    drop(working_directory);
    drop(agent_started);
    drop(input_gate);
    drop(input_queue);
    drop(active_task);
    drop(metadata);
    interrupt_terminal_coordination_after_process_cleanup(
        coordination.as_ref(),
        reason,
        coordination_cleanup_mode,
    );
    drop(coordination);
    log_terminal_crash_forensics_event(
        "backend.terminal_cleanup.done",
        json!({
            "instance_id": id,
            "reason": reason,
        }),
    );
}

fn cleanup_terminal_instance_async(
    instance: TerminalInstance,
    kill_first: bool,
    reason: &'static str,
    preserve_coordination_session: bool,
    cleanup_tracker: Option<Arc<TerminalCleanupTracker>>,
) {
    thread::spawn(move || {
        let instance_id = instance.id;
        let _cleanup_guard = cleanup_tracker
            .as_ref()
            .map(|tracker| tracker.begin(reason, Some(instance_id)));
        let coordination_cleanup_mode = if preserve_coordination_session {
            TerminalCoordinationCleanupMode::Preserve
        } else {
            TerminalCoordinationCleanupMode::InterruptAfterProcess
        };
        cleanup_terminal_instance_with_context(
            instance,
            kill_first,
            reason,
            coordination_cleanup_mode,
        );
    });
}

