            | "transcriptchanged"
            | "permissiondenied"
            | "permissionresult"
            | "permissionresolved"
            | "permissionprompt"
            | "permissionpromptstarted"
            | "permissionrequest"
            | "postcompact"
            | "posttoolbatch"
            | "posttooluse"
            | "posttoolusefailure"
            | "providerretry"
