fn terminal_activity_runtime_turn_id(runtime: &TerminalRuntimeSnapshot) -> String {
    runtime
        .turn_id
        .as_deref()
        .or(runtime.provider_turn_id.as_deref())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("")
        .to_string()
}

fn terminal_activity_hook_is_idle_stop_payload(payload: &TerminalActivityHookPayload) -> bool {
    terminal_activity_payload_is_idle_ready(payload)
        && matches!(
            terminal_activity_hook_name_key(&payload.hook_event_name).as_str(),
            "stop" | "turnstop" | "assistantstop"
        )
}

fn terminal_runtime_snapshot_has_unsettled_turn(runtime: &TerminalRuntimeSnapshot) -> bool {
    terminal_runtime_snapshot_is_busy_turn(runtime) || runtime.turn_active
}

fn terminal_pending_final_stop_activity_matches(
    candidate: &PendingTerminalFinalStopCandidate,
    runtime: &TerminalRuntimeSnapshot,
    payload: &TerminalActivityHookPayload,
) -> bool {
    let payload_session_id = terminal_activity_payload_session_id(payload);
    let runtime_session_id = terminal_activity_runtime_session_id(runtime);
    let session_id = if payload_session_id.is_empty() {
        runtime_session_id.as_str()
    } else {
        payload_session_id.as_str()
    };
    if !candidate.session_id.is_empty()
        && !session_id.is_empty()
        && candidate.session_id != session_id
    {
        return false;
    }

    let payload_turn_id = terminal_activity_payload_turn_id(payload);
    let runtime_turn_id = terminal_activity_runtime_turn_id(runtime);
    let turn_id = if payload_turn_id.is_empty() {
        runtime_turn_id.as_str()
    } else {
        payload_turn_id.as_str()
    };
    candidate.turn_id.is_empty() || turn_id.is_empty() || candidate.turn_id == turn_id
}

fn terminal_activity_hook_cancels_pending_final_stop(
    payload: &TerminalActivityHookPayload,
) -> bool {
    let hook_key = terminal_activity_hook_name_key(&payload.hook_event_name);
    terminal_activity_hook_is_prompt_submit_key(&hook_key)
        || matches!(
            terminal_projection_text(&payload.event_type, "").as_str(),
            "provider_turn_error"
                | "provider-turn-error"
                | "provider_turn_interrupted"
                | "provider-turn-interrupted"
                | "provider_permission_requested"
                | "provider-permission-requested"
                | "provider_user_prompt_started"
                | "provider-user-prompt-started"
        )
        || matches!(
            hook_key.as_str(),
            "error"
                | "turnerror"
                | "assistantturnerror"
                | "stopfailure"
                | "interrupt"
                | "interrupted"
                | "turninterrupt"
                | "turninterrupted"
                | "assistantinterrupt"
                | "assistantturninterrupted"
                | "userinterrupt"
                | "userinterrupted"
                | "permissionrequest"
                | "userpromptrequired"
                | "manualprompt"
                | "permissionprompt"
                | "permissionpromptstarted"
                | "userinputrequired"
                | "userinputrequested"
                | "userpromptstarted"
                | "elicitation"
        )
}

fn terminal_activity_hook_idle_stop_already_settled(
    payload: &TerminalActivityHookPayload,
    current_runtime: &TerminalRuntimeSnapshot,
    current_runtime_is_busy_turn: bool,
    pane_id: &str,
    instance_id: u64,
) -> bool {
    if current_runtime_is_busy_turn || !terminal_activity_hook_is_idle_stop_payload(payload) {
        return false;
    }
    if current_runtime.turn_active {
        // UIR and paused are intentionally classified as non-busy, but both
        // still own an unsettled turn. Their Stop must reach correlation and
        // the reducer instead of being mistaken for a duplicate idle frame.
        return false;
    }
    if !current_runtime.input_ready
        && (terminal_runtime_snapshot_is_interrupted(current_runtime)
            || terminal_runtime_snapshot_is_recoverable_startup_error(current_runtime))
    {
        return false;
    }
    let runtime_session_id = terminal_activity_runtime_session_id(current_runtime);
    let payload_session_id = terminal_activity_payload_session_id(payload);
    if !runtime_session_id.is_empty()
        && (!payload_session_id.is_empty() && payload_session_id != runtime_session_id
            || (payload_session_id.is_empty()
                && !terminal_activity_hook_pane_scoped_payload_matches_target(
                    payload,
                    pane_id,
                    instance_id,
                )))
    {
        return true;
    }
    let runtime_turn_id = terminal_activity_runtime_turn_id(current_runtime);
    let payload_turn_id = terminal_activity_payload_turn_id(payload);
    !runtime_turn_id.is_empty()
        && (!payload_turn_id.is_empty() && payload_turn_id == runtime_turn_id
            || payload_turn_id.is_empty())
}

fn terminal_activity_hook_is_startup_readiness_signal(
    event: &Value,
    source: &str,
    payload: &TerminalActivityHookPayload,
    current_runtime: &TerminalRuntimeSnapshot,
) -> bool {
    if !terminal_runtime_snapshot_is_starting(current_runtime)
        || current_runtime.turn_active
        || !terminal_activity_payload_is_idle_ready(payload)
    {
        return false;
    }
    matches!(
        source.trim().to_ascii_lowercase().as_str(),
        "backend-startup-prompt-ready" | "backend-startup-watchdog" | "startup-idle-buffer"
    ) || terminal_activity_hook_startup_idle_buffered(event)
        || (terminal_activity_hook_bool(event, &["backend_watchdog"])
            && terminal_activity_hook_string(event, &["watchdog_reason"])
                .is_some_and(|reason| reason.starts_with("starting_")))
}

fn terminal_activity_hook_update_pending_final_stop_for_activity(
    pane_id: &str,
    instance_id: u64,
    runtime: &TerminalRuntimeSnapshot,
    payload: &TerminalActivityHookPayload,
    source: &str,
) -> Option<u64> {
    if terminal_activity_hook_is_idle_stop_payload(payload) {
        return None;
    }
    let key = terminal_pending_final_stop_key(pane_id, instance_id);
    let Ok(mut pending) = terminal_pending_final_stops().lock() else {
        return None;
    };
    let Some(candidate) = pending.get_mut(&key) else {
        return None;
    };
    if terminal_activity_hook_cancels_pending_final_stop(payload)
        || !terminal_pending_final_stop_activity_matches(candidate, runtime, payload)
    {
        pending.remove(&key);
        log_terminal_status_event(
            "backend.terminal_activity_hook.pending_final_stop_cancelled",
            json!({
                "hook_event_name": payload.hook_event_name.clone(),
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                "reason": "new_turn_or_mismatch",
                "source": source,
            }),
        );
        return None;
    }
    // Every candidate and replacement sleeper draws from the same allocator.
    // A cancelled candidate can leave an old sleeper alive, so a key-local
    // increment must never collide with a later globally allocated candidate.
    let generation = terminal_pending_final_stop_next_generation();
    candidate.generation = generation;
    log_terminal_status_event(
        "backend.terminal_activity_hook.pending_final_stop_extended",
        json!({
            "buffer_ms": TERMINAL_ACTIVITY_IDLE_QUIESCE_MS,
            "hook_event_name": payload.hook_event_name.clone(),
            "instance_id": instance_id,
            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
            "source": source,
        }),
    );
    Some(generation)
}

fn terminal_pending_final_stop_take_generation(
    key: &str,
    generation: u64,
) -> Option<PendingTerminalFinalStopCandidate> {
    let Ok(mut pending) = terminal_pending_final_stops().lock() else {
        return None;
    };
    if pending.get(key)?.generation != generation {
        return None;
    }
    pending.remove(key)
}

fn terminal_activity_hook_schedule_final_stop_quiesce(
    app: &AppHandle,
    terminals: &Arc<RwLock<HashMap<String, TerminalInstance>>>,
    cloud_mcp_state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    generation: u64,
) {
    let app = app.clone();
    let terminals = Arc::clone(terminals);
    let cloud_mcp_state = cloud_mcp_state.clone();
    let pane_id = pane_id.to_string();
    let key = terminal_pending_final_stop_key(&pane_id, instance_id);
    tauri::async_runtime::spawn(async move {
        sleep(Duration::from_millis(TERMINAL_ACTIVITY_IDLE_QUIESCE_MS)).await;
        let candidate = terminal_pending_final_stop_take_generation(&key, generation);
        let Some(candidate) = candidate else {
            return;
        };
        let Some(current_instance) =
            terminal_activity_hook_current_instance(&terminals, &pane_id, instance_id).await
        else {
            return;
        };
        let runtime = terminal_runtime_snapshot(&current_instance);
        if runtime.input_ready || !terminal_runtime_snapshot_has_unsettled_turn(&runtime) {
            log_terminal_status_event(
                "backend.terminal_activity_hook.idle_quiesce_cancelled",
                json!({
                    "instance_id": instance_id,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "reason": "already_settled",
                }),
            );
            return;
        }
        let runtime_session_id = terminal_activity_runtime_session_id(&runtime);
        if !candidate.session_id.is_empty()
            && !runtime_session_id.is_empty()
            && candidate.session_id != runtime_session_id
        {
            log_terminal_status_event(
                "backend.terminal_activity_hook.idle_quiesce_cancelled",
                json!({
                    "instance_id": instance_id,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "reason": "session_changed",
                }),
            );
            return;
        }
        let runtime_turn_id = terminal_activity_runtime_turn_id(&runtime);
        if !candidate.turn_id.is_empty()
            && !runtime_turn_id.is_empty()
            && candidate.turn_id != runtime_turn_id
        {
            // WAITING awaits a FUTURE turn's stop: the background continuation
            // mints a new turn id, so a turn mismatch must not cancel the
            // buffered final Stop when the session is waiting AND the event
            // FIRED at/after the waiting entry's ORIGIN (hook CLI stamps
            // `timestamp_ms` at fire time). Unstamped candidates fail closed.
            // The session-changed check above already rejected foreign
            // sessions.
            let runtime_waiting =
                terminal_projection_text(&runtime.canonical_state, "") == "waiting";
            let candidate_origin_ms = terminal_event_origin_ms(&candidate.event);
            let ordered_after_waiting =
                terminal_waiting_origin_ordered(candidate_origin_ms, runtime.waiting_origin_ms);
            if !(runtime_waiting && ordered_after_waiting) {
                log_terminal_status_event(
                    "backend.terminal_activity_hook.idle_quiesce_cancelled",
                    json!({
                        "instance_id": instance_id,
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "reason": "turn_changed",
                    }),
                );
                return;
            }
        }
        let Some(delayed_payload) =
            terminal_activity_hook_payload(&current_instance, &candidate.event)
        else {
            return;
        };
        let delayed_architecture_payload =
            terminal_architecture_activity_payload(&current_instance, &candidate.event);
        apply_terminal_activity_hook_payload(
            &app,
            &terminals,
            &cloud_mcp_state,
            &current_instance,
            &candidate.event,
            delayed_payload,
            delayed_architecture_payload,
            "terminal-idle-quiesce",
        );
    });
}

fn terminal_activity_hook_buffer_final_stop_candidate(
    app: &AppHandle,
    terminals: &Arc<RwLock<HashMap<String, TerminalInstance>>>,
    cloud_mcp_state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    current_runtime: &TerminalRuntimeSnapshot,
    event: &Value,
    payload: &TerminalActivityHookPayload,
    source: &str,
) {
    let key = terminal_pending_final_stop_key(pane_id, instance_id);
    let generation = terminal_pending_final_stop_next_generation();
    let session_id = {
        let payload_session_id = terminal_activity_payload_session_id(payload);
        if payload_session_id.is_empty() {
            terminal_activity_runtime_session_id(current_runtime)
        } else {
            payload_session_id
        }
    };
    let turn_id = {
        let payload_turn_id = terminal_activity_payload_turn_id(payload);
        if payload_turn_id.is_empty() {
            terminal_activity_runtime_turn_id(current_runtime)
        } else {
            payload_turn_id
        }
    };
    let mut buffered_event = event.clone();
    if let Some(object) = buffered_event.as_object_mut() {
        object.insert("terminal_idle_quiesce_buffered".to_string(), json!(true));
        object.insert("codex_idle_quiesce_buffered".to_string(), json!(true));
    }
    // Keep provider generation absence observable. Binding an idle-timer Stop
    // here would let it masquerade as the current generation after a UIR
    // request races ahead of the timer.
    if let Ok(mut pending) = terminal_pending_final_stops().lock() {
        pending.insert(
            key.clone(),
            PendingTerminalFinalStopCandidate {
                generation,
                session_id,
                turn_id,
                event: buffered_event,
            },
        );
    }
    log_terminal_status_event(
        "backend.terminal_activity_hook.idle_quiesce_buffered",
        json!({
            "buffer_ms": TERMINAL_ACTIVITY_IDLE_QUIESCE_MS,
            "hook_event_name": payload.hook_event_name.clone(),
            "instance_id": instance_id,
            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
            "source": source,
        }),
    );
    terminal_activity_hook_schedule_final_stop_quiesce(
        app,
        terminals,
        cloud_mcp_state,
        pane_id,
        instance_id,
        generation,
    );
}

fn terminal_structured_interaction_matches_resolution(
    interaction: &TerminalStructuredInteraction,
    resolved_interaction_id: Option<&str>,
    resolved_interaction_revision: Option<u64>,
    resolved_request_id: Option<&str>,
) -> bool {
    resolved_interaction_id == Some(interaction.interaction_id.as_str())
        && resolved_interaction_revision == Some(interaction.revision)
        && resolved_request_id.is_none_or(|request_id| {
            interaction.provider_request_id == request_id || interaction.prompt_id == request_id
        })
}

fn terminal_structured_interaction_authoritative_open<'a>(
    interactions: impl Iterator<Item = &'a TerminalStructuredInteraction>,
    pane_id: &str,
    instance_id: u64,
) -> Option<&'a TerminalStructuredInteraction> {
    interactions
        .filter(|interaction| {
            interaction.pane_id == pane_id && interaction.instance_id == instance_id
        })
        .max_by(|left, right| {
            left.revision
                .cmp(&right.revision)
                .then_with(|| left.interaction_id.cmp(&right.interaction_id))
        })
}

fn terminal_structured_interaction_open_is_older(
    current: &TerminalStructuredInteraction,
    incoming_revision: u64,
) -> bool {
    incoming_revision < current.revision
}

fn terminal_activity_payload_overlay_open_interaction(
    payload: &mut TerminalActivityHookPayload,
    interaction: &TerminalStructuredInteraction,
) {
    payload.status = "active".to_string();
    payload.activity_status = "awaiting_input".to_string();
    payload.command_phase = "awaiting_input".to_string();
    payload.input_ready = false;
    payload.approval_id = interaction.prompt_metadata.approval_id.clone();
    payload.permission_prompt_id = interaction.prompt_metadata.permission_prompt_id.clone();
    payload.permission_request_id = interaction.prompt_metadata.permission_request_id.clone();
    payload.permission_mode = interaction.prompt_metadata.permission_mode.clone();
    payload.prompt_id = Some(interaction.prompt_id.clone());
    payload.prompt_kind = interaction.prompt_metadata.prompt_kind.clone();
    payload.prompt_default_option = interaction.prompt_metadata.prompt_default_option.clone();
    payload.prompt_ttl_ms = interaction.prompt_metadata.prompt_ttl_ms;
    payload.prompt_options = interaction.options.clone();
    payload.prompt_questions = interaction.prompt_questions.clone();
    payload.prompt_schema = interaction.prompt_schema.clone();
    payload.prompt_url = interaction.prompt_metadata.prompt_url.clone();
    payload.provider_payload = interaction.provider_payload.clone();
    payload.allows_free_text = interaction.prompt_metadata.allows_free_text;
    payload.manual_prompt_source = interaction.prompt_metadata.manual_prompt_source.clone();
    payload.manual_approval_required = interaction.prompt_metadata.manual_approval_required;
    payload.provider_blocked_for_user = true;
    payload.terminal_is_prompting_user = true;
    payload.prompting_user_kind = interaction.prompt_metadata.prompting_user_kind.clone();
    payload.prompting_user_source = interaction.prompt_metadata.prompting_user_source.clone();
    payload.prompting_user_confidence = interaction.prompt_metadata.prompting_user_confidence.clone();
    payload.prompting_user_text = interaction.prompt_metadata.prompting_user_text.clone();
    payload.interaction_id = Some(interaction.interaction_id.clone());
    payload.interaction_revision = Some(interaction.revision);
    payload.interaction_source = Some("provider_hook".to_string());
    payload.interaction_response_mode = Some(interaction.response_mode.clone());
    payload.provider_request_id = Some(interaction.provider_request_id.clone());
}

fn terminal_structured_interaction_reconcile(
    app: &AppHandle,
    event: &Value,
    payload: &TerminalActivityHookPayload,
) -> bool {
    let state = app.state::<TerminalState>();
    let Ok(mut interactions) = state.terminal_structured_interactions.lock() else {
        return false;
    };

    let provider_interaction = payload
        .interaction_source
        .as_deref()
        .is_some_and(|source| matches!(source, "provider_hook" | "diffforge_intervention"))
        && payload.terminal_is_prompting_user;
    if provider_interaction {
        let Some(interaction_id) = payload.interaction_id.clone() else {
            return false;
        };
        let Some(provider_request_id) = payload.provider_request_id.clone() else {
            return false;
        };
        let incoming_revision = payload
            .interaction_revision
            .unwrap_or(payload.observed_at_ms);
        let authoritative_open = terminal_structured_interaction_authoritative_open(
            interactions.values(),
            &payload.pane_id,
            payload.instance_id,
        );
        let lower_than_current = authoritative_open.is_some_and(|current| {
            terminal_structured_interaction_open_is_older(current, incoming_revision)
        });
        if lower_than_current
            || terminal_structured_interaction_is_superseded(
                &payload.pane_id,
                payload.instance_id,
                &interaction_id,
                incoming_revision,
            )
        {
            log_terminal_status_event(
                "backend.terminal_structured_interaction.stale_open_rejected",
                json!({
                    "incoming_interaction_id": interaction_id,
                    "incoming_revision": incoming_revision,
                    "instance_id": payload.instance_id,
                    "pane_id": payload.pane_id,
                }),
            );
            return true;
        }
        let superseded_ids = interactions
            .iter()
            .filter_map(|(id, interaction)| {
                (id != &interaction_id
                    && interaction.pane_id == payload.pane_id
                    && interaction.instance_id == payload.instance_id)
                    .then(|| id.clone())
            })
            .collect::<Vec<_>>();
        terminal_structured_interaction_record_superseded(
            &payload.pane_id,
            payload.instance_id,
            interactions.values().filter(|interaction| {
                interaction.interaction_id != interaction_id
                    && interaction.pane_id == payload.pane_id
                    && interaction.instance_id == payload.instance_id
            }),
        );
        interactions.retain(|id, interaction| {
            id == &interaction_id
                || interaction.pane_id != payload.pane_id
                || interaction.instance_id != payload.instance_id
        });
        let awaiting_provider_confirmation =
            interactions
                .get(&interaction_id)
                .is_some_and(|interaction| {
                    interaction.revision
                        == payload
                            .interaction_revision
                            .unwrap_or(payload.observed_at_ms)
                        && interaction.awaiting_provider_confirmation
                });
        let claimed_option_id = interactions
            .get(&interaction_id)
            .filter(|interaction| {
                interaction.revision
                    == payload
                        .interaction_revision
                        .unwrap_or(payload.observed_at_ms)
            })
            .and_then(|interaction| interaction.claimed_option_id.clone());
        interactions.insert(
            interaction_id.clone(),
            TerminalStructuredInteraction {
                interaction_id: interaction_id.clone(),
                revision: incoming_revision,
                pane_id: payload.pane_id.clone(),
                instance_id: payload.instance_id,
                provider: payload.provider.clone(),
                provider_request_id,
                prompt_id: payload.prompt_id.clone().unwrap_or_default(),
                hook_event_name: payload.hook_event_name.clone(),
                response_mode: payload
                    .interaction_response_mode
                    .clone()
                    .unwrap_or_else(|| "structured_pty".to_string()),
                awaiting_provider_confirmation,
                claimed_option_id,
                options: payload.prompt_options.clone(),
                permission_suggestions: terminal_activity_hook_value(
                    event,
                    &["permission_suggestions", "updated_permissions"],
                ),
                prompt_questions: payload.prompt_questions.clone(),
                prompt_schema: payload.prompt_schema.clone(),
                provider_payload: payload.provider_payload.clone(),
                prompt_metadata: TerminalStructuredInteractionPromptMetadata {
                    approval_id: payload.approval_id.clone(),
                    permission_prompt_id: payload.permission_prompt_id.clone(),
                    permission_request_id: payload.permission_request_id.clone(),
                    permission_mode: payload.permission_mode.clone(),
                    prompt_kind: payload.prompt_kind.clone(),
                    prompt_default_option: payload.prompt_default_option.clone(),
                    prompt_ttl_ms: payload.prompt_ttl_ms,
                    prompt_url: payload.prompt_url.clone(),
                    allows_free_text: payload.allows_free_text,
                    manual_prompt_source: payload.manual_prompt_source.clone(),
                    manual_approval_required: payload.manual_approval_required,
                    prompting_user_kind: payload.prompting_user_kind.clone(),
                    prompting_user_source: payload.prompting_user_source.clone(),
                    prompting_user_confidence: payload.prompting_user_confidence.clone(),
                    prompting_user_text: payload.prompting_user_text.clone(),
                },
            },
        );
        log_terminal_status_event(
            "backend.terminal_structured_interaction.opened",
            json!({
                "hook_event_name": payload.hook_event_name,
                "instance_id": payload.instance_id,
                "interaction_id": interaction_id,
                "pane_id": payload.pane_id,
                "provider": payload.provider,
                "response_mode": payload.interaction_response_mode,
                "revision": payload.interaction_revision,
            }),
        );
        drop(interactions);
        if !superseded_ids.is_empty() {
            if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
                for id in superseded_ids {
                    waiters.remove(&id);
                }
            }
        }
        return false;
    }

    let hook_key = terminal_activity_hook_name_key(&payload.hook_event_name);
    let provider_resolved_interaction = matches!(
        hook_key.as_str(),
        "permissiondenied"
            | "permissionresult"
            | "permissionresolved"
            | "elicitationresult"
            | "elicitationresolved"
    );
    let provider_error = terminal_projection_text(&payload.event_type, "")
        == "provider_turn_error"
        || payload.provider_error.is_some();
    if !payload.terminal_is_prompting_user || provider_resolved_interaction {
        let resolved_request_id = terminal_activity_hook_string(
            event,
            &[
                "permission_request_id",
                "permission_prompt_id",
                "approval_id",
                "prompt_id",
                "question_id",
                "selection_id",
                "tool_use_id",
                "id",
            ],
        );
        let same_terminal_open = interactions.values().any(|interaction| {
            interaction.pane_id == payload.pane_id && interaction.instance_id == payload.instance_id
        });
        let removed_ids = interactions
            .iter()
            .filter_map(|(id, interaction)| {
                let same_terminal = interaction.pane_id == payload.pane_id
                    && interaction.instance_id == payload.instance_id;
                let same_resolution = if provider_error {
                    payload.event_interaction_id.as_deref()
                        == Some(interaction.interaction_id.as_str())
                        && payload.event_interaction_revision == Some(interaction.revision)
                } else {
                    !provider_resolved_interaction
                        || terminal_structured_interaction_matches_resolution(
                            interaction,
                            payload.event_interaction_id.as_deref(),
                            payload.event_interaction_revision,
                            resolved_request_id.as_deref(),
                        )
                };
                let lifecycle_can_close = terminal_structured_interaction_lifecycle_can_close(
                    interaction,
                    provider_resolved_interaction,
                );
                (same_terminal && same_resolution && lifecycle_can_close).then(|| id.clone())
            })
            .collect::<Vec<_>>();
        let explicitly_correlated_resolution =
            payload.interaction_id.is_some() || payload.interaction_revision.is_some();
        let rejected_resolution = provider_resolved_interaction
            && removed_ids.is_empty()
            && (same_terminal_open || explicitly_correlated_resolution);
        if rejected_resolution {
            let pending_native_provider_confirmation = (!explicitly_correlated_resolution)
                .then_some(resolved_request_id.as_deref())
                .flatten()
                .and_then(|resolved_request_id| {
                    interactions
                        .values()
                        .find(|interaction| {
                            interaction.pane_id == payload.pane_id
                                && interaction.instance_id == payload.instance_id
                                && interaction.response_mode == "provider_api"
                                && (interaction.provider_request_id == resolved_request_id
                                    || interaction.prompt_id == resolved_request_id)
                        })
                        .cloned()
                });
            drop(interactions);
            log_terminal_status_event(
                "backend.terminal_structured_interaction.stale_resolution_rejected",
                json!({
                    "instance_id": payload.instance_id,
                    "pane_id": payload.pane_id,
                    "resolved_interaction_id": payload.interaction_id,
                    "resolved_interaction_revision": payload.interaction_revision,
                    "resolved_request_id": resolved_request_id,
                    "same_terminal_open": same_terminal_open,
                }),
            );
            if let Some(interaction) = pending_native_provider_confirmation {
                terminal_structured_interaction_arm_answer_confirmation_timeout(
                    app,
                    interaction,
                    "provider_api",
                );
            }
            // If a newer interaction is still open, continue into projection:
            // the caller will overlay and emit that authoritative interaction.
            // With no surviving interaction, the stale resolution has no
            // canonical effect and is rejected outright.
            return !same_terminal_open;
        }
        let resolved_codex_hook_trust = provider_resolved_interaction
            && removed_ids.iter().any(|id| {
                interactions.get(id).is_some_and(|interaction| {
                    terminal_codex_hook_trust_is_catalog_request(&interaction.provider_request_id)
                })
            });
        terminal_structured_interaction_record_superseded(
            &payload.pane_id,
            payload.instance_id,
            removed_ids.iter().filter_map(|id| interactions.get(id)),
        );
        interactions.retain(|id, _| !removed_ids.contains(id));
        drop(interactions);
        if resolved_codex_hook_trust {
            terminal_codex_hook_trust_discovery_set(
                &payload.pane_id,
                payload.instance_id,
                TerminalCodexHookTrustDiscoveryState::Resolved,
            );
        }
        if !removed_ids.is_empty() {
            if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
                for id in removed_ids {
                    waiters.remove(&id);
                }
            }
        }
    }
    false
}

fn terminal_structured_interaction_uses_blocking_transport(
    interaction: &TerminalStructuredInteraction,
) -> bool {
    matches!(
        interaction.response_mode.as_str(),
        "blocking_hook"
            | "structured_pty"
            | "provider_api"
            | "codex_app_server"
            | "diffforge_intervention"
    )
}

fn terminal_structured_interaction_lifecycle_can_close(
    interaction: &TerminalStructuredInteraction,
    provider_resolved_interaction: bool,
) -> bool {
    provider_resolved_interaction
        || !terminal_structured_interaction_uses_blocking_transport(interaction)
}

fn terminal_structured_interaction_ids_for_terminal(
    interactions: &HashMap<String, TerminalStructuredInteraction>,
    pane_id: &str,
    instance_id: u64,
) -> Vec<String> {
    interactions
        .iter()
        .filter_map(|(id, interaction)| {
            (interaction.pane_id == pane_id && interaction.instance_id == instance_id)
                .then(|| id.clone())
        })
        .collect()
}

fn terminal_structured_interaction_remove_terminal_from_map(
    interactions: &mut HashMap<String, TerminalStructuredInteraction>,
    pane_id: &str,
    instance_id: u64,
) -> Vec<String> {
    let removed =
        terminal_structured_interaction_ids_for_terminal(interactions, pane_id, instance_id);
    interactions.retain(|_, interaction| {
        interaction.pane_id != pane_id || interaction.instance_id != instance_id
    });
    removed
}

fn terminal_structured_interaction_clear_terminal(
    state: &TerminalState,
    pane_id: &str,
    instance_id: u64,
) -> usize {
    let removed_ids = state
        .terminal_structured_interactions
        .lock()
        .ok()
        .map(|mut interactions| {
            terminal_structured_interaction_record_superseded(
                pane_id,
                instance_id,
                interactions.values().filter(|interaction| {
                    interaction.pane_id == pane_id && interaction.instance_id == instance_id
                }),
            );
            terminal_structured_interaction_remove_terminal_from_map(
                &mut interactions,
                pane_id,
                instance_id,
            )
        })
        .unwrap_or_default();
    if !removed_ids.is_empty() {
        if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
            for id in &removed_ids {
                waiters.remove(id);
            }
        }
    }
    removed_ids.len()
}

fn apply_terminal_activity_hook_payload(
    app: &AppHandle,
    terminals: &Arc<RwLock<HashMap<String, TerminalInstance>>>,
    cloud_mcp_state: &CloudMcpState,
    instance: &TerminalInstance,
    event: &Value,
    mut payload: TerminalActivityHookPayload,
    architecture_payload: Option<TerminalArchitectureActivityPayload>,
    source: &str,
) {
    let Some(_operation) = terminal_operation_try_admit(instance) else {
        log_terminal_status_event(
            "backend.terminal_activity_hook.publish_rejected",
            json!({
                "instance_id": instance.id,
                "pane_id": clean_terminal_diagnostic_log_text(&instance.metadata.pane_id),
                "reason": "terminal_closing",
                "source": source,
            }),
        );
        return;
    };
    if payload.interaction_response_mode.as_deref() == Some("blocking_hook")
        && source != "transport"
    {
        payload.terminal_is_prompting_user = false;
        payload.provider_blocked_for_user = false;
        payload.prompt_id = None;
        payload.prompt_kind = None;
        payload.prompt_options.clear();
        payload.prompt_default_option = None;
        payload.interaction_id = None;
        payload.interaction_revision = None;
        payload.event_interaction_id = None;
        payload.event_interaction_revision = None;
        payload.interaction_source = None;
        payload.interaction_response_mode = None;
        payload.provider_request_id = None;
        payload.event_type = "provider-turn-error".to_string();
        payload.status = "error".to_string();
        payload.activity_status = "error".to_string();
        payload.command_phase = "failed".to_string();
        payload.input_ready = false;
        payload.provider_error = Some(json!({
            "contract": "diffforge.terminal_error.v1",
            "scope": "turn",
            "category": "network",
            "provider_code": "blocking_hook_transport_unavailable",
            "safe_message": "Diff Forge could not establish its authenticated UIR transport.",
            "retryable": true,
            "source": "terminal_hook_transport_guard",
        }));
        payload.hook_health_status = "error".to_string();
        payload.hook_health_event = "blocking_hook_transport_required".to_string();
        payload.completion_evidence = "blocking_hook_transport_unavailable".to_string();
        log_terminal_status_event(
            "backend.terminal_structured_interaction.transport_failure",
            json!({
                "hook_event_name": payload.hook_event_name,
                "instance_id": payload.instance_id,
                "pane_id": payload.pane_id,
                "source": source,
            }),
        );
    }
    if terminal_structured_interaction_reconcile(app, event, &payload) {
        return;
    }
    terminal_activity_hook_reconcile_prompt_state(&mut payload);
    let previous_runtime = terminal_runtime_snapshot(instance);
    if terminal_activity_hook_is_startup_readiness_signal(
        event,
        source,
        &payload,
        &previous_runtime,
    ) {
        // Startup prompt/watchdog recovery proves readiness, not completion of
        // a generated turn. Normalize it onto the reducer's readiness input so
        // a missed SessionStart can settle without fabricating a Stop.
        payload.event_type = "terminal-input-ready".to_string();
        payload.completion_evidence = "startup_readiness_recovery".to_string();
    }
    let prompt_state_update = terminal_activity_payload_has_prompt_signal(&payload);
    if payload.completion_evidence == "cli_hook_provider_observation" {
        payload.status = previous_runtime.status.clone();
        payload.activity_status = previous_runtime.activity_status.clone();
        payload.command_phase = previous_runtime.command_phase.clone();
        payload.input_ready = previous_runtime.input_ready;
        payload.input_ready_at = previous_runtime.input_ready_at.clone();
        payload.prompt_ready_at = previous_runtime.prompt_ready_at.clone();
        payload.completed_at = previous_runtime.completed_at.clone();
    }
    let terminal_state = app.state::<TerminalState>();
    let open_structured_interaction = terminal_state
        .terminal_structured_interactions
        .lock()
        .ok()
        .and_then(|interactions| {
            terminal_structured_interaction_authoritative_open(
                interactions.values(),
                &payload.pane_id,
                payload.instance_id,
            )
            .cloned()
        });
    if let Some(interaction) = open_structured_interaction.as_ref() {
        // Reconciliation can resolve A while a newer B remains open. The
        // emitted frame must describe B; replaying A's resolution fields would
        // clear or overwrite B in the cloud prompt cohort.
        terminal_activity_payload_overlay_open_interaction(&mut payload, interaction);
    }
    let task_parked = terminal_state
        .parked_prompts
        .try_read()
        .ok()
        .is_some_and(|parked| {
            parked.values().any(|prompt| {
                prompt.pane_id == payload.pane_id && prompt.instance_id == payload.instance_id
            })
        });
    let (runtime_snapshot, canonical_projection) = terminal_runtime_apply_activity_payload(
        instance,
        &payload,
        open_structured_interaction.as_ref(),
        task_parked,
        prompt_state_update,
    );
    terminal_apply_canonical_projection_to_payload(&mut payload, &canonical_projection);
    let terminal_error_event = terminal_projection_text(&payload.event_type, "")
        == "provider_turn_error"
        || payload.provider_error.is_some();
    let terminal_error_accepted = canonical_projection.error_accepted;
    if terminal_error_event && !terminal_error_accepted {
        // A stale interaction-scoped failure is diagnostic evidence for its
        // own generation, not a lifecycle event for the newer open UIR.
        payload.provider_error = None;
        payload.event_type = runtime_snapshot.event_type.clone();
        payload.hook_event_name = runtime_snapshot.hook_event_name.clone();
        payload.source = runtime_snapshot.source.clone();
        payload.completion_evidence = "stale_error_rejected".to_string();
    }
    if canonical_projection.completion_accepted
        || canonical_projection.interrupt_accepted
        || terminal_error_accepted
    {
        // The reducer has atomically ended the interaction. Emit the same
        // withdrawal in the prompt cohort; otherwise an overlaid UIR can leak
        // into the cloud beside canonical idle/interrupted/error.
        terminal_activity_payload_clear_interaction_state(&mut payload);
        terminal_structured_interaction_clear_terminal(
            terminal_state.inner(),
            &payload.pane_id,
            payload.instance_id,
        );
    }
    terminal_apply_projected_runtime_to_payload(
        &mut payload,
        &instance.metadata,
        &runtime_snapshot,
    );
    if terminal_restart_intent_for_instance(terminal_state.inner(), instance)
        .is_some_and(|intent| intent.state == "pending")
        && terminal_restart_intent_canonical_eligible(terminal_state.inner(), instance)
    {
        terminal_spawn_restart_intent_reevaluation(
            app.clone(),
            payload.pane_id.clone(),
            payload.instance_id,
            "canonical_transition",
        );
    }
    if let Ok(mut launch_metadata) = instance.launch_metadata.lock() {
        if let Some(provider_error) = payload.provider_error.clone() {
            launch_metadata.provider_error = Some(provider_error);
        } else if matches!(
            payload.event_type.as_str(),
            "provider-turn-started" | "provider-turn-completed" | "provider-turn-interrupted"
        ) {
            launch_metadata.provider_error = None;
        }
    }
    log_terminal_status_event(
        "backend.terminal_activity_hook.lifecycle",
        json!({
            "activity_status": payload.activity_status.clone(),
            "event_type": payload.event_type.clone(),
            "hook_health_event": payload.hook_health_event.clone(),
            "hook_health_status": payload.hook_health_status.clone(),
            "hook_event_name": payload.hook_event_name.clone(),
            "instance_id": payload.instance_id,
            "pane_id": payload.pane_id.clone(),
            "provider_session_id_present": payload.provider_session_id.is_some(),
            "runtime_provider_session_id_present": runtime_snapshot.provider_session_id.is_some(),
            "source": source,
            "thread_id": payload.thread_id.clone(),
            "workspace_id": payload.workspace_id.clone(),
        }),
    );
    let mut cloud_payload = payload.clone();
    if cloud_payload.provider_session_id.is_none() {
        cloud_payload.provider_session_id = runtime_snapshot.provider_session_id.clone();
    }
    if cloud_payload.native_session_id.is_none() {
        cloud_payload.native_session_id = runtime_snapshot.native_session_id.clone();
    }
    if cloud_payload.provider_turn_id.is_none() {
        cloud_payload.provider_turn_id = runtime_snapshot.provider_turn_id.clone();
    }
    if cloud_payload.turn_id.is_none() {
        cloud_payload.turn_id = runtime_snapshot.turn_id.clone();
    }
    let cloud_state = cloud_mcp_state.clone();
    tauri::async_runtime::spawn(async move {
        cloud_mcp_sync_terminal_activity_hook_delta(&cloud_state, &cloud_payload).await;
    });
    if payload.provider_session_id.is_none() {
        let history_status = terminal_workspace_agent_session_status_from_payload(&payload);
        terminal_record_workspace_agent_session_history(
            Some(app.clone()),
            instance,
            None,
            None,
            &history_status,
            "terminal_activity_hook",
            None,
        );
    }
    if let Some(provider_session_id) = payload.provider_session_id.as_deref().and_then(|value| {
        terminal_recordable_provider_session_id_for_metadata(&instance.metadata, Some(value))
    }) {
        let binding_changed = previous_runtime
            .provider_session_id
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            != Some(provider_session_id.as_str());
        if binding_changed {
            terminal_record_workspace_provider_session_binding_with_transcript_path(
                Some(app.clone()),
                instance,
                provider_session_id.clone(),
                "terminal_activity_hook",
                payload.transcript_path.as_deref(),
            );
            if let Some(coordination) = instance.coordination.clone() {
                terminal_record_coordination_provider_session_id(
                    coordination,
                    provider_session_id,
                    "terminal_activity_hook",
                );
            }
        }
    }
    if matches!(
        payload.event_type.as_str(),
        "provider-turn-completed" | "provider-turn-error" | "provider-turn-interrupted"
    ) || terminal_activity_hook_name_key(&payload.hook_event_name) == "transcriptchanged"
    {
        let watch_reason =
            if terminal_activity_hook_name_key(&payload.hook_event_name) == "transcriptchanged" {
                "terminal-transcript-changed"
            } else {
                "terminal-activity-final"
            };
        let triggered = trigger_agent_thread_transcript_native_watch(
            app,
            &payload.pane_id,
            Some(payload.instance_id),
            watch_reason,
        );
        log_terminal_status_event(
            "backend.agent_thread_transcript.native_watch_triggered",
            json!({
                "event_type": payload.event_type.clone(),
                "hook_event_name": payload.hook_event_name.clone(),
                "instance_id": payload.instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(&payload.pane_id),
                "reason": watch_reason,
                "watch_count": triggered,
            }),
        );
    }
    let resume_app = app.clone();
    let resume_cloud_state = cloud_mcp_state.clone();
    let resume_terminals = Arc::clone(terminals);
    let resume_payload = payload.clone();
    tauri::async_runtime::spawn(async move {
        let _ = terminal_try_crash_todo_resume_prompt_once(
            resume_app,
            resume_cloud_state,
            resume_terminals,
            resume_payload,
        )
        .await;
    });
    if terminal_activity_hook_should_skip_todo_settlement(event, source) {
        todo_dispatch_observe_activity_hook_readiness(app, &payload);
        log_terminal_status_event(
            "backend.terminal_activity_hook.todo_settlement_skipped",
            json!({
                "hook_event_name": payload.hook_event_name.clone(),
                "instance_id": payload.instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(&payload.pane_id),
                "reason": "startup_derived",
                "source": source,
            }),
        );
    } else {
        todo_dispatch_observe_activity_hook(app, &payload);
    }
    terminal_hook_prompt_submitted_observe(app, instance, &payload);
    terminal_native_plan_capture_observe(instance, event, &payload);
    let _ = app.emit(TERMINAL_ACTIVITY_HOOK_EVENT, payload);
    if let Some(payload) = architecture_payload {
        let _ = app.emit(TERMINAL_ARCHITECTURE_ACTIVITY_EVENT, payload);
    }
}

async fn process_terminal_activity_hook_event(
    app: &AppHandle,
    terminals: &Arc<RwLock<HashMap<String, TerminalInstance>>>,
    cloud_mcp_state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    instance: &TerminalInstance,
    event: &Value,
    source: &str,
) {
    let architecture_payload = terminal_architecture_activity_payload(instance, event);
    let Some(payload) = terminal_activity_hook_payload(instance, event) else {
        if let Some(payload) = architecture_payload {
            let _ = app.emit(TERMINAL_ARCHITECTURE_ACTIVITY_EVENT, payload);
        }
        let hook_event_name =
            terminal_activity_hook_string(event, &["hook_event_name", "event_name"])
                .unwrap_or_default();
        if terminal_activity_hook_non_lifecycle_is_expected(&hook_event_name) {
            return;
        }
        let event_keys = event
            .as_object()
            .map(|object| object.keys().take(16).cloned().collect::<Vec<_>>())
            .unwrap_or_default();
        log_terminal_status_event(
            "backend.terminal_activity_hook.unmapped",
            json!({
                "event_keys": event_keys,
                "hook_event_name": clean_terminal_diagnostic_log_text(&hook_event_name),
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                "reason": if hook_event_name.is_empty() {
                    "missing_hook_event_name"
                } else {
                    "unsupported_hook_event_name"
                },
                "source": source,
            }),
        );
        return;
    };
    if terminal_codex_hook_trust_discovery_blocks_idle(pane_id, instance_id)
        && terminal_activity_payload_is_idle_ready(&payload)
    {
        let hook_key = terminal_activity_hook_name_key(&payload.hook_event_name);
        if matches!(hook_key.as_str(), "sessionstart" | "sessionstarted") {
            // A real provider SessionStart can only run after the native hook
            // trust gate has been answered.  It is deterministic resolution,
            // unlike PTY prompt text, and may now establish the ready state.
            terminal_codex_hook_trust_discovery_set(
                pane_id,
                instance_id,
                TerminalCodexHookTrustDiscoveryState::Resolved,
            );
        } else {
            log_terminal_status_event(
                "backend.codex_hook_trust.idle_transition_ignored",
                json!({
                    "hook_event_name": payload.hook_event_name.clone(),
                    "instance_id": instance_id,
                    "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                    "source": source,
                }),
            );
            return;
        }
    }
    let current_runtime = terminal_runtime_snapshot(instance);
    let current_runtime_is_starting = terminal_runtime_snapshot_is_starting(&current_runtime);
    let current_runtime_is_busy_turn = terminal_runtime_snapshot_is_busy_turn(&current_runtime);
    if terminal_activity_hook_should_ignore_startup_idle_candidate(
        event,
        current_runtime_is_starting,
    ) {
        log_terminal_status_event(
            "backend.terminal_activity_hook.startup_idle_candidate_ignored",
            json!({
                "hook_event_name": payload.hook_event_name.clone(),
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                "reason": if current_runtime_is_busy_turn {
                    "runtime_busy"
                } else {
                    "runtime_not_starting"
                },
                "source": source,
            }),
        );
        return;
    }
    if terminal_activity_hook_session_id_mismatches_busy_runtime(
        &payload,
        &current_runtime,
        current_runtime_is_busy_turn,
        pane_id,
        instance_id,
    ) {
        log_terminal_status_event(
            "backend.terminal_activity_hook.idle_session_mismatch_ignored",
            json!({
                "hook_event_name": payload.hook_event_name.clone(),
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                "payload_provider_session_id": payload.provider_session_id.clone(),
                "runtime_provider_session_id": current_runtime.provider_session_id.clone(),
                "source": source,
            }),
        );
        return;
    }
    if terminal_activity_hook_idle_stop_already_settled(
        &payload,
        &current_runtime,
        current_runtime_is_busy_turn,
        pane_id,
        instance_id,
    ) {
        log_terminal_status_event(
            "backend.terminal_activity_hook.duplicate_idle_stop_ignored",
            json!({
                "hook_event_name": payload.hook_event_name.clone(),
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                "payload_provider_session_id": payload.provider_session_id.clone(),
                "runtime_provider_session_id": current_runtime.provider_session_id.clone(),
                "source": source,
            }),
        );
        return;
    }
    if !terminal_activity_hook_startup_idle_buffered(event)
        && current_runtime_is_starting
        && terminal_activity_payload_is_idle_ready(&payload)
    {
        let scheduled_runtime_fingerprint =
            terminal_runtime_startup_idle_fingerprint(&current_runtime);
        let app = app.clone();
        let terminals = Arc::clone(terminals);
        let cloud_mcp_state = cloud_mcp_state.clone();
        let pane_id = pane_id.to_string();
        let mut buffered_event = event.clone();
        if let Some(object) = buffered_event.as_object_mut() {
            object.insert("startup_idle_buffered".to_string(), json!(true));
        }
        log_terminal_status_event(
            "backend.terminal_activity_hook.startup_idle_buffered",
            json!({
                "buffer_ms": TERMINAL_STARTING_IDLE_BUFFER_MS,
                "hook_event_name": payload.hook_event_name.clone(),
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "source": source,
            }),
        );
        tauri::async_runtime::spawn(async move {
            sleep(Duration::from_millis(TERMINAL_STARTING_IDLE_BUFFER_MS)).await;
            let Some(current_instance) =
                terminal_activity_hook_current_instance(&terminals, &pane_id, instance_id).await
            else {
                return;
            };
            let runtime = terminal_runtime_snapshot(&current_instance);
            if !terminal_runtime_snapshot_is_starting(&runtime)
                || runtime.input_ready
                || terminal_runtime_startup_idle_fingerprint(&runtime)
                    != scheduled_runtime_fingerprint
            {
                log_terminal_status_event(
                    "backend.terminal_activity_hook.startup_idle_buffer_cancelled",
                    json!({
                        "instance_id": instance_id,
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "reason": "runtime_changed",
                    }),
                );
                return;
            }
            let Some(delayed_payload) =
                terminal_activity_hook_payload(&current_instance, &buffered_event)
            else {
                return;
            };
            let delayed_architecture_payload =
                terminal_architecture_activity_payload(&current_instance, &buffered_event);
            apply_terminal_activity_hook_payload(
                &app,
                &terminals,
                &cloud_mcp_state,
                &current_instance,
                &buffered_event,
                delayed_payload,
                delayed_architecture_payload,
                "startup-idle-buffer",
            );
        });
        return;
    }
    if terminal_activity_hook_should_quiesce_idle(
        &instance.metadata,
        event,
        &payload,
        current_runtime_is_starting,
        terminal_runtime_snapshot_has_unsettled_turn(&current_runtime),
    ) {
        terminal_activity_hook_buffer_final_stop_candidate(
            app,
            terminals,
            cloud_mcp_state,
            pane_id,
            instance_id,
            &current_runtime,
            event,
            &payload,
            source,
        );
        return;
    }
    if let Some(generation) = terminal_activity_hook_update_pending_final_stop_for_activity(
        pane_id,
        instance_id,
        &current_runtime,
        &payload,
        source,
    ) {
        terminal_activity_hook_schedule_final_stop_quiesce(
            app,
            terminals,
            cloud_mcp_state,
            pane_id,
            instance_id,
            generation,
        );
    }
    apply_terminal_activity_hook_payload(
        app,
        terminals,
        cloud_mcp_state,
        instance,
        event,
        payload,
        architecture_payload,
        source,
    );
}

fn spawn_terminal_activity_hook_watcher(
    app: AppHandle,
    terminals: Arc<RwLock<HashMap<String, TerminalInstance>>>,
    cloud_mcp_state: CloudMcpState,
    pane_id: String,
    instance_id: u64,
    workspace_id: String,
    poll_ms: u64,
) {
    let activity_events_path =
        terminal_activity_events_path(&pane_id, instance_id, Some(&workspace_id));
    let activity_debug_path =
        terminal_activity_debug_path(&pane_id, instance_id, Some(&workspace_id));
    tauri::async_runtime::spawn(async move {
        let mut offset = 0u64;
        let mut debug_offset = 0u64;
        let mut partial = String::new();
        let mut debug_partial = String::new();
        let mut last_activity_fingerprint: Option<TerminalActivityHookFileFingerprint> = None;
        let mut last_debug_fingerprint: Option<TerminalActivityHookFileFingerprint> = None;
        let mut current_poll_ms = poll_ms;
        let mut unchanged_polls = 0u32;
        let mut last_output_total_bytes = 0u64;
        let mut last_output_activity_ms = terminal_now_ms();
        let mut last_hook_or_output_activity_ms = last_output_activity_ms;
        let mut mcp_startup_observed_at_ms: Option<u64> = None;
        loop {
            if app_shutdown_requested() {
                break;
            }
            let Some(instance) =
                terminal_activity_hook_current_instance(&terminals, &pane_id, instance_id).await
            else {
                break;
            };
            let now_ms = terminal_now_ms();
            let runtime = terminal_runtime_snapshot(&instance);
            let headless_output = Arc::clone(&instance.headless_output);
            let output_total_bytes =
                terminal_activity_watchdog_headless_total_bytes(&headless_output);
            let output_changed = output_total_bytes != last_output_total_bytes;
            if output_changed {
                last_output_total_bytes = output_total_bytes;
                last_output_activity_ms = now_ms;
                last_hook_or_output_activity_ms = now_ms;
            }
            let output_quiet =
                now_ms.saturating_sub(last_output_activity_ms) >= TERMINAL_WATCHDOG_OUTPUT_QUIET_MS;
            let output_flowing = output_changed && !output_quiet;
            let prompt_marker_visible = terminal_headless_tail_has_prompt_marker(&headless_output);
            let mcp_startup_visible =
                terminal_headless_tail_has_mcp_startup_marker(&headless_output);
            if mcp_startup_visible {
                mcp_startup_observed_at_ms.get_or_insert(now_ms);
            } else {
                mcp_startup_observed_at_ms = None;
            }
            let mcp_startup_age_ms = mcp_startup_observed_at_ms
                .map(|observed_at_ms| now_ms.saturating_sub(observed_at_ms))
                .unwrap_or_default();
            let live_process = terminal_activity_watchdog_child_is_live(&instance).await;
            let starting_age_ms = now_ms.saturating_sub(runtime.updated_at_ms);
            let runtime_activity = terminal_projection_text(&runtime.activity_status, "");
            let runtime_interrupted = matches!(
                runtime_activity.as_str(),
                "cancelled" | "canceled" | "interrupted"
            ) || terminal_projection_text(&runtime.event_type, "")
                == "provider_turn_interrupted";
            if mcp_startup_visible
                && !runtime_interrupted
                && runtime.event_type != "provider-mcp-starting"
                && !terminal_projection_state_is_error(&runtime.status)
                && !terminal_projection_state_is_error(&runtime.activity_status)
            {
                let event = terminal_activity_watchdog_event(
                    &instance,
                    &runtime,
                    "McpStartup",
                    "backend-mcp-startup-classifier",
                    "mcp_startup_visible",
                );
                process_terminal_activity_hook_event(
                    &app,
                    &terminals,
                    &cloud_mcp_state,
                    &pane_id,
                    instance_id,
                    &instance,
                    &event,
                    "backend-mcp-startup-classifier",
                )
                .await;
            }
            let watchdog_action = terminal_activity_watchdog_mcp_startup_action(
                &runtime,
                mcp_startup_visible,
                mcp_startup_age_ms,
            )
            .or_else(|| {
                (!terminal_codex_hook_trust_discovery_blocks_idle(&pane_id, instance_id)
                    && terminal_activity_provider_allows_pty_lifecycle_recovery(&instance.metadata))
                .then(|| {
                    terminal_activity_watchdog_starting_action(
                        &runtime,
                        starting_age_ms,
                        live_process,
                        prompt_marker_visible,
                        mcp_startup_visible,
                        output_quiet,
                        output_flowing,
                    )
                    .or_else(|| {
                        terminal_activity_watchdog_stale_hot_action(
                            &runtime,
                            now_ms.saturating_sub(last_hook_or_output_activity_ms),
                        )
                    })
                })
                .flatten()
            })
            // OUTSIDE the pty-lifecycle-recovery gate: WAITING is Claude-only
            // and that gate rejects Claude — the release must run for it.
            .or_else(|| {
                terminal_activity_watchdog_waiting_release_action(
                    &runtime,
                    now_ms.saturating_sub(last_hook_or_output_activity_ms),
                )
            });
            if let Some(action) = watchdog_action {
                let (hook_event_name, source, reason) = match action {
                    TerminalActivityWatchdogAction::StartupStop => (
                        "Stop",
                        "backend-startup-watchdog",
                        if prompt_marker_visible {
                            "starting_prompt_marker_visible"
                        } else {
                            "starting_output_quiet"
                        },
                    ),
                    TerminalActivityWatchdogAction::StartupDowngradeRunning => (
                        "Notification",
                        "backend-startup-output-flowing",
                        "starting_output_flowing",
                    ),
                    TerminalActivityWatchdogAction::McpStartupError => (
                        "McpStartupError",
                        "backend-mcp-startup-watchdog",
                        "mcp_startup_deadline_exceeded",
                    ),
                    TerminalActivityWatchdogAction::StaleHotStop => (
                        "Stop",
                        "backend-stale-hot-watchdog",
                        "stale_hot_no_hook_or_output",
                    ),
                    TerminalActivityWatchdogAction::WaitingRelease => (
                        "Stop",
                        "backend-waiting-release-watchdog",
                        "waiting_background_ttl_exceeded",
                    ),
                };
                log_terminal_status_event(
                    "backend.terminal_activity_watchdog.transition",
                    json!({
                        "action": format!("{action:?}"),
                        "agent_id": clean_terminal_diagnostic_log_text(&instance.metadata.agent_id),
                        "hook_event_name": hook_event_name,
                        "instance_id": instance_id,
                        "launch_mode": terminal_activity_watchdog_launch_mode(&runtime),
                        "output_quiet": output_quiet,
                        "mcp_startup_age_ms": mcp_startup_age_ms,
                        "mcp_startup_visible": mcp_startup_visible,
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "prompt_marker_visible": prompt_marker_visible,
                        "provider": clean_terminal_diagnostic_log_text(&instance.metadata.agent_kind),
                        "reason": reason,
                        "runtime_source": clean_terminal_diagnostic_log_text(&runtime.source),
                        "starting_age_ms": starting_age_ms,
                        "stale_age_ms": now_ms.saturating_sub(last_hook_or_output_activity_ms),
                    }),
                );
                let mut event = terminal_activity_watchdog_event(
                    &instance,
                    &runtime,
                    hook_event_name,
                    source,
                    reason,
                );
                if matches!(action, TerminalActivityWatchdogAction::McpStartupError) {
                    if let Some(object) = event.as_object_mut() {
                        object.insert("error_code".to_string(), json!("mcp_startup_timeout"));
                        object.insert(
                            "error".to_string(),
                            json!("An MCP server is still starting. The terminal remains open; retry the MCP connection or sign in again if authentication failed."),
                        );
                        object.insert("retryable".to_string(), json!(true));
                    }
                }
                process_terminal_activity_hook_event(
                    &app,
                    &terminals,
                    &cloud_mcp_state,
                    &pane_id,
                    instance_id,
                    &instance,
                    &event,
                    source,
                )
                .await;
                last_hook_or_output_activity_ms = now_ms;
                if matches!(
                    action,
                    TerminalActivityWatchdogAction::StartupStop
                        | TerminalActivityWatchdogAction::StaleHotStop
                        | TerminalActivityWatchdogAction::WaitingRelease
                ) {
                    last_output_activity_ms = now_ms;
                }
            }

            let activity_fingerprint =
                terminal_activity_hook_file_fingerprint(&activity_events_path).await;
            let debug_fingerprint =
                terminal_activity_hook_file_fingerprint(&activity_debug_path).await;
            let activity_changed = activity_fingerprint != last_activity_fingerprint;
            let debug_changed = debug_fingerprint != last_debug_fingerprint;
            if activity_changed && activity_fingerprint.is_some()
                || debug_changed && debug_fingerprint.is_some()
            {
                last_hook_or_output_activity_ms = terminal_now_ms();
            }
            if activity_changed || debug_changed {
                current_poll_ms = TERMINAL_ACTIVITY_HOOK_POLL_MS;
                unchanged_polls = 0;
            } else {
                unchanged_polls = unchanged_polls.saturating_add(1);
                if unchanged_polls >= TERMINAL_ACTIVITY_HOOK_BACKOFF_UNCHANGED_POLLS {
                    current_poll_ms = terminal_activity_hook_next_poll_ms(current_poll_ms);
                    unchanged_polls = 0;
                }
                sleep(Duration::from_millis(current_poll_ms)).await;
                continue;
            }
            last_activity_fingerprint = activity_fingerprint;
            last_debug_fingerprint = debug_fingerprint;

            if activity_changed {
                match read_terminal_activity_hook_chunk(&activity_events_path, offset).await {
                    Ok((next_offset, chunk)) => {
                        if next_offset < offset {
                            partial.clear();
                        }
                        offset = next_offset;
                        if !chunk.is_empty() {
                            partial.push_str(&chunk);
                            let has_complete_tail = partial.ends_with('\n');
                            let mut lines = partial.lines().map(str::to_string).collect::<Vec<_>>();
                            partial = if has_complete_tail {
                                String::new()
                            } else {
                                lines.pop().unwrap_or_default()
                            };

                            for line in lines {
                                let line = line.trim();
                                if line.is_empty() {
                                    continue;
                                }
                                let Ok(event) = serde_json::from_str::<Value>(line) else {
                                    continue;
                                };
                                if terminal_activity_hook_event_was_transport_delivered(&event) {
                                    continue;
                                }
                                process_terminal_activity_hook_event(
                                    &app,
                                    &terminals,
                                    &cloud_mcp_state,
                                    &pane_id,
                                    instance_id,
                                    &instance,
                                    &event,
                                    "jsonl",
                                )
                                .await;
                            }
                        }
                    }
                    Err(error) => {
                        if activity_events_path.exists() {
                            log_terminal_status_event(
                                "backend.terminal_activity_hook.read_error",
                                json!({
                                    "error": clean_terminal_diagnostic_log_text(&error),
                                    "instance_id": instance_id,
                                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                                }),
                            );
                        }
                    }
                }
            }

            if debug_changed {
                match read_terminal_activity_hook_chunk(&activity_debug_path, debug_offset).await {
                    Ok((next_offset, chunk)) => {
                        if next_offset < debug_offset {
                            debug_partial.clear();
                        }
                        debug_offset = next_offset;
                        if !chunk.is_empty() {
                            debug_partial.push_str(&chunk);
                            let has_complete_tail = debug_partial.ends_with('\n');
                            let mut lines = debug_partial
                                .lines()
                                .map(str::to_string)
                                .collect::<Vec<_>>();
                            debug_partial = if has_complete_tail {
                                String::new()
                            } else {
                                lines.pop().unwrap_or_default()
                            };

                            for line in lines {
                                let line = line.trim();
                                if line.is_empty() {
                                    continue;
                                }
                                let Ok(event) = serde_json::from_str::<Value>(line) else {
                                    continue;
                                };
                                log_terminal_status_event(
                                    "backend.terminal_activity_hook.debug",
                                    json!({
                                        "activity_path": event.get("activity_path").and_then(Value::as_str).unwrap_or_default(),
                                        "debug_phase": event.get("phase").and_then(Value::as_str).unwrap_or_default(),
                                        "details": event.get("details").cloned().unwrap_or(Value::Null),
                                        "hook_instance_id": event.get("instance_id").and_then(Value::as_u64).unwrap_or_default(),
                                        "hook_pane_id": clean_terminal_diagnostic_log_text(event.get("pane_id").and_then(Value::as_str).unwrap_or_default()),
                                        "hook_provider": event.get("provider").and_then(Value::as_str).unwrap_or_default(),
                                        "instance_id": instance_id,
                                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                                        "terminal_index": event.get("terminal_index").and_then(Value::as_str).unwrap_or_default(),
                                        "workspace_id": event.get("workspace_id").and_then(Value::as_str).unwrap_or_default(),
                                    }),
                                );
                            }
                        }
                    }
                    Err(error) => {
                        if activity_debug_path.exists() {
                            log_terminal_status_event(
                                "backend.terminal_activity_hook.debug_read_error",
                                json!({
                                    "error": clean_terminal_diagnostic_log_text(&error),
                                    "instance_id": instance_id,
                                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                                }),
                            );
                        }
                    }
                }
            }

            sleep(Duration::from_millis(current_poll_ms)).await;
        }
        log_terminal_status_event(
            "backend.terminal_activity_hook.watcher_stopped",
            json!({
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "poll_ms": poll_ms,
            }),
        );
        terminal_codex_hook_trust_discovery_clear(&pane_id, instance_id);
        let state = app.state::<TerminalState>();
        if let Ok(mut tokens) = state.terminal_activity_transport_tokens.lock() {
            tokens.remove(&terminal_output_transport_key(&pane_id, instance_id));
        };
        let removed_interaction_ids = state
            .terminal_structured_interactions
            .lock()
            .ok()
            .map(|mut interactions| {
                let removed = interactions
                    .iter()
                    .filter_map(|(id, interaction)| {
                        (interaction.pane_id == pane_id && interaction.instance_id == instance_id)
                            .then(|| id.clone())
                    })
                    .collect::<Vec<_>>();
                interactions.retain(|_, interaction| {
                    interaction.pane_id != pane_id || interaction.instance_id != instance_id
                });
                removed
            })
            .unwrap_or_default();
        if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
            for interaction_id in removed_interaction_ids {
                waiters.remove(&interaction_id);
            }
        };
        terminal_structured_interaction_clear_superseded(&pane_id, instance_id);
    });
}

fn terminal_activity_hook_event_was_transport_delivered(event: &Value) -> bool {
    event
        .get("_diffforge_transport_delivered")
        .and_then(Value::as_bool)
        .unwrap_or(false)
}

fn terminal_prompt_submitted_source_is_authoritative(
    prompt_source: &str,
    prompt_match: bool,
    observed_prompt: Option<&str>,
) -> bool {
    if !prompt_match {
        return false;
    }

    match prompt_source {
        "activity_hook_user_prompt_submit" | "cli_hook_user_prompt_submit" => true,
        "observed_input_gate" => observed_prompt
            .map(str::trim)
            .is_some_and(|value| !value.is_empty()),
        "parked_resume_backend_submit"
        | "crash_todo_resume_backend_submit"
        | "todo_queue_backend_submit" => true,
        _ => false,
    }
}

fn terminal_prompt_event_source_allows_empty_gate_metadata_diagnostic(
    prompt_event_source: Option<&str>,
) -> bool {
    let source = prompt_event_source
        .unwrap_or_default()
        .trim()
        .to_ascii_lowercase()
        .replace('_', "-");

    matches!(
        source.as_str(),
        "tui-terminal-direct-input"
            | "terminal-direct-input"
            | "tui-manual-input"
            | "observed-terminal-prompt"
            | "terminal-prompt-submitted"
            | "terminal-view-drop"
            | "todo-auto-queue"
            | "voice-agent-queue"
            | "voice-plan-queue"
            | "remote-control"
    ) || source.starts_with("tui-manual-input:")
}

fn terminal_input_queue_key(pane_id: &str, instance_id: Option<u64>) -> String {
    format!("{pane_id}:{}", instance_id.unwrap_or_default())
}

fn spawn_terminal_input_queue_worker(
    app: AppHandle,
    queue_key: String,
    queue_id: u64,
    mut receiver: mpsc::Receiver<TerminalInputQueueItem>,
) {
    tauri::async_runtime::spawn(async move {
        loop {
            let item = match timeout(
                Duration::from_secs(TERMINAL_INPUT_QUEUE_IDLE_SECS),
                receiver.recv(),
            )
            .await
            {
                Ok(Some(payload)) => payload,
                Ok(None) | Err(_) => break,
            };

            let TerminalInputQueueItem { payload, ack } = item;
            let pane_id = payload.pane_id.clone();
            let instance_id = payload.instance_id;
            let state = app.state::<TerminalState>();
            let cloud_mcp_state = app.state::<CloudMcpState>();
            let write_result = terminal_write_inner(
                app.clone(),
                state.inner(),
                cloud_mcp_state.inner(),
                payload.pane_id,
                payload.instance_id,
                payload.data,
                payload.prompt_event_id,
                payload.prompt_event_revision,
                payload.prompt_event_source,
                payload.prompt_event_submitted_at,
                payload.prompt_event_text,
                payload.todo_id,
                payload.todo_dispatch_id,
                payload.todo_command_id,
                payload.todo_action,
                payload.todo_resume_requested,
                payload.thread_id,
                payload.app_fork_enabled,
                None,
                true,
                true,
            )
            .await;

            match write_result {
                Ok(()) => {
                    if let Some(ack) = ack {
                        let _ = ack.send(Ok(()));
                    }
                }
                Err(error) => {
                    emit_terminal_input_error(&app, pane_id, instance_id, error.clone());
                    if let Some(ack) = ack {
                        let _ = ack.send(Err(error));
                    }
                }
            }
        }

        let state = app.state::<TerminalState>();
        if let Ok(mut queues) = state.terminal_input_queues.lock() {
            if queues
                .get(&queue_key)
                .is_some_and(|handle| handle.id == queue_id)
            {
                queues.remove(&queue_key);
            }
        };
    });
}

fn enqueue_terminal_input_event(app: &AppHandle, payload: TerminalInputEventPayload) {
    enqueue_terminal_input_queue_item(app, payload, None);
}

fn enqueue_terminal_input_event_with_ack(
    app: &AppHandle,
    payload: TerminalInputEventPayload,
) -> oneshot::Receiver<Result<(), String>> {
    let (ack_sender, ack_receiver) = oneshot::channel();
    enqueue_terminal_input_queue_item(app, payload, Some(ack_sender));
    ack_receiver
}

fn send_terminal_input_queue_ack(
    ack: Option<oneshot::Sender<Result<(), String>>>,
    result: Result<(), String>,
) {
    if let Some(ack) = ack {
        let _ = ack.send(result);
    }
}

fn enqueue_terminal_input_queue_item(
    app: &AppHandle,
    payload: TerminalInputEventPayload,
    ack: Option<oneshot::Sender<Result<(), String>>>,
) {
    let pane_id = payload.pane_id.clone();
    let instance_id = payload.instance_id;

    if let Err(error) = validate_terminal_pane_id(&pane_id) {
        emit_terminal_input_error(app, pane_id, instance_id, error.clone());
        send_terminal_input_queue_ack(ack, Err(error));
        return;
    }

    if payload.data.len() > MAX_TERMINAL_WRITE_BYTES {
        let error = "Terminal input chunk is too large.".to_string();
        emit_terminal_input_error(app, pane_id, instance_id, error.clone());
        send_terminal_input_queue_ack(ack, Err(error));
        return;
    }

    let state = app.state::<TerminalState>();
    let queue_key = terminal_input_queue_key(&payload.pane_id, payload.instance_id);
    let mut item = TerminalInputQueueItem { payload, ack };

    loop {
        let handle = match state.terminal_input_queues.lock() {
            Ok(mut queues) => {
                if let Some(handle) = queues.get(&queue_key).cloned() {
                    handle
                } else {
                    let (sender, receiver) = mpsc::channel(TERMINAL_INPUT_QUEUE_CAPACITY);
                    let handle = TerminalInputQueueHandle {
                        id: state
                            .next_terminal_input_queue_id
                            .fetch_add(1, Ordering::AcqRel),
                        sender,
                    };
                    queues.insert(queue_key.clone(), handle.clone());
                    spawn_terminal_input_queue_worker(
                        app.clone(),
                        queue_key.clone(),
                        handle.id,
                        receiver,
                    );
                    handle
                }
            }
            Err(_) => {
                let error = "Unable to queue terminal input.".to_string();
                emit_terminal_input_error(app, pane_id, instance_id, error.clone());
                send_terminal_input_queue_ack(item.ack, Err(error));
                return;
            }
        };

        match handle.sender.try_send(item) {
            Ok(()) => return,
            Err(mpsc::error::TrySendError::Full(returned_item)) => {
                let error = "Terminal input queue is full.".to_string();
                emit_terminal_input_error(app, pane_id, instance_id, error.clone());
                send_terminal_input_queue_ack(returned_item.ack, Err(error));
                return;
            }
            Err(mpsc::error::TrySendError::Closed(returned_item)) => {
                if let Ok(mut queues) = state.terminal_input_queues.lock() {
                    if queues
                        .get(&queue_key)
                        .is_some_and(|current| current.id == handle.id)
                    {
                        queues.remove(&queue_key);
                    }
                }
                item = returned_item;
            }
        }
    }
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_input_transport_endpoint(
    app: AppHandle,
    state: State<'_, TerminalState>,
) -> Result<TerminalInputTransportEndpoint, String> {
    if let Ok(transport) = state.terminal_input_transport.lock() {
        if let Some(endpoint) = transport.clone() {
            return Ok(endpoint);
        }
    } else {
        return Err("Unable to read terminal input transport.".to_string());
    }

    let listener = TcpListener::bind(("127.0.0.1", 0))
        .await
        .map_err(|error| format!("Unable to start terminal input transport: {error}"))?;
    let port = listener
        .local_addr()
        .map_err(|error| format!("Unable to read terminal input transport address: {error}"))?
        .port();
    let endpoint = TerminalInputTransportEndpoint {
        url: format!("ws://127.0.0.1:{port}/terminal-input"),
        token: uuid::Uuid::new_v4().to_string(),
    };

    {
        let mut transport = state
            .terminal_input_transport
            .lock()
            .map_err(|_| "Unable to save terminal input transport.".to_string())?;
        if let Some(existing) = transport.clone() {
            return Ok(existing);
        }
        *transport = Some(endpoint.clone());
    }

    spawn_terminal_input_transport_listener(app, listener, endpoint.token.clone());
    Ok(endpoint)
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_output_transport_endpoint(
    app: AppHandle,
    state: State<'_, TerminalState>,
) -> Result<TerminalOutputTransportEndpoint, String> {
    if let Ok(transport) = state.terminal_output_transport.lock() {
        if let Some(endpoint) = transport.clone() {
            return Ok(endpoint);
        }
    } else {
        return Err("Unable to read terminal output transport.".to_string());
    }

    let listener = TcpListener::bind(("127.0.0.1", 0))
        .await
        .map_err(|error| format!("Unable to start terminal output transport: {error}"))?;
    let port = listener
        .local_addr()
        .map_err(|error| format!("Unable to read terminal output transport address: {error}"))?
        .port();
    let endpoint = TerminalOutputTransportEndpoint {
        url: format!("ws://127.0.0.1:{port}/terminal-output"),
        token: uuid::Uuid::new_v4().to_string(),
    };

    {
        let mut transport = state
            .terminal_output_transport
            .lock()
            .map_err(|_| "Unable to save terminal output transport.".to_string())?;
        if let Some(existing) = transport.clone() {
            return Ok(existing);
        }
        *transport = Some(endpoint.clone());
    }

    spawn_terminal_output_transport_listener(app, listener, endpoint.token.clone());
    Ok(endpoint)
}

async fn terminal_activity_transport_endpoint_for_state(
    app: AppHandle,
    state: &TerminalState,
) -> Result<TerminalActivityTransportEndpoint, String> {
    if let Ok(transport) = state.terminal_activity_transport.lock() {
        if let Some(endpoint) = transport.clone() {
            return Ok(endpoint);
        }
    } else {
        return Err("Unable to read terminal activity transport.".to_string());
    }

    let listener = TcpListener::bind(("127.0.0.1", 0))
        .await
        .map_err(|error| format!("Unable to start terminal activity transport: {error}"))?;
    let port = listener
        .local_addr()
        .map_err(|error| format!("Unable to read terminal activity transport address: {error}"))?
        .port();
    let endpoint = TerminalActivityTransportEndpoint {
        host: "127.0.0.1".to_string(),
        port,
        token: uuid::Uuid::new_v4().to_string(),
    };

    {
        let mut transport = state
            .terminal_activity_transport
            .lock()
            .map_err(|_| "Unable to save terminal activity transport.".to_string())?;
        if let Some(existing) = transport.clone() {
            return Ok(existing);
        }
        *transport = Some(endpoint.clone());
    }

    spawn_terminal_activity_transport_listener(app, listener);
    Ok(endpoint)
}

async fn terminal_activity_transport_for_terminal(
    app: AppHandle,
    state: &TerminalState,
    pane_id: &str,
    instance_id: u64,
) -> Result<TerminalActivityTransportEndpoint, String> {
    let endpoint = terminal_activity_transport_endpoint_for_state(app, state).await?;
    let token = terminal_activity_transport_token_for_terminal(state, pane_id, instance_id)?;
    Ok(TerminalActivityTransportEndpoint {
        host: endpoint.host,
        port: endpoint.port,
        token,
    })
}

fn terminal_activity_transport_token_for_terminal(
    state: &TerminalState,
    pane_id: &str,
    instance_id: u64,
) -> Result<String, String> {
    let key = terminal_output_transport_key(pane_id, instance_id);
    let mut tokens = state
        .terminal_activity_transport_tokens
        .lock()
        .map_err(|_| "Unable to save terminal activity transport token.".to_string())?;
    Ok(tokens
        .entry(key)
        .or_insert_with(|| uuid::Uuid::new_v4().to_string())
        .clone())
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum TerminalCodexGatewayWinner {
    NativeTui,
    Web,
}

#[derive(Clone, Debug)]
struct TerminalCodexGatewayPendingRequest {
    request_id: Value,
    method: String,
    interaction_id: String,
    interaction_revision: u64,
    winner: Option<TerminalCodexGatewayWinner>,
}

#[derive(Default)]
struct TerminalCodexGatewayPendingRequests {
    by_request_id: HashMap<String, VecDeque<TerminalCodexGatewayPendingRequest>>,
    ambiguous_request_ids: HashSet<String>,
}

const TERMINAL_CODEX_GATEWAY_PENDING_PER_REQUEST_ID_MAX: usize = 16;
const TERMINAL_CODEX_GATEWAY_PENDING_TOTAL_MAX: usize = 256;

static TERMINAL_CODEX_GATEWAY_INTERACTION_REVISION: AtomicU64 = AtomicU64::new(0);

fn terminal_codex_gateway_next_interaction_revision() -> u64 {
    let now_ms = terminal_now_ms();
    let mut current = TERMINAL_CODEX_GATEWAY_INTERACTION_REVISION.load(Ordering::SeqCst);
    loop {
        let next = now_ms.max(current.saturating_add(1));
        match TERMINAL_CODEX_GATEWAY_INTERACTION_REVISION.compare_exchange(
            current,
            next,
            Ordering::SeqCst,
            Ordering::SeqCst,
        ) {
            Ok(_) => return next,
            Err(observed) => current = observed,
        }
    }
}

#[derive(Clone, Debug)]
struct TerminalCodexGatewayClientRequest {
    method: String,
    message: Value,
    sequence: u64,
}

#[derive(Clone, Debug)]
struct TerminalCodexGatewayActiveTurn {
    thread_id: Option<String>,
    turn_id: Option<String>,
}

fn terminal_codex_app_server_request_id_key(value: &Value) -> Option<String> {
    match value {
        Value::String(value) if !value.trim().is_empty() => {
            Some(format!("string:{}", value.trim()))
        }
        Value::Number(value) => Some(format!("number:{value}")),
        _ => None,
    }
}

fn terminal_codex_app_server_request_id_text(value: &Value) -> String {
    match value {
        Value::String(value) => value.trim().to_string(),
        Value::Number(value) => value.to_string(),
        _ => value.to_string(),
    }
}

fn terminal_codex_gateway_track_client_request(
    requests: &mut HashMap<String, TerminalCodexGatewayClientRequest>,
    next_sequence: &mut u64,
    message: &Value,
) {
    if let (Some(request_key), Some(method)) = (
        message
            .get("id")
            .and_then(terminal_codex_app_server_request_id_key),
        message.get("method").and_then(Value::as_str),
    ) {
        let sequence = *next_sequence;
        *next_sequence = next_sequence.saturating_add(1);
        requests.insert(
            request_key,
            TerminalCodexGatewayClientRequest {
                method: method.to_string(),
                message: message.clone(),
                sequence,
            },
        );
    }
}

fn terminal_codex_gateway_take_client_response_method(
    requests: &mut HashMap<String, TerminalCodexGatewayClientRequest>,
    message: &Value,
) -> Option<String> {
    message
        .get("id")
        .and_then(terminal_codex_app_server_request_id_key)
        .and_then(|request_key| requests.remove(&request_key))
        .map(|request| request.method)
}

fn terminal_codex_gateway_outstanding_requests(
    requests: &HashMap<String, TerminalCodexGatewayClientRequest>,
) -> Vec<Value> {
    let mut requests = requests.values().collect::<Vec<_>>();
    requests.sort_by_key(|request| request.sequence);
    requests
        .into_iter()
        .map(|request| request.message.clone())
        .collect()
}

fn terminal_codex_gateway_active_turn(request: &Value) -> TerminalCodexGatewayActiveTurn {
    TerminalCodexGatewayActiveTurn {
        thread_id: request
            .pointer("/params/threadId")
            .or_else(|| request.pointer("/params/thread_id"))
            .and_then(Value::as_str)
            .map(str::to_string),
        turn_id: None,
    }
}

fn terminal_codex_gateway_observe_turn_started(
    active_turn: &mut Option<TerminalCodexGatewayActiveTurn>,
    value: &Value,
) {
    if value.get("method").and_then(Value::as_str) != Some("turn/started") {
        return;
    }
    let Some(active_turn) = active_turn.as_mut() else {
        return;
    };
    if let Some(thread_id) = value.pointer("/params/threadId").and_then(Value::as_str) {
        active_turn.thread_id = Some(thread_id.to_string());
    }
    if let Some(turn_id) = value.pointer("/params/turn/id").and_then(Value::as_str) {
        active_turn.turn_id = Some(turn_id.to_string());
    }
}

fn terminal_codex_gateway_clear_completed_turn(
    active_turn: &mut Option<TerminalCodexGatewayActiveTurn>,
    value: &Value,
) {
    if terminal_codex_turn_completed(value) {
        *active_turn = None;
    }
}

fn terminal_codex_gateway_record_replacement_started(
    connected_generation: &mut u64,
    replacement_generation: u64,
) {
    *connected_generation = replacement_generation;
}

fn terminal_codex_app_server_uir_method(method: &str) -> bool {
    matches!(
        method,
        "item/commandExecution/requestApproval"
            | "item/fileChange/requestApproval"
            | "item/tool/requestUserInput"
            | "item/permissions/requestApproval"
            | "mcpServer/elicitation/request"
            | "execCommandApproval"
            | "applyPatchApproval"
    )
}

fn terminal_codex_app_server_option(
    id: &str,
    label: &str,
    description: Option<&str>,
    value: Value,
    danger: bool,
) -> Value {
    json!({
        "id": id,
        "label": label,
        "description": description,
        "value": if value.is_string() {
            value
        } else {
            Value::String(value.to_string())
        },
        "danger": danger,
    })
}

fn terminal_codex_app_server_decision_option(decision: &Value) -> Option<Value> {
    let decision_key = decision
        .as_str()
        .map(str::to_string)
        .or_else(|| {
            decision
                .as_object()
                .and_then(|object| object.keys().next().cloned())
        })
        .unwrap_or_else(|| decision.to_string());
    let normalized = terminal_activity_hook_name_key(&decision_key);
    let (id, label, description, danger) = match normalized.as_str() {
        "accept" | "approved" => ("allow_once", "Allow once", None, false),
        "acceptforsession" | "approvedforsession" => (
            "allow_always",
            "Allow for this session",
            Some("Persist this approval for the current Codex session."),
            false,
        ),
        "decline" | "denied" => ("reject", "Reject", None, true),
        "cancel" | "abort" | "timedout" => ("cancel", "Cancel", None, true),
        "acceptwithexecpolicyamendment" | "approvedexecpolicyamendment" => (
            "allow_rule",
            "Allow and remember command rule",
            Some("Apply Codex's proposed command-policy amendment."),
            false,
        ),
        "applynetworkpolicyamendment" | "networkpolicyamendment" => (
            "allow_network_rule",
            "Allow and remember network rule",
            Some("Apply Codex's proposed network-policy amendment."),
            false,
        ),
        _ => return None,
    };
    Some(terminal_codex_app_server_option(
        id,
        label,
        description,
        decision.clone(),
        danger,
    ))
}

fn terminal_codex_app_server_approval_options(method: &str, params: &Value) -> Vec<Value> {
    let decisions = if method == "item/commandExecution/requestApproval" {
        params
            .get("availableDecisions")
            .and_then(Value::as_array)
            .cloned()
            .filter(|values| !values.is_empty())
            .unwrap_or_else(|| {
                vec![
                    json!("accept"),
                    json!("acceptForSession"),
                    json!("decline"),
                    json!("cancel"),
                ]
            })
    } else if method == "item/fileChange/requestApproval" {
        vec![
            json!("accept"),
            json!("acceptForSession"),
            json!("decline"),
            json!("cancel"),
        ]
    } else {
        vec![
            json!("approved"),
            json!("approved_for_session"),
            json!("denied"),
            json!("abort"),
        ]
    };
    decisions
        .iter()
        .filter_map(terminal_codex_app_server_decision_option)
        .collect()
}

fn terminal_codex_app_server_prompt_message(method: &str, params: &Value) -> String {
    let reason = params
        .get("reason")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty());
    match method {
        "item/commandExecution/requestApproval" => {
            if let Some(network) = params
                .get("networkApprovalContext")
                .and_then(Value::as_object)
            {
                let host = network
                    .get("host")
                    .and_then(Value::as_str)
                    .unwrap_or("this destination");
                let protocol = network
                    .get("protocol")
                    .and_then(Value::as_str)
                    .unwrap_or("network");
                format!("Codex requests {protocol} access to {host}.")
            } else {
                let command = params
                    .get("command")
                    .and_then(Value::as_str)
                    .unwrap_or("the requested command");
                reason
                    .map(|reason| format!("{reason}\n\n{command}"))
                    .unwrap_or_else(|| format!("Allow Codex to run this command?\n\n{command}"))
            }
        }
        "execCommandApproval" => {
            let command = params
                .get("command")
                .and_then(Value::as_array)
                .map(|parts| {
                    parts
                        .iter()
                        .filter_map(Value::as_str)
                        .collect::<Vec<_>>()
                        .join(" ")
                })
                .filter(|value| !value.is_empty())
                .unwrap_or_else(|| "the requested command".to_string());
            reason
                .map(|reason| format!("{reason}\n\n{command}"))
                .unwrap_or_else(|| format!("Allow Codex to run this command?\n\n{command}"))
        }
        "item/fileChange/requestApproval" | "applyPatchApproval" => reason
            .map(str::to_string)
            .unwrap_or_else(|| "Allow Codex to apply the proposed file changes?".to_string()),
        "item/permissions/requestApproval" => reason
            .map(str::to_string)
            .unwrap_or_else(|| "Codex requests additional sandbox permissions.".to_string()),
        "mcpServer/elicitation/request" => params
            .get("message")
            .and_then(Value::as_str)
            .unwrap_or("An MCP server needs your input.")
            .to_string(),
        "item/tool/requestUserInput" => params
            .get("questions")
            .and_then(Value::as_array)
            .and_then(|questions| questions.first())
            .and_then(|question| question.get("question"))
            .and_then(Value::as_str)
            .unwrap_or("Codex needs your input to continue.")
            .to_string(),
        _ => "Codex needs your input to continue.".to_string(),
    }
}

fn terminal_codex_app_server_request_event(
    pane_id: &str,
    instance_id: u64,
    request: &Value,
) -> Option<Value> {
    let method = request.get("method")?.as_str()?.trim();
    if !terminal_codex_app_server_uir_method(method) {
        return None;
    }
    let request_id = request.get("id")?;
    let request_id_text = terminal_codex_app_server_request_id_text(request_id);
    if request_id_text.is_empty() {
        return None;
    }
    let params = request.get("params").cloned().unwrap_or_else(|| json!({}));
    let thread_id = params
        .get("threadId")
        .or_else(|| params.get("conversationId"))
        .and_then(Value::as_str)
        .unwrap_or_default();
    let turn_id = params
        .get("turnId")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let prompt_kind = if method == "item/tool/requestUserInput" {
        "question"
    } else if method == "mcpServer/elicitation/request" {
        if params.get("url").is_some() {
            "selection"
        } else {
            "input"
        }
    } else {
        "permission"
    };
    let hook_event_name = if method == "item/tool/requestUserInput" {
        "UserInputRequired"
    } else if method == "mcpServer/elicitation/request" {
        "Elicitation"
    } else {
        "PermissionRequest"
    };
    let prompt_options = match method {
        "item/commandExecution/requestApproval"
        | "item/fileChange/requestApproval"
        | "execCommandApproval"
        | "applyPatchApproval" => terminal_codex_app_server_approval_options(method, &params),
        "item/permissions/requestApproval" => vec![
            terminal_codex_app_server_option(
                "allow_once",
                "Allow for this turn",
                None,
                json!("turn"),
                false,
            ),
            terminal_codex_app_server_option(
                "allow_always",
                "Allow for this session",
                Some("Persist the granted subset for later turns in this Codex session."),
                json!("session"),
                false,
            ),
            terminal_codex_app_server_option(
                "reject",
                "Reject",
                Some("Grant none of the requested permissions."),
                json!("reject"),
                true,
            ),
        ],
        "mcpServer/elicitation/request" if params.get("url").is_some() => vec![
            terminal_codex_app_server_option("continue", "Continue", None, json!("accept"), false),
            terminal_codex_app_server_option("reject", "Decline", None, json!("decline"), true),
            terminal_codex_app_server_option("cancel", "Cancel", None, json!("cancel"), true),
        ],
        _ => Vec::new(),
    };
    let prompt_questions = if method == "item/tool/requestUserInput" {
        params.get("questions").cloned().map(|questions| {
            Value::Array(
                questions
                    .as_array()
                    .cloned()
                    .unwrap_or_default()
                    .into_iter()
                    .map(|mut question| {
                        if let Some(object) = question.as_object_mut() {
                            let custom = object
                                .get("isOther")
                                .and_then(Value::as_bool)
                                .unwrap_or(false);
                            object.insert("custom".to_string(), json!(custom));
                            object.insert("multiple".to_string(), json!(false));
                        }
                        question
                    })
                    .collect(),
            )
        })
    } else {
        None
    };
    let prompt_schema = if method == "mcpServer/elicitation/request" {
        params.get("requestedSchema").cloned()
    } else {
        None
    };
    let prompt_url = if method == "mcpServer/elicitation/request" {
        params.get("url").cloned()
    } else {
        None
    };
    let prompt_ttl_ms = params.get("autoResolutionMs").cloned();
    let message = terminal_codex_app_server_prompt_message(method, &params);
    let observed_at_ms = terminal_codex_gateway_next_interaction_revision();
    let interaction_id = format!(
        "uir:codex:{pane_id}:{instance_id}:{}:{request_id_text}",
        if thread_id.is_empty() {
            "session"
        } else {
            thread_id
        },
    );
    Some(json!({
        "hook_event_name": hook_event_name,
        "provider": "codex",
        "pane_id": pane_id,
        "instance_id": instance_id,
        "session_id": thread_id,
        "turn_id": turn_id,
        "permission_request_id": request_id_text,
        "prompt_id": request_id_text,
        "prompt_kind": prompt_kind,
        "prompting_user_text": message,
        "message": message,
        "prompt_options": prompt_options,
        "prompt_questions": prompt_questions,
        "prompt_schema": prompt_schema,
        "prompt_url": prompt_url,
        "prompt_ttl_ms": prompt_ttl_ms,
        "allows_free_text": method == "item/tool/requestUserInput"
            || (method == "mcpServer/elicitation/request" && params.get("url").is_none()),
        "manual_approval_required": true,
        "provider_blocked_for_user": true,
        "terminal_is_prompting_user": true,
        "interaction_id": interaction_id,
        "interaction_revision": observed_at_ms,
        "interaction_response_mode": "codex_app_server",
        "provider_payload": {
            "app_server_method": method,
            "provider_request": params,
            "request_id": request_id,
        },
        "timestamp_ms": observed_at_ms,
        "source": "codex_app_server",
    }))
}

fn terminal_codex_gateway_register_server_request(
    pending: &Arc<StdMutex<TerminalCodexGatewayPendingRequests>>,
    pane_id: &str,
    instance_id: u64,
    request: &Value,
) -> Option<Value> {
    let event = terminal_codex_app_server_request_event(pane_id, instance_id, request)?;
    let request_key = request
        .get("id")
        .and_then(terminal_codex_app_server_request_id_key)?;
    let request_id = request.get("id")?.clone();
    let method = request.get("method")?.as_str()?.to_string();
    let interaction_id = event.get("interaction_id")?.as_str()?.to_string();
    let interaction_revision = event.get("interaction_revision")?.as_u64()?;
    let mut pending = pending.lock().ok()?;
    let total_pending = pending
        .by_request_id
        .values()
        .map(VecDeque::len)
        .sum::<usize>();
    let queue_len = pending
        .by_request_id
        .get(&request_key)
        .map(VecDeque::len)
        .unwrap_or_default();
    if total_pending >= TERMINAL_CODEX_GATEWAY_PENDING_TOTAL_MAX
        || queue_len >= TERMINAL_CODEX_GATEWAY_PENDING_PER_REQUEST_ID_MAX
    {
        return None;
    }
    if queue_len > 0 {
        pending.ambiguous_request_ids.insert(request_key.clone());
    }
    pending
        .by_request_id
        .entry(request_key)
        .or_default()
        .push_back(TerminalCodexGatewayPendingRequest {
            request_id,
            method,
            interaction_id,
            interaction_revision,
            winner: None,
        });
    Some(event)
}

fn terminal_codex_app_server_parse_option_value(
    option_id: &str,
    option_value: Option<&str>,
) -> Value {
    option_value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .and_then(|value| serde_json::from_str::<Value>(value).ok())
        .unwrap_or_else(
            || match terminal_activity_hook_name_key(option_id).as_str() {
                "allowalways" => json!("acceptForSession"),
                "reject" | "deny" | "decline" => json!("decline"),
                "cancel" => json!("cancel"),
                _ => json!("accept"),
            },
        )
}

fn terminal_codex_app_server_interaction_response(
    interaction: &TerminalStructuredInteraction,
    option_id: &str,
    option_value: Option<&str>,
    answer_text: Option<&str>,
    answer_payload: Option<&Value>,
) -> Value {
    let payload = interaction
        .provider_payload
        .as_ref()
        .unwrap_or(&Value::Null);
    let method = payload
        .get("app_server_method")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let params = payload.get("provider_request").unwrap_or(&Value::Null);
    let option_key = terminal_activity_hook_name_key(option_id);
    match method {
        "item/commandExecution/requestApproval" | "item/fileChange/requestApproval" => json!({
            "decision": terminal_codex_app_server_parse_option_value(option_id, option_value),
        }),
        "execCommandApproval" | "applyPatchApproval" => {
            let mut decision =
                terminal_codex_app_server_parse_option_value(option_id, option_value);
            if let Some(value) = decision.as_str() {
                decision = json!(match value {
                    "accept" => "approved",
                    "acceptForSession" => "approved_for_session",
                    "decline" => "denied",
                    "cancel" => "abort",
                    other => other,
                });
            }
            json!({ "decision": decision })
        }
        "item/permissions/requestApproval" => {
            let denied = matches!(
                option_key.as_str(),
                "reject" | "deny" | "decline" | "cancel"
            );
            let mut permissions = serde_json::Map::new();
            if !denied {
                if let Some(network) = params.pointer("/permissions/network") {
                    if !network.is_null() {
                        permissions.insert("network".to_string(), network.clone());
                    }
                }
                if let Some(file_system) = params.pointer("/permissions/fileSystem") {
                    if !file_system.is_null() {
                        permissions.insert("fileSystem".to_string(), file_system.clone());
                    }
                }
            }
            json!({
                "permissions": Value::Object(permissions),
                "scope": if !denied && option_key == "allowalways" { "session" } else { "turn" },
            })
        }
        "item/tool/requestUserInput" => {
            let ordered = answer_payload
                .and_then(|value| value.get("answers"))
                .and_then(Value::as_array)
                .cloned()
                .unwrap_or_default();
            let mut answers = serde_json::Map::new();
            for (index, question) in params
                .get("questions")
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
                .enumerate()
            {
                let Some(id) = question.get("id").and_then(Value::as_str) else {
                    continue;
                };
                let values = if matches!(option_key.as_str(), "reject" | "deny" | "cancel") {
                    Vec::new()
                } else {
                    ordered
                        .get(index)
                        .and_then(Value::as_array)
                        .cloned()
                        .unwrap_or_else(|| {
                            answer_text
                                .or(option_value)
                                .map(|value| vec![json!(value)])
                                .unwrap_or_default()
                        })
                };
                answers.insert(id.to_string(), json!({ "answers": values }));
            }
            json!({ "answers": answers })
        }
        "mcpServer/elicitation/request" => {
            let action = if matches!(option_key.as_str(), "reject" | "deny" | "decline") {
                "decline"
            } else if option_key == "cancel" {
                "cancel"
            } else {
                "accept"
            };
            let url_mode = params.get("mode").and_then(Value::as_str) == Some("url");
            let content = if action == "accept" && !url_mode {
                answer_payload
                    .and_then(|value| value.get("content"))
                    .cloned()
                    .or_else(|| answer_payload.cloned())
                    .or_else(|| {
                        answer_text.or(option_value).map(|value| {
                            serde_json::from_str(value)
                                .unwrap_or_else(|_| json!({ "answer": value }))
                        })
                    })
                    .unwrap_or_else(|| json!({}))
            } else {
                Value::Null
            };
            json!({ "action": action, "content": content, "_meta": Value::Null })
        }
        _ => json!({}),
    }
}

fn terminal_codex_app_server_enable_tui_capabilities(message: &mut Value) {
    if message.get("method").and_then(Value::as_str) != Some("initialize") {
        return;
    }
    let Some(object) = message.as_object_mut() else {
        return;
    };
    let params = object.entry("params").or_insert_with(|| json!({}));
    let Some(params) = params.as_object_mut() else {
        return;
    };
    let capabilities = params.entry("capabilities").or_insert_with(|| json!({}));
    if !capabilities.is_object() {
        *capabilities = json!({});
    }
    let Some(capabilities) = capabilities.as_object_mut() else {
        return;
    };
    capabilities.insert("experimentalApi".to_string(), json!(true));
    capabilities
        .entry("requestAttestation".to_string())
        .or_insert_with(|| json!(false));
    capabilities.insert("mcpServerOpenaiFormElicitation".to_string(), json!(true));
}

async fn terminal_codex_gateway_publish_startup_hook_review_resolved(
    app: AppHandle,
    pane_id: String,
    instance_id: u64,
    method: String,
) {
    let state = app.state::<TerminalState>();
    let cloud_mcp_state = app.state::<CloudMcpState>();
    let Some(instance) =
        terminal_activity_hook_current_instance(&state.terminals, &pane_id, instance_id).await
    else {
        return;
    };
    let interactions = state
        .terminal_structured_interactions
        .lock()
        .ok()
        .map(|interactions| {
            interactions
                .values()
                .filter(|interaction| {
                    interaction.pane_id == pane_id
                        && interaction.instance_id == instance_id
                        && terminal_codex_hook_trust_is_catalog_request(
                            &interaction.provider_request_id,
                        )
                })
                .cloned()
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let resolved_count = interactions.len();
    for interaction in interactions {
        terminal_structured_interaction_publish_answered(
            &app,
            state.inner(),
            cloud_mcp_state.inner(),
            &instance,
            &interaction,
            "native_tui",
            "codex-app-server-startup-hook-review-resolved",
        )
        .await;
    }
    log_terminal_status_event(
        "backend.codex_hook_trust.native_tui_resolved",
        json!({
            "instance_id": instance_id,
            "method": method,
            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
            "structured_interactions_resolved": resolved_count,
        }),
    );
}

async fn terminal_codex_hook_trust_withdraw_stale_publication(
    app: &AppHandle,
    cloud_mcp_state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    provider_request_id: &str,
    terminal_closed: bool,
    reason: &str,
) {
    // Publication and terminal cleanup are separate asynchronous paths. If
    // cleanup wins after publication cloned the terminal, remove only this
    // exact interaction and update the already-existing cloud row directly.
    // Never run a removed TerminalInstance through the normal activity path:
    // that would project it as thinking/running and could race after close.
    let state = app.state::<TerminalState>();
    let removed_ids = state
        .terminal_structured_interactions
        .lock()
        .ok()
        .map(|mut interactions| {
            let removed_ids = interactions
                .iter()
                .filter_map(|(id, interaction)| {
                    (interaction.pane_id == pane_id
                        && interaction.instance_id == instance_id
                        && interaction.provider_request_id == provider_request_id)
                        .then(|| id.clone())
                })
                .collect::<Vec<_>>();
            interactions.retain(|id, _| !removed_ids.contains(id));
            removed_ids
        })
        .unwrap_or_default();
    if !removed_ids.is_empty() {
        if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
            for interaction_id in &removed_ids {
                waiters.remove(interaction_id);
            }
        }
    }
    let cloud_changed = cloud_mcp_withdraw_stale_terminal_prompt(
        cloud_mcp_state,
        pane_id,
        instance_id,
        provider_request_id,
        terminal_closed,
        reason,
    )
    .await;
    log_terminal_status_event(
        "backend.codex_hook_trust.stale_publication_withdrawn",
        json!({
            "cloud_changed": cloud_changed,
            "instance_id": instance_id,
            "local_interactions_removed": removed_ids.len(),
            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
            "provider_request_id": provider_request_id,
            "reason": reason,
            "terminal_closed": terminal_closed,
        }),
    );
}

fn terminal_codex_gateway_claim(
    pending: &Arc<StdMutex<TerminalCodexGatewayPendingRequests>>,
    request_key: &str,
    response: &Value,
    winner: TerminalCodexGatewayWinner,
) -> Option<TerminalCodexGatewayPendingRequest> {
    let Ok(mut pending) = pending.lock() else {
        return None;
    };
    let queue_len = pending.by_request_id.get(request_key)?.len();
    let ambiguous = queue_len > 1;
    if ambiguous {
        pending
            .ambiguous_request_ids
            .insert(request_key.to_string());
    } else {
        pending.ambiguous_request_ids.remove(request_key);
    }
    let queue = pending.by_request_id.get_mut(request_key)?;
    let matching = queue
        .iter()
        .enumerate()
        .filter(|(_, request)| terminal_codex_gateway_response_matches_request(request, response))
        .map(|(index, _)| index)
        .collect::<Vec<_>>();
    let index = if matching.len() == 1 {
        matching[0]
    } else if !ambiguous && queue.len() == 1 && queue[0].winner.is_none() {
        0
    } else {
        return None;
    };
    let request = queue.get_mut(index)?;
    if request.winner.is_some() {
        return None;
    }
    request.winner = Some(winner);
    Some(request.clone())
}

fn terminal_codex_gateway_response_matches_request(
    request: &TerminalCodexGatewayPendingRequest,
    response: &Value,
) -> bool {
    let method_hint = response
        .pointer("/params/method")
        .or_else(|| response.pointer("/params/requestMethod"))
        .or_else(|| response.get("method"))
        .and_then(Value::as_str);
    if let Some(method_hint) = method_hint {
        return request.method == method_hint;
    }
    let result = response
        .get("result")
        .or_else(|| response.pointer("/params/result"))
        .or_else(|| response.pointer("/params/response"));
    let Some(result) = result else {
        return false;
    };
    match request.method.as_str() {
        "item/permissions/requestApproval" => {
            result.get("permissions").is_some() || result.get("scope").is_some()
        }
        "item/tool/requestUserInput" => result.get("answers").is_some(),
        "mcpServer/elicitation/request" => result.get("action").is_some(),
        "item/commandExecution/requestApproval"
        | "item/fileChange/requestApproval"
        | "execCommandApproval"
        | "applyPatchApproval" => result.get("decision").is_some(),
        _ => false,
    }
}

fn terminal_codex_gateway_claim_generation(
    pending: &Arc<StdMutex<TerminalCodexGatewayPendingRequests>>,
    request_key: &str,
    interaction_id: &str,
    interaction_revision: u64,
    winner: TerminalCodexGatewayWinner,
) -> Option<TerminalCodexGatewayPendingRequest> {
    let Ok(mut pending) = pending.lock() else {
        return None;
    };
    let request = pending
        .by_request_id
        .get_mut(request_key)?
        .iter_mut()
        .find(|request| {
            request.interaction_id == interaction_id
                && request.interaction_revision == interaction_revision
                && request.winner.is_none()
        })?;
    request.winner = Some(winner);
    Some(request.clone())
}

fn terminal_codex_gateway_take_resolved(
    pending: &Arc<StdMutex<TerminalCodexGatewayPendingRequests>>,
    request_key: &str,
    resolution: &Value,
) -> Option<TerminalCodexGatewayPendingRequest> {
    let Ok(mut pending) = pending.lock() else {
        return None;
    };
    let explicit_interaction_id = resolution
        .pointer("/params/interactionId")
        .or_else(|| resolution.pointer("/params/resolvedInteractionId"))
        .and_then(Value::as_str);
    let explicit_revision = resolution
        .pointer("/params/interactionRevision")
        .or_else(|| resolution.pointer("/params/resolvedInteractionRevision"))
        .and_then(Value::as_u64);
    let has_explicit_identity = explicit_interaction_id.is_some() || explicit_revision.is_some();
    let has_generation_hint = has_explicit_identity
        || resolution.pointer("/params/method").is_some()
        || resolution.pointer("/params/requestMethod").is_some()
        || resolution.get("result").is_some()
        || resolution.pointer("/params/result").is_some()
        || resolution.pointer("/params/response").is_some();
    let queue_len = pending.by_request_id.get(request_key)?.len();
    let ambiguous = queue_len > 1;
    if ambiguous {
        pending
            .ambiguous_request_ids
            .insert(request_key.to_string());
    } else {
        pending.ambiguous_request_ids.remove(request_key);
    }
    let (request, remaining) = {
        let queue = pending.by_request_id.get_mut(request_key)?;
        let matching = queue
            .iter()
            .enumerate()
            .filter(|(_, request)| {
                let explicit_match = match (explicit_interaction_id, explicit_revision) {
                    (Some(interaction_id), revision) => {
                        request.interaction_id == interaction_id
                            && revision
                                .is_none_or(|revision| request.interaction_revision == revision)
                    }
                    (None, Some(revision)) => request.interaction_revision == revision,
                    (None, None) => false,
                };
                if has_explicit_identity {
                    explicit_match
                } else {
                    terminal_codex_gateway_response_matches_request(request, resolution)
                }
            })
            .map(|(index, _)| index)
            .collect::<Vec<_>>();
        let index = if matching.len() == 1 {
            matching[0]
        } else if !ambiguous && queue.len() == 1 && !has_generation_hint {
            0
        } else {
            return None;
        };
        let request = queue.remove(index)?;
        (request, queue.len())
    };
    if remaining == 0 {
        pending.by_request_id.remove(request_key);
    }
    if remaining <= 1 {
        pending.ambiguous_request_ids.remove(request_key);
    }
    Some(request)
}

fn terminal_codex_gateway_remove_generation(
    pending: &Arc<StdMutex<TerminalCodexGatewayPendingRequests>>,
    request_key: &str,
    interaction_id: &str,
    interaction_revision: u64,
) -> bool {
    let Ok(mut pending) = pending.lock() else {
        return false;
    };
    let (removed, remaining) = {
        let Some(queue) = pending.by_request_id.get_mut(request_key) else {
            return false;
        };
        let before = queue.len();
        queue.retain(|request| {
            request.interaction_id != interaction_id
                || request.interaction_revision != interaction_revision
        });
        (queue.len() != before, queue.len())
    };
    if remaining == 0 {
        pending.by_request_id.remove(request_key);
    }
    if remaining <= 1 {
        pending.ambiguous_request_ids.remove(request_key);
    }
    removed
}

struct TerminalCodexGatewayPendingGenerationCleanup {
    pending: Arc<StdMutex<TerminalCodexGatewayPendingRequests>>,
    request_key: String,
    interaction_id: String,
    interaction_revision: u64,
}

impl Drop for TerminalCodexGatewayPendingGenerationCleanup {
    fn drop(&mut self) {
        terminal_codex_gateway_remove_generation(
            &self.pending,
            &self.request_key,
            &self.interaction_id,
            self.interaction_revision,
        );
    }
}

fn terminal_codex_gateway_response_already_won_by_web(
    pending: &Arc<StdMutex<TerminalCodexGatewayPendingRequests>>,
    request_key: &str,
    response: &Value,
) -> bool {
    let Ok(pending) = pending.lock() else {
        return false;
    };
    let Some(queue) = pending.by_request_id.get(request_key) else {
        return false;
    };
    let matching = queue
        .iter()
        .filter(|request| terminal_codex_gateway_response_matches_request(request, response))
        .collect::<Vec<_>>();
    if matching.len() == 1 {
        return matching[0].winner == Some(TerminalCodexGatewayWinner::Web);
    }
    queue.len() == 1 && queue[0].winner == Some(TerminalCodexGatewayWinner::Web)
}

fn terminal_codex_gateway_drain_pending(
    pending: &Arc<StdMutex<TerminalCodexGatewayPendingRequests>>,
) -> Vec<TerminalCodexGatewayPendingRequest> {
    pending
        .lock()
        .ok()
        .map(|mut pending| {
            let drained = pending
                .by_request_id
                .drain()
                .flat_map(|(_, requests)| requests)
                .collect();
            pending.ambiguous_request_ids.clear();
            drained
        })
        .unwrap_or_default()
}

async fn terminal_codex_gateway_publish_resolution(
    app: &AppHandle,
    pane_id: &str,
    instance_id: u64,
    request: &TerminalCodexGatewayPendingRequest,
    source: &str,
) {
    let state = app.state::<TerminalState>();
    let cloud_mcp_state = app.state::<CloudMcpState>();
    let event = terminal_codex_gateway_resolution_event(pane_id, instance_id, request, source);
    let _ = handle_terminal_activity_hook_event(
        app,
        &state.terminals,
        cloud_mcp_state.inner(),
        pane_id,
        instance_id,
        event,
        source,
    )
    .await;
}

fn terminal_codex_gateway_resolution_event(
    pane_id: &str,
    instance_id: u64,
    request: &TerminalCodexGatewayPendingRequest,
    source: &str,
) -> Value {
    let request_id_text = terminal_codex_app_server_request_id_text(&request.request_id);
    let hook_event_name = if request.method == "mcpServer/elicitation/request"
        || request.method == "item/tool/requestUserInput"
    {
        "ElicitationResult"
    } else {
        "PermissionResult"
    };
    json!({
        "hook_event_name": hook_event_name,
        "provider": "codex",
        "pane_id": pane_id,
        "instance_id": instance_id,
        "permission_request_id": request_id_text,
        "prompt_id": request_id_text,
        "resolved_interaction_id": request.interaction_id,
        "resolved_interaction_revision": request.interaction_revision,
        "decision": "resolved",
        "timestamp_ms": terminal_now_ms(),
        "resolution_reason": source,
        "source": "codex_app_server",
    })
}

fn terminal_codex_gateway_spawn_web_waiter(
    app: AppHandle,
    pane_id: String,
    instance_id: u64,
    request: Value,
    event: Value,
    pending: Arc<StdMutex<TerminalCodexGatewayPendingRequests>>,
    upstream_sender: mpsc::Sender<Message>,
) -> oneshot::Receiver<bool> {
    let (ready_sender, ready_receiver) = oneshot::channel::<bool>();
    tauri::async_runtime::spawn(async move {
        let Some(request_key) = request
            .get("id")
            .and_then(terminal_codex_app_server_request_id_key)
        else {
            let _ = ready_sender.send(false);
            return;
        };
        let request_id_text = request
            .get("id")
            .map(terminal_codex_app_server_request_id_text)
            .unwrap_or_default();
        let interaction_id = event
            .get("interaction_id")
            .and_then(Value::as_str)
            .unwrap_or_default()
            .to_string();
        let interaction_revision = event
            .get("interaction_revision")
            .and_then(Value::as_u64)
            .unwrap_or_default();
        let _pending_cleanup = TerminalCodexGatewayPendingGenerationCleanup {
            pending: Arc::clone(&pending),
            request_key: request_key.clone(),
            interaction_id: interaction_id.clone(),
            interaction_revision,
        };
        let state = app.state::<TerminalState>();
        let token = {
            let Ok(tokens) = state.terminal_activity_transport_tokens.lock() else {
                let _ = ready_sender.send(false);
                return;
            };
            tokens
                .get(&terminal_output_transport_key(&pane_id, instance_id))
                .cloned()
        };
        let Some(token) = token else {
            let _ = ready_sender.send(false);
            return;
        };
        let envelope = json!({
            "type": "terminal-activity-hook",
            "token": token,
            "event": event,
        });
        let handler_app = app.clone();
        let envelope_text = envelope.to_string();
        let response_task = tauri::async_runtime::spawn(async move {
            handle_terminal_activity_transport_message(&handler_app, &envelope_text).await
        });
        let mut published = false;
        for _ in 0..100 {
            published = state
                .terminal_structured_interactions
                .lock()
                .ok()
                .is_some_and(|interactions| {
                    interactions.values().any(|interaction| {
                        interaction.pane_id == pane_id
                            && interaction.instance_id == instance_id
                            && interaction.provider_request_id == request_id_text
                            && interaction.interaction_id == interaction_id
                            && interaction.revision == interaction_revision
                    })
                });
            if published {
                break;
            }
            sleep(Duration::from_millis(2)).await;
        }
        let _ = ready_sender.send(published);
        if !published {
            response_task.abort();
            let removed_ids = state
                .terminal_structured_interactions
                .lock()
                .ok()
                .map(|mut interactions| {
                    let removed = interactions
                        .iter()
                        .filter_map(|(id, interaction)| {
                            (interaction.pane_id == pane_id
                                && interaction.instance_id == instance_id
                                && interaction.provider_request_id == request_id_text
                                && interaction.interaction_id == interaction_id
                                && interaction.revision == interaction_revision)
                                .then(|| id.clone())
                        })
                        .collect::<Vec<_>>();
                    interactions.retain(|_, interaction| {
                        interaction.pane_id != pane_id
                            || interaction.instance_id != instance_id
                            || interaction.provider_request_id != request_id_text
                            || interaction.interaction_id != interaction_id
                            || interaction.revision != interaction_revision
                    });
                    removed
                })
                .unwrap_or_default();
            if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
                for interaction_id in removed_ids {
                    waiters.remove(&interaction_id);
                }
            }
            return;
        }
        let result = match response_task.await {
            Ok(Ok(Some(result))) => result,
            Ok(Ok(None)) | Ok(Err(_)) | Err(_) => return,
        };
        if terminal_codex_gateway_claim_generation(
            &pending,
            &request_key,
            &interaction_id,
            interaction_revision,
            TerminalCodexGatewayWinner::Web,
        )
        .is_none()
        {
            return;
        }
        let response = json!({
            "id": request.get("id").cloned().unwrap_or(Value::Null),
            "result": result,
        });
        if upstream_sender
            .send(Message::Text(response.to_string().into()))
            .await
            .is_err()
        {
            return;
        }
    });
    ready_receiver
}

struct TerminalCodexGatewayDownstreamMessage {
    message: Message,
    flushed: Option<oneshot::Sender<bool>>,
}

async fn terminal_codex_gateway_send_downstream(
    sender: &mpsc::Sender<TerminalCodexGatewayDownstreamMessage>,
    message: Message,
    require_flush: bool,
) -> bool {
    if !require_flush {
        return sender
            .send(TerminalCodexGatewayDownstreamMessage {
                message,
                flushed: None,
            })
            .await
            .is_ok();
    }
    let (flushed_sender, flushed_receiver) = oneshot::channel();
    if sender
        .send(TerminalCodexGatewayDownstreamMessage {
            message,
            flushed: Some(flushed_sender),
        })
        .await
        .is_err()
    {
        return false;
    }
    timeout(
        Duration::from_millis(TERMINAL_CODEX_AUTH_EXHAUSTED_FLUSH_TIMEOUT_MS),
        flushed_receiver,
    )
    .await
    .ok()
    .and_then(Result::ok)
    .unwrap_or(false)
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum TerminalCodexRecoveryControlOutcome {
    NotControl,
    Continue,
    Close,
}

async fn terminal_codex_gateway_service_recovery_control(
    sender: &mpsc::Sender<TerminalCodexGatewayDownstreamMessage>,
    message: &Message,
) -> TerminalCodexRecoveryControlOutcome {
    let (reply, outcome) = match message {
        Message::Ping(bytes) => (
            Some(Message::Pong(bytes.clone())),
            TerminalCodexRecoveryControlOutcome::Continue,
        ),
        Message::Close(frame) => (
            Some(Message::Close(frame.clone())),
            TerminalCodexRecoveryControlOutcome::Close,
        ),
        Message::Pong(_) | Message::Frame(_) => {
            return TerminalCodexRecoveryControlOutcome::Continue
        }
        Message::Text(_) | Message::Binary(_) => {
            return TerminalCodexRecoveryControlOutcome::NotControl
        }
    };
    if sender
        .send(TerminalCodexGatewayDownstreamMessage {
            message: reply.expect("recovery control reply"),
            flushed: None,
        })
        .await
        .is_err()
    {
        return TerminalCodexRecoveryControlOutcome::Close;
    }
    outcome
}

#[derive(Debug, Eq, PartialEq)]
enum TerminalCodexThreadBootstrapForward {
    Blocked,
    Sent,
    Full,
    Closed,
}

#[derive(Default)]
struct TerminalCodexAuthReloadBudget {
    attempts: usize,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum TerminalCodexAuthReloadDecision {
    Retry { attempt: usize, delay_ms: u64 },
    Exhausted,
}

struct TerminalCodexAppServerRestartRequest {
    observed_generation: u64,
    delay_ms: u64,
    response: oneshot::Sender<Result<u64, String>>,
}

fn terminal_codex_stable_jitter_seed(pane_id: &str, instance_id: u64, salt: u64) -> u64 {
    let mut hash = 0xcbf2_9ce4_8422_2325_u64;
    for byte in pane_id
        .as_bytes()
        .iter()
        .copied()
        .chain(instance_id.to_le_bytes())
        .chain(salt.to_le_bytes())
    {
        hash ^= u64::from(byte);
        hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
    }
    hash
}

fn terminal_codex_app_server_startup_jitter_ms(pane_id: &str, instance_id: u64) -> u64 {
    TERMINAL_CODEX_APP_SERVER_STARTUP_JITTER_MIN_MS
        + terminal_codex_stable_jitter_seed(pane_id, instance_id, u64::from(std::process::id()))
            % TERMINAL_CODEX_APP_SERVER_STARTUP_JITTER_SPAN_MS
}

fn terminal_codex_auth_reload_backoff_ms(pane_id: &str, instance_id: u64, attempt: usize) -> u64 {
    let exponent = u32::try_from(attempt.saturating_sub(1).min(2)).unwrap_or(2);
    let base = TERMINAL_CODEX_AUTH_RELOAD_BACKOFF_BASE_MS.saturating_mul(1_u64 << exponent);
    let jitter = terminal_codex_stable_jitter_seed(
        pane_id,
        instance_id,
        u64::try_from(attempt).unwrap_or(u64::MAX),
    ) % (TERMINAL_CODEX_AUTH_RELOAD_JITTER_MAX_MS + 1);
    base.saturating_add(jitter)
}

fn terminal_codex_auth_reload_next(
    budget: &mut TerminalCodexAuthReloadBudget,
    pane_id: &str,
    instance_id: u64,
    _now_ms: u64,
) -> TerminalCodexAuthReloadDecision {
    // This is deliberately a lifetime budget for the pane instance. A time
    // window (or a successful turn) must never reset it: otherwise two panes
    // with slowly alternating auth failures can restart each other forever.
    if budget.attempts >= TERMINAL_CODEX_AUTH_RELOAD_MAX_ATTEMPTS {
        return TerminalCodexAuthReloadDecision::Exhausted;
    }
    budget.attempts += 1;
    TerminalCodexAuthReloadDecision::Retry {
        attempt: budget.attempts,
        delay_ms: terminal_codex_auth_reload_backoff_ms(pane_id, instance_id, budget.attempts),
    }
}

fn terminal_codex_app_server_auth_error_payload(value: &Value) -> Option<&Value> {
    if let Some(error) = value.get("error") {
        return Some(error);
    }
    match value.get("method").and_then(Value::as_str) {
        Some("error") => value
            .pointer("/params/error")
            .or_else(|| value.get("params")),
        Some("turn/completed") => value.pointer("/params/turn/error"),
        Some("account/chatgptAuthTokens/refresh")
            if value
                .pointer("/params/reason")
                .and_then(Value::as_str)
                .is_some_and(|reason| {
                    matches!(
                        reason.trim().to_ascii_lowercase().as_str(),
                        "unauthorized" | "refresh-unauthorized" | "refresh_unauthorized"
                    )
                }) =>
        {
            value.get("params")
        }
        _ => None,
    }
}

fn terminal_codex_gateway_client_response_method<'a>(
    requests: &'a HashMap<String, TerminalCodexGatewayClientRequest>,
    message: &Value,
) -> Option<&'a str> {
    message
        .get("id")
        .and_then(terminal_codex_app_server_request_id_key)
        .and_then(|request_key| requests.get(&request_key))
        .map(|request| request.method.as_str())
}

fn terminal_codex_auth_request_method(method: Option<&str>) -> bool {
    method.is_some_and(|method| {
        let method = method.trim().to_ascii_lowercase();
        method.starts_with("account/")
            || method.split(['/', '.', '_', '-', ':']).any(|segment| {
                matches!(
                    segment,
                    "auth"
                        | "authenticate"
                        | "authentication"
                        | "token"
                        | "tokens"
                        | "refresh"
                        | "login"
                )
            })
    })
}

fn terminal_codex_app_server_auth_invalidated(
    value: &Value,
    correlated_request_method: Option<&str>,
) -> bool {
    if value.get("method").and_then(Value::as_str) == Some("account/chatgptAuthTokens/refresh")
        && value
            .pointer("/params/reason")
            .and_then(Value::as_str)
            .is_some_and(|reason| {
                matches!(
                    reason.trim().to_ascii_lowercase().as_str(),
                    "unauthorized" | "refresh-unauthorized" | "refresh_unauthorized"
                )
            })
    {
        return true;
    }
    let Some(error) = terminal_codex_app_server_auth_error_payload(value) else {
        return false;
    };
    let lower = error.to_string().to_ascii_lowercase();
    if [
        "token_invalidated",
        "token-invalidation",
        "refresh_token_reused",
        "refresh_token_invalidated",
        "refresh-unauthorized",
        "refresh_unauthorized",
        "auth-invalidated",
        "auth_invalidated",
    ]
    .iter()
    .any(|marker| lower.contains(marker))
    {
        return true;
    }
    if lower.contains("refresh token")
        && [
            "already used",
            "has been used",
            "reused",
            "revoked",
            "invalidated",
        ]
        .iter()
        .any(|marker| lower.contains(marker))
    {
        return true;
    }
    let codex_unauthorized = (lower.contains("codexerrorinfo")
        || lower.contains("codex_error_info"))
        && lower.contains("unauthorized");
    let status_401 = [
        "\"status\":401",
        "\"statuscode\":401",
        "\"httpstatuscode\":401",
        "\"status\":\"401\"",
        "401 unauthorized",
    ]
    .iter()
    .any(|marker| lower.contains(marker));
    codex_unauthorized
        || (status_401
            && terminal_codex_auth_request_method(correlated_request_method)
            && [
                "\"auth",
                "authentication",
                "token",
                "credential",
                "login",
                "invalid_request_error",
            ]
            .iter()
            .any(|marker| lower.contains(marker)))
}

fn terminal_codex_auth_reload_retryable_error(
    original: &Value,
    active_turn: Option<&TerminalCodexGatewayActiveTurn>,
) -> Value {
    let message = "Codex reloaded the pane credentials, but did not automatically retry the interrupted operation because it may already have produced side effects. Re-submit it explicitly if appropriate.";
    let data = json!({
        "code": "codex_auth_reloaded_retry_required",
        "retryable": true,
        "automaticallyRetried": false,
    });
    if original.get("method").is_none() {
        let Some(id) = original.get("id") else {
            return original.clone();
        };
        return json!({
            "jsonrpc": "2.0",
            "id": id,
            "error": {
                "code": -32096,
                "message": message,
                "data": data,
            }
        });
    }
    let turn_error = json!({
        "message": message,
        "additionalDetails": "codex_auth_reloaded_retry_required",
        "code": "codex_auth_reloaded_retry_required",
        "retryable": true,
        "automaticallyRetried": false,
    });
    if original.get("method").and_then(Value::as_str) == Some("turn/completed") {
        let mut retryable = original.clone();
        retryable["params"]["turn"]["error"] = turn_error;
        return retryable;
    }
    let thread_id = original
        .pointer("/params/threadId")
        .and_then(Value::as_str)
        .map(str::to_string)
        .or_else(|| active_turn.and_then(|turn| turn.thread_id.clone()));
    let turn_id = original
        .pointer("/params/turnId")
        .or_else(|| original.pointer("/params/turn/id"))
        .and_then(Value::as_str)
        .map(str::to_string)
        .or_else(|| active_turn.and_then(|turn| turn.turn_id.clone()));
    let (Some(thread_id), Some(turn_id)) = (thread_id, turn_id) else {
        return json!({
            "jsonrpc": "2.0",
            "method": "error",
            "params": {
                "error": turn_error,
                "willRetry": false,
            }
        });
    };
    json!({
        "jsonrpc": "2.0",
        "method": "error",
        "params": {
            "error": turn_error,
            "threadId": thread_id,
            "turnId": turn_id,
            "willRetry": false,
        }
    })
}

fn terminal_codex_auth_reload_abandoned_request_error(request: &Value) -> Option<Value> {
    let id = request.get("id")?;
    Some(json!({
        "jsonrpc": "2.0",
        "id": id,
        "error": {
            "code": -32096,
            "message": "Codex reloaded the pane credentials. This already-submitted request was not automatically retried because its prior execution outcome is uncertain.",
            "data": {
                "code": "codex_auth_reloaded_retry_required",
                "retryable": true,
                "automaticallyRetried": false,
            }
        }
    }))
}

fn terminal_codex_auth_reload_recovery_reports(
    original: &Value,
    active_turn: Option<&TerminalCodexGatewayActiveTurn>,
    outstanding_requests: &[Value],
) -> Vec<Value> {
    let trigger_key = original
        .get("id")
        .and_then(terminal_codex_app_server_request_id_key);
    let mut reports = vec![terminal_codex_auth_reload_retryable_error(
        original,
        active_turn,
    )];
    reports.extend(outstanding_requests.iter().filter_map(|request| {
        let request_key = request
            .get("id")
            .and_then(terminal_codex_app_server_request_id_key);
        (request_key != trigger_key)
            .then(|| terminal_codex_auth_reload_abandoned_request_error(request))
            .flatten()
    }));
    reports
}

fn terminal_codex_auth_reload_exhausted_error(
    original: &Value,
    active_turn: Option<&TerminalCodexGatewayActiveTurn>,
    detail: &str,
) -> Value {
    let message = format!(
        "Codex authentication remained invalid after {TERMINAL_CODEX_AUTH_RELOAD_MAX_ATTEMPTS} on-disk reload attempts. Sign in again for this account."
    );
    let clean_detail = clean_terminal_diagnostic_log_text(detail);
    let data = json!({
        "code": "codex_auth_reload_exhausted",
        "detail": clean_detail,
        "retryable": false,
    });
    if original.get("method").is_none() {
        let Some(id) = original.get("id") else {
            return json!({
                "jsonrpc": "2.0",
                "method": "error",
                "params": {
                    "error": {
                        "code": "codex_auth_reload_exhausted",
                        "message": message,
                        "additionalDetails": format!(
                            "codex_auth_reload_exhausted: {clean_detail}"
                        ),
                        "retryable": false,
                        "automaticallyRetried": false,
                    },
                    "willRetry": false,
                }
            });
        };
        return json!({
            "jsonrpc": "2.0",
            "id": id,
            "error": {
                "code": -32097,
                "message": message,
                "data": data,
            }
        });
    }
    let turn_error = json!({
        "message": message,
        "additionalDetails": format!(
            "codex_auth_reload_exhausted: {clean_detail}"
        ),
        "codexErrorInfo": "unauthorized",
    });
    if original.get("method").and_then(Value::as_str) == Some("turn/completed") {
        let mut exhausted = original.clone();
        exhausted["params"]["turn"]["error"] = turn_error;
        return exhausted;
    }
    let thread_id = original
        .pointer("/params/threadId")
        .and_then(Value::as_str)
        .map(str::to_string)
        .or_else(|| active_turn.and_then(|turn| turn.thread_id.clone()));
    let turn_id = original
        .pointer("/params/turnId")
        .or_else(|| original.pointer("/params/turn/id"))
        .and_then(Value::as_str)
        .map(str::to_string)
        .or_else(|| active_turn.and_then(|turn| turn.turn_id.clone()));
    let (Some(thread_id), Some(turn_id)) = (thread_id, turn_id) else {
        // Background external-token refresh notifications have no turn
        // correlation. Still surface the deterministic terminal condition;
        // forwarding the original invalidation would make exhaustion
        // indistinguishable from another recoverable auth notification.
        return json!({
            "jsonrpc": "2.0",
            "method": "error",
            "params": {
                "error": {
                    "code": "codex_auth_reload_exhausted",
                    "message": message,
                    "additionalDetails": format!(
                        "codex_auth_reload_exhausted: {clean_detail}"
                    ),
                    "retryable": false,
                    "automaticallyRetried": false,
                },
                "willRetry": false,
            }
        });
    };
    json!({
        "jsonrpc": "2.0",
        "method": "error",
        "params": {
            "error": turn_error,
            "threadId": thread_id,
            "turnId": turn_id,
            "willRetry": false,
        }
    })
}

fn terminal_codex_turn_completed(value: &Value) -> bool {
    value.get("method").and_then(Value::as_str) == Some("turn/completed")
}

type TerminalCodexUpstreamSocket = WebSocketStream<MaybeTlsStream<TcpStream>>;

async fn terminal_codex_gateway_connect_upstream(
    upstream_url: &str,
) -> Result<TerminalCodexUpstreamSocket, String> {
    let mut last_error = None;
    for _ in 0..TERMINAL_CODEX_APP_SERVER_CONNECT_ATTEMPTS {
        match connect_async(upstream_url).await {
            Ok((socket, _)) => return Ok(socket),
            Err(error) => {
                last_error = Some(error.to_string());
                sleep(Duration::from_millis(
                    TERMINAL_CODEX_APP_SERVER_CONNECT_RETRY_MS,
                ))
                .await;
            }
        }
    }
    Err(format!(
        "Unable to connect Codex TUI gateway to its pane app-server: {}",
        last_error.unwrap_or_else(|| "connection timed out".to_string())
    ))
}

fn terminal_codex_gateway_response_matches(request: &Value, response: &Value) -> bool {
    let Some(request_id) = request
        .get("id")
        .and_then(terminal_codex_app_server_request_id_key)
    else {
        return false;
    };
    response
        .get("id")
        .and_then(terminal_codex_app_server_request_id_key)
        .is_some_and(|response_id| response_id == request_id)
}

async fn terminal_codex_gateway_send_internal_request(
    upstream: &mut TerminalCodexUpstreamSocket,
    request: &Value,
    buffered: &mut Vec<Message>,
) -> Result<(), String> {
    upstream
        .send(Message::Text(request.to_string().into()))
        .await
        .map_err(|error| format!("Unable to initialize replacement Codex app-server: {error}"))?;
    loop {
        let message = timeout(Duration::from_secs(8), upstream.next())
            .await
            .map_err(|_| "Replacement Codex app-server initialization timed out.".to_string())?
            .ok_or_else(|| {
                "Replacement Codex app-server disconnected during initialization.".to_string()
            })?
            .map_err(|error| {
                format!("Replacement Codex app-server initialization failed: {error}")
            })?;
        match message {
            Message::Text(text) => {
                let value = serde_json::from_str::<Value>(text.as_ref()).map_err(|error| {
                    format!("Replacement Codex app-server returned invalid JSON: {error}")
                })?;
                if terminal_codex_gateway_response_matches(request, &value) {
                    if value.get("error").is_some() {
                        return Err(format!(
                            "Replacement Codex app-server rejected {}: {}",
                            request
                                .get("method")
                                .and_then(Value::as_str)
                                .unwrap_or("request"),
                            value.get("error").unwrap_or(&Value::Null)
                        ));
                    }
                    return Ok(());
                }
                buffered.push(Message::Text(text));
            }
            Message::Ping(bytes) => {
                upstream.send(Message::Pong(bytes)).await.map_err(|error| {
                    format!("Unable to answer replacement Codex app-server ping: {error}")
                })?;
            }
            Message::Close(_) => {
                return Err("Replacement Codex app-server closed during initialization.".to_string())
            }
            other => buffered.push(other),
        }
    }
}

async fn terminal_codex_gateway_reinitialize_upstream(
    upstream: &mut TerminalCodexUpstreamSocket,
    initialize: &Value,
    initialized: &Value,
    resume_thread_id: Option<&str>,
    pane_cwd: &str,
    pane_config: &Value,
) -> Result<Vec<Message>, String> {
    let mut buffered = Vec::new();
    terminal_codex_gateway_send_internal_request(upstream, initialize, &mut buffered).await?;
    upstream
        .send(Message::Text(initialized.to_string().into()))
        .await
        .map_err(|error| {
            format!("Unable to finish replacement Codex app-server initialization: {error}")
        })?;
    if let Some(thread_id) = resume_thread_id {
        let mut resume = json!({
            "id": format!("diffforge-auth-reload-resume-{}", uuid::Uuid::new_v4()),
            "method": "thread/resume",
            "params": { "threadId": thread_id },
        });
        terminal_codex_gateway_bind_pane_request(&mut resume, pane_cwd, pane_config);
        terminal_codex_gateway_send_internal_request(upstream, &resume, &mut buffered).await?;
    }
    Ok(buffered)
}

struct TerminalCodexGatewayRecoveredUpstream {
    upstream: TerminalCodexUpstreamSocket,
    connected_generation: u64,
    buffered: Vec<Message>,
    attempt: usize,
}

enum TerminalCodexGatewayRecoveryOutcome {
    Recovered(TerminalCodexGatewayRecoveredUpstream),
    Exhausted { detail: String },
}

struct TerminalCodexGatewayRecoveryInFlight {
    original: Value,
    active_turn: Option<TerminalCodexGatewayActiveTurn>,
    future: futures_util::future::BoxFuture<'static, TerminalCodexGatewayRecoveryOutcome>,
}

#[allow(clippy::too_many_arguments)]
async fn terminal_codex_gateway_recover_upstream(
    upstream_url: String,
    restart_sender: mpsc::Sender<TerminalCodexAppServerRestartRequest>,
    mut connected_generation: u64,
    auth_reload_budget: Arc<StdMutex<TerminalCodexAuthReloadBudget>>,
    initialize_request: Option<Value>,
    initialized_notification: Option<Value>,
    resume_thread_id: Option<String>,
    pane_id: String,
    instance_id: u64,
    pane_cwd: String,
    pane_config: Value,
) -> TerminalCodexGatewayRecoveryOutcome {
    let mut last_recovery_error =
        "the replacement app-server did not validate the rotated credentials".to_string();
    loop {
        let decision = auth_reload_budget
            .lock()
            .ok()
            .map(|mut budget| {
                terminal_codex_auth_reload_next(
                    &mut budget,
                    &pane_id,
                    instance_id,
                    terminal_now_ms(),
                )
            })
            .unwrap_or(TerminalCodexAuthReloadDecision::Exhausted);
        let TerminalCodexAuthReloadDecision::Retry { attempt, delay_ms } = decision else {
            log_terminal_status_event(
                "backend.codex_app_server_gateway.auth_reload_exhausted",
                json!({
                    "attempts": TERMINAL_CODEX_AUTH_RELOAD_MAX_ATTEMPTS,
                    "error": clean_terminal_diagnostic_log_text(&last_recovery_error),
                    "instance_id": instance_id,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                }),
            );
            return TerminalCodexGatewayRecoveryOutcome::Exhausted {
                detail: last_recovery_error,
            };
        };
        log_terminal_status_event(
            "backend.codex_app_server_gateway.auth_reload_retry",
            json!({
                "attempt": attempt,
                "delay_ms": delay_ms,
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
            }),
        );
        let (response_sender, response_receiver) = oneshot::channel();
        if restart_sender
            .send(TerminalCodexAppServerRestartRequest {
                observed_generation: connected_generation,
                delay_ms,
                response: response_sender,
            })
            .await
            .is_err()
        {
            last_recovery_error = "the pane app-server supervisor stopped".to_string();
            continue;
        }
        let replacement_generation = match response_receiver.await {
            Ok(Ok(generation)) => generation,
            Ok(Err(error)) => {
                last_recovery_error = error;
                continue;
            }
            Err(_) => {
                last_recovery_error =
                    "the pane app-server supervisor dropped its restart response".to_string();
                continue;
            }
        };
        // The supervisor already replaced the child. A later failed connect
        // must charge another absolute-budget attempt against that generation.
        terminal_codex_gateway_record_replacement_started(
            &mut connected_generation,
            replacement_generation,
        );
        let mut replacement = match terminal_codex_gateway_connect_upstream(&upstream_url).await {
            Ok(replacement) => replacement,
            Err(error) => {
                last_recovery_error = error;
                continue;
            }
        };
        let buffered = match (
            initialize_request.as_ref(),
            initialized_notification.as_ref(),
        ) {
            (Some(initialize), Some(initialized)) => {
                match terminal_codex_gateway_reinitialize_upstream(
                    &mut replacement,
                    initialize,
                    initialized,
                    resume_thread_id.as_deref(),
                    &pane_cwd,
                    &pane_config,
                )
                .await
                {
                    Ok(buffered) => buffered,
                    Err(error) => {
                        last_recovery_error = error;
                        continue;
                    }
                }
            }
            // The failed initialize itself is already an accepted request and
            // is therefore never replayed. Leave the replacement pristine so
            // a future explicit initialize can start normally.
            _ => Vec::new(),
        };
        return TerminalCodexGatewayRecoveryOutcome::Recovered(
            TerminalCodexGatewayRecoveredUpstream {
                upstream: replacement,
                connected_generation,
                buffered,
                attempt,
            },
        );
    }
}

async fn terminal_codex_gateway_connection(
    app: AppHandle,
    stream: TcpStream,
    upstream_url: String,
    restart_sender: mpsc::Sender<TerminalCodexAppServerRestartRequest>,
    app_server_generation: Arc<AtomicU64>,
    auth_reload_budget: Arc<StdMutex<TerminalCodexAuthReloadBudget>>,
    pane_id: String,
    instance_id: u64,
    pane_cwd: String,
    pane_config: Value,
) -> Result<(), String> {
    let downstream = accept_async(stream)
        .await
        .map_err(|error| format!("Unable to accept Codex TUI websocket: {error}"))?;
    let upstream = terminal_codex_gateway_connect_upstream(&upstream_url).await?;
    let mut connected_generation = app_server_generation.load(Ordering::Acquire);
    let (mut downstream_write, mut downstream_read) = downstream.split();
    let (mut upstream_write, mut upstream_read) = upstream.split();
    let (mut upstream_sender, mut upstream_receiver) = mpsc::channel::<Message>(1024);
    let (downstream_sender, mut downstream_receiver) =
        mpsc::channel::<TerminalCodexGatewayDownstreamMessage>(1024);
    let mut upstream_writer = tauri::async_runtime::spawn(async move {
        while let Some(message) = upstream_receiver.recv().await {
            if upstream_write.send(message).await.is_err() {
                break;
            }
        }
    });
    let downstream_writer = tauri::async_runtime::spawn(async move {
        while let Some(outbound) = downstream_receiver.recv().await {
            let sent = downstream_write.send(outbound.message).await.is_ok();
            if let Some(flushed) = outbound.flushed {
                let _ = flushed.send(sent);
            }
            if !sent {
                break;
            }
        }
    });
    let pending = Arc::new(StdMutex::new(TerminalCodexGatewayPendingRequests::default()));
    let mut client_requests = HashMap::<String, TerminalCodexGatewayClientRequest>::new();
    let mut client_request_sequence = 0_u64;
    let mut blocked_bootstrap_requests = VecDeque::<Value>::new();
    let mut initialize_request = None::<Value>;
    let mut initialized_notification = None::<Value>;
    let mut active_turn = None::<TerminalCodexGatewayActiveTurn>;
    let mut auth_recovery = None::<TerminalCodexGatewayRecoveryInFlight>;
    let mut recovery_buffered_upstream = VecDeque::<Message>::new();
    let mut recovery_deferred_downstream = VecDeque::<Message>::new();

    log_terminal_status_event(
        "backend.codex_app_server_gateway.connected",
        json!({
            "instance_id": instance_id,
            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
        }),
    );

    loop {
        let recovering = auth_recovery.is_some();
        let has_buffered_upstream = !recovery_buffered_upstream.is_empty();
        let replay_deferred_downstream =
            !recovering && !has_buffered_upstream && !recovery_deferred_downstream.is_empty();
        tokio::select! {
            downstream_message = async {
                if replay_deferred_downstream {
                    return recovery_deferred_downstream.pop_front().map(Ok);
                }
                downstream_read.next().await
            }, if recovering || !has_buffered_upstream => {
                let Some(downstream_message) = downstream_message else { break; };
                let message = downstream_message
                    .map_err(|error| format!("Codex TUI websocket read failed: {error}"))?;
                if recovering {
                    match terminal_codex_gateway_service_recovery_control(
                        &downstream_sender,
                        &message,
                    )
                    .await
                    {
                        TerminalCodexRecoveryControlOutcome::Continue => continue,
                        TerminalCodexRecoveryControlOutcome::Close => break,
                        TerminalCodexRecoveryControlOutcome::NotControl => {
                            // These messages have provably not crossed the
                            // replacement app-server boundary, so they are the
                            // only operations recovery may later submit.
                            if recovery_deferred_downstream.len()
                                < TERMINAL_CODEX_AUTH_RECOVERY_DOWNSTREAM_QUEUE_MAX
                            {
                                recovery_deferred_downstream.push_back(message);
                            } else {
                                let error = json!({
                                    "jsonrpc": "2.0",
                                    "method": "error",
                                    "params": {
                                        "error": {
                                            "message": "Codex authentication recovery queue is full; the request was not submitted.",
                                            "additionalDetails": "codex_auth_recovery_queue_full"
                                        },
                                        "willRetry": false
                                    }
                                });
                                if !terminal_codex_gateway_send_downstream(
                                    &downstream_sender,
                                    Message::Text(error.to_string().into()),
                                    false,
                                )
                                .await
                                {
                                    break;
                                }
                            }
                        }
                    }
                    continue;
                }
                match message {
                    Message::Text(text) => {
                        let mut value = serde_json::from_str::<Value>(text.as_ref()).ok();
                        if let Some(value) = value.as_mut() {
                            terminal_codex_app_server_enable_tui_capabilities(value);
                            terminal_codex_gateway_bind_pane_request(
                                value,
                                &pane_cwd,
                                &pane_config,
                            );
                            match value.get("method").and_then(Value::as_str) {
                                Some("initialize") => initialize_request = Some(value.clone()),
                                Some("initialized") => {
                                    initialized_notification = Some(value.clone())
                                }
                                _ => {}
                            }
                        }
                        if value.as_ref().is_some_and(terminal_codex_gateway_is_thread_bootstrap) {
                            let request = value.take().expect("checked Codex thread request");
                            // Preserve request order once any bootstrap is waiting.
                            // Otherwise verify and enqueue the request while holding
                            // the same mutex used by terminal cleanup to revoke the
                            // pane trust state. This makes clear-vs-forward ordering
                            // atomic instead of awaiting after a stale state read.
                            let outcome = if blocked_bootstrap_requests.is_empty() {
                                terminal_codex_gateway_try_forward_thread_bootstrap(
                                    &upstream_sender,
                                    &pane_id,
                                    instance_id,
                                    &request,
                                )
                            } else {
                                TerminalCodexThreadBootstrapForward::Blocked
                            };
                            match outcome {
                                TerminalCodexThreadBootstrapForward::Sent => {
                                    terminal_codex_gateway_track_client_request(
                                        &mut client_requests,
                                        &mut client_request_sequence,
                                        &request,
                                    );
                                }
                                TerminalCodexThreadBootstrapForward::Blocked
                                | TerminalCodexThreadBootstrapForward::Full => {
                                    if blocked_bootstrap_requests.len() < 16 {
                                        blocked_bootstrap_requests.push_back(request);
                                    } else if let Some(request_id) = request.get("id").cloned() {
                                        let error = json!({
                                            "jsonrpc": "2.0",
                                            "id": request_id,
                                            "error": {
                                                "code": -32091,
                                                "message": "Codex hook trust review is still required for this pane."
                                            }
                                        });
                                        let _ = downstream_sender
                                            .send(TerminalCodexGatewayDownstreamMessage {
                                                message: Message::Text(error.to_string().into()),
                                                flushed: None,
                                            })
                                            .await;
                                    }
                                }
                                TerminalCodexThreadBootstrapForward::Closed => break,
                            }
                            continue;
                        }
                        if let Some(value) = value.as_ref() {
                            terminal_codex_gateway_track_client_request(
                                &mut client_requests,
                                &mut client_request_sequence,
                                value,
                            );
                        }
                        let is_response = value.as_ref().is_some_and(|value| {
                            value.get("method").is_none()
                                && value.get("id").and_then(terminal_codex_app_server_request_id_key).is_some()
                        });
                        if is_response {
                            let value_ref = value.as_ref().unwrap();
                            let request_id = value_ref.get("id").unwrap();
                            let request_key = terminal_codex_app_server_request_id_key(request_id).unwrap();
                            let request = terminal_codex_gateway_claim(
                                &pending,
                                &request_key,
                                value_ref,
                                TerminalCodexGatewayWinner::NativeTui,
                            );
                            if let Some(request) = request {
                                terminal_codex_gateway_publish_resolution(
                                    &app,
                                    &pane_id,
                                    instance_id,
                                    &request,
                                    "codex_app_server_native_tui_answer",
                                ).await;
                                terminal_codex_gateway_remove_generation(
                                    &pending,
                                    &request_key,
                                    &request.interaction_id,
                                    request.interaction_revision,
                                );
                            } else if terminal_codex_gateway_response_already_won_by_web(
                                &pending,
                                &request_key,
                                value_ref,
                            ) {
                                // The web answer already won. App-server has a response;
                                // suppress the TUI's late duplicate.
                                continue;
                            }
                        }
                        let sent_request = value.clone();
                        let text = value.map(|value| value.to_string()).unwrap_or_else(|| text.to_string());
                        if upstream_sender.send(Message::Text(text.into())).await.is_err() {
                            break;
                        }
                        match sent_request
                            .as_ref()
                            .and_then(|request| request.get("method"))
                            .and_then(Value::as_str)
                        {
                            Some("turn/start") => {
                                active_turn = sent_request
                                    .as_ref()
                                    .map(terminal_codex_gateway_active_turn);
                            }
                            Some("turn/interrupt") => active_turn = None,
                            _ => {}
                        }
                    }
                    Message::Binary(bytes) => {
                        if upstream_sender.send(Message::Binary(bytes)).await.is_err() { break; }
                    }
                    Message::Ping(bytes) => {
                        if downstream_sender.send(TerminalCodexGatewayDownstreamMessage { message: Message::Pong(bytes), flushed: None }).await.is_err() { break; }
                    }
                    Message::Close(frame) => {
                        let _ = upstream_sender.send(Message::Close(frame)).await;
                        break;
                    }
                    Message::Pong(_) | Message::Frame(_) => {}
                }
            }
            upstream_message = async {
                if let Some(message) = recovery_buffered_upstream.pop_front() {
                    Some(Ok(message))
                } else {
                    upstream_read.next().await
                }
            }, if !recovering => {
                let Some(upstream_message) = upstream_message else { break; };
                let message = match upstream_message {
                    Ok(message) => message,
                    Err(error) => {
                        return Err(format!("Codex pane app-server connection failed: {error}"));
                    }
                };
                match message {
                    Message::Text(text) => {
                        if let Ok(mut value) = serde_json::from_str::<Value>(text.as_ref()) {
                            terminal_codex_gateway_observe_turn_started(
                                &mut active_turn,
                                &value,
                            );
                            let correlated_method = terminal_codex_gateway_client_response_method(
                                &client_requests,
                                &value,
                            );
                            if terminal_codex_app_server_auth_invalidated(
                                &value,
                                correlated_method,
                            ) {
                                // Once a request crossed upstream, recovery can no longer prove
                                // that it did not start. Never replay it. Keep only the correlation
                                // needed to surface a deterministic retry-required result.
                                let interrupted_turn = active_turn.take();
                                let resume_thread_id = interrupted_turn
                                    .as_ref()
                                    .and_then(|turn| turn.thread_id.clone());
                                let recovery_future = terminal_codex_gateway_recover_upstream(
                                    upstream_url.clone(),
                                    restart_sender.clone(),
                                    connected_generation,
                                    Arc::clone(&auth_reload_budget),
                                    initialize_request.clone(),
                                    initialized_notification.clone(),
                                    resume_thread_id,
                                    pane_id.clone(),
                                    instance_id,
                                    pane_cwd.clone(),
                                    pane_config.clone(),
                                )
                                .boxed();
                                auth_recovery = Some(TerminalCodexGatewayRecoveryInFlight {
                                    original: value,
                                    active_turn: interrupted_turn,
                                    future: recovery_future,
                                });
                                continue;
                            }
                            let client_method = terminal_codex_gateway_take_client_response_method(
                                &mut client_requests,
                                &value,
                            );
                            terminal_codex_gateway_clear_completed_turn(
                                &mut active_turn,
                                &value,
                            );
                            if client_method.as_deref() == Some("hooks/list") {
                                terminal_codex_gateway_handle_hooks_list_response(
                                    &app,
                                    &pane_id,
                                    instance_id,
                                    &value,
                                )
                                .await;
                            }
                            if client_method.as_deref() == Some("config/read") {
                                terminal_codex_gateway_merge_pane_config_response(
                                    &mut value,
                                    &pane_config,
                                );
                            }
                            if let Some(event) = terminal_codex_gateway_register_server_request(
                                &pending,
                                &pane_id,
                                instance_id,
                                &value,
                            ) {
                                let web_ready = terminal_codex_gateway_spawn_web_waiter(
                                    app.clone(),
                                    pane_id.clone(),
                                    instance_id,
                                    value.clone(),
                                    event,
                                    Arc::clone(&pending),
                                    upstream_sender.clone(),
                                );
                                let published = timeout(Duration::from_millis(500), web_ready)
                                    .await
                                    .ok()
                                    .and_then(Result::ok)
                                    .unwrap_or(false);
                                if !published {
                                    log_terminal_status_event(
                                        "backend.codex_app_server_gateway.uir_publish_error",
                                        json!({
                                            "instance_id": instance_id,
                                            "method": value.get("method").and_then(Value::as_str).unwrap_or_default(),
                                            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                                        }),
                                    );
                                }
                            } else if value.get("method").and_then(Value::as_str)
                                == Some("serverRequest/resolved")
                            {
                                if let Some(request_id) = value.pointer("/params/requestId") {
                                    if let Some(request_key) = terminal_codex_app_server_request_id_key(request_id) {
                                        let request = terminal_codex_gateway_take_resolved(
                                            &pending,
                                            &request_key,
                                            &value,
                                        );
                                        if let Some(request) = request {
                                            terminal_codex_gateway_publish_resolution(
                                                &app,
                                                &pane_id,
                                                instance_id,
                                                &request,
                                                "codex_app_server_resolved",
                                            ).await;
                                        }
                                    }
                                }
                            }
                            let text = value.to_string();
                            if !terminal_codex_gateway_send_downstream(
                                &downstream_sender,
                                Message::Text(text.into()),
                                false,
                            )
                            .await
                            {
                                break;
                            }
                            continue;
                        }
                        if downstream_sender.send(TerminalCodexGatewayDownstreamMessage { message: Message::Text(text), flushed: None }).await.is_err() { break; }
                    }
                    Message::Binary(bytes) => {
                        if downstream_sender.send(TerminalCodexGatewayDownstreamMessage { message: Message::Binary(bytes), flushed: None }).await.is_err() { break; }
                    }
                    Message::Ping(bytes) => {
                        if upstream_sender.send(Message::Pong(bytes)).await.is_err() { break; }
                    }
                    Message::Close(frame) => {
                        let _ = downstream_sender.send(TerminalCodexGatewayDownstreamMessage { message: Message::Close(frame), flushed: None }).await;
                        break;
                    }
                    Message::Pong(_) | Message::Frame(_) => {}
                }
            }
            recovery_result = async {
                auth_recovery
                    .as_mut()
                    .expect("guarded Codex auth recovery")
                    .future
                    .as_mut()
                    .await
            }, if recovering => {
                let recovery = auth_recovery
                    .take()
                    .expect("completed Codex auth recovery");
                match recovery_result {
                    TerminalCodexGatewayRecoveryOutcome::Exhausted { detail } => {
                        let exhausted = terminal_codex_auth_reload_exhausted_error(
                            &recovery.original,
                            recovery.active_turn.as_ref(),
                            &detail,
                        );
                        let _ = terminal_codex_gateway_send_downstream(
                            &downstream_sender,
                            Message::Text(exhausted.to_string().into()),
                            true,
                        )
                        .await;
                        // The pane-instance restart budget is permanently
                        // exhausted. Stop this connection instead of allowing
                        // another request to start an unbounded recovery cycle.
                        break;
                    }
                    TerminalCodexGatewayRecoveryOutcome::Recovered(recovered) => {
                        connected_generation = recovered.connected_generation;
                        let stale_server_requests =
                            terminal_codex_gateway_drain_pending(&pending);
                        for request in stale_server_requests {
                            terminal_codex_gateway_publish_resolution(
                                &app,
                                &pane_id,
                                instance_id,
                                &request,
                                "codex_app_server_auth_reload",
                            )
                            .await;
                        }

                        upstream_writer.abort();
                        let (mut replacement_write, replacement_read) =
                            recovered.upstream.split();
                        let (replacement_sender, mut replacement_receiver) =
                            mpsc::channel::<Message>(1024);
                        let replacement_writer = tauri::async_runtime::spawn(async move {
                            while let Some(message) = replacement_receiver.recv().await {
                                if replacement_write.send(message).await.is_err() {
                                    break;
                                }
                            }
                        });
                        upstream_read = replacement_read;
                        upstream_sender = replacement_sender;
                        upstream_writer = replacement_writer;

                        // Re-enter every message observed during initialize/resume through
                        // the ordinary upstream branch. This preserves auth detection, turn
                        // state, hooks/list correlation, and permission/UIR registration.
                        recovery_buffered_upstream.extend(recovered.buffered);
                        let outstanding_requests =
                            terminal_codex_gateway_outstanding_requests(&client_requests);
                        let reports = terminal_codex_auth_reload_recovery_reports(
                            &recovery.original,
                            recovery.active_turn.as_ref(),
                            &outstanding_requests,
                        );
                        let abandoned_count = reports.len().saturating_sub(1);
                        for report in reports {
                            recovery_buffered_upstream
                                .push_back(Message::Text(report.to_string().into()));
                        }
                        log_terminal_status_event(
                            "backend.codex_app_server_gateway.auth_reload_recovered",
                            json!({
                                "attempt": recovered.attempt,
                                "deferred_unsubmitted_requests": recovery_deferred_downstream.len(),
                                "instance_id": instance_id,
                                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                                "replayed_active_turn": false,
                                "replayed_accepted_requests": 0,
                                "reported_abandoned_requests": abandoned_count,
                            }),
                        );
                    }
                }
            }
            _ = sleep(Duration::from_millis(50)), if !recovering && !blocked_bootstrap_requests.is_empty() => {
                let mut upstream_closed = false;
                while let Some(value) = blocked_bootstrap_requests.front().cloned() {
                    // Re-check under the discovery mutex for every request. If
                    // cleanup clears the pane between queued items, no later
                    // item can inherit the first request's stale allow result.
                    match terminal_codex_gateway_try_forward_thread_bootstrap(
                        &upstream_sender,
                        &pane_id,
                        instance_id,
                        &value,
                    ) {
                        TerminalCodexThreadBootstrapForward::Sent => {
                            blocked_bootstrap_requests.pop_front();
                            terminal_codex_gateway_track_client_request(
                                &mut client_requests,
                                &mut client_request_sequence,
                                &value,
                            );
                        }
                        TerminalCodexThreadBootstrapForward::Blocked
                        | TerminalCodexThreadBootstrapForward::Full => break,
                        TerminalCodexThreadBootstrapForward::Closed => {
                            upstream_closed = true;
                            break;
                        }
                    }
                }
                if upstream_closed {
                    break;
                }
            }
        }
    }

    let unresolved = terminal_codex_gateway_drain_pending(&pending);
    for request in unresolved {
        terminal_codex_gateway_publish_resolution(
            &app,
            &pane_id,
            instance_id,
            &request,
            "codex_app_server_gateway_disconnected",
        )
        .await;
    }
    upstream_writer.abort();
    downstream_writer.abort();
    Ok(())
}

fn terminal_json_merge(base: &mut Value, overlay: &Value) {
    match (base, overlay) {
        (Value::Object(base), Value::Object(overlay)) => {
            for (key, value) in overlay {
                terminal_json_merge(base.entry(key.clone()).or_insert(Value::Null), value);
            }
        }
        (base, overlay) => *base = overlay.clone(),
    }
}

/// ALLOWLIST of Codex request-`config` override keys that are safe to pass
/// through to thread execution. Everything NOT in this set is stripped, so
/// thread execution resolves the SAME hooks as `hooks/list` (which in Codex
/// 0.144 accepts only `cwds` and receives no request config) — guaranteeing
/// reviewed catalog == executed hooks. This is an allowlist, not a denylist, on
/// purpose: a denylist is fragile and un-upgrade-safe (the hook-injection surface
/// spans `hooks`/`hooks.*`, `bypass_hook_trust`, `notify`→legacy_notify,
/// `project_root_markers`/`projects.*`, AND `features.hooks`/`features.plugins`/
/// `features.remote_plugin` feature gates — and future Codex versions can add
/// more). The allowlisted keys reflect the user's in-TUI selections (model,
/// reasoning effort) and cannot inject/trust/redirect hook discovery. Non-hook
/// operational settings DiffForge cares about (sandbox/approval/mcp) are already
/// applied via managed launch args + CODEX_HOME config, not per-request.
/// Case/separator-insensitive on the full key.
fn terminal_codex_thread_config_passthrough(key: &str) -> bool {
    let canon: String = key
        .trim()
        .chars()
        .filter(|character| *character != '_' && *character != '-')
        .flat_map(char::to_lowercase)
        .collect();
    matches!(canon.as_str(), "model" | "modelreasoningeffort")
}

fn terminal_codex_gateway_bind_pane_request(
    request: &mut Value,
    pane_cwd: &str,
    _pane_config: &Value,
) {
    let Some(method) = request
        .get("method")
        .and_then(Value::as_str)
        .map(str::to_string)
    else {
        return;
    };
    if !matches!(
        method.as_str(),
        "thread/start" | "thread/resume" | "thread/fork" | "hooks/list" | "config/read"
    ) {
        return;
    }
    let Some(object) = request.as_object_mut() else {
        return;
    };
    let params = object.entry("params").or_insert_with(|| json!({}));
    if !params.is_object() {
        *params = json!({});
    }
    let Some(params) = params.as_object_mut() else {
        return;
    };
    match method.as_str() {
        "thread/start" | "thread/resume" | "thread/fork" => {
            params.insert("cwd".to_string(), json!(pane_cwd));
            // hooks/list and thread execution must resolve the same natural
            // layered configuration (managed CODEX_HOME + pane cwd project
            // layers). A request-level hooks override would either mask a
            // reviewed project hook or add a hook that was never reviewed.
            // `hooks/list` receives NO request config, so thread execution must
            // carry no config override that could inject/trust/redirect a hook,
            // else reviewed catalog != executed hooks (a trust bypass). Rather
            // than deny an ever-growing set of hook-affecting keys, ALLOWLIST the
            // few proven-safe passthroughs (model / reasoning effort) and strip
            // everything else — see terminal_codex_thread_config_passthrough.
            let remove_config = match params.get_mut("config") {
                Some(Value::Object(config)) => {
                    config.retain(|key, _| terminal_codex_thread_config_passthrough(key));
                    config.is_empty()
                }
                Some(_) => true,
                None => false,
            };
            if remove_config {
                params.remove("config");
            }
        }
        // Codex 0.144 HooksListParams accepts `cwds`, not `cwd`/`config`.
        // The pane-owned app-server evaluates this native request against
        // its own working directory and CODEX_HOME hook configuration.
        "hooks/list" => {
            params.insert("cwds".to_string(), json!([pane_cwd]));
            params.remove("cwd");
            params.remove("config");
        }
        // ConfigReadParams accepts cwd but no arbitrary config overlay.
        "config/read" => {
            params.insert("cwd".to_string(), json!(pane_cwd));
            params.remove("config");
        }
        _ => {}
    }
}

fn terminal_codex_gateway_is_thread_bootstrap(request: &Value) -> bool {
    matches!(
        request.get("method").and_then(Value::as_str),
        Some("thread/start" | "thread/resume" | "thread/fork")
    )
}

fn terminal_codex_gateway_try_forward_thread_bootstrap(
    sender: &mpsc::Sender<Message>,
    pane_id: &str,
    instance_id: u64,
    request: &Value,
) -> TerminalCodexThreadBootstrapForward {
    let Ok(states) = terminal_codex_hook_trust_discovery_states().lock() else {
        return TerminalCodexThreadBootstrapForward::Blocked;
    };
    let state = states
        .get(&(pane_id.to_string(), instance_id))
        .map(|entry| entry.state);
    if !terminal_codex_hook_trust_allows_thread(state) {
        return TerminalCodexThreadBootstrapForward::Blocked;
    }
    match sender.try_send(Message::Text(request.to_string().into())) {
        Ok(()) => TerminalCodexThreadBootstrapForward::Sent,
        Err(mpsc::error::TrySendError::Full(_)) => TerminalCodexThreadBootstrapForward::Full,
        Err(mpsc::error::TrySendError::Closed(_)) => TerminalCodexThreadBootstrapForward::Closed,
    }
}

fn terminal_codex_hook_trust_allows_thread(
    state: Option<TerminalCodexHookTrustDiscoveryState>,
) -> bool {
    matches!(
        state,
        Some(
            TerminalCodexHookTrustDiscoveryState::Open
                | TerminalCodexHookTrustDiscoveryState::Resolved
        )
    )
}

fn terminal_codex_gateway_pane_config(env_vars: &[(String, String)]) -> Value {
    let env_value = |key: &str| {
        env_vars
            .iter()
            .find_map(|(candidate, value)| (candidate == key).then(|| value.trim().to_string()))
            .filter(|value| !value.is_empty())
    };
    let Some(home) = env_value("CODEX_HOME").or_else(|| env_value("DIFFFORGE_CODEX_HOME")) else {
        return json!({});
    };
    let home = PathBuf::from(home);
    let mut config = json!({});
    let mut merge_toml_file = |path: PathBuf| {
        let Ok(body) = fs::read_to_string(path) else {
            return;
        };
        let Ok(value) = toml::from_str::<toml::Value>(&body) else {
            return;
        };
        if let Ok(value) = serde_json::to_value(value) {
            terminal_json_merge(&mut config, &value);
        }
    };
    merge_toml_file(home.join("config.toml"));
    if let Some(profile) = env_value("DIFFFORGE_CODEX_PROFILE") {
        merge_toml_file(home.join(format!("{profile}.config.toml")));
    }
    if let Ok(hooks) = fs::read(home.join("hooks.json"))
        .and_then(|bytes| serde_json::from_slice::<Value>(&bytes).map_err(std::io::Error::other))
    {
        if let Some(hooks) = hooks.get("hooks") {
            if let Some(object) = config.as_object_mut() {
                object.insert("hooks".to_string(), hooks.clone());
            }
        }
    }
    config
}

fn terminal_codex_gateway_merge_pane_config_response(response: &mut Value, pane_config: &Value) {
    if response.get("error").is_some() {
        return;
    }
    let Some(response) = response.as_object_mut() else {
        return;
    };
    let result = response.entry("result").or_insert_with(|| json!({}));
    if !result.is_object() {
        *result = json!({});
    }
    let Some(result) = result.as_object_mut() else {
        return;
    };
    let config = result.entry("config").or_insert_with(|| json!({}));
    terminal_json_merge(config, pane_config);
    result.entry("origins").or_insert_with(|| json!({}));
}

struct TerminalCodexAppServerStartingChild {
    child: Option<std::process::Child>,
}

impl TerminalCodexAppServerStartingChild {
    fn new(child: std::process::Child) -> Self {
        Self { child: Some(child) }
    }

    fn child_mut(&mut self) -> &mut std::process::Child {
        self.child
            .as_mut()
            .expect("Codex startup child must exist until gateway handoff")
    }

    fn into_child(mut self) -> std::process::Child {
        self.child
            .take()
            .expect("Codex startup child must exist at gateway handoff")
    }

    fn stop_and_wait(&mut self) {
        if let Some(mut child) = self.child.take() {
            let _ = child.kill();
            let _ = child.wait();
        }
    }
}

impl Drop for TerminalCodexAppServerStartingChild {
    fn drop(&mut self) {
        self.stop_and_wait();
    }
}

fn terminal_codex_app_server_trusted_args(
    coordination: Option<&TerminalCoordinationSession>,
    permission_mode: Option<&str>,
    app_control_mcp_launch: Option<&(String, Vec<String>)>,
    bypass_hook_trust: bool,
) -> Vec<String> {
    let mut args = Vec::new();
    if bypass_hook_trust {
        terminal_codex_push_config_override(&mut args, "bypass_hook_trust=true".to_string());
    }
    if coordination.is_some() {
        let permission_mode = permission_mode.unwrap_or(TERMINAL_PERMISSION_MODE_ACCEPT_EDITS);
        let (approval_policy, sandbox_mode) = match permission_mode {
            TERMINAL_PERMISSION_MODE_PLAN => ("never", "read-only"),
            TERMINAL_PERMISSION_MODE_ASK => ("on-request", "workspace-write"),
            TERMINAL_PERMISSION_MODE_FULL_ACCESS | TERMINAL_PERMISSION_MODE_BYPASS => {
                ("never", "danger-full-access")
            }
            _ => ("never", "workspace-write"),
        };

        // The pane-owned CODEX_HOME base config already contains the managed
        // permission definition, selected default permission profile,
        // coordination-kernel, workspace-mcp-gateway, their tool approvals,
        // and shell environment policy. App-control instructions are synced
        // into this trusted base only for app-control launches. Pass only the
        // launch-specific approval/sandbox posture here.
        for (key, value) in [
            ("approval_policy", approval_policy),
            ("sandbox_mode", sandbox_mode),
        ] {
            terminal_codex_push_config_override(
                &mut args,
                format!("{key}={}", terminal_toml_string(value)),
            );
        }
    }

    if let Some((command, server_args)) = app_control_mcp_launch {
        if coordination.is_none() {
            // Uncoordinated app-control sessions have no pane-owned managed
            // home to update, so preserve their trusted launch override.
            append_codex_app_control_developer_instructions_arg(&mut args);
        }
        let app_control_tools = APP_CONTROL_MCP_TOOL_NAMES
            .iter()
            .map(|tool| (*tool).to_string())
            .collect::<Vec<_>>();
        terminal_codex_push_config_override(
            &mut args,
            terminal_codex_mcp_server_inline_override(
                APP_CONTROL_MCP_SERVER_NAME,
                command,
                server_args,
                &app_control_tools,
                &[],
            ),
        );
        if coordination.is_none() {
            terminal_codex_push_config_override(
                &mut args,
                format!(
                    "shell_environment_policy.inherit={}",
                    terminal_toml_string("all")
                ),
            );
        }
    }
    args
}

fn terminal_codex_push_config_override(args: &mut Vec<String>, config: String) {
    args.push("-c".to_string());
    args.push(config);
}

fn terminal_codex_mcp_server_inline_override(
    server_key: &str,
    command: &str,
    server_args: &[String],
    approved_tools: &[String],
    env_vars: &[(String, String)],
) -> String {
    let mut seen_tools = HashSet::new();
    let tools = approved_tools
        .iter()
        .map(|tool| tool.trim())
        .filter(|tool| !tool.is_empty() && seen_tools.insert((*tool).to_string()))
        .map(|tool| {
            format!(
                "{}={{approval_mode={}}}",
                terminal_toml_key_segment(tool),
                terminal_toml_string("approve")
            )
        })
        .collect::<Vec<_>>()
        .join(",");
    let mut seen_env = HashSet::new();
    let env = env_vars
        .iter()
        .filter(|(key, _)| !key.trim().is_empty() && seen_env.insert(key.clone()))
        .map(|(key, value)| {
            format!(
                "{}={}",
                terminal_toml_key_segment(key),
                terminal_toml_string(value)
            )
        })
        .collect::<Vec<_>>()
        .join(",");
    let env = if env.is_empty() {
        String::new()
    } else {
        format!(",env={{{env}}}")
    };
    format!(
        "mcp_servers.{}={{enabled=true,command={},args={},default_tools_approval_mode={},tools={{{tools}}}{env}}}",
        terminal_toml_key_segment(server_key),
        terminal_toml_string(command),
        terminal_toml_string_array(server_args),
        terminal_toml_string("prompt"),
    )
}

fn terminal_codex_app_server_process_args(
    listen_url: &str,
    trusted_args: &[String],
) -> Vec<String> {
    let mut args = Vec::with_capacity(trusted_args.len().saturating_add(3));
    args.push("app-server".to_string());
    args.extend_from_slice(trusted_args);
    args.extend(["--listen".to_string(), listen_url.to_string()]);
    args
}

#[cfg(any(windows, test))]
fn terminal_codex_windows_node_entrypoint(command_path: &Path) -> Option<PathBuf> {
    let extension = command_path.extension()?.to_str()?;
    if !extension.eq_ignore_ascii_case("cmd") && !extension.eq_ignore_ascii_case("bat") {
        return None;
    }
    let parent = command_path.parent()?;
    let mut candidates = vec![parent
        .join("node_modules")
        .join("@openai")
        .join("codex")
        .join("bin")
        .join("codex.js")];
    if parent
        .file_name()
        .and_then(|name| name.to_str())
        .is_some_and(|name| name.eq_ignore_ascii_case(".bin"))
    {
        if let Some(node_modules) = parent.parent() {
            candidates.push(
                node_modules
                    .join("@openai")
                    .join("codex")
                    .join("bin")
                    .join("codex.js"),
            );
        }
    }
    candidates.into_iter().find(|candidate| candidate.is_file())
}

#[cfg(any(windows, test))]
fn terminal_codex_windows_node_program(command_path: &Path) -> PathBuf {
    command_path
        .parent()
        .map(|parent| parent.join("node.exe"))
        .filter(|candidate| candidate.is_file())
        .unwrap_or_else(|| PathBuf::from("node.exe"))
}

fn terminal_spawn_codex_app_server_process(
    command_path: &str,
    listen_url: &str,
    working_directory: &Path,
    env_vars: &[(String, String)],
    trusted_args: &[String],
) -> Result<std::process::Child, String> {
    let process_args = terminal_codex_app_server_process_args(listen_url, trusted_args);
    #[cfg(windows)]
    let mut command = {
        let lower = command_path.to_ascii_lowercase();
        if lower.ends_with(".cmd") || lower.ends_with(".bat") {
            let command_path_buf = PathBuf::from(command_path);
            if let Some(entrypoint) =
                terminal_codex_windows_node_entrypoint(command_path_buf.as_path())
            {
                // npm's codex.cmd shim routes through cmd.exe, whose command
                // line limit is only about 8191 UTF-16 code units. App-control
                // carries a large trusted developer prompt, so invoke the
                // package's Node entrypoint directly under CreateProcessW's
                // much larger native limit. This preserves the exact trusted
                // arguments instead of weakening or truncating them.
                let node_program = terminal_codex_windows_node_program(&command_path_buf);
                let mut native_args = vec![entrypoint.to_string_lossy().to_string()];
                native_args.extend(process_args.iter().cloned());
                let native_len = windows_agent_launch_command_line_len(
                    node_program.to_string_lossy().as_ref(),
                    &native_args,
                );
                if native_len >= WINDOWS_NATIVE_CLAUDE_LAUNCH_STAGE_THRESHOLD {
                    return Err(format!(
                        "Codex app-server launch is too long even for the native Windows Node entrypoint ({native_len} characters)."
                    ));
                }
                let mut command = Command::new(node_program);
                command.arg(entrypoint);
                command
            } else {
                let batch_len = windows_agent_launch_command_line_len(command_path, &process_args);
                if batch_len >= WINDOWS_CLAUDE_LAUNCH_STAGE_THRESHOLD {
                    return Err(format!(
                        "Codex app-server batch launch is too long for cmd.exe ({batch_len} characters), and the trusted @openai/codex Node entrypoint could not be located."
                    ));
                }
                let mut command = Command::new("cmd.exe");
                command.args(["/D", "/S", "/C", command_path]);
                command
            }
        } else {
            Command::new(command_path)
        }
    };
    #[cfg(not(windows))]
    let mut command = Command::new(command_path);
    command
        .args(process_args)
        .current_dir(working_directory)
        .stdin(Stdio::null())
        .stdout(Stdio::null())
        .stderr(Stdio::null());
    apply_desktop_command_environment(&mut command);
    for (key, value) in env_vars {
        if !key.trim().is_empty() {
            command.env(key, value);
        }
    }
    #[cfg(windows)]
    {
        use std::os::windows::process::CommandExt as _;

        const CREATE_NO_WINDOW: u32 = 0x0800_0000;
        command.creation_flags(CREATE_NO_WINDOW);
    }
    command
        .spawn()
        .map_err(|error| format!("Unable to start Codex app-server: {error}"))
}

async fn terminal_start_ready_codex_app_server_process(
    command_path: &str,
    upstream_url: &str,
    upstream_port: u16,
    working_directory: &Path,
    env_vars: &[(String, String)],
    trusted_args: &[String],
) -> Result<std::process::Child, String> {
    let mut starting_child =
        TerminalCodexAppServerStartingChild::new(terminal_spawn_codex_app_server_process(
            command_path,
            upstream_url,
            working_directory,
            env_vars,
            trusted_args,
        )?);
    let readiness_url = format!("http://127.0.0.1:{upstream_port}/readyz");
    let readiness_client = reqwest::Client::builder()
        .timeout(Duration::from_millis(500))
        .build()
        .map_err(|error| format!("Unable to create Codex app-server probe: {error}"))?;
    let ready_started = Instant::now();
    loop {
        if let Ok(Some(status)) = starting_child.child_mut().try_wait() {
            starting_child.child.take();
            return Err(format!(
                "Codex app-server exited before becoming ready ({status})."
            ));
        }
        if readiness_client
            .get(&readiness_url)
            .send()
            .await
            .is_ok_and(|response| response.status().is_success())
        {
            return Ok(starting_child.into_child());
        }
        if ready_started.elapsed()
            >= Duration::from_millis(TERMINAL_CODEX_APP_SERVER_READY_TIMEOUT_MS)
        {
            return Err("Codex app-server did not become ready in time.".to_string());
        }
        sleep(Duration::from_millis(
            TERMINAL_CODEX_APP_SERVER_READY_POLL_MS,
        ))
        .await;
    }
}

fn terminal_stop_codex_app_server_process(child: &mut Option<std::process::Child>) {
    if let Some(mut child) = child.take() {
        let _ = child.kill();
        let _ = child.wait();
    }
}

async fn terminal_start_codex_app_server_gateway(
    app: AppHandle,
    command_path: &str,
    working_directory: &Path,
    env_vars: &[(String, String)],
    trusted_args: &[String],
    managed_app_control_enabled: Option<bool>,
    pane_id: &str,
    instance_id: u64,
) -> Result<TerminalCodexGatewayHandle, String> {
    if let Some(enabled) = managed_app_control_enabled {
        let home = terminal_launch_env_value(env_vars, "DIFFFORGE_CODEX_HOME")
            .map(PathBuf::from)
            .ok_or_else(|| {
                "Managed Codex app-server launch is missing DIFFFORGE_CODEX_HOME.".to_string()
            })?;
        crate::coordination::kernel::codex_managed_home_set_app_control_instructions(
            &home, enabled,
        )?;
    }
    let upstream_reservation = TcpListener::bind(("127.0.0.1", 0))
        .await
        .map_err(|error| format!("Unable to reserve Codex app-server port: {error}"))?;
    let upstream_port = upstream_reservation
        .local_addr()
        .map_err(|error| format!("Unable to read Codex app-server port: {error}"))?
        .port();
    drop(upstream_reservation);
    let upstream_url = format!("ws://127.0.0.1:{upstream_port}");
    let proxy_listener = TcpListener::bind(("127.0.0.1", 0))
        .await
        .map_err(|error| format!("Unable to start Codex TUI gateway: {error}"))?;
    let proxy_port = proxy_listener
        .local_addr()
        .map_err(|error| format!("Unable to read Codex TUI gateway port: {error}"))?
        .port();
    let endpoint = format!("ws://127.0.0.1:{proxy_port}");

    sleep(Duration::from_millis(
        terminal_codex_app_server_startup_jitter_ms(pane_id, instance_id),
    ))
    .await;
    let child = terminal_start_ready_codex_app_server_process(
        command_path,
        &upstream_url,
        upstream_port,
        working_directory,
        env_vars,
        trusted_args,
    )
    .await?;
    let (shutdown_sender, mut shutdown_receiver) = oneshot::channel::<()>();
    let handle = TerminalCodexGatewayHandle {
        endpoint: endpoint.clone(),
        shutdown: Arc::new(StdMutex::new(Some(shutdown_sender))),
    };
    let (restart_sender, mut restart_receiver) =
        mpsc::channel::<TerminalCodexAppServerRestartRequest>(8);
    let app_server_generation = Arc::new(AtomicU64::new(1));
    let auth_reload_budget = Arc::new(StdMutex::new(TerminalCodexAuthReloadBudget::default()));
    let gateway_pane_id = pane_id.to_string();
    let gateway_upstream_url = upstream_url.clone();
    let gateway_command_path = command_path.to_string();
    let gateway_working_directory = working_directory.to_path_buf();
    let gateway_env_vars = env_vars.to_vec();
    let gateway_trusted_args = trusted_args.to_vec();
    let pane_cwd = working_directory.to_string_lossy().to_string();
    let pane_config = terminal_codex_gateway_pane_config(env_vars);
    let supervisor_generation = Arc::clone(&app_server_generation);
    tauri::async_runtime::spawn(async move {
        let mut child = Some(child);
        log_terminal_status_event(
            "backend.codex_app_server_gateway.ready",
            json!({
                "endpoint": clean_terminal_diagnostic_log_text(&endpoint),
                "instance_id": instance_id,
                "pane_cwd": clean_terminal_diagnostic_log_text(&pane_cwd),
                "pane_id": clean_terminal_diagnostic_log_text(&gateway_pane_id),
                "process_model": "one_app_server_per_pane",
                "transport": "localhost_websocket",
            }),
        );
        loop {
            tokio::select! {
                _ = &mut shutdown_receiver => break,
                Some(restart_request) = restart_receiver.recv() => {
                    let current_generation = supervisor_generation.load(Ordering::Acquire);
                    if restart_request.observed_generation != current_generation {
                        let response = if child.is_some() {
                            Ok(current_generation)
                        } else {
                            Err("The pane app-server replacement is not running.".to_string())
                        };
                        let _ = restart_request.response.send(response);
                        continue;
                    }
                    terminal_stop_codex_app_server_process(&mut child);
                    sleep(Duration::from_millis(restart_request.delay_ms)).await;
                    match terminal_start_ready_codex_app_server_process(
                        &gateway_command_path,
                        &gateway_upstream_url,
                        upstream_port,
                        &gateway_working_directory,
                        &gateway_env_vars,
                        &gateway_trusted_args,
                    )
                    .await
                    {
                        Ok(replacement) => {
                            child = Some(replacement);
                            let generation = current_generation.saturating_add(1);
                            supervisor_generation.store(generation, Ordering::Release);
                            let _ = restart_request.response.send(Ok(generation));
                        }
                        Err(error) => {
                            let _ = restart_request.response.send(Err(error));
                        }
                    }
                }
                accepted = proxy_listener.accept() => {
                    let Ok((stream, _)) = accepted else {
                        sleep(Duration::from_millis(100)).await;
                        continue;
                    };
                    let app = app.clone();
                    let upstream_url = gateway_upstream_url.clone();
                    let restart_sender = restart_sender.clone();
                    let app_server_generation = Arc::clone(&app_server_generation);
                    let auth_reload_budget = Arc::clone(&auth_reload_budget);
                    let pane_id = gateway_pane_id.clone();
                    let pane_cwd = pane_cwd.clone();
                    let pane_config = pane_config.clone();
                    tauri::async_runtime::spawn(async move {
                        if let Err(error) = terminal_codex_gateway_connection(
                            app,
                            stream,
                            upstream_url,
                            restart_sender,
                            app_server_generation,
                            auth_reload_budget,
                            pane_id.clone(),
                            instance_id,
                            pane_cwd,
                            pane_config,
                        ).await {
                            log_terminal_status_event(
                                "backend.codex_app_server_gateway.connection_error",
                                json!({
                                    "error": clean_terminal_diagnostic_log_text(&error),
                                    "instance_id": instance_id,
                                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                                }),
                            );
                        }
                    });
                }
                _ = sleep(Duration::from_secs(1)) => {
                    if child
                        .as_mut()
                        .is_some_and(|child| child.try_wait().ok().flatten().is_some())
                    {
                        log_terminal_status_event(
                            "backend.codex_app_server_gateway.app_server_exited",
                            json!({
                                "instance_id": instance_id,
                                "pane_id": clean_terminal_diagnostic_log_text(&gateway_pane_id),
                            }),
                        );
                        break;
                    }
                }
            }
        }
        terminal_stop_codex_app_server_process(&mut child);
    });
    Ok(handle)
}

fn terminal_apply_codex_gateway_launch(
    args: &mut Vec<String>,
    env_vars: &mut Vec<(String, String)>,
    gateway: &TerminalCodexGatewayHandle,
) {
    strip_terminal_arg_option(args, "--remote", "", true);
    strip_terminal_arg_option(args, "--remote-auth-token-env", "", true);
    args.insert(0, gateway.endpoint.clone());
    args.insert(0, "--remote".to_string());
    env_vars.retain(|(key, _)| key != "DIFFFORGE_CODEX_APP_SERVER_UIR");
    env_vars.push((
        "DIFFFORGE_CODEX_APP_SERVER_UIR".to_string(),
        "1".to_string(),
    ));
}

fn terminal_replace_codex_gateway(
    instance: &TerminalInstance,
    gateway: TerminalCodexGatewayHandle,
) -> Result<(), String> {
    let mut current = instance
        .codex_gateway
        .lock()
        .map_err(|_| "Unable to save Codex app-server gateway.".to_string())?;
    if let Some(previous) = current.replace(gateway) {
        previous.shutdown();
    }
    Ok(())
}

fn spawn_terminal_input_transport_listener(
    app: AppHandle,
    listener: TcpListener,
    expected_token: String,
) {
    tauri::async_runtime::spawn(async move {
        loop {
            // A transient accept error (ECONNABORTED/EMFILE under fd
            // pressure) must not kill the accept loop: the endpoint stays
            // cached, so a dead listener strands every future connection
            // ("Socket is not connected" storms). Back off and keep serving.
            let stream = match listener.accept().await {
                Ok((stream, _)) => stream,
                Err(_) => {
                    tokio::time::sleep(std::time::Duration::from_millis(100)).await;
                    continue;
                }
            };
            let app_handle = app.clone();
            let token = expected_token.clone();
            tauri::async_runtime::spawn(async move {
                handle_terminal_input_transport_connection(app_handle, stream, token).await;
            });
        }
    });
}

