async fn handle_terminal_input_transport_connection(
    app: AppHandle,
    stream: TcpStream,
    expected_token: String,
) {
    let Ok(mut socket) = accept_async(stream).await else {
        return;
    };

    while let Some(message) = socket.next().await {
        match message {
            Ok(Message::Text(text)) => {
                let Some(ack) =
                    handle_terminal_input_transport_message(&app, &expected_token, text.as_ref())
                        .await
                else {
                    let _ = socket.close(None).await;
                    break;
                };
                if let Some(ack) = ack {
                    let _ = socket
                        .send(Message::Text(
                            serde_json::to_string(&ack)
                                .unwrap_or_else(|_| {
                                    "{\"type\":\"terminal-input-ack\",\"messageId\":\"\",\"ok\":false,\"error\":\"Unable to serialize terminal input acknowledgement.\"}".to_string()
                                })
                                .into(),
                        ))
                        .await;
                }
            }
            Ok(Message::Binary(bytes)) => {
                let Ok(text) = std::str::from_utf8(bytes.as_ref()) else {
                    continue;
                };
                let Some(ack) =
                    handle_terminal_input_transport_message(&app, &expected_token, text).await
                else {
                    let _ = socket.close(None).await;
                    break;
                };
                if let Some(ack) = ack {
                    let _ = socket
                        .send(Message::Text(
                            serde_json::to_string(&ack)
                                .unwrap_or_else(|_| {
                                    "{\"type\":\"terminal-input-ack\",\"messageId\":\"\",\"ok\":false,\"error\":\"Unable to serialize terminal input acknowledgement.\"}".to_string()
                                })
                                .into(),
                        ))
                        .await;
                }
            }
            Ok(Message::Ping(payload)) => {
                let _ = socket.send(Message::Pong(payload)).await;
            }
            Ok(Message::Close(_)) => break,
            Ok(_) => {}
            Err(_) => break,
        }
    }
}

async fn handle_terminal_output_transport_connection(
    app: AppHandle,
    stream: TcpStream,
    expected_token: String,
) {
    let Ok(mut socket) = accept_async(stream).await else {
        return;
    };

    let subscribe_text = loop {
        let Some(message) = socket.next().await else {
            return;
        };
        match message {
            Ok(Message::Text(text)) => break text.to_string(),
            Ok(Message::Binary(bytes)) => {
                let Ok(text) = std::str::from_utf8(bytes.as_ref()) else {
                    continue;
                };
                break text.to_string();
            }
            Ok(Message::Ping(payload)) => {
                let _ = socket.send(Message::Pong(payload)).await;
            }
            Ok(Message::Close(_)) | Err(_) => return,
            Ok(_) => {}
        }
    };

    if subscribe_text.len() > MAX_TERMINAL_INPUT_TRANSPORT_MESSAGE_BYTES {
        let _ = socket.close(None).await;
        return;
    }

    let Ok(subscribe) = serde_json::from_str::<TerminalOutputTransportSubscribe>(&subscribe_text)
    else {
        let _ = socket.close(None).await;
        return;
    };

    if subscribe.token != expected_token || subscribe.r#type != "subscribe" {
        let _ = socket.close(None).await;
        return;
    }
    if validate_terminal_pane_id(&subscribe.pane_id).is_err() || subscribe.instance_id == 0 {
        let _ = socket.close(None).await;
        return;
    }

    let state = app.state::<TerminalState>();
    let subscriber_id = state
        .next_terminal_output_subscriber_id
        .fetch_add(1, Ordering::Relaxed);
    let key = terminal_output_transport_key(&subscribe.pane_id, subscribe.instance_id);
    let (sender, mut receiver) = mpsc::unbounded_channel::<Vec<u8>>();

    {
        let Ok(mut subscribers) = state.terminal_output_transport_subscribers.lock() else {
            let _ = socket.close(None).await;
            return;
        };
        subscribers
            .entry(key.clone())
            .or_default()
            .push(TerminalOutputTransportSubscriber {
                id: subscriber_id,
                sender,
            });
    }

    let ready_message = json!({
        "type": "ready",
        "id": subscribe.id.as_deref().unwrap_or_default(),
        "pane_id": subscribe.pane_id,
        "instance_id": subscribe.instance_id,
    });
    if socket
        .send(Message::Text(ready_message.to_string().into()))
        .await
        .is_err()
    {
        remove_terminal_output_transport_subscriber(&state, &key, subscriber_id);
        return;
    }

    let (mut writer, mut reader) = socket.split();
    let writer_task = tauri::async_runtime::spawn(async move {
        while let Some(bytes) = receiver.recv().await {
            if writer.send(Message::Binary(bytes.into())).await.is_err() {
                break;
            }
        }
    });

    while let Some(message) = reader.next().await {
        match message {
            Ok(Message::Close(_)) | Err(_) => break,
            Ok(_) => {}
        }
    }

    writer_task.abort();
    remove_terminal_output_transport_subscriber(&state, &key, subscriber_id);
}

async fn handle_terminal_activity_transport_connection(app: AppHandle, mut stream: TcpStream) {
    let result = match read_terminal_activity_transport_message(&mut stream).await {
        Ok(text) => handle_terminal_activity_transport_message(&app, &text).await,
        Err(error) => Err(error),
    };
    let (ok, error, hook_response) = match result {
        Ok(hook_response) => (true, None, hook_response),
        Err(error) => (false, Some(error), None),
    };
    let ack = TerminalActivityTransportAck {
        r#type: "terminal-activity-ack",
        ok,
        error,
        hook_response,
    };
    let response = serde_json::to_string(&ack).unwrap_or_else(|_| {
        "{\"type\":\"terminal-activity-ack\",\"ok\":false,\"error\":\"Unable to serialize terminal activity acknowledgement.\"}".to_string()
    });
    let response_line = format!("{response}\n");
    let _ = stream.write_all(response_line.as_bytes()).await;
}

async fn read_terminal_activity_transport_message(
    stream: &mut TcpStream,
) -> Result<String, String> {
    let mut buffer = Vec::new();
    let mut chunk = [0u8; 4096];
    loop {
        let read = timeout(
            Duration::from_millis(TERMINAL_ACTIVITY_TRANSPORT_IO_TIMEOUT_MS),
            stream.read(&mut chunk),
        )
        .await
        .map_err(|_| "Timed out reading activity transport message.".to_string())?
        .map_err(|error| format!("Unable to read activity transport message: {error}"))?;
        if read == 0 {
            break;
        }
        buffer.extend_from_slice(&chunk[..read]);
        if buffer.len() > MAX_TERMINAL_ACTIVITY_TRANSPORT_MESSAGE_BYTES {
            return Err("Terminal activity transport message is too large.".to_string());
        }
        if buffer.iter().any(|byte| *byte == b'\n') {
            break;
        }
    }

    if buffer.is_empty() {
        return Err("Terminal activity transport message was empty.".to_string());
    }
    let end = buffer
        .iter()
        .position(|byte| *byte == b'\n')
        .unwrap_or(buffer.len());
    String::from_utf8(buffer[..end].to_vec())
        .map_err(|error| format!("Terminal activity transport message was not UTF-8: {error}"))
}

async fn handle_terminal_activity_transport_message(
    app: &AppHandle,
    text: &str,
) -> Result<Option<Value>, String> {
    if text.len() > MAX_TERMINAL_ACTIVITY_TRANSPORT_MESSAGE_BYTES {
        return Err("Terminal activity transport message is too large.".to_string());
    }
    let envelope = serde_json::from_str::<TerminalActivityTransportEnvelope>(text)
        .map_err(|error| format!("Unable to parse terminal activity transport message: {error}"))?;
    if envelope.r#type != "terminal-activity-hook" {
        return Err("Terminal activity transport message had an unsupported type.".to_string());
    }

    let pane_id = terminal_activity_hook_string(&envelope.event, &["pane_id"])
        .ok_or_else(|| "Terminal activity event is missing pane id.".to_string())?;
    validate_terminal_pane_id(&pane_id)?;
    let instance_id = envelope
        .event
        .get("instance_id")
        .and_then(Value::as_u64)
        .filter(|value| *value > 0)
        .ok_or_else(|| "Terminal activity event is missing instance id.".to_string())?;
    let state = app.state::<TerminalState>();
    let expected_token = {
        let tokens = state
            .terminal_activity_transport_tokens
            .lock()
            .map_err(|_| "Unable to read terminal activity transport token.".to_string())?;
        tokens
            .get(&terminal_output_transport_key(&pane_id, instance_id))
            .cloned()
    }
    .ok_or_else(|| "Terminal activity event target is not registered.".to_string())?;
    if envelope.token != expected_token {
        return Err("Terminal activity transport authentication failed.".to_string());
    }
    let instance = terminal_activity_hook_current_instance(&state.terminals, &pane_id, instance_id)
        .await
        .ok_or_else(|| "Terminal activity event target is not active.".to_string())?;
    let blocking_payload =
        terminal_activity_hook_payload(&instance, &envelope.event).filter(|payload| {
            matches!(
                payload.interaction_response_mode.as_deref(),
                Some(
                    "blocking_hook"
                        | "provider_api"
                        | "codex_app_server"
                        | "diffforge_intervention"
                )
            )
        });
    let mut blocking_receiver = None;
    if let Some(payload) = blocking_payload.as_ref() {
        let interaction_id = payload
            .interaction_id
            .as_deref()
            .ok_or_else(|| "Blocking provider interaction is missing its identity.".to_string())?;
        let (sender, receiver) = oneshot::channel::<Value>();
        state
            .terminal_structured_interaction_waiters
            .lock()
            .map_err(|_| {
                "Unable to register structured terminal interaction response.".to_string()
            })?
            .insert(interaction_id.to_string(), sender);
        blocking_receiver = Some((interaction_id.to_string(), receiver));
    }
    let cloud_mcp_state = app.state::<CloudMcpState>();
    if let Err(error) = handle_terminal_activity_hook_event(
        app,
        &state.terminals,
        cloud_mcp_state.inner(),
        &pane_id,
        instance_id,
        envelope.event.clone(),
        "transport",
    )
    .await
    {
        if let Some((interaction_id, _)) = blocking_receiver.as_ref() {
            if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
                waiters.remove(interaction_id);
            }
        }
        return Err(error);
    }

    let Some((interaction_id, receiver)) = blocking_receiver else {
        return Ok(None);
    };

    let interaction = state
        .terminal_structured_interactions
        .lock()
        .map_err(|_| "Unable to read structured terminal interaction state.".to_string())?
        .get(&interaction_id)
        .cloned();
    let Some(interaction) = interaction else {
        if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
            waiters.remove(&interaction_id);
        }
        return Err("Blocking provider interaction was not published.".to_string());
    };
    log_terminal_status_event(
        "backend.terminal_structured_interaction.waiting",
        json!({
            "interaction_id": interaction.interaction_id,
            "pane_id": interaction.pane_id,
            "provider": interaction.provider,
            "revision": interaction.revision,
        }),
    );
    let response = timeout(
        Duration::from_secs(TERMINAL_STRUCTURED_INTERACTION_WAIT_SECONDS),
        receiver,
    )
    .await;
    if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
        waiters.remove(&interaction.interaction_id);
    }
    match response {
        Ok(Ok(response)) => Ok(Some(response)),
        Ok(Err(_)) => Err("Structured terminal interaction response channel closed.".to_string()),
        Err(_) => {
            log_terminal_status_event(
                "backend.terminal_structured_interaction.expired",
                json!({
                    "interaction_id": interaction.interaction_id,
                    "pane_id": interaction.pane_id,
                    "provider": interaction.provider,
                    "revision": interaction.revision,
                }),
            );
            let elicitation =
                terminal_activity_hook_name_key(&interaction.hook_event_name) == "elicitation";
            let timeout_event = json!({
                "hook_event_name": if elicitation { "ElicitationResult" } else { "PermissionResult" },
                "provider": interaction.provider,
                "permission_request_id": interaction.provider_request_id,
                "prompt_id": interaction.prompt_id,
                "resolved_interaction_id": interaction.interaction_id,
                "resolved_interaction_revision": interaction.revision,
                "decision": "timeout",
                "timestamp_ms": terminal_now_ms(),
                "resolution_reason": "structured_interaction_timeout",
            });
            process_terminal_activity_hook_event(
                app,
                &state.terminals,
                cloud_mcp_state.inner(),
                &pane_id,
                instance_id,
                &instance,
                &timeout_event,
                "structured-interaction-timeout",
            )
            .await;
            Ok(Some(terminal_structured_interaction_hook_response(
                &interaction,
                if elicitation { "cancel" } else { "deny" },
                None,
                Some("Timed out waiting for user input."),
                None,
            )))
        }
    }
}

fn remove_terminal_output_transport_subscriber(
    state: &TerminalState,
    key: &str,
    subscriber_id: u64,
) {
    let Ok(mut subscribers) = state.terminal_output_transport_subscribers.lock() else {
        return;
    };
    let Some(terminal_subscribers) = subscribers.get_mut(key) else {
        return;
    };
    terminal_subscribers.retain(|subscriber| subscriber.id != subscriber_id);
    if terminal_subscribers.is_empty() {
        subscribers.remove(key);
    }
}

async fn handle_terminal_input_transport_message(
    app: &AppHandle,
    expected_token: &str,
    text: &str,
) -> Option<Option<TerminalInputTransportAck>> {
    if text.len() > MAX_TERMINAL_INPUT_TRANSPORT_MESSAGE_BYTES {
        emit_terminal_input_error(
            app,
            String::new(),
            None,
            "Terminal input transport message is too large.".to_string(),
        );
        return Some(None);
    }

    let envelope = match serde_json::from_str::<TerminalInputTransportEnvelope>(text) {
        Ok(envelope) => envelope,
        Err(error) => {
            emit_terminal_input_error(
                app,
                String::new(),
                None,
                format!("Unable to parse terminal input transport message: {error}"),
            );
            return Some(None);
        }
    };
    let message_id = envelope
        .message_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);

    if envelope.token != expected_token {
        emit_terminal_input_error(
            app,
            envelope.payload.pane_id,
            envelope.payload.instance_id,
            "Terminal input transport authentication failed.".to_string(),
        );
        return None;
    }

    let Some(message_id) = message_id else {
        enqueue_terminal_input_event(app, envelope.payload);
        return Some(None);
    };

    let ack_payload_log = json!({
        "data": terminal_write_data_diagnostic(&envelope.payload.data),
        "has_prompt_event_id": envelope
            .payload
            .prompt_event_id
            .as_deref()
            .is_some_and(|value| !value.trim().is_empty()),
        "has_prompt_event_text": envelope
            .payload
            .prompt_event_text
            .as_deref()
            .is_some_and(|value| !value.trim().is_empty()),
        "instance_id": envelope.payload.instance_id,
        "message_id": clean_terminal_diagnostic_log_text(&message_id),
        "pane_id": clean_terminal_diagnostic_log_text(&envelope.payload.pane_id),
        "prompt_event_id": envelope.payload.prompt_event_id.as_deref().unwrap_or_default(),
        "prompt_event_source": envelope.payload.prompt_event_source.as_deref().unwrap_or_default(),
        "prompt_text_len": envelope.payload.prompt_event_text.as_deref().map(str::len).unwrap_or_default(),
        "thread_id": envelope.payload.thread_id.as_deref().unwrap_or_default(),
    });
    log_terminal_status_event(
        "backend.terminal_input_transport.submit_received",
        ack_payload_log.clone(),
    );
    let ack_receiver = enqueue_terminal_input_event_with_ack(app, envelope.payload);
    let result = match timeout(Duration::from_secs(8), ack_receiver).await {
        Ok(Ok(result)) => result,
        Ok(Err(_)) => Err("Terminal input acknowledgement channel closed.".to_string()),
        Err(_) => Err("Terminal input write acknowledgement timed out.".to_string()),
    };
    let ok = result.is_ok();
    log_terminal_status_event(
        "backend.terminal_input_transport.submit_ack",
        json!({
            "error": result.as_ref().err().map(|value| clean_terminal_diagnostic_log_text(value)).unwrap_or_default(),
            "message_id": clean_terminal_diagnostic_log_text(&message_id),
            "ok": ok,
            "payload": ack_payload_log,
        }),
    );

    Some(Some(TerminalInputTransportAck {
        r#type: "terminal-input-ack",
        message_id,
        ok,
        error: result.err(),
    }))
}

fn register_terminal_input_event_listener(app: &tauri::App) {
    let app_handle = app.handle().clone();

    app.listen(TERMINAL_INPUT_EVENT, move |event| {
        let payload = match serde_json::from_str::<TerminalInputEventPayload>(event.payload()) {
            Ok(payload) => payload,
            Err(error) => {
                emit_terminal_input_error(
                    &app_handle,
                    String::new(),
                    None,
                    format!("Unable to parse terminal input event: {error}"),
                );
                return;
            }
        };
        enqueue_terminal_input_event(&app_handle, payload);
    });
}

async fn mark_terminal_parked_prompt_lifecycle_in_cloud(
    app: &AppHandle,
    cloud_mcp_state: &CloudMcpState,
    parked: &TerminalParkedPrompt,
    status: &str,
    body: &str,
) {
    cloud_mcp_mark_terminal_task_lifecycle(
        cloud_mcp_state,
        &parked.pane_id,
        parked.instance_id,
        &parked.working_directory,
        Some(&parked.coordination),
        Some(&parked.task_id),
        Some(&parked.title),
        status,
        body,
    )
    .await;
    cloud_mcp_record_voice_plan_terminal_lifecycle(app, cloud_mcp_state, parked, status, body)
        .await;
}

fn terminal_write_is_prompt_answer(
    prompt_event_source: Option<&str>,
    todo_action: Option<&str>,
) -> bool {
    [prompt_event_source, todo_action]
        .into_iter()
        .flatten()
        .any(|value| {
            matches!(
                terminal_projection_text(value, "").as_str(),
                "agent_prompt_answer"
                    | "answer_agent_prompt"
                    | "agent_input_answer"
                    | "terminal_prompt_answer"
                    | "prompt_answer"
            )
        })
}

fn terminal_write_source_is_model_change(prompt_event_source: Option<&str>) -> bool {
    prompt_event_source
        .map(|source| terminal_projection_text(source, ""))
        .is_some_and(|source| {
            matches!(
                source.as_str(),
                "model_change"
                    | "model-change"
                    | "remote_model_config"
                    | "remote-model-config"
                    | "remote_model_config_picker"
                    | "remote-model-config-picker"
                    | "startup_model_restore"
                    | "startup-model-restore"
            )
        })
}

fn terminal_write_source_is_permission_config(prompt_event_source: Option<&str>) -> bool {
    prompt_event_source
        .map(|source| terminal_projection_text(source, ""))
        .is_some_and(|source| {
            matches!(
                source.as_str(),
                "remote_permission_config"
                    | "remote-permission-config"
                    | "permission_config"
                    | "permission-config"
            )
        })
}

fn terminal_write_source_is_idle_escape(prompt_event_source: Option<&str>) -> bool {
    prompt_event_source
        .map(|source| terminal_projection_text(source, ""))
        .is_some_and(|source| matches!(source.as_str(), "terminal_idle_escape" | "terminal-idle-escape"))
}

fn terminal_write_source_suppresses_prompt_tracking(prompt_event_source: Option<&str>) -> bool {
    terminal_write_source_is_model_change(prompt_event_source)
        || terminal_write_source_is_permission_config(prompt_event_source)
        || terminal_write_source_is_idle_escape(prompt_event_source)
}

fn terminal_write_escape_should_interrupt(
    data: &str,
    coordination_active: bool,
    prompt_event_source: Option<&str>,
    todo_action: Option<&str>,
) -> bool {
    data == "\x1b"
        && coordination_active
        && !terminal_write_is_prompt_answer(prompt_event_source, todo_action)
        && !terminal_write_source_suppresses_prompt_tracking(prompt_event_source)
}

fn terminal_runtime_accepts_interrupt(runtime: &TerminalRuntimeSnapshot) -> bool {
    runtime.turn_active
        && !runtime.input_ready
        && matches!(
            terminal_projection_text(&runtime.canonical_state, "").as_str(),
            "thinking" | "uir" | "paused" | "waiting"
        )
}

#[derive(Clone, Copy, Debug, Eq, PartialEq, Serialize)]
#[serde(rename_all = "snake_case")]
enum TerminalInterruptOutcome {
    InterruptApplied,
    IdleNoop,
}

fn terminal_permission_config_input_is_allowed(data: &str) -> bool {
    if data.contains('\n') {
        return false;
    }
    if data.contains("/permissions") {
        return matches!(
            data,
            "/permissions" | "/permissions\r" | "\u{15}/permissions" | "\u{15}/permissions\r"
        );
    }
    if data.contains("/status") {
        return matches!(
            data,
            "/status" | "/status\r" | "\u{15}/status" | "\u{15}/status\r"
        );
    }
    if data == "\r" {
        return true;
    }
    let mut remaining = data;
    while !remaining.is_empty() {
        if let Some(rest) = remaining.strip_prefix('\u{15}') {
            remaining = rest;
        } else if let Some(rest) = remaining.strip_prefix("\x1b[B") {
            remaining = rest;
        } else if let Some(rest) = remaining.strip_prefix("\x1b[Z") {
            remaining = rest;
        } else if let Some(rest) = remaining.strip_prefix('\x1b') {
            remaining = rest;
        } else if let Some(rest) = remaining.strip_prefix('\t') {
            remaining = rest;
        } else {
            return false;
        }
    }
    true
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct TerminalCodexModelChangeRequest {
    command: String,
    model: String,
    effort: Option<String>,
    catalog_match: bool,
    effort_catalog_match: Option<bool>,
}

fn terminal_codex_model_change_effort_fallback_match(effort: &str) -> bool {
    AGENT_MODEL_CATALOG_CODEX_REASONING_EFFORTS
        .iter()
        .any(|candidate| candidate.eq_ignore_ascii_case(effort))
}

fn terminal_codex_model_change_request_from_input(
    data: &str,
) -> Option<TerminalCodexModelChangeRequest> {
    let command = data
        .replace(TERMINAL_ENTER_SEQUENCE_MOD1, "")
        .replace(TERMINAL_ENTER_SEQUENCE, "")
        .trim_matches(|ch| ch == '\r' || ch == '\n')
        .trim()
        .to_string();
    if !command.starts_with("/model ") || command.contains('\r') || command.contains('\n') {
        return None;
    }
    let mut parts = command.split_whitespace();
    let slash = parts.next()?;
    let model = parts.next()?;
    let effort = parts.next();
    if slash != "/model"
        || model.len() > 160
        || !model.chars().all(|character| {
            character.is_ascii_alphanumeric() || matches!(character, '.' | '_' | ':' | '/' | '-')
        })
        || parts.next().is_some()
    {
        return None;
    }
    let model = model.to_string();
    let effort = effort.map(str::to_string);
    if let Some(effort) = effort.as_deref() {
        if effort.len() > 40
            || !effort.chars().all(|character| {
                character.is_ascii_alphanumeric() || matches!(character, '_' | '-')
            })
        {
            return None;
        }
    }
    let catalog_entry = cloud_mcp_agent_model_catalog_entry_for_model("codex", &model);
    let catalog_match = catalog_entry.is_some();
    let effort_catalog_match = effort.as_deref().map(|effort| {
        catalog_entry
            .as_ref()
            .map(|entry| {
                entry
                    .reasoning_efforts
                    .iter()
                    .any(|candidate| candidate.eq_ignore_ascii_case(effort))
            })
            .unwrap_or_else(|| terminal_codex_model_change_effort_fallback_match(effort))
    });
    Some(TerminalCodexModelChangeRequest {
        command,
        model,
        effort,
        catalog_match,
        effort_catalog_match,
    })
}

fn terminal_codex_model_change_input_requests_submit(data: &str) -> bool {
    data.contains(TERMINAL_ENTER_SEQUENCE)
        || data.contains(TERMINAL_ENTER_SEQUENCE_MOD1)
        || data.contains('\r')
        || data.contains('\n')
}

async fn terminal_write_inner(
    app: AppHandle,
    state: &TerminalState,
    cloud_mcp_state: &CloudMcpState,
    pane_id: String,
    instance_id: Option<u64>,
    mut data: String,
    prompt_event_id: Option<String>,
    prompt_event_revision: Option<u64>,
    prompt_event_source: Option<String>,
    prompt_event_submitted_at: Option<String>,
    prompt_event_text: Option<String>,
    todo_id: Option<String>,
    todo_dispatch_id: Option<String>,
    todo_command_id: Option<String>,
    todo_action: Option<String>,
    todo_resume_requested: Option<bool>,
    thread_id: Option<String>,
    app_fork_enabled: Option<bool>,
    structured_answer_option_id: Option<String>,
    arm_structured_answer_confirmation: bool,
    _realtime_write: bool,
) -> Result<(), String> {
    validate_terminal_pane_id(&pane_id)?;
    let prompt_answer_requested =
        terminal_write_is_prompt_answer(prompt_event_source.as_deref(), todo_action.as_deref());
    let Some(instance) = get_terminal_instance_if_current(state, &pane_id, instance_id).await?
    else {
        write_thread_bridge_diagnostic_log_entry(json!({
            "ts_ms": current_time_ms(),
            "phase": "backend.bridge.terminal_write.missing_session_any_input",
            "source": "backend",
            "app_pid": std::process::id(),
            "thread": terminal_diagnostic_thread_label(),
            "fields": {
                "data": terminal_write_data_diagnostic(&data),
                "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "has_prompt_event_text": prompt_event_text.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "thread_id": thread_id.as_deref().unwrap_or_default(),
            },
        }));
        if prompt_event_text
            .as_deref()
            .is_some_and(|value| !value.trim().is_empty())
        {
            write_thread_bridge_diagnostic_log_entry(json!({
                "ts_ms": current_time_ms(),
                "phase": "backend.bridge.terminal_write.missing_session",
                "source": "backend",
                "app_pid": std::process::id(),
                "thread": terminal_diagnostic_thread_label(),
                "fields": {
                    "data_len": data.len(),
                    "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                    "has_prompt_event_text": true,
                    "instance_id": instance_id,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "thread_id": thread_id.as_deref().unwrap_or_default(),
                },
            }));
            return Err("Terminal session is not running.".to_string());
        }
        if prompt_answer_requested {
            return Err("Terminal session is not running.".to_string());
        }
        return Ok(());
    };
    // Claim the pane before app-fork/coordination awaits and retain the claim
    // through activity publication and the PTY flush. An idle restart cannot
    // discard a prompt that was admitted from the inventory snapshot.
    let Some(_operation) = terminal_operation_try_admit(&instance) else {
        return Err("Terminal session is closing.".to_string());
    };
    let mut prompt_event_id = prompt_event_id;
    let mut prompt_event_text = prompt_event_text;
    if terminal_write_source_is_permission_config(prompt_event_source.as_deref())
        && !terminal_permission_config_input_is_allowed(&data)
    {
        return Err(
            "Remote permission configuration input contained an invalid command sequence."
                .to_string(),
        );
    }
    if terminal_metadata_is_codex(&instance.metadata)
        && terminal_write_source_is_model_change(prompt_event_source.as_deref())
    {
        if let Some(model_change) = terminal_codex_model_change_request_from_input(&data) {
            let runtime = terminal_runtime_snapshot(&instance);
            let submit = terminal_codex_model_change_input_requests_submit(&data);
            if !model_change.catalog_match || model_change.effort_catalog_match == Some(false) {
                log_terminal_status_event(
                    "backend.agent_chat_model_change.catalog_warning",
                    json!({
                        "agent_id": clean_terminal_diagnostic_log_text(&instance.metadata.agent_id),
                        "catalog_match": model_change.catalog_match,
                        "effort": model_change.effort.as_deref().unwrap_or_default(),
                        "effort_catalog_match": model_change.effort_catalog_match,
                        "instance_id": instance.id,
                        "level": "warning",
                        "model": clean_terminal_diagnostic_log_text(&model_change.model),
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "provider": clean_terminal_diagnostic_log_text(&instance.metadata.agent_kind),
                    }),
                );
            }
            log_terminal_status_event(
                "backend.agent_chat_model_change.inject",
                json!({
                    "agent_id": clean_terminal_diagnostic_log_text(&instance.metadata.agent_id),
                    "catalog_match": model_change.catalog_match,
                    "command_len": model_change.command.len(),
                    "effort": model_change.effort.as_deref().unwrap_or_default(),
                    "effort_catalog_match": model_change.effort_catalog_match,
                    "had_enhanced_enter": data.contains(TERMINAL_ENTER_SEQUENCE) || data.contains(TERMINAL_ENTER_SEQUENCE_MOD1),
                    "had_plain_enter": data.contains('\r') || data.contains('\n'),
                    "instance_id": instance.id,
                    "launch_mode": terminal_activity_watchdog_launch_mode(&runtime),
                    "model": clean_terminal_diagnostic_log_text(&model_change.model),
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "provider": clean_terminal_diagnostic_log_text(&instance.metadata.agent_kind),
                    "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                    "runtime_source": clean_terminal_diagnostic_log_text(&runtime.source),
                    "sequence": if submit { "ctrl_u_slash_model_plain_cr" } else { "ctrl_u_slash_model_defer_submit" },
                }),
            );
            return Err(
                "Codex model changes must use the native /model picker transaction; refusing to send an inline /model value as chat input."
                    .to_string(),
            );
        }
    }
    if terminal_write_source_suppresses_prompt_tracking(prompt_event_source.as_deref()) {
        prompt_event_id = None;
        prompt_event_text = None;
    }
    let prompt_submission_text = prompt_event_text
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let prompt_submission_requested = prompt_submission_text.is_some();
    if prompt_submission_requested {
        log_terminal_status_event(
            "backend.terminal_write.prompt_start",
            json!({
                "data": terminal_write_data_diagnostic(&data),
                "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "instance_id": instance.id,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                "prompt_text_len": prompt_event_text.as_deref().map(str::len).unwrap_or_default(),
                "thread_id": thread_id.as_deref().unwrap_or_default(),
            }),
        );
    }
    if app_fork_enabled.unwrap_or(false) {
        let fork_preview_data = normalize_terminal_enter_sequences_for_pty(data.clone());
        if terminal_try_emit_app_fork_request(
            &app,
            &instance,
            &pane_id,
            thread_id.as_deref(),
            &fork_preview_data,
            "terminal_write",
        )
        .await
        {
            return Ok(());
        }
    }
    if prompt_submission_requested {
        if let Some(coordination) = instance.coordination.clone() {
            let readiness = tauri::async_runtime::spawn_blocking(move || {
                ensure_terminal_coordination_ready_for_prompt(&coordination)
            })
            .await
            .map_err(|error| {
                format!("Unable to validate coordination session before prompt submit: {error}")
            })?;
            if let Err(error) = readiness {
                log_terminal_status_event(
                    "backend.terminal_write.prompt_coordination_not_ready",
                    json!({
                        "error": clean_terminal_diagnostic_log_text(&error),
                        "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                        "instance_id": instance.id,
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                        "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                        "prompt_text_len": prompt_event_text.as_deref().map(str::len).unwrap_or_default(),
                        "thread_id": thread_id.as_deref().unwrap_or_default(),
                    }),
                );
                write_thread_bridge_diagnostic_log_entry(json!({
                    "ts_ms": current_time_ms(),
                    "phase": "backend.bridge.terminal_write.coordination_not_ready",
                    "source": "backend",
                    "app_pid": std::process::id(),
                    "thread": terminal_diagnostic_thread_label(),
                    "fields": {
                        "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                        "has_prompt_event_text": true,
                        "instance_id": instance.id,
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "thread_id": thread_id.as_deref().unwrap_or_default(),
                    },
                }));
                return Err(error);
            }
        }
    }
    if let Some(event_prompt) = prompt_submission_text
        .as_deref()
        .filter(|value| !is_terminal_control_prompt(value))
    {
        let resolved_prompt_event_id = prompt_event_id
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string)
            .unwrap_or_else(|| {
                terminal_prompt_fallback_event_id(
                    &pane_id,
                    instance.id,
                    terminal_now_ms(),
                    event_prompt,
                )
            });
        prompt_event_id = Some(resolved_prompt_event_id);
        emit_terminal_prompt_submitted_activity_started(
            &app,
            &instance,
            event_prompt,
            prompt_event_id.as_deref(),
            prompt_event_submitted_at.as_deref(),
            "terminal_write_prompt_submit",
            thread_id.as_deref(),
        );
        log_terminal_status_event(
            "backend.terminal_write.prompt_first_paint_emitted",
            json!({
                "has_prompt_event_id": true,
                "instance_id": instance.id,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                "prompt_text_len": event_prompt.len(),
                "thread_id": thread_id.as_deref().unwrap_or_default(),
            }),
        );
    }
    let _input_guard = instance.input_queue.lock().await;
    let original_data_diagnostic = terminal_write_data_diagnostic(&data);
    let data = normalize_terminal_enter_sequences_for_pty(data);
    let normalized_data_diagnostic = terminal_write_data_diagnostic(&data);
    let input_write_diagnostic_kind =
        terminal_input_write_diagnostic_kind(&data, &prompt_event_id, &prompt_event_text);
    write_thread_bridge_diagnostic_log_entry(json!({
        "ts_ms": current_time_ms(),
        "phase": "backend.bridge.input_write_any_start",
        "source": "backend",
        "app_pid": std::process::id(),
        "thread": terminal_diagnostic_thread_label(),
        "fields": {
            "diagnostic_kind": input_write_diagnostic_kind.unwrap_or("raw_input"),
            "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
            "has_prompt_event_text": prompt_event_text.as_deref().is_some_and(|value| !value.trim().is_empty()),
            "instance_id": instance.id,
            "normalized_data": normalized_data_diagnostic.clone(),
            "original_data": original_data_diagnostic.clone(),
            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
            "thread_id": thread_id.as_deref().unwrap_or_default(),
        },
    }));

    let structured_answer_bypasses_interrupt = arm_structured_answer_confirmation
        && terminal_structured_interaction_for_written_answer(
            state,
            &pane_id,
            instance.id,
            prompt_event_id.as_deref(),
            prompt_event_revision,
        )
        .is_some_and(|interaction| {
            terminal_structured_answer_bypasses_interrupt(&interaction, &data)
        });
    let escape_interrupt_candidate = !structured_answer_bypasses_interrupt
        && terminal_write_escape_should_interrupt(
            &data,
            instance.coordination.is_some(),
            prompt_event_source.as_deref(),
            todo_action.as_deref(),
        );
    let escape_should_interrupt = if escape_interrupt_candidate {
        let interrupt_runtime = terminal_runtime_snapshot(&instance);
        let accepts_interrupt = terminal_runtime_accepts_interrupt(&interrupt_runtime);
        if !accepts_interrupt {
            log_terminal_status_event(
                "backend.terminal_write.escape_idle_fallthrough",
                json!({
                    "canonical_state": interrupt_runtime.canonical_state,
                    "input_ready": interrupt_runtime.input_ready,
                    "instance_id": instance.id,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "turn_active": interrupt_runtime.turn_active,
                }),
            );
        }
        accepts_interrupt
    } else {
        false
    };
    if escape_should_interrupt {
        let active_task_id = instance
            .active_task
            .lock()
            .await
            .as_ref()
            .map(|task| task.task_id.clone());
        write_terminal_interrupt_escape(&instance).await?;
        let publish_outcome = publish_terminal_provider_turn_interrupted(
            &app,
            state,
            cloud_mcp_state,
            &instance,
            "escape_key",
        )
        .await?;
        if publish_outcome == TerminalInterruptOutcome::IdleNoop {
            return Ok(());
        }
        mark_terminal_active_task_interrupted(
            cloud_mcp_state,
            &pane_id,
            &instance,
            "escape_key",
            "Interrupted by Escape; the terminal remains open for follow-up instructions.",
        )
        .await?;
        interrupt_terminal_parked_prompts(
            &app,
            state,
            cloud_mcp_state,
            &pane_id,
            &instance,
            "escape_key",
            active_task_id.as_deref(),
        )
        .await?;
        todo_dispatch_mark_active_for_pane_interrupted(
            &app,
            &instance.metadata.workspace_id,
            &pane_id,
            "escape_key",
        );
        return Ok(());
    }

    if let Some(diagnostic_kind) = input_write_diagnostic_kind {
        let input_gate_before_write = {
            let gate = instance.input_gate.lock().await;
            terminal_input_gate_diagnostic_snapshot(&gate)
        };
        write_thread_bridge_diagnostic_log_entry(json!({
            "ts_ms": current_time_ms(),
            "phase": "backend.bridge.input_write_start",
            "source": "backend",
            "app_pid": std::process::id(),
            "thread": terminal_diagnostic_thread_label(),
            "fields": {
                "diagnostic_kind": diagnostic_kind,
                "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "has_prompt_event_text": prompt_event_text.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "input_gate_before_write": input_gate_before_write,
                "instance_id": instance.id,
                "normalized_data": normalized_data_diagnostic.clone(),
                "original_data": original_data_diagnostic.clone(),
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "thread_id": thread_id.as_deref().unwrap_or_default(),
            },
        }));
    }

    let mut claimed_structured_answer = None;
    if arm_structured_answer_confirmation {
        if let Some(interaction) = terminal_structured_interaction_for_written_answer(
            state,
            &pane_id,
            instance.id,
            prompt_event_id.as_deref(),
            prompt_event_revision,
        ) {
            let local_option_id = terminal_structured_answer_local_option(&interaction, &data);
            let claimed_option_id = structured_answer_option_id
                .as_deref()
                .or(local_option_id.as_deref());
            let submitted_structured_answer = prompt_answer_requested
                || local_option_id.is_some()
                || terminal_structured_answer_local_submission(&data);
            if submitted_structured_answer
                && !terminal_structured_answer_keeps_open_for_input(&interaction, &data)
            {
                let runtime = terminal_runtime_snapshot(&instance);
                let still_prompting =
                    terminal_runtime_is_prompting_for_structured_interaction(&runtime);
                let confirmation_already_arms_write =
                    terminal_structured_answer_confirmation_allows_continuation(
                        &interaction,
                        &data,
                    );
                let claimed = still_prompting
                    && (terminal_structured_interaction_arm_answer_confirmation_timeout(
                        &app,
                        interaction.clone(),
                        claimed_option_id.unwrap_or_default(),
                    ) || confirmation_already_arms_write);
                if !claimed {
                    if !still_prompting {
                        terminal_structured_interaction_remove_generation(state, &interaction);
                    }
                    // The per-instance input queue serializes local and remote
                    // writers. Claiming the exact generation here, immediately
                    // before the PTY write, makes a late second answer a no-op.
                    if prompt_answer_requested {
                        return Err(STRUCTURED_INTERACTION_ALREADY_RESOLVED_ERROR.to_string());
                    }
                    return Ok(());
                }
                claimed_structured_answer = Some(interaction);
            }
        }
    }

    let input_write_started_at = Instant::now();
    let input_write_result = match write_terminal_input(
        Some(&app),
        state,
        &pane_id,
        instance_id,
        &data,
        claimed_structured_answer.as_ref(),
        "terminal.write.skipped_stale_or_missing",
    )
    .await
    {
        Ok(value) => value,
        Err(error) => {
            if prompt_submission_requested {
                log_terminal_status_event(
                    "backend.terminal_write.prompt_write_error",
                    json!({
                        "elapsed_ms": terminal_diagnostic_elapsed_ms(input_write_started_at),
                        "error": clean_terminal_diagnostic_log_text(&error),
                        "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                        "instance_id": instance.id,
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                        "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                        "prompt_text_len": prompt_event_text.as_deref().map(str::len).unwrap_or_default(),
                        "thread_id": thread_id.as_deref().unwrap_or_default(),
                    }),
                );
            }
            return Err(error);
        }
    };
    let input_write_elapsed_ms = terminal_diagnostic_elapsed_ms(input_write_started_at);
    if !input_write_result && claimed_structured_answer.is_some() {
        if prompt_answer_requested {
            return Err(STRUCTURED_INTERACTION_ALREADY_RESOLVED_ERROR.to_string());
        }
        return Ok(());
    }
    if prompt_answer_requested && !input_write_result {
        return Err("Agent prompt answer was not written to the terminal.".to_string());
    }
    if prompt_submission_requested {
        log_terminal_status_event(
            "backend.terminal_write.prompt_write_done",
            json!({
                "elapsed_ms": input_write_elapsed_ms,
                "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "instance_id": instance.id,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                "prompt_text_len": prompt_event_text.as_deref().map(str::len).unwrap_or_default(),
                "thread_id": thread_id.as_deref().unwrap_or_default(),
                "wrote": input_write_result,
            }),
        );
    }
    write_thread_bridge_diagnostic_log_entry(json!({
        "ts_ms": current_time_ms(),
        "phase": "backend.bridge.input_write_any_done",
        "source": "backend",
        "app_pid": std::process::id(),
        "thread": terminal_diagnostic_thread_label(),
        "fields": {
            "diagnostic_kind": input_write_diagnostic_kind.unwrap_or("raw_input"),
            "elapsed_ms": input_write_elapsed_ms,
            "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
            "has_prompt_event_text": prompt_event_text.as_deref().is_some_and(|value| !value.trim().is_empty()),
            "instance_id": instance.id,
            "normalized_data": normalized_data_diagnostic.clone(),
            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
            "thread_id": thread_id.as_deref().unwrap_or_default(),
            "wrote": input_write_result,
        },
    }));
    if let Some(diagnostic_kind) = input_write_diagnostic_kind {
        write_thread_bridge_diagnostic_log_entry(json!({
            "ts_ms": current_time_ms(),
            "phase": "backend.bridge.input_write_done",
            "source": "backend",
            "app_pid": std::process::id(),
            "thread": terminal_diagnostic_thread_label(),
            "fields": {
                "diagnostic_kind": diagnostic_kind,
                "elapsed_ms": input_write_elapsed_ms,
                "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "has_prompt_event_text": prompt_event_text.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "instance_id": instance.id,
                "normalized_data": normalized_data_diagnostic.clone(),
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "thread_id": thread_id.as_deref().unwrap_or_default(),
                "wrote": input_write_result,
            },
        }));
    }

    let (observed_prompt, input_gate_before, input_gate_after) =
        terminal_observe_submitted_prompt(&instance, &data).await;
    if let Some(prompt) = observed_prompt {
        let requested_event_prompt = prompt_event_text
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string);
        if is_terminal_control_prompt(&prompt) {
            write_thread_bridge_diagnostic_log_entry(json!({
                "ts_ms": current_time_ms(),
                "phase": "backend.bridge.prompt_observed_control_skip",
                "source": "backend",
                "app_pid": std::process::id(),
                "thread": terminal_diagnostic_thread_label(),
                "fields": {
                    "data_len": data.len(),
                    "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                    "has_prompt_event_text": prompt_event_text.as_deref().is_some_and(|value| !value.trim().is_empty()),
                    "instance_id": instance.id,
                    "normalized_data": normalized_data_diagnostic.clone(),
                    "observed_prompt_len": prompt.len(),
                    "original_data": original_data_diagnostic.clone(),
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "prompt_prefix": clean_terminal_diagnostic_log_text(prompt.split_whitespace().next().unwrap_or_default()),
                    "thread_id": thread_id.as_deref().unwrap_or_default(),
                },
            }));
            return Ok(());
        }
        let prompt_event_text_matches_observed = requested_event_prompt
            .as_ref()
            .map(|value| value == &prompt)
            .unwrap_or(true);
        let event_prompt = prompt.clone();
        let submitted_prompt_source = if prompt_event_text_matches_observed {
            "observed_input_gate"
        } else {
            "observed_input_gate_mismatch"
        };
        let submitted_prompt_authoritative = terminal_prompt_submitted_source_is_authoritative(
            submitted_prompt_source,
            prompt_event_text_matches_observed,
            Some(&prompt),
        );
        emit_terminal_prompt_submitted(
            &app,
            &instance,
            &event_prompt,
            prompt_event_id.as_deref(),
            prompt_event_revision,
            prompt_event_source.as_deref(),
            prompt_event_submitted_at.as_deref(),
            todo_id.as_deref(),
            todo_dispatch_id.as_deref(),
            todo_command_id.as_deref(),
            todo_action.as_deref(),
            todo_resume_requested.unwrap_or(false),
            requested_event_prompt.as_deref(),
            Some(&prompt),
            prompt_event_text_matches_observed,
            submitted_prompt_source,
            thread_id.as_deref(),
        );
        if submitted_prompt_authoritative && !terminal_runtime_has_provider_session(&instance) {
            // Harness session stores can materialize only after the first
            // prompt, after launch-time discovery has elapsed. Re-arm exact
            // prompt discovery so the provider session enters live state
            // without waiting for periodic reconciliation. Native hook IDs
            // still win whenever they arrive first.
            let normalized_agent =
                terminal_normalize_agent_kind(Some(&instance.metadata.agent_kind))
                    .or_else(|| terminal_normalize_agent_kind(Some(&instance.metadata.agent_id)))
                    .unwrap_or_default();
            log_terminal_status_event(
                "backend.terminal_provider_session.prompt_discovery_armed",
                json!({
                    "agent_id": normalized_agent.clone(),
                    "instance_id": instance.id,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                    "source": submitted_prompt_source,
                    "workspace_id": clean_terminal_diagnostic_log_text(&instance.metadata.workspace_id),
                }),
            );
            if normalized_agent == "codex" {
                spawn_terminal_codex_session_discovery(
                    app.clone(),
                    Arc::clone(&state.terminals),
                    pane_id.clone(),
                    instance.id,
                    terminal_now_ms().saturating_sub(30_000),
                    "terminal_prompt_submitted",
                    &TERMINAL_PROMPT_SESSION_DISCOVERY_DELAYS_MS,
                );
            } else if matches!(normalized_agent.as_str(), "claude" | "opencode") {
                spawn_terminal_non_codex_session_discovery_for_prompt(
                    app.clone(),
                    Arc::clone(&state.terminals),
                    pane_id.clone(),
                    instance.id,
                    event_prompt.clone(),
                    "terminal_prompt_submitted",
                );
            }
        }
        log_terminal_status_event(
            "backend.terminal_write.prompt_observed",
            json!({
                "event_prompt_len": event_prompt.len(),
                "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "input_gate_after": input_gate_after,
                "input_gate_before": input_gate_before,
                "instance_id": instance.id,
                "observed_prompt_len": prompt.len(),
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                "prompt_event_text_matches_observed": prompt_event_text_matches_observed,
                "submitted_event_prompt_authoritative": submitted_prompt_authoritative,
                "submitted_event_prompt_source": submitted_prompt_source,
                "thread_id": thread_id.as_deref().unwrap_or_default(),
            }),
        );
        write_thread_bridge_diagnostic_log_entry(json!({
            "ts_ms": current_time_ms(),
            "phase": "backend.bridge.prompt_observed",
            "source": "backend",
            "app_pid": std::process::id(),
            "thread": terminal_diagnostic_thread_label(),
            "fields": {
                "data_len": data.len(),
                "event_prompt_len": event_prompt.len(),
                "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "has_prompt_event_text": prompt_event_text.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "input_gate_after": input_gate_after,
                "input_gate_before": input_gate_before,
                "instance_id": instance.id,
                "normalized_data": normalized_data_diagnostic,
                "observed_prompt_len": prompt.len(),
                "observer_reason": "submitted_prompt_observed",
                "original_data": original_data_diagnostic,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "prompt_event_text_len": requested_event_prompt.as_deref().map(str::len).unwrap_or_default(),
                "prompt_event_text_matches_observed": prompt_event_text_matches_observed,
                "submitted_event_prompt_authoritative": submitted_prompt_authoritative,
                "submitted_event_prompt_source": submitted_prompt_source,
                "thread_id": thread_id.as_deref().unwrap_or_default(),
            },
        }));
        if submitted_prompt_authoritative && *instance.agent_started.lock().await {
            let cloud_state = cloud_mcp_state.clone();
            let pane_id_for_context = pane_id.clone();
            let working_directory = instance.working_directory.as_ref().clone();
            let coordination = instance.coordination.clone();
            let session_mode = instance.session_mode;
            let terminal_instance_id = instance.id;
            let active_task = instance.active_task.lock().await.clone();
            let local_task_id = active_task.as_ref().map(|task| task.task_id.clone());
            let local_task_title = active_task.as_ref().map(|task| task.title.clone());
            let metadata = instance.metadata.clone();
            let prompt_metadata = CloudMcpTerminalPromptMetadata {
                prompt_event_id: prompt_event_id.clone(),
                prompt_event_source: prompt_event_source.clone(),
                prompt_event_submitted_at: prompt_event_submitted_at.clone(),
                todo_id: todo_id.clone(),
                todo_dispatch_id: todo_dispatch_id.clone(),
                todo_command_id: todo_command_id.clone(),
                todo_action: todo_action.clone(),
                todo_resume_requested: todo_resume_requested.unwrap_or(false),
                terminal_index: metadata.terminal_index,
                thread_id: thread_id
                    .clone()
                    .or_else(|| Some(metadata.thread_id.clone())),
                workspace_id: metadata.workspace_id.clone(),
                workspace_name: metadata.workspace_name.clone(),
            };
            let prompt_for_cloud = prompt.clone();
            tauri::async_runtime::spawn(async move {
                cloud_mcp_terminal_context_pack_for_prompt(
                    cloud_state,
                    pane_id_for_context,
                    terminal_instance_id,
                    working_directory,
                    coordination,
                    session_mode,
                    local_task_id,
                    local_task_title,
                    prompt_for_cloud,
                    Some(prompt_metadata),
                )
                .await;
            });
        }
    } else if prompt_event_id
        .as_deref()
        .is_some_and(|value| !value.trim().is_empty())
        || prompt_event_text
            .as_deref()
            .is_some_and(|value| !value.trim().is_empty())
    {
        let observer_reason = terminal_prompt_observer_not_observed_reason(
            &data,
            &input_gate_before,
            &input_gate_after,
        );
        write_thread_bridge_diagnostic_log_entry(json!({
            "ts_ms": current_time_ms(),
            "phase": "backend.bridge.prompt_not_observed",
            "source": "backend",
            "app_pid": std::process::id(),
            "thread": terminal_diagnostic_thread_label(),
            "fields": {
                "data_len": data.len(),
                "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "has_prompt_event_text": prompt_event_text.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "input_gate_after": input_gate_after,
                "input_gate_before": input_gate_before,
                "instance_id": instance.id,
                "normalized_data": normalized_data_diagnostic,
                "observer_reason": observer_reason,
                "original_data": original_data_diagnostic,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "thread_id": thread_id.as_deref().unwrap_or_default(),
            },
        }));
        log_terminal_status_event(
            "backend.terminal_write.prompt_not_observed",
            json!({
                "data_len": data.len(),
                "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                "input_gate_after": input_gate_after,
                "input_gate_before": input_gate_before,
                "instance_id": instance.id,
                "observer_reason": observer_reason,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                "prompt_text_len": prompt_event_text.as_deref().map(str::len).unwrap_or_default(),
                "thread_id": thread_id.as_deref().unwrap_or_default(),
            }),
        );
        if let Some(event_prompt) = prompt_event_text
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string)
        {
            if observer_reason == "submit_with_empty_input_gate" {
                if terminal_prompt_event_source_allows_empty_gate_metadata_diagnostic(
                    prompt_event_source.as_deref(),
                ) {
                    log_terminal_status_event(
                        "backend.terminal_write.prompt_event_text_empty_gate_diagnostic",
                        json!({
                            "data_len": data.len(),
                            "instance_id": instance.id,
                            "observer_reason": observer_reason,
                            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                            "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                            "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                            "prompt_text_len": event_prompt.len(),
                            "thread_id": thread_id.as_deref().unwrap_or_default(),
                        }),
                    );
                    write_thread_bridge_diagnostic_log_entry(json!({
                        "ts_ms": current_time_ms(),
                        "phase": "backend.bridge.prompt_event_text_empty_gate_diagnostic",
                        "source": "backend",
                        "app_pid": std::process::id(),
                        "thread": terminal_diagnostic_thread_label(),
                        "fields": {
                            "data_len": data.len(),
                            "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                            "has_prompt_event_text": true,
                            "instance_id": instance.id,
                            "normalized_data": normalized_data_diagnostic.clone(),
                            "observer_reason": observer_reason,
                            "original_data": original_data_diagnostic.clone(),
                            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                            "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                            "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                            "prompt_text_len": event_prompt.len(),
                            "thread_id": thread_id.as_deref().unwrap_or_default(),
                        },
                    }));
                } else {
                    log_terminal_status_event(
                        "backend.terminal_write.prompt_event_text_empty_gate_skip",
                        json!({
                            "data_len": data.len(),
                            "instance_id": instance.id,
                            "observer_reason": observer_reason,
                            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                            "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                            "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                            "prompt_text_len": event_prompt.len(),
                            "status_truth": "prompt_submit_not_authoritative",
                            "thread_id": thread_id.as_deref().unwrap_or_default(),
                        }),
                    );
                    write_thread_bridge_diagnostic_log_entry(json!({
                        "ts_ms": current_time_ms(),
                        "phase": "backend.bridge.prompt_event_text_empty_gate_skip",
                        "source": "backend",
                        "app_pid": std::process::id(),
                        "thread": terminal_diagnostic_thread_label(),
                        "fields": {
                            "data_len": data.len(),
                            "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                            "has_prompt_event_text": true,
                            "instance_id": instance.id,
                            "normalized_data": normalized_data_diagnostic.clone(),
                            "observer_reason": observer_reason,
                            "original_data": original_data_diagnostic.clone(),
                            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                            "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                            "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                            "prompt_text_len": event_prompt.len(),
                            "thread_id": thread_id.as_deref().unwrap_or_default(),
                        },
                    }));
                    return Ok(());
                }
            }
            if is_terminal_control_prompt(&event_prompt) {
                write_thread_bridge_diagnostic_log_entry(json!({
                    "ts_ms": current_time_ms(),
                    "phase": "backend.bridge.prompt_event_text_control_skip",
                    "source": "backend",
                    "app_pid": std::process::id(),
                    "thread": terminal_diagnostic_thread_label(),
                    "fields": {
                        "data_len": data.len(),
                        "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                        "has_prompt_event_text": true,
                        "instance_id": instance.id,
                        "normalized_data": normalized_data_diagnostic.clone(),
                        "original_data": original_data_diagnostic.clone(),
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "prompt_prefix": clean_terminal_diagnostic_log_text(event_prompt.split_whitespace().next().unwrap_or_default()),
                        "thread_id": thread_id.as_deref().unwrap_or_default(),
                    },
                }));
                return Ok(());
            }
            if data.contains('\r') || data.contains('\n') {
                log_terminal_status_event(
                    "backend.terminal_write.prompt_event_submit_metadata_skip",
                    json!({
                        "data_len": data.len(),
                        "instance_id": instance.id,
                        "observer_reason": observer_reason,
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                        "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                        "prompt_text_len": event_prompt.len(),
                        "status_truth": "prompt_submit_not_observed",
                        "thread_id": thread_id.as_deref().unwrap_or_default(),
                    }),
                );
                write_thread_bridge_diagnostic_log_entry(json!({
                    "ts_ms": current_time_ms(),
                    "phase": "backend.bridge.prompt_event_submit_metadata_skip",
                    "source": "backend",
                    "app_pid": std::process::id(),
                    "thread": terminal_diagnostic_thread_label(),
                    "fields": {
                        "data_len": data.len(),
                        "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                        "has_prompt_event_text": true,
                        "instance_id": instance.id,
                        "observer_reason": observer_reason,
                        "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                        "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                        "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                        "prompt_text_len": event_prompt.len(),
                        "thread_id": thread_id.as_deref().unwrap_or_default(),
                    },
                }));
                return Ok(());
            }
            log_terminal_status_event(
                "backend.terminal_write.prompt_event_text_unobserved_skip",
                json!({
                    "data_len": data.len(),
                    "instance_id": instance.id,
                    "observer_reason": observer_reason,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                    "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                    "prompt_text_len": event_prompt.len(),
                    "status_truth": "prompt_submit_not_authoritative",
                    "thread_id": thread_id.as_deref().unwrap_or_default(),
                }),
            );
            write_thread_bridge_diagnostic_log_entry(json!({
                "ts_ms": current_time_ms(),
                "phase": "backend.bridge.prompt_event_text_unobserved_skip",
                "source": "backend",
                "app_pid": std::process::id(),
                "thread": terminal_diagnostic_thread_label(),
                "fields": {
                    "data_len": data.len(),
                    "has_prompt_event_id": prompt_event_id.as_deref().is_some_and(|value| !value.trim().is_empty()),
                    "has_prompt_event_text": true,
                    "instance_id": instance.id,
                    "observer_reason": observer_reason,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "prompt_event_id": prompt_event_id.as_deref().unwrap_or_default(),
                    "prompt_event_source": prompt_event_source.as_deref().unwrap_or_default(),
                    "prompt_text_len": event_prompt.len(),
                    "thread_id": thread_id.as_deref().unwrap_or_default(),
                },
            }));
            return Ok(());
        }
    } else if let Some(diagnostic_kind) = input_write_diagnostic_kind {
        let observer_reason = terminal_prompt_observer_not_observed_reason(
            &data,
            &input_gate_before,
            &input_gate_after,
        );
        write_thread_bridge_diagnostic_log_entry(json!({
            "ts_ms": current_time_ms(),
            "phase": "backend.bridge.input_observed_no_submit",
            "source": "backend",
            "app_pid": std::process::id(),
            "thread": terminal_diagnostic_thread_label(),
            "fields": {
                "data_len": data.len(),
                "diagnostic_kind": diagnostic_kind,
                "input_gate_after": input_gate_after,
                "input_gate_before": input_gate_before,
                "instance_id": instance.id,
                "normalized_data": normalized_data_diagnostic,
                "observer_reason": observer_reason,
                "original_data": original_data_diagnostic,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                "thread_id": thread_id.as_deref().unwrap_or_default(),
            },
        }));
    }

    Ok(())
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_write(
    app: AppHandle,
    state: State<'_, TerminalState>,
    cloud_mcp_state: State<'_, CloudMcpState>,
    pane_id: String,
    instance_id: Option<u64>,
    data: String,
    prompt_event_id: Option<String>,
    prompt_event_revision: Option<u64>,
    prompt_event_source: Option<String>,
    prompt_event_submitted_at: Option<String>,
    prompt_event_text: Option<String>,
    todo_id: Option<String>,
    todo_dispatch_id: Option<String>,
    todo_command_id: Option<String>,
    todo_action: Option<String>,
    todo_resume_requested: Option<bool>,
    thread_id: Option<String>,
    app_fork_enabled: Option<bool>,
) -> Result<(), String> {
    terminal_write_inner(
        app.clone(),
        state.inner(),
        cloud_mcp_state.inner(),
        pane_id,
        instance_id,
        data,
        prompt_event_id,
        prompt_event_revision,
        prompt_event_source,
        prompt_event_submitted_at,
        prompt_event_text,
        todo_id,
        todo_dispatch_id,
        todo_command_id,
        todo_action,
        todo_resume_requested,
        thread_id,
        app_fork_enabled,
        None,
        true,
        false,
    )
    .await
}

fn terminal_agent_kind_is_codex(value: &str) -> bool {
    terminal_projection_text(value, "") == "codex"
}

fn terminal_codex_hook_trust_prompt_answer_input(key: &str) -> Option<String> {
    match key {
        "trust_all_and_continue" | "trustallandcontinue" | "trust" | "2" => Some("2\r".to_string()),
        "continue_without_trusting" | "continuewithouttrusting" | "without_trusting" | "3" => {
            Some("3\r".to_string())
        }
        "review_hooks" | "reviewhooks" | "review" | "1" => Some("1\r".to_string()),
        _ => None,
    }
}

fn terminal_codex_hook_trust_answer_keeps_open(provider_request_id: &str, option_id: &str) -> bool {
    terminal_codex_hook_trust_is_catalog_request(provider_request_id)
        && terminal_activity_hook_prompt_option_id(option_id) == "review_hooks"
}

fn terminal_codex_hook_trust_is_catalog_request(provider_request_id: &str) -> bool {
    provider_request_id.starts_with("codex-hook-trust-catalog-")
}

fn terminal_codex_hook_trust_is_fail_closed_request(provider_request_id: &str) -> bool {
    provider_request_id.starts_with("codex-hook-trust-error-")
}

fn terminal_codex_hook_trust_prompt_options() -> Vec<Value> {
    vec![
        json!({
            "id": "review_hooks",
            "label": "Review hooks",
            "value": "1",
            "description": "Open Codex's native hook-review screen before deciding."
        }),
        json!({
            "id": "trust_all_and_continue",
            "label": "Trust all and continue",
            "value": "2",
            "danger": true,
            "description": "Trust the exact hook hashes listed above and allow them to run."
        }),
        json!({
            "id": "continue_without_trusting",
            "label": "Continue without trusting",
            "value": "3",
            "description": "Continue this Codex session with these hooks disabled."
        }),
    ]
}

fn terminal_agent_prompt_answer_input(
    agent_kind: &str,
    option_id: &str,
    option_label: &str,
    option_value: Option<&str>,
) -> String {
    let option_key = terminal_activity_hook_prompt_option_id(option_id);
    let label_key = terminal_activity_hook_prompt_option_id(option_label);
    let value_key = option_value
        .map(terminal_activity_hook_prompt_option_id)
        .unwrap_or_default();
    let key = [option_key.as_str(), label_key.as_str(), value_key.as_str()]
        .into_iter()
        .find(|value| !value.is_empty())
        .unwrap_or_default();
    if terminal_agent_kind_is_codex(agent_kind) {
        if let Some(input) = terminal_codex_hook_trust_prompt_answer_input(key) {
            return input;
        }
    }
    if let Some(value) = option_value
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        return format!("{value}\r");
    }
    let key = if key.is_empty() { option_id } else { key };
    match key {
        "allow" | "allow_once" | "approve" | "approved" | "once" | "yes" | "y" => "y\r".to_string(),
        "allow_always" | "always" | "approve_always" => "a\r".to_string(),
        "deny" | "denied" | "no" | "n" | "reject" | "rejected" => "n\r".to_string(),
        "cancel" | "escape" | "interrupt" | "park" | "skip" => "\x1b".to_string(),
        "continue" | "default" | "enter" | "ok" => "\r".to_string(),
        _ if key.len() == 1 => format!("{key}\r"),
        _ => format!("{option_id}\r"),
    }
}

fn terminal_codex_catalog_hooks(catalog: &Value) -> Vec<Value> {
    let mut hooks = catalog
        .get("data")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .flat_map(|row| {
            row.get("hooks")
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
        })
        .filter(|hook| hook.get("enabled").and_then(Value::as_bool) != Some(false))
        .filter(|hook| hook.get("isManaged").and_then(Value::as_bool) != Some(true))
        .cloned()
        .collect::<Vec<_>>();
    // hooks/list order is not an API guarantee.  Stable ordering keeps the
    // interaction id/revision unchanged across retries without collapsing
    // profile-scoped entries that Codex presents as distinct native rows.
    hooks.sort_by(|left, right| {
        terminal_codex_hook_identity(left).cmp(&terminal_codex_hook_identity(right))
    });
    hooks
}

fn terminal_codex_hook_identity(hook: &Value) -> String {
    [
        "key",
        "currentHash",
        "eventName",
        "sourcePath",
        "trustStatus",
    ]
    .iter()
    .map(|key| hook.get(*key).and_then(Value::as_str).unwrap_or_default())
    .collect::<Vec<_>>()
    .join(":")
}

fn terminal_codex_hooks_requiring_trust(catalog: &Value) -> Vec<Value> {
    terminal_codex_catalog_hooks(catalog)
        .into_iter()
        .filter(|hook| {
            !matches!(
                hook.get("trustStatus")
                    .and_then(Value::as_str)
                    .unwrap_or_default()
                    .trim()
                    .to_ascii_lowercase()
                    .as_str(),
                "approved" | "trusted"
            )
        })
        .collect()
}

fn terminal_codex_validated_hook_catalog(
    response: &Value,
    expected_cwd: &Path,
) -> Result<Value, String> {
    if let Some(error) = response.get("error") {
        return Err(format!("hooks/list returned an error: {error}"));
    }
    let result = response
        .get("result")
        .and_then(Value::as_object)
        .ok_or_else(|| "hooks/list did not return an object result".to_string())?;
    let rows = result
        .get("data")
        .and_then(Value::as_array)
        .ok_or_else(|| "hooks/list result.data is missing or malformed".to_string())?;
    if rows.len() != 1 {
        return Err(format!(
            "hooks/list returned {} cwd rows for a single-cwd request",
            rows.len()
        ));
    }
    let row = rows[0]
        .as_object()
        .ok_or_else(|| "hooks/list returned a malformed cwd row".to_string())?;
    let row_cwd = row
        .get("cwd")
        .and_then(Value::as_str)
        .ok_or_else(|| "hooks/list cwd row omitted its cwd".to_string())?;
    if Path::new(row_cwd) != expected_cwd {
        return Err("hooks/list returned a row for a different cwd".to_string());
    }
    let errors = row
        .get("errors")
        .and_then(Value::as_array)
        .ok_or_else(|| "hooks/list cwd row omitted its errors array".to_string())?;
    if !errors.is_empty() {
        return Err(format!(
            "hooks/list cwd row reported errors: {}",
            Value::Array(errors.clone())
        ));
    }
    let hooks = row
        .get("hooks")
        .and_then(Value::as_array)
        .ok_or_else(|| "hooks/list cwd row omitted or malformed its hooks array".to_string())?;
    for hook in hooks {
        let hook = hook
            .as_object()
            .ok_or_else(|| "hooks/list cwd row contained a malformed hook entry".to_string())?;
        for field in ["key", "currentHash", "trustStatus"] {
            if !hook
                .get(field)
                .and_then(Value::as_str)
                .is_some_and(|value| !value.trim().is_empty())
            {
                return Err(format!(
                    "hooks/list hook entry omitted or malformed {field}"
                ));
            }
        }
        for field in ["enabled", "isManaged"] {
            if !hook.get(field).is_some_and(Value::is_boolean) {
                return Err(format!(
                    "hooks/list hook entry omitted or malformed {field}"
                ));
            }
        }
    }
    Ok(json!({"data": [Value::Object(row.clone())]}))
}

#[allow(clippy::too_many_arguments)]
async fn terminal_codex_gateway_fail_hook_discovery(
    app: &AppHandle,
    state: &TerminalState,
    cloud_mcp_state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    generation: u64,
    error: &str,
) {
    let prompt_text = format!(
        "Codex could not load a valid hook trust catalog from app-server. The agent remains blocked; close and reopen this terminal to retry.\n\n{error}"
    );
    if !terminal_codex_hook_trust_discovery_transition(
        pane_id,
        instance_id,
        generation,
        &[TerminalCodexHookTrustDiscoveryState::Pending],
        TerminalCodexHookTrustDiscoveryState::FailedClosed,
    ) {
        return;
    }
    let event = json!({
        "hook_event_name": "UserInputRequired",
        "provider": "codex",
        "permission_request_id": format!("codex-hook-trust-error-{generation}"),
        "prompting_user_kind": "error",
        "prompting_user_text": prompt_text,
        "prompt_options": [{
            "id": "acknowledge",
            "label": "Acknowledge",
            "description": "Keep Codex blocked until this terminal is reopened."
        }],
        "manual_approval_required": true,
        "provider_blocked_for_user": true,
        "provider_health_error": true,
        "requires_user_input": true,
        "terminal_is_prompting_user": true,
        "timestamp_ms": terminal_now_ms(),
        "trust_source": "codex_app_server_hooks_list",
    });
    let publish_error = handle_terminal_activity_hook_event(
        app,
        &state.terminals,
        cloud_mcp_state,
        pane_id,
        instance_id,
        event,
        "codex-app-server-hook-trust-error",
    )
    .await
    .err();
    log_terminal_status_event(
        "backend.codex_hook_trust.discovery_error",
        json!({
            "error": clean_terminal_diagnostic_log_text(error),
            "instance_id": instance_id,
            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
            "publish_error": publish_error
                .as_deref()
                .map(clean_terminal_diagnostic_log_text)
                .unwrap_or_default(),
            "source": "gateway_hooks_list_response",
        }),
    );
}

fn spawn_terminal_codex_hook_trust_response_watchdog(
    app: AppHandle,
    pane_id: String,
    instance_id: u64,
) {
    let Some(discovery) = terminal_codex_hook_trust_discovery_snapshot(&pane_id, instance_id)
    else {
        return;
    };
    if discovery.state != TerminalCodexHookTrustDiscoveryState::Pending {
        return;
    }
    tauri::async_runtime::spawn(async move {
        sleep(Duration::from_millis(
            TERMINAL_CODEX_HOOK_TRUST_RESPONSE_TIMEOUT_MS,
        ))
        .await;
        if !terminal_codex_hook_trust_discovery_snapshot(&pane_id, instance_id).is_some_and(
            |current| {
                current.generation == discovery.generation
                    && current.state == TerminalCodexHookTrustDiscoveryState::Pending
            },
        ) {
            return;
        }
        terminal_codex_gateway_handle_hooks_list_response(
            &app,
            &pane_id,
            instance_id,
            &json!({
                "error": {
                    "code": "hooks_list_timeout",
                    "message": "Codex TUI did not return hooks/list through app-server in time."
                }
            }),
        )
        .await;
    });
}

async fn terminal_codex_gateway_handle_hooks_list_response(
    app: &AppHandle,
    pane_id: &str,
    instance_id: u64,
    response: &Value,
) {
    let Some(discovery) = terminal_codex_hook_trust_discovery_snapshot(pane_id, instance_id) else {
        return;
    };
    if discovery.state != TerminalCodexHookTrustDiscoveryState::Pending {
        return;
    }

    let state = app.state::<TerminalState>();
    let cloud_mcp_state = app.state::<CloudMcpState>();
    // A fresh stock TUI can complete hooks/list before terminal_open has
    // inserted its already-running PTY into the terminal map. Briefly wait for
    // that registration instead of discarding the provider-native result.
    let mut current_instance = None;
    for _ in 0..100 {
        current_instance =
            terminal_activity_hook_current_instance(&state.terminals, pane_id, instance_id).await;
        if current_instance.is_some() {
            break;
        }
        if !terminal_codex_hook_trust_discovery_snapshot(pane_id, instance_id).is_some_and(
            |current| {
                current.generation == discovery.generation
                    && current.state == TerminalCodexHookTrustDiscoveryState::Pending
            },
        ) {
            return;
        }
        sleep(Duration::from_millis(20)).await;
    }
    let Some(instance) = current_instance else {
        return;
    };
    if !terminal_metadata_is_codex(&instance.metadata) {
        terminal_codex_hook_trust_discovery_clear_generation(
            pane_id,
            instance_id,
            discovery.generation,
        );
        return;
    }

    let catalog = match terminal_codex_validated_hook_catalog(
        response,
        instance.working_directory.as_ref(),
    ) {
        Ok(catalog) => catalog,
        Err(error) => {
            terminal_codex_gateway_fail_hook_discovery(
                app,
                state.inner(),
                cloud_mcp_state.inner(),
                pane_id,
                instance_id,
                discovery.generation,
                &error,
            )
            .await;
            return;
        }
    };
    let configured_hook_count = terminal_codex_catalog_hooks(&catalog).len();
    let hooks = terminal_codex_hooks_requiring_trust(&catalog);
    if hooks.is_empty() {
        if terminal_codex_hook_trust_discovery_transition(
            pane_id,
            instance_id,
            discovery.generation,
            &[TerminalCodexHookTrustDiscoveryState::Pending],
            TerminalCodexHookTrustDiscoveryState::Resolved,
        ) {
            log_terminal_status_event(
                "backend.codex_hook_trust.discovery_trusted",
                json!({
                    "configured_hook_count": configured_hook_count,
                    "instance_id": instance_id,
                    "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                    "source": "gateway_hooks_list_response",
                }),
            );
        }
        return;
    }

    let identities = hooks
        .iter()
        .map(terminal_codex_hook_identity)
        .collect::<Vec<_>>();
    let catalog_hash = cloud_mcp_short_hash(&identities.join("|"));
    let request_id = format!("codex-hook-trust-catalog-{catalog_hash}");
    let hook_labels = hooks
        .iter()
        .take(12)
        .map(|hook| {
            let event = hook
                .get("eventName")
                .and_then(Value::as_str)
                .unwrap_or("hook");
            let source = hook
                .get("sourcePath")
                .and_then(Value::as_str)
                .unwrap_or("Codex configuration");
            format!("{event} — {source}")
        })
        .collect::<Vec<_>>();
    let overflow = hooks.len().saturating_sub(hook_labels.len());
    let mut prompt_text = format!(
        "{} Codex {} new or changed and need review before they can run.\n{}",
        hooks.len(),
        if hooks.len() == 1 {
            "hook is"
        } else {
            "hooks are"
        },
        hook_labels.join("\n"),
    );
    if overflow > 0 {
        prompt_text.push_str(&format!("\n…and {overflow} more."));
    }
    let event = json!({
        "hook_event_name": "UserInputRequired",
        "provider": "codex",
        "permission_request_id": request_id,
        "prompting_user_kind": "approval",
        "prompting_user_text": prompt_text,
        "prompt_default_option": "continue_without_trusting",
        "prompt_options": terminal_codex_hook_trust_prompt_options(),
        "manual_approval_required": true,
        "provider_blocked_for_user": true,
        "requires_user_input": true,
        "terminal_is_prompting_user": true,
        "timestamp_ms": terminal_now_ms(),
        "trust_catalog_hash": catalog_hash,
        "trust_source": "codex_app_server_hooks_list",
    });
    if !terminal_codex_hook_trust_discovery_transition(
        pane_id,
        instance_id,
        discovery.generation,
        &[TerminalCodexHookTrustDiscoveryState::Pending],
        TerminalCodexHookTrustDiscoveryState::Open,
    ) {
        return;
    }
    if let Err(error) = handle_terminal_activity_hook_event(
        app,
        &state.terminals,
        cloud_mcp_state.inner(),
        pane_id,
        instance_id,
        event,
        "codex-app-server-hook-trust",
    )
    .await
    {
        log_terminal_status_event(
            "backend.codex_hook_trust.publish_error",
            json!({
                "error": clean_terminal_diagnostic_log_text(&error),
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
            }),
        );
        return;
    }
    let post_publish_discovery = terminal_codex_hook_trust_discovery_snapshot(pane_id, instance_id);
    let post_publish_terminal_is_current =
        terminal_activity_hook_current_instance(&state.terminals, pane_id, instance_id)
            .await
            .is_some();
    if post_publish_terminal_is_current
        && post_publish_discovery.is_some_and(|entry| {
            entry.generation == discovery.generation
                && entry.state == TerminalCodexHookTrustDiscoveryState::Resolved
        })
    {
        terminal_codex_gateway_publish_startup_hook_review_resolved(
            app.clone(),
            pane_id.to_string(),
            instance_id,
            "thread/bootstrap-during-hook-publish".to_string(),
        )
        .await;
        return;
    }
    let publication_is_current = post_publish_terminal_is_current
        && post_publish_discovery.is_some_and(|entry| {
            entry.generation == discovery.generation
                && entry.state == TerminalCodexHookTrustDiscoveryState::Open
        });
    if !publication_is_current {
        terminal_codex_hook_trust_withdraw_stale_publication(
            app,
            cloud_mcp_state.inner(),
            pane_id,
            instance_id,
            &request_id,
            !post_publish_terminal_is_current,
            "codex_hook_trust_gateway_generation_or_terminal_replaced",
        )
        .await;
        return;
    }
    log_terminal_status_event(
        "backend.codex_hook_trust.discovery_opened",
        json!({
            "configured_hook_count": configured_hook_count,
            "instance_id": instance_id,
            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
            "source": "gateway_hooks_list_response",
            "untrusted_hook_count": hooks.len(),
        }),
    );
}

fn terminal_remote_command_string(event: &Value, keys: &[&str]) -> Option<String> {
    terminal_activity_hook_string(event, keys)
        .or_else(|| {
            event
                .get("payload")
                .and_then(|payload| terminal_activity_hook_string(payload, keys))
        })
        .or_else(|| {
            event
                .get("request")
                .and_then(|request| terminal_activity_hook_string(request, keys))
        })
}

fn terminal_remote_command_u64(event: &Value, keys: &[&str]) -> Option<u64> {
    let value_from = |root: &Value| {
        keys.iter().find_map(|key| {
            root.get(*key).and_then(|value| {
                value
                    .as_u64()
                    .or_else(|| value.as_str()?.parse::<u64>().ok())
            })
        })
    };
    value_from(event)
        .or_else(|| event.get("payload").and_then(|payload| value_from(payload)))
        .or_else(|| event.get("request").and_then(|request| value_from(request)))
}

fn terminal_answer_agent_prompt_target_pane_id(event: &Value) -> Result<String, String> {
    let pane_id =
        terminal_remote_command_string(event, &["target_terminal_id", "terminal_id", "pane_id"])
            .ok_or_else(|| "Prompt answer requires a target terminal id.".to_string())?;
    validate_terminal_pane_id(&pane_id)?;
    Ok(pane_id)
}

fn terminal_agent_prompt_already_resolved_result(
    pane_id: &str,
    instance_id: Option<u64>,
    prompt_id: &str,
    interaction_id: &str,
    interaction_revision: u64,
    reason: &str,
) -> Value {
    json!({
        "answered": true,
        "applied": false,
        "noop": true,
        "status": "already_resolved",
        "message": "This provider interaction is already closed or resolved.",
        "reason": reason,
        "pane_id": pane_id,
        "terminal_instance_id": instance_id.unwrap_or_default(),
        "prompt_id": prompt_id,
        "interaction_id": interaction_id,
        "interaction_revision": interaction_revision,
    })
}

fn terminal_structured_interaction_hook_response(
    interaction: &TerminalStructuredInteraction,
    option_id: &str,
    option_value: Option<&str>,
    answer_text: Option<&str>,
    answer_payload: Option<&Value>,
) -> Value {
    if interaction.response_mode == "codex_app_server" {
        return terminal_codex_app_server_interaction_response(
            interaction,
            option_id,
            option_value,
            answer_text,
            answer_payload,
        );
    }
    let option_key = terminal_activity_hook_name_key(option_id);
    let hook_key = terminal_activity_hook_name_key(&interaction.hook_event_name);
    let provider_key = terminal_activity_hook_name_key(&interaction.provider);
    if interaction.response_mode == "provider_api" && provider_key.contains("opencode") {
        if hook_key == "permissionrequest" {
            let reply = if matches!(option_key.as_str(), "deny" | "reject" | "cancel") {
                "reject"
            } else if option_key == "allowalways" {
                "always"
            } else {
                "once"
            };
            return json!({
                "reply": reply,
                "_diffforge_interaction_id": interaction.interaction_id,
                "_diffforge_interaction_revision": interaction.revision,
                "_diffforge_provider_request_id": interaction.provider_request_id,
            });
        }
        let answers = answer_payload
            .and_then(|value| value.get("answers"))
            .cloned()
            .or_else(|| answer_payload.cloned())
            .unwrap_or_else(|| json!([[answer_text.or(option_value).unwrap_or_default()]]));
        return json!({
            "answers": answers,
            "rejected": matches!(option_key.as_str(), "deny" | "reject" | "cancel"),
            "_diffforge_interaction_id": interaction.interaction_id,
            "_diffforge_interaction_revision": interaction.revision,
            "_diffforge_provider_request_id": interaction.provider_request_id,
        });
    }
    if hook_key == "permissiondenied" {
        return json!({
            "hookSpecificOutput": {
                "hookEventName": "PermissionDenied",
                "retry": option_key == "retry",
            }
        });
    }
    if hook_key == "permissionrequest" {
        let denied = matches!(
            option_key.as_str(),
            "deny" | "denied" | "reject" | "rejected" | "cancel"
        );
        let mut decision = if denied {
            json!({
                "behavior": "deny",
                "message": answer_text.unwrap_or("Rejected by the user."),
            })
        } else {
            json!({ "behavior": "allow" })
        };
        if !denied && option_key == "allowalways" && !provider_key.contains("codex") {
            if let Some(suggestions) = interaction.permission_suggestions.clone() {
                decision["updatedPermissions"] = suggestions;
            }
        }
        return json!({
            "hookSpecificOutput": {
                "hookEventName": "PermissionRequest",
                "decision": decision,
            }
        });
    }
    if hook_key == "elicitation" {
        let action = if matches!(option_key.as_str(), "deny" | "reject" | "decline") {
            "decline"
        } else if option_key == "cancel" {
            "cancel"
        } else {
            "accept"
        };
        let content = answer_payload
            .and_then(|value| value.get("content"))
            .cloned()
            .or_else(|| answer_payload.cloned())
            .or_else(|| {
                answer_text
                    .or(option_value)
                    .map(str::trim)
                    .filter(|value| !value.is_empty())
                    .map(|value| {
                        serde_json::from_str::<Value>(value)
                            .unwrap_or_else(|_| json!({ "answer": value }))
                    })
            });
        let mut output = json!({
            "hookEventName": "Elicitation",
            "action": action,
        });
        if let Some(content) = content {
            output["content"] = content;
        }
        return json!({ "hookSpecificOutput": output });
    }
    if hook_key == "pretooluse" {
        let tool_name = interaction
            .provider_payload
            .as_ref()
            .and_then(|value| value.get("tool_name"))
            .and_then(Value::as_str)
            .unwrap_or_default();
        let tool_key = terminal_activity_hook_name_key(tool_name);
        let denied = matches!(option_key.as_str(), "deny" | "reject" | "cancel")
            || (provider_key.contains("claude")
                && tool_key == "exitplanmode"
                && option_key == "keepplanning");
        let mut output = json!({
            "hookEventName": "PreToolUse",
            "permissionDecision": if denied { "deny" } else { "allow" },
            "permissionDecisionReason": answer_text.unwrap_or(if denied {
                "Rejected by the user."
            } else {
                "Approved by the user."
            }),
        });
        if !denied
            && matches!(
                tool_key.as_str(),
                "askuserquestion"
                    | "exitplanmode"
                    | "requestuserinput"
                    | "elicitation"
                    | "mcpelicitation"
            )
        {
            let mut updated_input = interaction
                .provider_payload
                .as_ref()
                .and_then(|value| value.get("tool_input"))
                .cloned()
                .unwrap_or_else(|| json!({}));
            if tool_key != "exitplanmode" {
                updated_input["answers"] = answer_payload
                    .and_then(|value| value.get("answers_by_question"))
                    .or_else(|| answer_payload.and_then(|value| value.get("answers")))
                    .cloned()
                    .or_else(|| answer_payload.cloned())
                    .unwrap_or_else(|| json!({}));
            }
            output["updatedInput"] = updated_input;
        }
        return json!({ "hookSpecificOutput": output });
    }
    json!({})
}

fn terminal_structured_interaction_same_generation(
    current: &TerminalStructuredInteraction,
    expected: &TerminalStructuredInteraction,
) -> bool {
    current.interaction_id == expected.interaction_id
        && current.revision == expected.revision
        && current.pane_id == expected.pane_id
        && current.instance_id == expected.instance_id
        && current.provider_request_id == expected.provider_request_id
        && current.response_mode == expected.response_mode
}

fn terminal_structured_interaction_remove_generation(
    state: &TerminalState,
    interaction: &TerminalStructuredInteraction,
) -> bool {
    let removed = state
        .terminal_structured_interactions
        .lock()
        .ok()
        .is_some_and(|mut interactions| {
            let matches = interactions
                .get(&interaction.interaction_id)
                .is_some_and(|current| {
                    terminal_structured_interaction_same_generation(current, interaction)
                });
            if matches {
                interactions.remove(&interaction.interaction_id);
            }
            matches
        });
    if removed {
        if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
            waiters.remove(&interaction.interaction_id);
        }
    }
    removed
}

fn terminal_structured_interaction_expire_answer_confirmation(
    interactions: &mut HashMap<String, TerminalStructuredInteraction>,
    interaction: &TerminalStructuredInteraction,
) -> bool {
    let matches_answered_generation =
        interactions
            .get(&interaction.interaction_id)
            .is_some_and(|current| {
                terminal_structured_interaction_same_generation(current, interaction)
                    && current.awaiting_provider_confirmation
            });
    if matches_answered_generation {
        interactions.remove(&interaction.interaction_id);
    }
    matches_answered_generation
}

fn terminal_structured_interaction_remove_answered_generation(
    state: &TerminalState,
    interaction: &TerminalStructuredInteraction,
) -> bool {
    let removed = state
        .terminal_structured_interactions
        .lock()
        .ok()
        .is_some_and(|mut interactions| {
            terminal_structured_interaction_expire_answer_confirmation(
                &mut interactions,
                interaction,
            )
        });
    if removed {
        if let Ok(mut waiters) = state.terminal_structured_interaction_waiters.lock() {
            waiters.remove(&interaction.interaction_id);
        }
    }
    removed
}

fn terminal_structured_interaction_for_written_answer(
    state: &TerminalState,
    pane_id: &str,
    instance_id: u64,
    prompt_event_id: Option<&str>,
    prompt_event_revision: Option<u64>,
) -> Option<TerminalStructuredInteraction> {
    let prompt_event_id = prompt_event_id
        .map(str::trim)
        .filter(|value| !value.is_empty());
    state
        .terminal_structured_interactions
        .lock()
        .ok()?
        .values()
        .find(|interaction| {
            interaction.pane_id == pane_id
                && interaction.instance_id == instance_id
                && interaction.response_mode == "structured_pty"
                && prompt_event_id.is_none_or(|prompt_event_id| {
                    interaction.prompt_id == prompt_event_id
                        || interaction.interaction_id == prompt_event_id
                })
                && prompt_event_revision.is_none_or(|revision| revision == interaction.revision)
        })
        .cloned()
}

fn terminal_structured_answer_keeps_open_for_input(
    interaction: &TerminalStructuredInteraction,
    data: &str,
) -> bool {
    terminal_codex_hook_trust_is_catalog_request(&interaction.provider_request_id)
        && terminal_codex_hook_trust_prompt_answer_input("review_hooks")
            .is_some_and(|review_input| review_input == data)
}

fn terminal_structured_answer_local_option(
    interaction: &TerminalStructuredInteraction,
    data: &str,
) -> Option<String> {
    if data.is_empty() {
        return None;
    }
    if interaction.awaiting_provider_confirmation
        && interaction.claimed_option_id.as_deref() == Some("")
        && data
            .chars()
            .all(|character| matches!(character, '\r' | '\n'))
    {
        return None;
    }
    if terminal_codex_hook_trust_is_catalog_request(&interaction.provider_request_id) {
        return match data {
            "2" | "2\r" | "2\n" => Some("trust_all_and_continue".to_string()),
            "3" | "3\r" | "3\n" => Some("continue_without_trusting".to_string()),
            _ => None,
        };
    }
    let option_input = data.trim_end_matches(['\r', '\n']);
    interaction
        .options
        .iter()
        .find(|option| {
            option.id == option_input
                || option.value.as_deref() == Some(option_input)
                || terminal_agent_prompt_answer_input(
                    &interaction.provider,
                    &option.id,
                    &option.label,
                    option.value.as_deref(),
                )
                .trim_end_matches(['\r', '\n'])
                    == option_input
        })
        .map(|option| option.id.clone())
}

fn terminal_structured_answer_local_submission(data: &str) -> bool {
    !data.is_empty()
}

fn terminal_structured_answer_confirmation_allows_continuation(
    interaction: &TerminalStructuredInteraction,
    data: &str,
) -> bool {
    if !interaction.awaiting_provider_confirmation {
        return false;
    }
    match interaction.claimed_option_id.as_deref() {
        Some("") => true,
        Some(_) => {
            !data.is_empty()
                && data
                    .chars()
                    .all(|character| matches!(character, '\r' | '\n'))
        }
        None => false,
    }
}

fn terminal_structured_answer_bypasses_interrupt(
    interaction: &TerminalStructuredInteraction,
    data: &str,
) -> bool {
    data == "\x1b" && terminal_structured_answer_local_option(interaction, data).is_some()
}

fn terminal_runtime_is_prompting_for_structured_interaction(
    runtime: &TerminalRuntimeSnapshot,
) -> bool {
    terminal_workspace_agent_session_status_requires_input(
        &runtime.event_type,
        &runtime.activity_status,
        &runtime.command_phase,
    )
}

fn terminal_runtime_is_done_after_structured_answer(runtime: &TerminalRuntimeSnapshot) -> bool {
    !terminal_runtime_snapshot_is_busy_turn(runtime)
}

const STRUCTURED_INTERACTION_ALREADY_RESOLVED_ERROR: &str =
    "Structured terminal interaction is already resolved.";

fn terminal_structured_interaction_claim_answer_confirmation(
    interactions: &mut HashMap<String, TerminalStructuredInteraction>,
    interaction: &TerminalStructuredInteraction,
    claimed_option_id: &str,
) -> bool {
    let Some(current) = interactions.get_mut(&interaction.interaction_id) else {
        return false;
    };
    if !terminal_structured_interaction_same_generation(current, interaction)
        || !matches!(
            current.response_mode.as_str(),
            "structured_pty" | "provider_api"
        )
    {
        return false;
    }
    if current.awaiting_provider_confirmation {
        if current.claimed_option_id.as_deref() == Some("") && !claimed_option_id.is_empty() {
            current.claimed_option_id = Some(claimed_option_id.to_string());
            return true;
        }
        return false;
    }
    current.awaiting_provider_confirmation = true;
    current.claimed_option_id = Some(claimed_option_id.to_string());
    true
}

fn terminal_structured_interaction_claim_matches_option(
    interaction: &TerminalStructuredInteraction,
    option_id: &str,
) -> bool {
    interaction.awaiting_provider_confirmation
        && interaction.claimed_option_id.as_deref() == Some(option_id)
}

fn terminal_structured_interaction_arm_answer_confirmation_timeout(
    app: &AppHandle,
    interaction: TerminalStructuredInteraction,
    claimed_option_id: &str,
) -> bool {
    let state = app.state::<TerminalState>();
    let newly_armed = state
        .terminal_structured_interactions
        .lock()
        .ok()
        .map(|mut interactions| {
            terminal_structured_interaction_claim_answer_confirmation(
                &mut interactions,
                &interaction,
                claimed_option_id,
            )
        })
        .unwrap_or(false);
    if !newly_armed {
        return false;
    }
    log_terminal_status_event(
        "backend.terminal_structured_interaction.confirmation_timeout_armed",
        json!({
            "interaction_id": interaction.interaction_id,
            "pane_id": interaction.pane_id,
            "provider": interaction.provider,
            "provider_request_id": interaction.provider_request_id,
            "response_mode": interaction.response_mode,
            "revision": interaction.revision,
            "timeout_secs": STRUCTURED_ANSWER_CONFIRMATION_TIMEOUT_SECS,
        }),
    );
    let app = app.clone();
    tauri::async_runtime::spawn(async move {
        sleep(Duration::from_secs(
            STRUCTURED_ANSWER_CONFIRMATION_TIMEOUT_SECS,
        ))
        .await;
        let state = app.state::<TerminalState>();
        let still_open = state
            .terminal_structured_interactions
            .lock()
            .ok()
            .and_then(|interactions| interactions.get(&interaction.interaction_id).cloned())
            .is_some_and(|current| {
                terminal_structured_interaction_same_generation(&current, &interaction)
                    && current.awaiting_provider_confirmation
                    && matches!(
                        current.response_mode.as_str(),
                        "structured_pty" | "provider_api"
                    )
            });
        if !still_open {
            return;
        }
        let Some(instance) = terminal_activity_hook_current_instance(
            &state.terminals,
            &interaction.pane_id,
            interaction.instance_id,
        )
        .await
        else {
            terminal_structured_interaction_remove_answered_generation(&state, &interaction);
            return;
        };
        let runtime = terminal_runtime_snapshot(&instance);
        let resolution_next_state = if terminal_runtime_is_done_after_structured_answer(&runtime) {
            "idle"
        } else {
            "running"
        };
        log_terminal_status_event(
            "backend.terminal_structured_interaction.confirmation_expired",
            json!({
                "interaction_id": interaction.interaction_id,
                "pane_id": interaction.pane_id,
                "provider": interaction.provider,
                "provider_request_id": interaction.provider_request_id,
                "reason": "structured_answer_confirmation_timeout",
                "resolution_next_state": resolution_next_state,
                "response_mode": interaction.response_mode,
                "revision": interaction.revision,
            }),
        );
        let elicitation = matches!(
            terminal_activity_hook_name_key(&interaction.hook_event_name).as_str(),
            "elicitation" | "userpromptrequired"
        );
        let event = json!({
            "hook_event_name": if elicitation { "ElicitationResult" } else { "PermissionResult" },
            "provider": interaction.provider,
            "permission_request_id": interaction.provider_request_id,
            "prompt_id": interaction.prompt_id,
            "resolved_interaction_id": interaction.interaction_id,
            "resolved_interaction_revision": interaction.revision,
            "decision": "accepted",
            "timestamp_ms": terminal_now_ms(),
            "resolution_next_state": resolution_next_state,
            "resolution_reason": "structured_answer_confirmation_timeout",
        });
        let cloud_mcp_state = app.state::<CloudMcpState>();
        process_terminal_activity_hook_event(
            &app,
            &state.terminals,
            cloud_mcp_state.inner(),
            &interaction.pane_id,
            interaction.instance_id,
            &instance,
            &event,
            "structured-answer-confirmation-timeout",
        )
        .await;
        // The hook-trust idle guard can intentionally reject this synthetic
        // lifecycle event before structured reconciliation.  The timeout is
        // still the terminal condition for this exact generation, so remove
        // it directly as a final self-heal guard.
        terminal_structured_interaction_remove_answered_generation(&state, &interaction);
    });
    true
}

async fn terminal_structured_interaction_publish_answered(
    app: &AppHandle,
    state: &TerminalState,
    cloud_mcp_state: &CloudMcpState,
    instance: &TerminalInstance,
    interaction: &TerminalStructuredInteraction,
    option_id: &str,
    source: &str,
) {
    let denied = matches!(
        terminal_activity_hook_name_key(option_id).as_str(),
        "deny" | "denied" | "reject" | "rejected" | "decline" | "cancel"
    );
    let permission_request = matches!(
        terminal_activity_hook_name_key(&interaction.hook_event_name).as_str(),
        "permissionrequest" | "permissiondenied"
    );
    let event = json!({
        "hook_event_name": if permission_request {
            "PermissionResult"
        } else {
            "ElicitationResult"
        },
        "provider": interaction.provider,
        "source_hook_event_name": interaction.hook_event_name,
        "permission_request_id": interaction.provider_request_id,
        "prompt_id": interaction.prompt_id,
        "resolved_interaction_id": interaction.interaction_id,
        "resolved_interaction_revision": interaction.revision,
        "selected_option_id": option_id,
        "decision": if denied { "denied" } else { "accepted" },
        "timestamp_ms": terminal_now_ms(),
        "resolution_reason": "structured_interaction_answered",
    });
    process_terminal_activity_hook_event(
        app,
        &state.terminals,
        cloud_mcp_state,
        &interaction.pane_id,
        interaction.instance_id,
        instance,
        &event,
        source,
    )
    .await;
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_answer_agent_prompt_remote_command(
    app: AppHandle,
    event: Value,
) -> Result<Value, String> {
    let pane_id = terminal_answer_agent_prompt_target_pane_id(&event)?;
    let _control_operation_guard = terminal_control_prompt_answer_begin(&pane_id)?;
    let instance_id = terminal_remote_command_u64(&event, &["terminal_instance_id"]);
    let prompt_id = terminal_remote_command_string(&event, &["prompt_id"])
        .ok_or_else(|| "Prompt answer requires a prompt id.".to_string())?;
    let option_id = terminal_remote_command_string(&event, &["option_id", "choice"])
        .ok_or_else(|| "Prompt answer requires an option id.".to_string())?;
    let option_label = terminal_remote_command_string(&event, &["option_label"])
        .unwrap_or_else(|| option_id.clone());
    let option_value = terminal_remote_command_string(&event, &["option_value", "value"]);
    let requested_interaction_id = terminal_remote_command_string(&event, &["interaction_id"])
        .ok_or_else(|| "Prompt answer requires a structured interaction id.".to_string())?;
    let requested_interaction_revision =
        terminal_remote_command_u64(&event, &["interaction_revision"])
            .filter(|revision| *revision > 0)
            .ok_or_else(|| {
                "Prompt answer requires a structured interaction revision.".to_string()
            })?;
    let answer_text =
        terminal_remote_command_string(&event, &["answer_text", "message", "text", "free_text"]);
    let answer_payload = event
        .get("answer_payload")
        .or_else(|| event.get("answerPayload"))
        .cloned();
    let state_app = app.clone();
    let cloud_app = app.clone();
    let state = state_app.state::<TerminalState>();
    let cloud_mcp_state = cloud_app.state::<CloudMcpState>();
    let Some(instance) =
        get_terminal_instance_if_current(state.inner(), &pane_id, instance_id).await?
    else {
        return Ok(terminal_agent_prompt_already_resolved_result(
            &pane_id,
            instance_id,
            &prompt_id,
            &requested_interaction_id,
            requested_interaction_revision,
            "terminal_not_running",
        ));
    };
    let interaction = state
        .terminal_structured_interactions
        .lock()
        .map_err(|_| "Structured terminal interaction state is unavailable.".to_string())?
        .values()
        .find(|interaction| {
            interaction.pane_id == pane_id
                && interaction.instance_id == instance.id
                && interaction.prompt_id == prompt_id
        })
        .cloned();
    let Some(interaction) = interaction else {
        return Ok(terminal_agent_prompt_already_resolved_result(
            &pane_id,
            Some(instance.id),
            &prompt_id,
            &requested_interaction_id,
            requested_interaction_revision,
            "interaction_not_open",
        ));
    };
    if requested_interaction_id != interaction.interaction_id {
        return Ok(terminal_agent_prompt_already_resolved_result(
            &pane_id,
            Some(instance.id),
            &prompt_id,
            &requested_interaction_id,
            requested_interaction_revision,
            "stale_interaction_id",
        ));
    }
    if requested_interaction_revision != interaction.revision {
        return Ok(terminal_agent_prompt_already_resolved_result(
            &pane_id,
            Some(instance.id),
            &prompt_id,
            &requested_interaction_id,
            requested_interaction_revision,
            "stale_interaction_revision",
        ));
    }
    if interaction.response_mode == "structured_pty" {
        let runtime = terminal_runtime_snapshot(&instance);
        if !terminal_runtime_is_prompting_for_structured_interaction(&runtime) {
            terminal_structured_interaction_remove_generation(state.inner(), &interaction);
            return Ok(terminal_agent_prompt_already_resolved_result(
                &pane_id,
                Some(instance.id),
                &prompt_id,
                &requested_interaction_id,
                requested_interaction_revision,
                "terminal_no_longer_prompting",
            ));
        }
    }
    if interaction.awaiting_provider_confirmation {
        let _pending_write_guard = if interaction.response_mode == "structured_pty" {
            Some(instance.input_queue.lock().await)
        } else {
            None
        };
        let submitted_answer = state
            .terminal_structured_interactions
            .lock()
            .map_err(|_| "Structured terminal interaction state is unavailable.".to_string())?
            .get(&interaction.interaction_id)
            .filter(|current| {
                terminal_structured_interaction_same_generation(current, &interaction)
                    && current.awaiting_provider_confirmation
            })
            .cloned();
        let Some(submitted_answer) = submitted_answer else {
            return Ok(terminal_agent_prompt_already_resolved_result(
                &pane_id,
                Some(instance.id),
                &prompt_id,
                &requested_interaction_id,
                requested_interaction_revision,
                "interaction_no_longer_open",
            ));
        };
        if !terminal_structured_interaction_claim_matches_option(&submitted_answer, &option_id) {
            return Ok(terminal_agent_prompt_already_resolved_result(
                &pane_id,
                Some(instance.id),
                &prompt_id,
                &requested_interaction_id,
                requested_interaction_revision,
                "different_answer_already_submitted",
            ));
        }
        let runtime = terminal_runtime_snapshot(&instance);
        return Ok(json!({
            "interaction_id": interaction.interaction_id,
            "interaction_revision": interaction.revision,
            "prompt_id": prompt_id,
            "option_id": option_id,
            "option_value": option_value.unwrap_or_default(),
            "pane_id": pane_id,
            "terminal_instance_id": instance.id,
            "turn_id": runtime.turn_id.unwrap_or_default(),
            "provider_turn_id": runtime.provider_turn_id.unwrap_or_default(),
            "provider_session_id": runtime.provider_session_id.unwrap_or_default(),
            "native_session_id": runtime.native_session_id.unwrap_or_default(),
            "status": "accepted_pending_confirmation",
            "message": "Answer already submitted; awaiting provider confirmation.",
            "answered": false,
            "accepted": true,
            "resolved": false,
        }));
    }
    if !interaction.options.is_empty()
        && !interaction
            .options
            .iter()
            .any(|option| option.id == option_id)
    {
        return Err("The selected provider interaction option is unavailable.".to_string());
    }

    if matches!(
        interaction.response_mode.as_str(),
        "blocking_hook" | "provider_api" | "codex_app_server" | "diffforge_intervention"
    ) {
        let response = terminal_structured_interaction_hook_response(
            &interaction,
            &option_id,
            option_value.as_deref(),
            answer_text.as_deref(),
            answer_payload.as_ref(),
        );
        let sender = state
            .terminal_structured_interaction_waiters
            .lock()
            .map_err(|_| "Structured terminal response state is unavailable.".to_string())?
            .remove(&interaction.interaction_id);
        let response_applied = sender.is_some_and(|sender| sender.send(response).is_ok());
        if !response_applied {
            terminal_structured_interaction_publish_answered(
                &app,
                state.inner(),
                cloud_mcp_state.inner(),
                &instance,
                &interaction,
                "provider_no_longer_waiting",
                "already-resolved-noop",
            )
            .await;
            return Ok(terminal_agent_prompt_already_resolved_result(
                &pane_id,
                Some(instance.id),
                &prompt_id,
                &requested_interaction_id,
                requested_interaction_revision,
                "provider_no_longer_waiting",
            ));
        }
        let provider_ack_pending = interaction.response_mode == "provider_api";
        if provider_ack_pending {
            terminal_structured_interaction_arm_answer_confirmation_timeout(
                &app,
                interaction.clone(),
                &option_id,
            );
        } else {
            terminal_structured_interaction_publish_answered(
                &app,
                state.inner(),
                cloud_mcp_state.inner(),
                &instance,
                &interaction,
                &option_id,
                "blocking-hook-answer",
            )
            .await;
        }
        log_terminal_status_event(
            "backend.terminal_structured_interaction.answered",
            json!({
                "interaction_id": interaction.interaction_id,
                "option_id": option_id,
                "pane_id": pane_id,
                "provider": interaction.provider,
                "response_mode": interaction.response_mode,
                "revision": interaction.revision,
            }),
        );
        let runtime = terminal_runtime_snapshot(&instance);
        return Ok(json!({
            "interaction_id": interaction.interaction_id,
            "interaction_revision": interaction.revision,
            "prompt_id": prompt_id,
            "option_id": option_id,
            "option_value": option_value.unwrap_or_default(),
            "pane_id": pane_id,
            "terminal_instance_id": instance.id,
            "turn_id": runtime.turn_id.unwrap_or_default(),
            "provider_turn_id": runtime.provider_turn_id.unwrap_or_default(),
            "provider_session_id": runtime.provider_session_id.unwrap_or_default(),
            "native_session_id": runtime.native_session_id.unwrap_or_default(),
            "status": if provider_ack_pending { "accepted_pending_confirmation" } else { "applied" },
            "message": if provider_ack_pending { "Waiting for OpenCode to confirm the response." } else { "" },
            "answered": !provider_ack_pending,
            "accepted": true,
            "resolved": !provider_ack_pending,
        }));
    }

    if terminal_codex_hook_trust_is_fail_closed_request(&interaction.provider_request_id) {
        terminal_structured_interaction_publish_answered(
            &app,
            state.inner(),
            cloud_mcp_state.inner(),
            &instance,
            &interaction,
            "acknowledge",
            "codex-hook-trust-error-acknowledged",
        )
        .await;
        return Ok(json!({
            "interaction_id": interaction.interaction_id,
            "interaction_revision": interaction.revision,
            "prompt_id": prompt_id,
            "option_id": "acknowledge",
            "pane_id": pane_id,
            "terminal_instance_id": instance.id,
            "status": "blocked_until_reopen",
            "message": "Codex remains blocked. Close and reopen this terminal to retry app-server hook discovery.",
            "answered": true,
        }));
    }

    let review_hooks =
        terminal_codex_hook_trust_answer_keeps_open(&interaction.provider_request_id, &option_id);
    let awaiting_provider_confirmation = !review_hooks;
    let data = terminal_agent_prompt_answer_input(
        &instance.metadata.agent_kind,
        &option_id,
        &option_label,
        option_value.as_deref().or(answer_text.as_deref()),
    );
    let write_result = terminal_write_inner(
        app.clone(),
        state.inner(),
        cloud_mcp_state.inner(),
        pane_id.clone(),
        instance_id,
        data,
        Some(prompt_id.clone()).filter(|value| !value.trim().is_empty()),
        Some(interaction.revision),
        Some("agent_prompt_answer".to_string()),
        Some(crate::coordination::kernel::now_rfc3339()),
        None,
        None,
        None,
        None,
        Some("prompt_answer".to_string()),
        Some(false),
        None,
        Some(false),
        Some(option_id.clone()),
        awaiting_provider_confirmation,
        true,
    )
    .await;
    if let Err(error) = write_result {
        if error == STRUCTURED_INTERACTION_ALREADY_RESOLVED_ERROR {
            return Ok(terminal_agent_prompt_already_resolved_result(
                &pane_id,
                Some(instance.id),
                &prompt_id,
                &requested_interaction_id,
                requested_interaction_revision,
                "interaction_no_longer_open",
            ));
        }
        let terminal_still_current =
            get_terminal_instance_if_current(state.inner(), &pane_id, Some(instance.id))
                .await
                .ok()
                .flatten()
                .is_some();
        if terminal_still_current {
            return Err(error);
        }
        if let Ok(mut interactions) = state.terminal_structured_interactions.lock() {
            interactions.remove(&interaction.interaction_id);
        }
        return Ok(terminal_agent_prompt_already_resolved_result(
            &pane_id,
            Some(instance.id),
            &prompt_id,
            &requested_interaction_id,
            requested_interaction_revision,
            "terminal_closed_before_write",
        ));
    }
    if !review_hooks && !awaiting_provider_confirmation {
        terminal_structured_interaction_publish_answered(
            &app,
            state.inner(),
            cloud_mcp_state.inner(),
            &instance,
            &interaction,
            &option_id,
            "structured-pty-answer",
        )
        .await;
    }
    log_terminal_status_event(
        if review_hooks {
            "backend.terminal_structured_interaction.review_opened"
        } else if awaiting_provider_confirmation {
            "backend.codex_hook_trust.answer_forwarded"
        } else {
            "backend.terminal_structured_interaction.answered"
        },
        json!({
            "interaction_id": interaction.interaction_id,
            "option_id": option_id,
            "pane_id": pane_id,
            "provider": interaction.provider,
            "response_mode": interaction.response_mode,
            "revision": interaction.revision,
        }),
    );
    let runtime = match get_terminal_instance_if_current(state.inner(), &pane_id, instance_id).await
    {
        Ok(Some(instance)) => Some(terminal_runtime_snapshot(&instance)),
        _ => None,
    };
    Ok(json!({
        "prompt_id": prompt_id,
        "option_id": option_id,
        "option_value": option_value.unwrap_or_default(),
        "pane_id": pane_id,
        "terminal_instance_id": instance_id,
        "turn_id": runtime
            .as_ref()
            .and_then(|snapshot| snapshot.turn_id.clone())
            .unwrap_or_default(),
        "provider_turn_id": runtime
            .as_ref()
            .and_then(|snapshot| snapshot.provider_turn_id.clone())
            .unwrap_or_default(),
        "provider_session_id": runtime
            .as_ref()
            .and_then(|snapshot| snapshot.provider_session_id.clone())
            .unwrap_or_default(),
        "native_session_id": runtime
            .as_ref()
            .and_then(|snapshot| snapshot.native_session_id.clone())
            .unwrap_or_default(),
        "interaction_id": interaction.interaction_id,
        "interaction_revision": interaction.revision,
        "status": if review_hooks {
            "reviewing_hooks"
        } else if awaiting_provider_confirmation {
            "accepted_pending_confirmation"
        } else {
            "applied"
        },
        "message": if awaiting_provider_confirmation {
            "Answer submitted; waiting for Codex to confirm the response."
        } else {
            ""
        },
        "answered": !review_hooks && !awaiting_provider_confirmation,
        "accepted": !review_hooks || awaiting_provider_confirmation,
        "resolved": !review_hooks && !awaiting_provider_confirmation,
    }))
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_request_fork(
    app: AppHandle,
    state: State<'_, TerminalState>,
    pane_id: String,
    instance_id: Option<u64>,
) -> Result<(), String> {
    validate_terminal_pane_id(&pane_id)?;
    let Some(instance) =
        get_terminal_instance_if_current(state.inner(), &pane_id, instance_id).await?
    else {
        return Err("Terminal session is not running.".to_string());
    };
    let Some(provider_session_id) = terminal_current_recordable_provider_session_id(&instance)
    else {
        return Err("This terminal does not have a provider session to fork yet.".to_string());
    };

    log_terminal_status_event(
        "backend.terminal_request_fork.accepted",
        json!({
            "agent_kind": clean_terminal_diagnostic_log_text(&instance.metadata.agent_kind),
            "instance_id": instance.id,
            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
            "provider_session_id_present": true,
            "thread_id": clean_terminal_diagnostic_log_text(&instance.metadata.thread_id),
            "workspace_id": clean_terminal_diagnostic_log_text(&instance.metadata.workspace_id),
        }),
    );
    emit_terminal_fork_requested(&app, &instance, provider_session_id);
    Ok(())
}

#[derive(Deserialize)]
struct TerminalCaptureDirectPromptTodoRequest {
    workspace_id: String,
    workspace_name: Option<String>,
    pane_id: String,
    terminal_index: Option<u64>,
    thread_id: String,
    agent_kind: String,
    prompt: String,
    prompt_event_id: Option<String>,
    item_id: Option<String>,
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_capture_direct_prompt_todo(
    app: AppHandle,
    request: TerminalCaptureDirectPromptTodoRequest,
) -> Result<Option<String>, String> {
    validate_terminal_pane_id(&request.pane_id)?;
    let workspace_id = request.workspace_id.trim();
    let pane_id = request.pane_id.trim();
    let prompt = request.prompt.trim();
    if workspace_id.is_empty() || prompt.is_empty() {
        return Ok(None);
    }
    if todo_dispatch_is_app_control_terminal_surface(workspace_id, pane_id) {
        log_terminal_status_event(
            "backend.terminal.capture_direct_prompt_app_control_skip",
            json!({
                "agent_kind": request.agent_kind.trim(),
                "pane_id": pane_id,
                "prompt_len": prompt.len(),
                "workspace_id": workspace_id,
            }),
        );
        return Ok(None);
    }
    Ok(todo_dispatch_capture_direct_prompt_todo(
        &app,
        workspace_id,
        request.workspace_name.as_deref().unwrap_or_default(),
        pane_id,
        request.terminal_index.unwrap_or(0),
        request.thread_id.trim(),
        request.agent_kind.trim(),
        prompt,
        request.prompt_event_id.as_deref(),
        request.item_id.as_deref(),
    ))
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_write_realtime(
    app: AppHandle,
    pane_id: String,
    instance_id: Option<u64>,
    data: String,
    prompt_event_id: Option<String>,
    prompt_event_revision: Option<u64>,
    prompt_event_source: Option<String>,
    prompt_event_submitted_at: Option<String>,
    prompt_event_text: Option<String>,
    todo_id: Option<String>,
    todo_dispatch_id: Option<String>,
    todo_command_id: Option<String>,
    todo_action: Option<String>,
    todo_resume_requested: Option<bool>,
    thread_id: Option<String>,
    app_fork_enabled: Option<bool>,
) -> Result<(), String> {
    validate_terminal_pane_id(&pane_id)?;
    if data.len() > MAX_TERMINAL_WRITE_BYTES {
        return Err("Terminal input chunk is too large.".to_string());
    }

    let task_app = app.clone();
    let error_pane_id = pane_id.clone();
    let error_instance_id = instance_id;
    tauri::async_runtime::spawn(async move {
        let state = task_app.state::<TerminalState>();
        let cloud_mcp_state = task_app.state::<CloudMcpState>();
        if let Err(error) = terminal_write_inner(
            task_app.clone(),
            state.inner(),
            cloud_mcp_state.inner(),
            pane_id,
            instance_id,
            data,
            prompt_event_id,
            prompt_event_revision,
            prompt_event_source,
            prompt_event_submitted_at,
            prompt_event_text,
            todo_id,
            todo_dispatch_id,
            todo_command_id,
            todo_action,
            todo_resume_requested,
            thread_id,
            app_fork_enabled,
            None,
            true,
            true,
        )
        .await
        {
            emit_terminal_input_error(&task_app, error_pane_id, error_instance_id, error);
        }
    });

    Ok(())
}

fn terminal_provider_turn_should_reconcile_coordination(
    reconcile_coordination: Option<bool>,
) -> bool {
    reconcile_coordination.unwrap_or(false)
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_provider_turn_completed(
    app: AppHandle,
    state: State<'_, TerminalState>,
    pane_id: String,
    instance_id: Option<u64>,
    reason: Option<String>,
    reconcile_coordination: Option<bool>,
) -> Result<Value, String> {
    validate_terminal_pane_id(&pane_id)?;
    if !terminal_provider_turn_should_reconcile_coordination(reconcile_coordination) {
        return Ok(json!({
            "ok": true,
            "status": "skipped",
            "reason": "provider_turn_not_coordination_scoped",
        }));
    }
    let Some(instance) = get_terminal_instance_if_current(&state, &pane_id, instance_id).await?
    else {
        return Ok(json!({
            "ok": true,
            "status": "skipped",
            "reason": "stale_or_missing_terminal",
        }));
    };
    let Some(coordination) = instance.coordination.clone() else {
        return Ok(json!({
            "ok": true,
            "status": "skipped",
            "reason": "terminal_has_no_coordination_session",
        }));
    };
    let kernel = crate::coordination::CoordinationKernel::open(
        &coordination.repo_path,
        Some(PathBuf::from(&coordination.db_path)),
    )?;
    let active_task_id = {
        let active_task = instance.active_task.lock().await;
        active_task.as_ref().map(|task| task.task_id.clone())
    };
    let session_task_id = kernel
        .query_json(
            "SELECT task_id
             FROM agent_sessions
             WHERE id=?1
             LIMIT 1",
            &[&coordination.session_id],
        )
        .ok()
        .and_then(|rows| rows.into_iter().next())
        .and_then(|row| row["task_id"].as_str().map(str::to_string));
    let latest_session_task_id = kernel
        .query_json(
            "SELECT id
             FROM tasks
             WHERE claimed_session_id=?1
             ORDER BY updated_at DESC, created_at DESC
             LIMIT 1",
            &[&coordination.session_id],
        )
        .ok()
        .and_then(|rows| rows.into_iter().next())
        .and_then(|row| row["id"].as_str().map(str::to_string));
    let Some(task_id) = active_task_id
        .or(session_task_id)
        .or(latest_session_task_id)
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
    else {
        return Ok(json!({
            "ok": true,
            "status": "skipped",
            "reason": "terminal_has_no_known_coordination_task",
        }));
    };

    let result = kernel.reconcile_provider_turn_completed(
        &task_id,
        Some(&coordination.session_id),
        reason.as_deref(),
    )?;
    log_terminal_diagnostic_event(
        &app,
        "backend.provider_turn_completed.reconciled",
        json!({
            "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
            "session_id": coordination.session_id,
            "task_id": task_id,
            "result": result.clone(),
        }),
    );
    Ok(result)
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_refresh_theme(
    state: State<'_, TerminalState>,
    pane_id: String,
    instance_id: Option<u64>,
) -> Result<bool, String> {
    validate_terminal_pane_id(&pane_id)?;
    let Some(instance) = get_terminal_instance_if_current(&state, &pane_id, instance_id).await?
    else {
        return Ok(false);
    };

    if !terminal_metadata_is_opencode(&instance.metadata) {
        return Ok(false);
    }

    if !*instance.agent_started.lock().await {
        return Ok(false);
    }

    let root_pid = {
        let child = instance.child.lock().await;
        child.as_ref().and_then(|child| child.process_id())
    };
    let Some(root_pid) = root_pid.filter(|pid| *pid > 0) else {
        return Ok(false);
    };

    Ok(!signal_opencode_theme_refresh(root_pid)?.is_empty())
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_delete_selection(
    state: State<'_, TerminalState>,
    pane_id: String,
    instance_id: Option<u64>,
    selection: String,
    current_line: Option<String>,
    selection_start: Option<usize>,
    selection_end: Option<usize>,
) -> Result<Value, String> {
    validate_terminal_pane_id(&pane_id)?;
    let selected_text = selection
        .chars()
        .filter(|character| !matches!(character, '\r' | '\n'))
        .collect::<String>();

    if selected_text.is_empty() {
        return Ok(json!({
            "deleted": false,
            "reason": "empty_selection",
        }));
    }

    let Some(instance) = get_terminal_instance_if_current(&state, &pane_id, instance_id).await?
    else {
        return Ok(json!({
            "deleted": false,
            "reason": "stale_or_missing_terminal",
        }));
    };
    let Some(_operation) = terminal_operation_try_admit(&instance) else {
        return Ok(json!({
            "deleted": false,
            "reason": "terminal_closing",
        }));
    };

    let _input_guard = instance.input_queue.lock().await;
    let mut gate = instance.input_gate.lock().await;
    let observed_line = current_line
        .unwrap_or_default()
        .chars()
        .filter(|character| !matches!(character, '\r' | '\n'))
        .collect::<String>();
    let current_line = if observed_line.trim().is_empty() {
        gate.current_line.clone()
    } else {
        observed_line
    };
    let line_char_len = current_line.chars().count();
    let offset_range = selection_start
        .zip(selection_end)
        .map(|(start, end)| (start.min(end), start.max(end)))
        .filter(|(start, end)| *end > *start && *end <= line_char_len);
    let text_range = if offset_range.is_some() {
        offset_range
    } else {
        current_line.rfind(&selected_text).map(|start_byte| {
            let start = current_line[..start_byte].chars().count();
            let end = start + selected_text.chars().count();
            (start, end)
        })
    };
    let Some((start, end)) = text_range else {
        return Ok(json!({
            "deleted": false,
            "reason": "selection_not_in_current_input",
        }));
    };

    let start_byte = terminal_input_gate_byte_index(&current_line, start);
    let end_byte = terminal_input_gate_byte_index(&current_line, end);
    let mut next_line = current_line;
    next_line.replace_range(start_byte..end_byte, "");
    let rewrite_input = format!("\u{15}{next_line}");
    if rewrite_input.len() > MAX_TERMINAL_WRITE_BYTES {
        return Err("Terminal rewrite input is too large.".to_string());
    }

    {
        let mut writer = instance.writer.lock().await;
        log_terminal_crash_forensics_event(
            "backend.terminal_selection_delete.write.begin",
            json!({
                "bytes": rewrite_input.len(),
                "instance_id": instance.id,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
            }),
        );
        if let Err(error) = writer.write_all(rewrite_input.as_bytes()) {
            log_terminal_crash_forensics_event(
                "backend.terminal_selection_delete.write.error",
                json!({
                    "bytes": rewrite_input.len(),
                    "error": clean_terminal_diagnostic_log_text(&error.to_string()),
                    "instance_id": instance.id,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "stage": "write_all",
                }),
            );
            return Err(format!(
                "Unable to write terminal selection delete: {error}"
            ));
        }
        if let Err(error) = writer.flush() {
            log_terminal_crash_forensics_event(
                "backend.terminal_selection_delete.write.error",
                json!({
                    "bytes": rewrite_input.len(),
                    "error": clean_terminal_diagnostic_log_text(&error.to_string()),
                    "instance_id": instance.id,
                    "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
                    "stage": "flush",
                }),
            );
            return Err(format!(
                "Unable to flush terminal selection delete: {error}"
            ));
        }
        log_terminal_crash_forensics_event(
            "backend.terminal_selection_delete.write.done",
            json!({
                "bytes": rewrite_input.len(),
                "instance_id": instance.id,
                "pane_id": clean_terminal_diagnostic_log_text(&pane_id),
            }),
        );
    }

    gate.current_line = next_line;
    gate.cursor_position = terminal_input_gate_line_char_len(&gate);
    gate.current_line_user_touched = true;

    Ok(json!({
        "deleted": true,
        "remaining_line": gate.current_line,
        "remaining_chars": gate.current_line.chars().count(),
        "removed_chars": selected_text.chars().count(),
    }))
}

#[tauri::command(rename_all = "snake_case")]
async fn terminal_cancel_parked_task(
    app: AppHandle,
    state: State<'_, TerminalState>,
    cloud_mcp_state: State<'_, CloudMcpState>,
    pane_id: String,
    instance_id: u64,
    task_id: String,
) -> Result<(), String> {
    validate_terminal_pane_id(&pane_id)?;
    let parked_key = terminal_parked_prompt_key(&pane_id, instance_id, &task_id);
    let Some(parked) = state.parked_prompts.write().await.remove(&parked_key) else {
        return Ok(());
    };

    if let Ok(kernel) = crate::coordination::CoordinationKernel::open(
        &parked.coordination.repo_path,
        Some(PathBuf::from(&parked.coordination.db_path)),
    ) {
        let _ = kernel.mark_terminal_task_stopped(
            &parked.task_id,
            &parked.coordination.session_id,
            "cancelled",
            "parked_task_cancel_button",
        );
    }

    if let Some(instance) =
        get_terminal_instance_if_current(&state, &pane_id, Some(instance_id)).await?
    {
        let mut active_task = instance.active_task.lock().await;
        if active_task
            .as_ref()
            .is_some_and(|task| task.task_id == parked.task_id)
        {
            *active_task = None;
        }
    }

    emit_terminal_parked_prompt_event(&app, &parked, "cancelled", Some("cancel_button"));

    let app_for_cloud = app.clone();
    let cloud_state = cloud_mcp_state.inner().clone();
    tauri::async_runtime::spawn(async move {
        mark_terminal_parked_prompt_lifecycle_in_cloud(
            &app_for_cloud,
            &cloud_state,
            &parked,
            "cancelled",
            "Cancelled before resuming: the parked task was cancelled from the terminal bar.",
        )
        .await;
    });

    Ok(())
}

async fn write_terminal_interrupt_escape(instance: &TerminalInstance) -> Result<(), String> {
    let mut writer = instance.writer.lock().await;
    log_terminal_crash_forensics_event(
        "backend.terminal_interrupt.write.begin",
        json!({
            "bytes": 1,
            "instance_id": instance.id,
            "metadata": terminal_metadata_forensics_json(&instance.metadata),
        }),
    );
    if let Err(error) = writer.write_all(b"\x1b") {
        log_terminal_crash_forensics_event(
            "backend.terminal_interrupt.write.error",
            json!({
                "bytes": 1,
                "error": clean_terminal_diagnostic_log_text(&error.to_string()),
                "instance_id": instance.id,
                "stage": "write_all",
            }),
        );
        return Err(format!("Unable to send terminal interrupt: {error}"));
    }
    if let Err(error) = writer.flush() {
        log_terminal_crash_forensics_event(
            "backend.terminal_interrupt.write.error",
            json!({
                "bytes": 1,
                "error": clean_terminal_diagnostic_log_text(&error.to_string()),
                "instance_id": instance.id,
                "stage": "flush",
            }),
        );
        return Err(format!("Unable to flush terminal interrupt: {error}"));
    }
    log_terminal_crash_forensics_event(
        "backend.terminal_interrupt.write.done",
        json!({
            "bytes": 1,
            "instance_id": instance.id,
        }),
    );
    Ok(())
}

async fn publish_terminal_provider_turn_interrupted(
    app: &AppHandle,
    state: &TerminalState,
    cloud_mcp_state: &CloudMcpState,
    instance: &TerminalInstance,
    reason: &str,
) -> Result<TerminalInterruptOutcome, String> {
    let runtime = terminal_runtime_snapshot(instance);
    if !terminal_runtime_accepts_interrupt(&runtime) {
        log_terminal_status_event(
            "backend.terminal_interrupt.publish_idle_noop",
            json!({
                "canonical_state": runtime.canonical_state,
                "input_ready": runtime.input_ready,
                "instance_id": instance.id,
                "reason": clean_terminal_diagnostic_log_text(reason),
                "turn_active": runtime.turn_active,
            }),
        );
        return Ok(TerminalInterruptOutcome::IdleNoop);
    }
    let event = terminal_activity_watchdog_event(
        instance,
        &runtime,
        "Interrupt",
        "backend-terminal-interrupt",
        reason,
    );
    process_terminal_activity_hook_event(
        app,
        &state.terminals,
        cloud_mcp_state,
        &instance.metadata.pane_id,
        instance.id,
        instance,
        &event,
        "backend-terminal-interrupt",
    )
    .await;
    let applied = terminal_runtime_snapshot(instance);
    if applied.event_type != "provider-turn-interrupted"
        || applied.activity_status != "interrupted"
        || applied.command_phase != "interrupted"
        || applied.input_ready
    {
        if !terminal_runtime_accepts_interrupt(&applied) {
            log_terminal_status_event(
                "backend.terminal_interrupt.reducer_race_noop",
                json!({
                    "canonical_state": applied.canonical_state,
                    "event_type": applied.event_type,
                    "input_ready": applied.input_ready,
                    "instance_id": instance.id,
                    "reason": clean_terminal_diagnostic_log_text(reason),
                    "turn_active": applied.turn_active,
                }),
            );
            return Ok(TerminalInterruptOutcome::IdleNoop);
        }
        return Err("Unable to publish terminal interrupt runtime state.".to_string());
    }
    Ok(TerminalInterruptOutcome::InterruptApplied)
}

async fn mark_terminal_active_task_interrupted(
    cloud_mcp_state: &CloudMcpState,
    pane_id: &str,
    instance: &TerminalInstance,
    reason: &str,
    lifecycle_message: &str,
) -> Result<bool, String> {
    let active_task = instance.active_task.lock().await.clone();
    let (Some(coordination), Some(active_task)) =
        (instance.coordination.as_ref(), active_task.as_ref())
    else {
        return Ok(false);
    };

    if let Ok(kernel) = crate::coordination::CoordinationKernel::open(
        &coordination.repo_path,
        Some(PathBuf::from(&coordination.db_path)),
    ) {
        let _ = kernel.mark_terminal_task_stopped(
            &active_task.task_id,
            &coordination.session_id,
            "interrupted",
            reason,
        );
    }
    cloud_mcp_mark_terminal_task_lifecycle(
        cloud_mcp_state,
        pane_id,
        instance.id,
        instance.working_directory.as_ref(),
        Some(coordination),
        Some(&active_task.task_id),
        Some(&active_task.title),
        "interrupted",
        lifecycle_message,
    )
    .await;
    let mut stored_active_task = instance.active_task.lock().await;
    if stored_active_task
        .as_ref()
        .is_some_and(|task| task.task_id == active_task.task_id)
    {
        *stored_active_task = None;
    }
    Ok(true)
}

fn mark_terminal_parked_prompt_stopped(parked: &TerminalParkedPrompt, status: &str, reason: &str) {
    if let Ok(kernel) = crate::coordination::CoordinationKernel::open(
        &parked.coordination.repo_path,
        Some(PathBuf::from(&parked.coordination.db_path)),
    ) {
        let _ = kernel.mark_terminal_task_stopped(
            &parked.task_id,
            &parked.coordination.session_id,
            status,
            reason,
        );
    }
}

async fn interrupt_terminal_parked_prompts(
    app: &AppHandle,
    state: &TerminalState,
    cloud_mcp_state: &CloudMcpState,
    pane_id: &str,
    instance: &TerminalInstance,
    reason: &str,
    skip_kernel_task_id: Option<&str>,
) -> Result<usize, String> {
    let parked_to_interrupt = {
        let mut parked = state.parked_prompts.write().await;
        let matching_keys = parked
            .iter()
            .filter_map(|(key, value)| {
                (value.pane_id == pane_id && value.instance_id == instance.id).then(|| key.clone())
            })
            .collect::<Vec<_>>();
        matching_keys
            .into_iter()
            .filter_map(|key| parked.remove(&key))
            .collect::<Vec<_>>()
    };
    let interrupted_count = parked_to_interrupt.len();
    for parked in parked_to_interrupt {
        if skip_kernel_task_id != Some(parked.task_id.as_str()) {
            mark_terminal_parked_prompt_stopped(&parked, "interrupted", reason);
        }
        cloud_mcp_mark_terminal_task_lifecycle(
            cloud_mcp_state,
            &parked.pane_id,
            parked.instance_id,
            &parked.working_directory,
            Some(&parked.coordination),
            Some(&parked.task_id),
            Some(&parked.title),
            "interrupted",
            "Interrupted by Escape while parked; the task was not marked cancelled.",
        )
        .await;
        emit_terminal_parked_prompt_event(app, &parked, "interrupted", Some("escape_key"));
    }
    Ok(interrupted_count)
}

#[derive(Serialize)]
struct TerminalInterruptAgentResult {
    outcome: TerminalInterruptOutcome,
    session_found: bool,
    interrupted_active_task: bool,
    interrupted_parked_prompt_count: usize,
    interrupted_todo_count: usize,
    wrote_escape: bool,
}

impl TerminalInterruptAgentResult {
    fn idle_noop(session_found: bool, wrote_escape: bool) -> Self {
        Self {
            outcome: TerminalInterruptOutcome::IdleNoop,
            session_found,
            interrupted_active_task: false,
            interrupted_parked_prompt_count: 0,
            interrupted_todo_count: 0,
            wrote_escape,
        }
    }
}

