    #[test]
    fn canonical_transition_table_rejects_direct_active_to_idle_shortcuts() {
        for transition in [
            ("starting", "idle"),
            ("starting", "thinking"),
            ("idle", "thinking"),
            ("thinking", "uir"),
            ("thinking", "paused"),
            ("uir", "thinking"),
            ("paused", "thinking"),
            ("thinking", "idle"),
            ("uir", "idle"),
            ("paused", "idle"),
            ("thinking", "interrupted"),
            ("uir", "interrupted"),
            ("paused", "interrupted"),
            ("closing", "closed"),
            ("closed", "starting"),
        ] {
            assert!(terminal_canonical_transition_allowed(
                transition.0,
                transition.1,
            ));
        }
        for transition in [("idle", "uir"), ("closed", "idle"), ("error", "idle")] {
            assert!(!terminal_canonical_transition_allowed(
                transition.0,
                transition.1,
            ));
        }
    }

