    #[test]
    fn canonical_reducer_recovers_interrupted_and_startup_error_to_idle_for_same_session() {
        for previous_state in ["interrupted", "error"] {
            let mut runtime = TerminalRuntimeSnapshot::opened_idle(Some("session-1".to_string()));
            runtime.canonical_state = previous_state.to_string();
            runtime.canonical_badge_label = previous_state.to_string();
            runtime.canonical_state_seq = 4;
            runtime.turn_generation = 1;
            runtime.completed_turn_generation = 1;
            runtime.turn_active = false;
            runtime.input_ready = false;

            let ready = terminal_activity_hook_test_payload(
                "terminal-input-ready",
                "idle",
                "ready",
                true,
                Some("session-1"),
            );
            let mut ready = ready;
            ready.turn_generation = runtime.turn_generation;
            let projection =
                terminal_reduce_canonical_state(&runtime, &ready, None, false, false);
            assert_eq!(projection.canonical_state, "idle", "{previous_state}");
            assert!(!projection.turn_active, "{previous_state}");
            assert_eq!(
                projection.completed_turn_generation,
                projection.turn_generation,
                "{previous_state}",
            );

            let mut mismatched = terminal_activity_hook_test_payload(
                "terminal-input-ready",
                "idle",
                "ready",
                true,
                Some("different-session"),
            );
            mismatched.turn_generation = runtime.turn_generation;
            let rejected =
                terminal_reduce_canonical_state(&runtime, &mismatched, None, false, false);
            assert_eq!(
                rejected.canonical_state, previous_state,
                "a stale session must not recover {previous_state}",
            );

            let mut stale_generation = ready.clone();
            stale_generation.turn_generation = runtime.turn_generation.saturating_sub(1);
            let rejected = terminal_reduce_canonical_state(
                &runtime,
                &stale_generation,
                None,
                false,
                false,
            );
            assert_eq!(
                rejected.canonical_state, previous_state,
                "a stale turn generation must not recover {previous_state}",
            );

            let mut identified_runtime = runtime.clone();
            identified_runtime.provider_turn_id = Some("turn-current".to_string());
            identified_runtime.turn_id = Some("turn-current".to_string());
            let mut stale_turn = ready.clone();
            stale_turn.provider_turn_id = Some("turn-old".to_string());
            stale_turn.turn_id = Some("turn-old".to_string());
            let rejected = terminal_reduce_canonical_state(
                &identified_runtime,
                &stale_turn,
                None,
                false,
                false,
            );
            assert_eq!(
                rejected.canonical_state, previous_state,
                "a stale turn id must not recover {previous_state}",
            );

            let mut same_turn = ready.clone();
            same_turn.provider_turn_id = Some("turn-current".to_string());
            same_turn.turn_id = Some("turn-current".to_string());
            let recovered = terminal_reduce_canonical_state(
                &identified_runtime,
                &same_turn,
                None,
                false,
                false,
            );
            assert_eq!(recovered.canonical_state, "idle", "{previous_state}");
        }
    }

    #[test]
    fn backend_interrupt_lifecycle_applies_authoritative_runtime_state() {
        let root = env::temp_dir().join(format!(
            "terminal-interrupt-runtime-{}",
            uuid::Uuid::new_v4()
        ));
        fs::create_dir_all(&root).unwrap();
        let size = PtySize {
            rows: 12,
            cols: 80,
            pixel_width: 0,
            pixel_height: 0,
        };
        let warm = create_warm_shell_pty_in_directory(size, &root).unwrap();
        let metadata = TerminalInstanceMetadata {
            pane_id: "pane-interrupt-runtime".to_string(),
            agent_id: "codex".to_string(),
            agent_kind: "codex".to_string(),
            ..TerminalInstanceMetadata::default()
        };
        let (instance, reader) = TerminalInstance::from_warm_shell(
            71,
            warm,
            root.clone(),
            true,
            None,
            TerminalSessionMode::General,
            metadata,
            TerminalLaunchRuntimeMetadata::default(),
            None,
            false,
        );
        *instance.runtime.lock().unwrap() = TerminalRuntimeSnapshot {
            status: "active".to_string(),
            activity_status: "thinking".to_string(),
            command_phase: "running".to_string(),
            input_ready: false,
            input_ready_at: None,
            prompt_ready_at: None,
            completed_at: None,
            provider_session_id: Some("session-1".to_string()),
            native_session_id: Some("session-1".to_string()),
            fork_from_provider_session_id: None,
            provider_turn_id: Some("turn-1".to_string()),
            turn_id: Some("turn-1".to_string()),
            source: "test".to_string(),
            event_type: "provider-turn-started".to_string(),
            hook_event_name: "UserPromptSubmit".to_string(),
            updated_at_ms: 1,
            canonical_state: "thinking".to_string(),
            canonical_badge_label: "thinking".to_string(),
            canonical_state_seq: 2,
            turn_generation: 1,
            turn_active: true,
            ..TerminalRuntimeSnapshot::opened_idle(None)
        };
        let event = json!({
            "hook_event_name": "Interrupt",
            "provider": "codex",
            "session_id": "session-1",
            "turn_id": "turn-1",
            "source": "backend-terminal-interrupt",
        });
        let payload = terminal_activity_hook_payload(&instance, &event).unwrap();
        assert_eq!(payload.event_type, "provider-turn-interrupted");
        assert_eq!(payload.turn_generation, 1);
        assert!(!payload.turn_generation_explicit);
        assert_eq!(payload.activity_status, "interrupted");
        assert!(!payload.input_ready);
        assert!(payload.input_ready_at.is_none());

        let (runtime, _) =
            terminal_runtime_apply_activity_payload(&instance, &payload, None, false, false);
        assert_eq!(runtime.event_type, "provider-turn-interrupted");
        assert_eq!(runtime.activity_status, "interrupted");
        assert_eq!(runtime.command_phase, "interrupted");
        assert!(!runtime.input_ready);
        assert!(runtime.input_ready_at.is_none());

        let mut newer_interrupted = runtime.clone();
        newer_interrupted.turn_generation = 2;
        newer_interrupted.completed_turn_generation = 2;
        newer_interrupted.provider_turn_id = Some("turn-2".to_string());
        newer_interrupted.turn_id = Some("turn-2".to_string());
        newer_interrupted.source = "newer-interrupt".to_string();
        newer_interrupted.updated_at_ms = 2;
        *instance.runtime.lock().unwrap() = newer_interrupted.clone();

        let stale_ready_payload = terminal_activity_hook_payload(
            &instance,
            &json!({
                "hook_event_name": "PromptReadyAfterInterrupt",
                "provider": "codex",
                "session_id": "session-1",
                "turn_generation": 1,
                "turn_id": "turn-1",
                "source": "backend-interrupt-prompt-ready",
            }),
        )
        .unwrap();
        let (stale_runtime, stale_projection) = terminal_runtime_apply_activity_payload(
            &instance,
            &stale_ready_payload,
            None,
            false,
            false,
        );
        assert_eq!(stale_projection.canonical_state, "interrupted");
        assert_eq!(stale_runtime.canonical_state, "interrupted");
        assert_eq!(stale_runtime.activity_status, "interrupted");
        assert_eq!(stale_runtime.command_phase, "interrupted");
        assert!(!stale_runtime.input_ready);
        assert_eq!(stale_runtime.provider_turn_id.as_deref(), Some("turn-2"));
        assert_eq!(stale_runtime.turn_id.as_deref(), Some("turn-2"));
        assert_eq!(stale_runtime.source, "newer-interrupt");
        assert_eq!(stale_runtime.event_type, newer_interrupted.event_type);
        assert_eq!(stale_runtime.updated_at_ms, newer_interrupted.updated_at_ms);

        let current_ready_payload = terminal_activity_hook_payload(
            &instance,
            &json!({
                "hook_event_name": "PromptReadyAfterInterrupt",
                "provider": "codex",
                "session_id": "session-1",
                "turn_generation": 2,
                "turn_id": "turn-2",
                "source": "backend-interrupt-prompt-ready",
            }),
        )
        .unwrap();
        let (current_ready_runtime, _) = terminal_runtime_apply_activity_payload(
            &instance,
            &current_ready_payload,
            None,
            false,
            false,
        );
        assert_eq!(current_ready_runtime.canonical_state, "idle");
        assert_eq!(current_ready_runtime.provider_turn_id.as_deref(), Some("turn-2"));
        assert!(current_ready_runtime.input_ready);

        *instance.runtime.lock().unwrap() = runtime.clone();

        let provider_stop_event = json!({
            "hook_event_name": "Stop",
            "provider": "codex",
            "session_id": "session-1",
            "turn_id": "turn-1",
        });
        let provider_stop_payload =
            terminal_activity_hook_payload(&instance, &provider_stop_event).unwrap();
        assert_eq!(provider_stop_payload.event_type, "terminal-input-ready");
        assert!(provider_stop_payload.input_ready);
        assert!(!terminal_activity_hook_idle_stop_already_settled(
            &provider_stop_payload,
            &runtime,
            false,
            "pane-interrupt-runtime",
            71,
        ));

        let prompt_ready_event = json!({
            "hook_event_name": "PromptReadyAfterInterrupt",
            "provider": "codex",
            "session_id": "session-1",
            "turn_generation": 1,
            "turn_id": "turn-1",
            "source": "backend-interrupt-prompt-ready",
        });
        let prompt_ready_payload =
            terminal_activity_hook_payload(&instance, &prompt_ready_event).unwrap();
        assert_eq!(prompt_ready_payload.event_type, "terminal-input-ready");
        assert_eq!(prompt_ready_payload.activity_status, "idle");
        assert!(prompt_ready_payload.input_ready);

        let (ready_runtime, _) = terminal_runtime_apply_activity_payload(
            &instance,
            &prompt_ready_payload,
            None,
            false,
            false,
        );
        assert_eq!(ready_runtime.event_type, "terminal-input-ready");
        assert_eq!(ready_runtime.activity_status, "idle");
        assert!(ready_runtime.input_ready);
        assert!(ready_runtime.input_ready_at.is_some());
        assert!(ready_runtime.completed_at.is_none());

        let mut active_runtime =
            TerminalRuntimeSnapshot::opened_idle(Some("session-1".to_string()));
        active_runtime.canonical_state = "thinking".to_string();
        active_runtime.canonical_badge_label = "thinking".to_string();
        active_runtime.canonical_state_seq = 10;
        active_runtime.turn_generation = 1;
        active_runtime.turn_active = true;
        active_runtime.activity_status = "thinking".to_string();
        active_runtime.command_phase = "running".to_string();
        active_runtime.input_ready = false;
        active_runtime.provider_turn_id = Some("turn-1".to_string());
        active_runtime.turn_id = Some("turn-1".to_string());
        active_runtime.event_type = "provider-turn-started".to_string();
        active_runtime.hook_event_name = "UserPromptSubmit".to_string();
        *instance.runtime.lock().unwrap() = active_runtime;

        let current_runtime = terminal_runtime_snapshot(&instance);
        let generationless_stop = terminal_activity_hook_payload(
            &instance,
            &json!({
                "hook_event_name": "Stop",
                "provider": "codex",
                "session_id": "session-1",
                "turn_id": "turn-1",
            }),
        )
        .unwrap();
        assert_eq!(generationless_stop.turn_generation, 1);
        assert!(!generationless_stop.turn_generation_explicit);
        let accepted_generationless = terminal_reduce_canonical_state(
            &current_runtime,
            &generationless_stop,
            None,
            false,
            false,
        );
        assert!(accepted_generationless.completion_accepted);

        let mut uir_runtime = current_runtime.clone();
        uir_runtime.canonical_state = "uir".to_string();
        uir_runtime.canonical_badge_label = "input required".to_string();
        uir_runtime.active_interaction_id = Some("uir:b".to_string());
        uir_runtime.active_interaction_revision = Some(2);
        uir_runtime.interaction_actionable = true;
        let rejected_idle_timer_stop = terminal_reduce_canonical_state(
            &uir_runtime,
            &generationless_stop,
            None,
            false,
            false,
        );
        assert!(!rejected_idle_timer_stop.completion_accepted);
        assert_eq!(rejected_idle_timer_stop.canonical_state, "uir");
        assert!(rejected_idle_timer_stop.turn_active);
        assert_eq!(
            rejected_idle_timer_stop.active_interaction_id.as_deref(),
            Some("uir:b"),
        );

        let mut explicit_current_stop = generationless_stop.clone();
        explicit_current_stop.turn_generation_explicit = true;
        let accepted_explicit_uir_stop = terminal_reduce_canonical_state(
            &uir_runtime,
            &explicit_current_stop,
            None,
            false,
            false,
        );
        assert!(accepted_explicit_uir_stop.completion_accepted);
        assert_eq!(accepted_explicit_uir_stop.canonical_state, "idle");

        let explicit_old_stop = terminal_activity_hook_payload(
            &instance,
            &json!({
                "hook_event_name": "Stop",
                "provider": "codex",
                "session_id": "session-1",
                "turn_id": "turn-1",
                "turn_generation": 0,
            }),
        )
        .unwrap();
        assert_eq!(explicit_old_stop.turn_generation, 0);
        assert!(explicit_old_stop.turn_generation_explicit);
        let rejected_explicit_old = terminal_reduce_canonical_state(
            &current_runtime,
            &explicit_old_stop,
            None,
            false,
            false,
        );
        assert!(!rejected_explicit_old.completion_accepted);
        assert_eq!(rejected_explicit_old.canonical_state, "thinking");

        let mut wrong_stop = terminal_activity_hook_test_payload(
            "provider-turn-completed",
            "idle",
            "completed",
            true,
            Some("session-1"),
        );
        wrong_stop.provider_turn_id = Some("turn-old".to_string());
        wrong_stop.turn_id = Some("turn-old".to_string());
        let (after_wrong_stop, wrong_projection) =
            terminal_runtime_apply_activity_payload(&instance, &wrong_stop, None, false, false);
        assert!(!wrong_projection.completion_accepted);
        assert_eq!(after_wrong_stop.canonical_state, "thinking");
        assert!(after_wrong_stop.turn_active);
        assert_eq!(after_wrong_stop.activity_status, "thinking");
        assert_eq!(after_wrong_stop.command_phase, "running");
        assert_eq!(after_wrong_stop.provider_turn_id.as_deref(), Some("turn-1"));

        let mut wrong_interrupt = terminal_activity_hook_test_payload(
            "provider-turn-interrupted",
            "interrupted",
            "interrupted",
            false,
            Some("session-1"),
        );
        wrong_interrupt.hook_event_name = "Interrupt".to_string();
        wrong_interrupt.source = "stale-interrupt".to_string();
        wrong_interrupt.provider_turn_id = Some("turn-old".to_string());
        wrong_interrupt.turn_id = Some("turn-old".to_string());
        let (after_wrong_interrupt, wrong_interrupt_projection) =
            terminal_runtime_apply_activity_payload(
                &instance,
                &wrong_interrupt,
                None,
                false,
                false,
            );
        assert!(!wrong_interrupt_projection.interrupt_accepted);
        assert_eq!(after_wrong_interrupt.canonical_state, "thinking");
        assert!(after_wrong_interrupt.turn_active);
        assert_eq!(after_wrong_interrupt.activity_status, "thinking");
        assert_eq!(after_wrong_interrupt.command_phase, "running");
        assert_eq!(
            after_wrong_interrupt.provider_turn_id.as_deref(),
            Some("turn-1")
        );
        assert_eq!(after_wrong_interrupt.event_type, "provider-turn-started");
        assert_eq!(after_wrong_interrupt.hook_event_name, "UserPromptSubmit");

        let mut correlated_stop = wrong_stop;
        correlated_stop.provider_turn_id = Some("turn-1".to_string());
        correlated_stop.turn_id = Some("turn-1".to_string());
        correlated_stop.turn_generation = 1;
        let (after_correlated_stop, correlated_projection) =
            terminal_runtime_apply_activity_payload(
                &instance,
                &correlated_stop,
                None,
                false,
                false,
            );
        assert!(correlated_projection.completion_accepted);
        assert_eq!(after_correlated_stop.canonical_state, "idle");
        assert!(!after_correlated_stop.turn_active);
        assert_eq!(
            after_correlated_stop.completed_turn_generation,
            after_correlated_stop.turn_generation,
        );
        assert_eq!(after_correlated_stop.activity_status, "idle");
        assert_eq!(after_correlated_stop.command_phase, "completed");
        assert_eq!(after_correlated_stop.event_type, "provider-turn-completed");

        drop(reader);
        cleanup_terminal_instance_async(
            instance,
            true,
            "terminal_interrupt_runtime_test",
            true,
            None,
        );
        let _ = fs::remove_dir_all(root);
    }

    #[test]
    fn terminal_prompt_ready_recovery_uses_provider_structured_lifecycle_for_claude() {
        let mut runtime = TerminalRuntimeSnapshot {
            status: "active".to_string(),
            activity_status: "thinking".to_string(),
            command_phase: "running".to_string(),
            input_ready: false,
            input_ready_at: None,
            prompt_ready_at: Some("2026-06-19T00:00:00Z".to_string()),
            completed_at: None,
            provider_session_id: Some("session-1".to_string()),
            native_session_id: Some("session-1".to_string()),
            fork_from_provider_session_id: None,
            provider_turn_id: Some("turn-1".to_string()),
            turn_id: Some("turn-1".to_string()),
            source: "backend:prompt-submitted".to_string(),
            event_type: "provider-turn-started".to_string(),
            hook_event_name: "BackendPromptSubmit".to_string(),
            updated_at_ms: 1,
            canonical_state: "thinking".to_string(),
            canonical_badge_label: "thinking".to_string(),
            canonical_state_seq: 2,
            turn_generation: 1,
            turn_active: true,
            ..TerminalRuntimeSnapshot::opened_idle(None)
        };
        let codex_metadata = terminal_projection_test_metadata();
        let mut claude_metadata = codex_metadata.clone();
        claude_metadata.agent_id = "claude".to_string();
        claude_metadata.agent_kind = "claude".to_string();
        let mut opencode_metadata = codex_metadata.clone();
        opencode_metadata.agent_id = "opencode".to_string();
        opencode_metadata.agent_kind = "opencode".to_string();

        assert!(terminal_runtime_snapshot_is_busy_turn(&runtime));
        assert!(!terminal_prompt_ready_recovery_allowed(
            &codex_metadata,
            &runtime
        ));
        assert!(!terminal_prompt_ready_recovery_allowed(
            &claude_metadata,
            &runtime
        ));
        assert!(terminal_prompt_ready_recovery_allowed(
            &opencode_metadata,
            &runtime
        ));

        runtime.status = "starting".to_string();
        runtime.activity_status = "starting".to_string();
        runtime.command_phase = "starting".to_string();
        // Claude allows prompt-ready PTY recovery only during startup.
        assert!(terminal_prompt_ready_recovery_allowed(
            &claude_metadata,
            &runtime
        ));
        assert!(terminal_prompt_ready_recovery_allowed(
            &opencode_metadata,
            &runtime
        ));

        runtime.status = "active".to_string();
        runtime.activity_status = "interrupted".to_string();
        runtime.command_phase = "interrupted".to_string();
        runtime.event_type = "provider-turn-interrupted".to_string();
        assert!(terminal_prompt_ready_recovery_allowed(
            &codex_metadata,
            &runtime
        ));
        assert!(!terminal_prompt_ready_recovery_allowed(
            &claude_metadata,
            &runtime
        ));

        runtime.status = "error".to_string();
        runtime.activity_status = "error".to_string();
        runtime.command_phase = "failed".to_string();
        runtime.event_type = "provider-startup-error".to_string();
        assert!(terminal_prompt_ready_recovery_allowed(
            &codex_metadata,
            &runtime
        ));

        runtime.input_ready = true;
        runtime.activity_status = "idle".to_string();
        runtime.command_phase = "completed".to_string();
        assert!(!terminal_runtime_snapshot_is_busy_turn(&runtime));

        runtime.input_ready = false;
        runtime.activity_status = "paused".to_string();
        runtime.command_phase = "awaiting_permission".to_string();
        assert!(!terminal_runtime_snapshot_is_busy_turn(&runtime));

        runtime.activity_status = "error".to_string();
        runtime.command_phase = "failed".to_string();
        assert!(!terminal_runtime_snapshot_is_busy_turn(&runtime));
    }

