    #[test]
    fn parked_resume_lifecycle_states_do_not_project_to_idle_for_agent_providers() {
        for provider in ["codex", "claude", "opencode"] {
            let mut metadata = terminal_projection_test_metadata();
            metadata.agent_id = provider.to_string();
            metadata.agent_kind = provider.to_string();
            for (activity, expected_execution, expected_rail) in [
                ("parked", "needs_input", "paused"),
                ("resume_ready", "needs_input", "paused"),
                ("resume_requested", "running", "thinking"),
                ("resumed", "running", "thinking"),
            ] {
                let runtime = TerminalRuntimeSnapshot {
                    status: "active".to_string(),
                    activity_status: activity.to_string(),
                    command_phase: activity.to_string(),
                    input_ready: false,
                    input_ready_at: None,
                    prompt_ready_at: None,
                    completed_at: None,
                    provider_session_id: Some("session-1".to_string()),
                    native_session_id: Some("session-1".to_string()),
                    fork_from_provider_session_id: None,
                    provider_turn_id: Some("turn-1".to_string()),
                    turn_id: Some("turn-1".to_string()),
                    source: "terminal-parked-lifecycle".to_string(),
                    event_type: activity.to_string(),
                    hook_event_name: activity.to_string(),
                    updated_at_ms: 1,
                    canonical_state: if matches!(activity, "parked" | "resume_ready") {
                        "paused".to_string()
                    } else {
                        "thinking".to_string()
                    },
                    canonical_badge_label: if matches!(activity, "parked" | "resume_ready") {
                        "paused".to_string()
                    } else {
                        "thinking".to_string()
                    },
                    canonical_state_seq: 2,
                    turn_generation: 1,
                    turn_active: true,
                    ..TerminalRuntimeSnapshot::opened_idle(None)
                };
                let projected = terminal_project_runtime(&metadata, &runtime, false);
                assert_eq!(
                    projected.execution_phase, expected_execution,
                    "{provider} {activity}"
                );
                assert_eq!(
                    projected.native_rail_state, expected_rail,
                    "{provider} {activity}"
                );
                assert_ne!(projected.execution_phase, "idle", "{provider} {activity}");
            }
        }
    }

    #[test]
    fn activity_watchdog_transitions_stuck_starting_by_prompt_or_quiet_output() {
        let runtime = TerminalRuntimeSnapshot::opened_starting(None, "terminal-open");
        assert_eq!(
            terminal_activity_watchdog_starting_action(
                &runtime,
                TERMINAL_STARTING_WATCHDOG_MS,
                true,
                true,
                false,
                false,
                false,
            ),
            Some(TerminalActivityWatchdogAction::StartupStop)
        );
        assert_eq!(
            terminal_activity_watchdog_starting_action(
                &runtime,
                TERMINAL_STARTING_WATCHDOG_MS,
                true,
                false,
                false,
                true,
                false,
            ),
            Some(TerminalActivityWatchdogAction::StartupStop)
        );
        assert_eq!(
            terminal_activity_watchdog_starting_action(
                &runtime,
                TERMINAL_STARTING_WATCHDOG_MS,
                true,
                false,
                false,
                false,
                true,
            ),
            Some(TerminalActivityWatchdogAction::StartupDowngradeRunning)
        );
        assert_eq!(
            terminal_activity_watchdog_starting_action(
                &runtime,
                TERMINAL_STARTING_WATCHDOG_MS - 1,
                true,
                true,
                false,
                true,
                false,
            ),
            None
        );
        assert_eq!(
            terminal_activity_watchdog_starting_action(
                &runtime,
                TERMINAL_STARTING_WATCHDOG_MS,
                true,
                false,
                true,
                true,
                false,
            ),
            None,
            "an MCP boot marker must block false startup readiness"
        );
        assert_eq!(
            terminal_activity_watchdog_mcp_startup_action(
                &runtime,
                true,
                TERMINAL_MCP_STARTUP_DEGRADED_MS,
            ),
            Some(TerminalActivityWatchdogAction::McpStartupError)
        );
    }

