    #[test]
    fn claude_stop_with_background_work_parks_in_waiting_never_false_completion() {
        let mut claude_metadata = terminal_projection_test_metadata();
        claude_metadata.agent_id = "claude".to_string();
        claude_metadata.agent_kind = "claude".to_string();
        let background_stop = json!({
            "hook_event_name": "Stop",
            "background_tasks": [{ "status": "running" }],
        });
        assert!(terminal_activity_hook_claude_stop_has_background_work(
            &background_stop
        ));
        // Prompt available + background running is WAITING, not forced-busy…
        assert!(!terminal_activity_hook_background_stop_forces_busy(
            &claude_metadata,
            "stop",
            &background_stop,
        ));
        // …and not a plain completion either: the payload site diverts a
        // background-carrying Stop to the waiting tuple (covered below via
        // the reducer); the bare lifecycle mapping stays a completion for
        // background-free Stops.
        assert_eq!(
            terminal_activity_hook_lifecycle_kind("Stop"),
            Some((
                "provider-turn-completed",
                "idle",
                "active",
                "completed",
                true,
            ))
        );

        let blocked_background_stop = json!({
            "hook_event_name": "Stop",
            "background_tasks": [{ "status": "running" }],
            "input_ready": false,
        });
        assert!(terminal_activity_hook_background_stop_forces_busy(
            &claude_metadata,
            "stop",
            &blocked_background_stop,
        ));
    }

    fn waiting_test_runtime_thinking() -> TerminalRuntimeSnapshot {
        TerminalRuntimeSnapshot {
            status: "active".to_string(),
            activity_status: "thinking".to_string(),
            command_phase: "running".to_string(),
            input_ready: false,
            input_ready_at: None,
            prompt_ready_at: None,
            completed_at: None,
            provider_session_id: Some("session-waiting".to_string()),
            native_session_id: Some("session-waiting".to_string()),
            fork_from_provider_session_id: None,
            provider_turn_id: Some("turn-w1".to_string()),
            turn_id: Some("turn-w1".to_string()),
            source: "cli-hook:provider-turn-started".to_string(),
            event_type: "provider-turn-started".to_string(),
            hook_event_name: "PreToolUse".to_string(),
            canonical_state: "thinking".to_string(),
            turn_active: true,
            turn_generation: 3,
            completed_turn_generation: 2,
            updated_at_ms: 1,
            ..TerminalRuntimeSnapshot::opened_idle(None)
        }
    }

    fn waiting_test_payload(event_type: &str, background: bool) -> TerminalActivityHookPayload {
        let activity_status = if event_type == "provider-turn-waiting" {
            "waiting"
        } else if event_type == "provider-turn-started" {
            "thinking"
        } else {
            "idle"
        };
        let mut payload = terminal_activity_hook_test_payload(
            event_type,
            activity_status,
            "completed",
            event_type == "provider-turn-completed",
            Some("session-waiting"),
        );
        payload.background_work_active = background;
        payload.native_session_id = Some("session-waiting".to_string());
        payload.provider_turn_id = Some("turn-w1".to_string());
        payload.turn_id = Some("turn-w1".to_string());
        payload.turn_generation = 3;
        payload.turn_generation_explicit = true;
        payload
    }

    /// THE WAITING CONTRACT: a Stop that arrives while the harness still owns
    /// live background shells/subagents parks the session in `waiting` — the
    /// turn stays OPEN (no settlement, no completed generation, no false
    /// completion) — until the true final Stop lands, which settles normally.
    #[test]
    fn waiting_reducer_parks_turn_open_then_final_stop_settles() {
        let thinking = waiting_test_runtime_thinking();
        // Stop-with-background → waiting, turn still active, NOT settled.
        let waiting_stop = waiting_test_payload("provider-turn-waiting", true);
        let projection =
            terminal_reduce_canonical_state(&thinking, &waiting_stop, None, false, false);
        assert_eq!(projection.canonical_state, "waiting");
        assert!(projection.turn_active, "turn must stay open while waiting");
        assert!(!projection.completion_accepted);
        assert_eq!(
            projection.completed_turn_generation, 2,
            "waiting must not advance the completed generation"
        );

        // Re-entry: background work re-invokes the model — waiting → thinking.
        let mut waiting_runtime = thinking.clone();
        waiting_runtime.canonical_state = "waiting".to_string();
        let re_entry = {
            let mut payload = waiting_test_payload("provider-turn-started", false);
            payload.activity_status = "thinking".to_string();
            payload.input_ready = false;
            payload
        };
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &re_entry, None, false, false);
        assert_eq!(projection.canonical_state, "thinking");
        assert!(projection.turn_active);

        // Final Stop without background → idle + settlement accepted, straight
        // from waiting too (no re-entry evidence required).
        let final_stop = waiting_test_payload("provider-turn-completed", false);
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &final_stop, None, false, false);
        assert_eq!(projection.canonical_state, "idle");
        assert!(projection.completion_accepted);
        assert!(!projection.turn_active);
        assert_eq!(projection.completed_turn_generation, 3);

        // Idempotent re-waiting: another background Stop while already waiting
        // stays waiting (no flap to thinking).
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &waiting_stop, None, false, false);
        assert_eq!(projection.canonical_state, "waiting");
        assert!(projection.turn_active);

        // The background continuation may mint a NEW turn id with no
        // intermediate event: the final Stop must still correlate from
        // waiting (session match is what counts) and settle.
        let mut new_turn_final_stop = waiting_test_payload("provider-turn-completed", false);
        new_turn_final_stop.provider_turn_id = Some("turn-w2".to_string());
        new_turn_final_stop.turn_id = Some("turn-w2".to_string());
        let projection = terminal_reduce_canonical_state(
            &waiting_runtime,
            &new_turn_final_stop,
            None,
            false,
            false,
        );
        assert_eq!(
            projection.canonical_state, "idle",
            "a new-turn-id final Stop must settle from waiting"
        );
        assert!(projection.completion_accepted);

        // Durable ordering: a same-session new-turn Stop whose ORIGIN
        // timestamp predates the WAITING ENTRY's ORIGIN is a delayed stale
        // stop and must NOT settle; the same stop with a fresh origin
        // settles. `updated_at_ms` (ingestion clock, bumped by unrelated
        // writes like provider-session recording) plays NO part — the fresh
        // origin below is far older than it and still settles.
        let mut ordered_runtime = waiting_runtime.clone();
        ordered_runtime.waiting_origin_ms = 100;
        ordered_runtime.updated_at_ms = 999_999;
        let mut stale_stop = waiting_test_payload("provider-turn-completed", false);
        stale_stop.provider_turn_id = Some("turn-old".to_string());
        stale_stop.turn_id = Some("turn-old".to_string());
        stale_stop.hook_timestamp_ms = 50;
        let projection =
            terminal_reduce_canonical_state(&ordered_runtime, &stale_stop, None, false, false);
        assert_eq!(
            projection.canonical_state, "waiting",
            "a pre-waiting-origin stop must not settle the waiting turn"
        );
        assert!(!projection.completion_accepted);
        let mut fresh_stop = stale_stop.clone();
        fresh_stop.hook_timestamp_ms = 150;
        let projection =
            terminal_reduce_canonical_state(&ordered_runtime, &fresh_stop, None, false, false);
        assert_eq!(projection.canonical_state, "idle");
        assert!(projection.completion_accepted);

        // A waiting Stop from a DIFFERENT session must hold waiting (rejected,
        // no id adoption, no thinking flap).
        let mut foreign_waiting_stop = waiting_test_payload("provider-turn-waiting", true);
        foreign_waiting_stop.provider_session_id = Some("session-other".to_string());
        foreign_waiting_stop.native_session_id = Some("session-other".to_string());
        let projection = terminal_reduce_canonical_state(
            &waiting_runtime,
            &foreign_waiting_stop,
            None,
            false,
            false,
        );
        assert_eq!(projection.canonical_state, "waiting");
        assert!(!projection.waiting_accepted);
        assert!(projection.turn_active);
    }

    #[test]
    fn waiting_accepts_interrupt_and_stale_hot_never_owns_it() {
        // Interrupt from waiting settles (user pressed Escape while background
        // work ran) — guard + reducer agree.
        let mut waiting_runtime = waiting_test_runtime_thinking();
        waiting_runtime.canonical_state = "waiting".to_string();
        waiting_runtime.input_ready = false;
        assert!(terminal_runtime_accepts_interrupt(&waiting_runtime));
        let mut interrupt = waiting_test_payload("provider-turn-interrupted", false);
        interrupt.activity_status = "interrupted".to_string();
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &interrupt, None, false, false);
        assert_eq!(projection.canonical_state, "interrupted");
        assert!(projection.interrupt_accepted);
        assert!(!projection.turn_active);
        // Stale-hot (10 min) must never own a waiting session — only the
        // 30-min WaitingRelease may.
        assert!(!terminal_activity_watchdog_runtime_is_stale_hot_candidate(
            &waiting_runtime
        ));
    }

    /// Round-5 hardening: settling WAITING always consults the origin gate.
    /// Turnless Stops must not dodge it via the `turn_matches` missing-field
    /// default, matching turn ids are no proof against a delayed duplicate,
    /// and unstamped candidates fail closed.
    #[test]
    fn waiting_settle_gate_holds_turnless_and_unstamped_stops() {
        let mut waiting_runtime = waiting_test_runtime_thinking();
        waiting_runtime.canonical_state = "waiting".to_string();
        waiting_runtime.waiting_origin_ms = 100;

        // Turnless same-session Stop with a STALE origin: previously settled
        // through the absent-turn-id default; must hold waiting.
        let mut turnless_stale = waiting_test_payload("provider-turn-completed", false);
        turnless_stale.provider_turn_id = None;
        turnless_stale.turn_id = None;
        turnless_stale.hook_timestamp_ms = 50;
        let projection = terminal_reduce_canonical_state(
            &waiting_runtime,
            &turnless_stale,
            None,
            false,
            false,
        );
        assert_eq!(
            projection.canonical_state, "waiting",
            "turnless stale stop must not settle waiting"
        );
        assert!(!projection.completion_accepted);

        // The same turnless Stop with a fresh origin settles.
        let mut turnless_fresh = turnless_stale.clone();
        turnless_fresh.hook_timestamp_ms = 150;
        let projection = terminal_reduce_canonical_state(
            &waiting_runtime,
            &turnless_fresh,
            None,
            false,
            false,
        );
        assert_eq!(projection.canonical_state, "idle");
        assert!(projection.completion_accepted);

        // Unstamped candidate (no fire time, no observed time): every
        // legitimate producer stamps origin, so even a matching turn id
        // fails closed and holds waiting.
        let mut unstamped = waiting_test_payload("provider-turn-completed", false);
        unstamped.hook_timestamp_ms = 0;
        unstamped.observed_at_ms = 0;
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &unstamped, None, false, false);
        assert_eq!(
            projection.canonical_state, "waiting",
            "unstamped stop must fail the origin gate closed"
        );
        assert!(!projection.completion_accepted);

        // Raw-event origin reader (quiesce-gate parity): the hook CLI stamps
        // `timestamp_ms` at fire time and it must be seen first.
        assert_eq!(terminal_event_origin_ms(&json!({ "timestamp_ms": 42 })), 42);
        assert_eq!(terminal_event_origin_ms(&json!({ "ts_ms": 41 })), 41);
        assert_eq!(
            terminal_event_origin_ms(&json!({ "observed_at_ms": 40 })),
            40
        );
        assert_eq!(terminal_event_origin_ms(&json!({})), 0);
        assert!(terminal_waiting_origin_ordered(150, 100));
        assert!(!terminal_waiting_origin_ordered(50, 100));
        assert!(!terminal_waiting_origin_ordered(0, 100));
        assert!(!terminal_waiting_origin_ordered(0, 0));
        assert!(terminal_waiting_origin_ordered(1, 0));
    }

    /// Round-6 hardening: SubagentStop / TaskCompleted map to passive
    /// thinking-family events ("provider-subagent-completed" /
    /// "provider-task-completed") — they are the awaited background work
    /// completing and must HOLD the waiting latch with the ordering origin
    /// intact; the true final Stop then settles through it.
    #[test]
    fn waiting_latch_survives_background_completion_hooks_then_final_stop_settles() {
        let mut waiting_runtime = waiting_test_runtime_thinking();
        waiting_runtime.canonical_state = "waiting".to_string();
        waiting_runtime.waiting_origin_ms = 100;

        for event_type in ["provider-subagent-completed", "provider-task-completed"] {
            let mut background_done = waiting_test_payload(event_type, false);
            background_done.activity_status = "thinking".to_string();
            background_done.input_ready = false;
            background_done.hook_timestamp_ms = 300;
            let projection = terminal_reduce_canonical_state(
                &waiting_runtime,
                &background_done,
                None,
                false,
                false,
            );
            assert_eq!(
                projection.canonical_state, "waiting",
                "{event_type} must hold the waiting latch"
            );
            assert_eq!(
                terminal_next_waiting_origin_ms(
                    &waiting_runtime,
                    &background_done,
                    &projection,
                    false,
                ),
                100,
                "{event_type} must preserve the waiting origin"
            );
        }

        // A parked todo queue must not melt waiting either: waiting→paused is
        // not an allowed edge and the veto fallback must hold waiting, not
        // decay to thinking.
        let mut passive = waiting_test_payload("provider-subagent-completed", false);
        passive.activity_status = "thinking".to_string();
        passive.input_ready = false;
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &passive, None, true, false);
        assert_eq!(projection.canonical_state, "waiting");

        // With the latch intact, the true final Stop (new turn id, fresh
        // origin) settles.
        let mut final_stop = waiting_test_payload("provider-turn-completed", false);
        final_stop.provider_turn_id = Some("turn-w9".to_string());
        final_stop.turn_id = Some("turn-w9".to_string());
        final_stop.hook_timestamp_ms = 400;
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &final_stop, None, false, false);
        assert_eq!(projection.canonical_state, "idle");
        assert!(projection.completion_accepted);

        // Explicit turn re-entry still moves waiting → thinking.
        let mut re_entry = waiting_test_payload("provider-turn-started", false);
        re_entry.activity_status = "thinking".to_string();
        re_entry.input_ready = false;
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &re_entry, None, false, false);
        assert_eq!(projection.canonical_state, "thinking");
    }

    /// Round-7 hardening: WAITING must be busy on the WIRE too — a held
    /// stale Stop's emitted payload carried its original completion tuple
    /// (input_ready=true), disabling Escape in the UI and projecting remote
    /// awaiting_input while background work still ran.
    #[test]
    fn waiting_wire_payload_never_carries_input_ready() {
        let mut waiting_runtime = waiting_test_runtime_thinking();
        waiting_runtime.canonical_state = "waiting".to_string();
        waiting_runtime.waiting_origin_ms = 100;

        // Same-turn stale Stop: rejected (held waiting), but the raw payload
        // is a completion tuple that starts input-ready.
        let mut stale_stop = waiting_test_payload("provider-turn-completed", false);
        stale_stop.hook_timestamp_ms = 50;
        assert!(stale_stop.input_ready, "completion tuple starts ready");
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &stale_stop, None, false, false);
        assert_eq!(projection.canonical_state, "waiting");
        assert!(!projection.completion_accepted);
        let mut emitted = stale_stop.clone();
        terminal_apply_canonical_projection_to_payload(&mut emitted, &projection);
        assert_eq!(emitted.canonical_state, "waiting");
        assert!(
            !emitted.input_ready,
            "wire waiting must never be input-ready"
        );
        assert_eq!(emitted.activity_status, "waiting");
        assert_eq!(emitted.command_phase, "background_waiting");
        assert!(emitted.completed_at.is_none());
        assert!(!emitted.turn_settlement_accepted);

        // Accepted parks stay busy on the wire as well.
        let thinking = waiting_test_runtime_thinking();
        let park = waiting_test_payload("provider-turn-waiting", true);
        let projection = terminal_reduce_canonical_state(&thinking, &park, None, false, false);
        let mut emitted = park.clone();
        terminal_apply_canonical_projection_to_payload(&mut emitted, &projection);
        assert_eq!(emitted.canonical_state, "waiting");
        assert!(!emitted.input_ready);
    }

    /// The waiting ordering identity is stamped from the PARKING event's
    /// ORIGIN (hook fire time), survives rejected events and continued
    /// waiting, never rewinds on a stale re-park, and clears on exit.
    #[test]
    fn waiting_origin_stamps_from_parking_event_and_clears_on_exit() {
        let thinking = waiting_test_runtime_thinking();
        let mut park = waiting_test_payload("provider-turn-waiting", true);
        park.hook_timestamp_ms = 500;
        let projection = terminal_reduce_canonical_state(&thinking, &park, None, false, false);
        assert!(projection.waiting_accepted);
        assert_eq!(
            terminal_next_waiting_origin_ms(&thinking, &park, &projection, false),
            500
        );

        let mut waiting_runtime = thinking.clone();
        waiting_runtime.canonical_state = "waiting".to_string();
        waiting_runtime.waiting_origin_ms = 500;

        // A stale re-park must not rewind the ordering identity.
        let mut stale_repark = waiting_test_payload("provider-turn-waiting", true);
        stale_repark.hook_timestamp_ms = 200;
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &stale_repark, None, false, false);
        assert_eq!(
            terminal_next_waiting_origin_ms(&waiting_runtime, &stale_repark, &projection, false),
            500
        );

        // Rejected events preserve the identity untouched.
        assert_eq!(
            terminal_next_waiting_origin_ms(&waiting_runtime, &stale_repark, &projection, true),
            500
        );

        // Settling clears it.
        let mut final_stop = waiting_test_payload("provider-turn-completed", false);
        final_stop.hook_timestamp_ms = 600;
        let projection =
            terminal_reduce_canonical_state(&waiting_runtime, &final_stop, None, false, false);
        assert!(projection.completion_accepted);
        assert_eq!(
            terminal_next_waiting_origin_ms(&waiting_runtime, &final_stop, &projection, false),
            0
        );
    }

    #[test]
    fn waiting_projection_is_busy_running_never_needs_input_or_complete() {
        let metadata = terminal_projection_test_metadata();
        let mut runtime = waiting_test_runtime_thinking();
        runtime.canonical_state = "waiting".to_string();
        runtime.canonical_badge_label = "waiting".to_string();
        let projected = terminal_project_runtime(&metadata, &runtime, false);
        assert_eq!(projected.readiness, "busy");
        assert_eq!(projected.turn_status, "running");
        assert_eq!(projected.terminal_work_state, "running");
        assert_eq!(projected.execution_phase, "waiting");
        // waiting is not paused/needs-input anywhere.
        assert!(!terminal_projection_state_is_paused("waiting"));
        assert!(terminal_projection_state_is_busy("waiting"));
    }

    #[test]
    fn waiting_release_watchdog_fires_only_for_stale_waiting_sessions() {
        let mut runtime = waiting_test_runtime_thinking();
        runtime.canonical_state = "waiting".to_string();
        assert_eq!(
            terminal_activity_watchdog_waiting_release_action(
                &runtime,
                TERMINAL_WAITING_RELEASE_WATCHDOG_MS,
            ),
            Some(TerminalActivityWatchdogAction::WaitingRelease)
        );
        assert_eq!(
            terminal_activity_watchdog_waiting_release_action(
                &runtime,
                TERMINAL_WAITING_RELEASE_WATCHDOG_MS - 1,
            ),
            None
        );
        runtime.canonical_state = "thinking".to_string();
        assert_eq!(
            terminal_activity_watchdog_waiting_release_action(
                &runtime,
                TERMINAL_WAITING_RELEASE_WATCHDOG_MS,
            ),
            None
        );
    }

    #[test]
    fn same_turn_activity_matches_pending_final_stop() {
        let runtime = TerminalRuntimeSnapshot {
            status: "active".to_string(),
            activity_status: "thinking".to_string(),
            command_phase: "running".to_string(),
            input_ready: false,
            input_ready_at: None,
            prompt_ready_at: None,
            completed_at: None,
            provider_session_id: Some("session-main".to_string()),
            native_session_id: Some("session-main".to_string()),
            fork_from_provider_session_id: None,
            provider_turn_id: Some("turn-1".to_string()),
            turn_id: Some("turn-1".to_string()),
            source: "cli-hook:provider-turn-started".to_string(),
            event_type: "provider-turn-started".to_string(),
            hook_event_name: "UserPromptSubmit".to_string(),
            updated_at_ms: 1,
            ..TerminalRuntimeSnapshot::opened_idle(None)
        };
        let candidate = PendingTerminalFinalStopCandidate {
            generation: 1,
            session_id: "session-main".to_string(),
            turn_id: "turn-1".to_string(),
            event: json!({}),
        };
        let mut tool_payload = terminal_activity_hook_test_payload(
            "provider-tool-completed",
            "thinking",
            "tool_completed",
            false,
            Some("session-main"),
        );
        tool_payload.hook_event_name = "PostToolUse".to_string();
        tool_payload.turn_id = Some("turn-1".to_string());
        tool_payload.provider_turn_id = Some("turn-1".to_string());

        assert!(terminal_pending_final_stop_activity_matches(
            &candidate,
            &runtime,
            &tool_payload,
        ));

        tool_payload.turn_id = Some("turn-2".to_string());
        tool_payload.provider_turn_id = Some("turn-2".to_string());
        assert!(!terminal_pending_final_stop_activity_matches(
            &candidate,
            &runtime,
            &tool_payload,
        ));
    }

    #[test]
    fn cancelled_bump_stale_sleeper_cannot_claim_rebuffered_final_stop() {
        let pane_id = "pane-final-stop-reschedule";
        let instance_id = 73;
        let key = terminal_pending_final_stop_key(pane_id, instance_id);
        let original_generation = terminal_pending_final_stop_next_generation();
        let runtime = TerminalRuntimeSnapshot {
            status: "active".to_string(),
            activity_status: "thinking".to_string(),
            command_phase: "running".to_string(),
            input_ready: false,
            input_ready_at: None,
            prompt_ready_at: None,
            completed_at: None,
            provider_session_id: Some("session-main".to_string()),
            native_session_id: Some("session-main".to_string()),
            fork_from_provider_session_id: None,
            provider_turn_id: Some("turn-1".to_string()),
            turn_id: Some("turn-1".to_string()),
            source: "cli-hook:provider-turn-started".to_string(),
            event_type: "provider-turn-started".to_string(),
            hook_event_name: "UserPromptSubmit".to_string(),
            updated_at_ms: 1,
            ..TerminalRuntimeSnapshot::opened_idle(None)
        };
        terminal_pending_final_stops().lock().unwrap().insert(
            key.clone(),
            PendingTerminalFinalStopCandidate {
                generation: original_generation,
                session_id: "session-main".to_string(),
                turn_id: "turn-1".to_string(),
                event: json!({}),
            },
        );
        let mut payload = terminal_activity_hook_test_payload(
            "provider-tool-completed",
            "thinking",
            "tool_completed",
            false,
            Some("session-main"),
        );
        payload.hook_event_name = "PostToolUse".to_string();
        payload.turn_id = Some("turn-1".to_string());
        payload.provider_turn_id = Some("turn-1".to_string());

        let generation = terminal_activity_hook_update_pending_final_stop_for_activity(
            pane_id,
            instance_id,
            &runtime,
            &payload,
            "test",
        )
        .expect("replacement sleeper generation");

        assert_ne!(generation, original_generation);
        assert_eq!(
            terminal_pending_final_stops()
                .lock()
                .unwrap()
                .get(&key)
                .map(|candidate| candidate.generation),
            Some(generation)
        );

        // Cancellation removes the candidate but cannot stop its already
        // spawned replacement sleeper. Re-buffering the same pane must use a
        // generation that the stale sleeper can never claim.
        terminal_pending_final_stops().lock().unwrap().remove(&key);
        let rebuffered_generation = terminal_pending_final_stop_next_generation();
        terminal_pending_final_stops().lock().unwrap().insert(
            key.clone(),
            PendingTerminalFinalStopCandidate {
                generation: rebuffered_generation,
                session_id: "session-main".to_string(),
                turn_id: "turn-2".to_string(),
                event: json!({"hook_event_name": "Stop"}),
            },
        );

        assert_ne!(rebuffered_generation, generation);
        assert!(terminal_pending_final_stop_take_generation(&key, generation).is_none());
        assert_eq!(
            terminal_pending_final_stops()
                .lock()
                .unwrap()
                .get(&key)
                .map(|candidate| candidate.generation),
            Some(rebuffered_generation)
        );
        assert!(terminal_pending_final_stop_take_generation(&key, rebuffered_generation).is_some());
    }

