    #[cfg(unix)]
    #[test]
    fn codex_hook_trust_keys_use_provider_canonical_hooks_path() {
        let root = terminal_test_directory("codex_hook_trust_canonical_path");
        let real_home = root.join("real-home");
        let alias_home = root.join("alias-home");
        fs::create_dir_all(&real_home).unwrap();
        std::os::unix::fs::symlink(&real_home, &alias_home).unwrap();
        let hooks_path = alias_home.join("hooks.json");
        let hooks_json = json!({
            "hooks": {
                "Stop": [{
                    "hooks": [{
                        "type": "command",
                        "command": "coordination_mcp --diff-forge-activity-hook --provider codex",
                        "timeout": 5
                    }]
                }]
            }
        });
        fs::write(&hooks_path, serde_json::to_vec_pretty(&hooks_json).unwrap()).unwrap();

        let records = codex_managed_activity_hook_trust_records(&hooks_path, &hooks_json).unwrap();
        assert_eq!(records.len(), 1);
        let canonical_hooks_path = fs::canonicalize(&hooks_path).unwrap();
        assert_eq!(
            records[0].0,
            format!("{}:stop:0:0", canonical_hooks_path.to_string_lossy())
        );
        assert!(!records[0]
            .0
            .starts_with(alias_home.to_string_lossy().as_ref()));
    }

    #[test]
    fn coordinated_codex_activity_hook_profile_refresh_scopes_commands() {
        let mut coordination = terminal_test_coordination("codex_hook_profile_scope");
        let home = terminal_test_directory("codex_hook_profile_home");
        let profile = "diffforge-test-profile";
        // Codex only loads hooks from the home-level hooks.json.
        let hooks_path = home.join("hooks.json");
        let profile_path = home.join(format!("{profile}.config.toml"));
        fs::create_dir_all(&home).unwrap();
        fs::write(
            &profile_path,
            "default_permissions = \"diffforge-coordinated\"\n",
        )
        .unwrap();
        fs::write(
            &hooks_path,
            serde_json::to_string_pretty(&json!({
                "hooks": {
                    "Stop": [
                        {
                            "hooks": [
                                {
                                    "type": "command",
                                    "command": "'coordination_mcp' --diff-forge-activity-hook --provider 'codex'",
                                    "timeout": 5
                                },
                                {
                                    "type": "command",
                                    "command": "echo user-hook",
                                    "timeout": 5
                                }
                            ]
                        }
                    ],
                    "PreToolUse": [
                        {
                            "hooks": [
                                {
                                    "type": "command",
                                    "command": "'coordination_mcp' --diff-forge-write-guard --provider 'codex'",
                                    "timeout": 30
                                }
                            ],
                            "matcher": "functions.apply_patch"
                        }
                    ],
                    "PostToolUse": [
                        {
                            "hooks": [
                                {
                                    "type": "command",
                                    "command": "'coordination_mcp' --diff-forge-activity-hook --provider 'codex'",
                                    "timeout": 5
                                }
                            ],
                            "matcher": "Bash|Shell"
                        }
                    ]
                }
            }))
            .unwrap(),
        )
        .unwrap();
        let home_text = home.to_string_lossy().to_string();
        coordination
            .env_vars
            .push(("DIFFFORGE_CODEX_HOME".to_string(), home_text.clone()));
        coordination
            .env_vars
            .push(("CODEX_HOME".to_string(), home_text));
        coordination
            .env_vars
            .push(("DIFFFORGE_CODEX_PROFILE".to_string(), profile.to_string()));

        let updated = refresh_codex_activity_hook_profile_for_terminal(
            Some(&coordination),
            "codex",
            "workspace-terminal/workspace-1-0-codex",
            42,
            Some("workspace-1"),
            Some(2),
        )
        .unwrap();

        assert!(updated);
        let hooks = fs::read_to_string(&hooks_path).unwrap();
        assert!(hooks.contains("--diff-forge-activity-hook"));
        assert!(hooks.contains("UserPromptSubmit"));
        assert!(hooks.contains("SessionStart"));
        assert!(hooks.contains("PreCompact"));
        assert!(hooks.contains("PostCompact"));
        assert!(hooks.contains("Stop"));
        assert!(hooks.contains("PreToolUse"));
        assert!(hooks.contains("PostToolUse"));
        assert!(hooks.contains("PermissionRequest"));
        assert!(hooks.contains("SubagentStart"));
        assert!(hooks.contains("SubagentStop"));
        assert!(hooks.contains("--pane-id"));
        assert!(hooks.contains("workspace-terminal/workspace-1-0-codex"));
        assert!(hooks.contains("--instance-id"));
        assert!(hooks.contains("42"));
        assert!(hooks.contains("--workspace-id"));
        assert!(hooks.contains("workspace-1"));
        assert!(hooks.contains("--terminal-index"));
        assert!(hooks.contains("--events-path"));
        assert!(hooks.contains("--debug-path"));
        assert!(!hooks.contains("--diff-forge-write-guard"));
        // One scoped command per ensured activity-hook event.
        assert_eq!(hooks.matches("--pane-id").count(), 10);
        let profile_config = fs::read_to_string(&profile_path).unwrap();
        assert!(profile_config.contains("default_permissions = \"diffforge-coordinated\""));
        assert!(!profile_config.contains("[[hooks."));
        assert!(!profile_config.contains("--diff-forge-activity-hook"));
        assert!(!profile_config.contains("--pane-id"));
        assert!(!profile_config.contains("--debug-path"));
        assert!(!profile_config.contains("--diff-forge-write-guard"));
        assert!(!profile_config.contains("hooksPath ="));

        let hooks_json: Value = serde_json::from_str(&hooks).unwrap();
        let records = codex_managed_activity_hook_trust_records(&hooks_path, &hooks_json).unwrap();
        assert_eq!(records.len(), 10);
        let user_hook_location = hooks_json["hooks"]["Stop"]
            .as_array()
            .unwrap()
            .iter()
            .enumerate()
            .find_map(|(group_index, group)| {
                group["hooks"]
                    .as_array()
                    .unwrap()
                    .iter()
                    .enumerate()
                    .find_map(|(handler_index, handler)| {
                        (handler["command"].as_str() == Some("echo user-hook"))
                            .then_some((group_index, handler_index))
                    })
            })
            .expect("neighboring user hook must survive the managed refresh");
        let user_hook_key = format!(
            "{}:stop:{}:{}",
            hooks_path.to_string_lossy(),
            user_hook_location.0,
            user_hook_location.1
        );
        let base_config_path = home.join("config.toml");
        for config_path in [&base_config_path, &profile_path] {
            let config: toml::Value =
                toml::from_str(&fs::read_to_string(config_path).unwrap()).unwrap();
            let state = config["hooks"]["state"].as_table().unwrap();
            assert_eq!(state.len(), 10);
            assert!(!state.contains_key(&user_hook_key));
            for (key, current_hash) in &records {
                let entry = state.get(key).unwrap().as_table().unwrap();
                assert_eq!(
                    entry.get("trusted_hash").and_then(toml::Value::as_str),
                    Some(current_hash.as_str())
                );
                assert_eq!(
                    entry.get("enabled").and_then(toml::Value::as_bool),
                    Some(true)
                );
            }
        }

        // A stale/disabled profile entry overrides the base layer in Codex.
        // Refreshing a launch must repair both layers so the hook is active.
        let stale_key = &records[0].0;
        for config_path in [&base_config_path, &profile_path] {
            let mut config: toml::Value =
                toml::from_str(&fs::read_to_string(config_path).unwrap()).unwrap();
            let entry = config["hooks"]["state"][stale_key].as_table_mut().unwrap();
            entry.insert(
                "trusted_hash".to_string(),
                toml::Value::String("sha256:stale".to_string()),
            );
            entry.insert("enabled".to_string(), toml::Value::Boolean(false));
            fs::write(config_path, toml::to_string_pretty(&config).unwrap()).unwrap();
        }
        assert!(refresh_codex_activity_hook_profile_for_terminal(
            Some(&coordination),
            "codex",
            "workspace-terminal/workspace-1-0-codex",
            42,
            Some("workspace-1"),
            Some(2),
        )
        .unwrap());
        for config_path in [&base_config_path, &profile_path] {
            let config: toml::Value =
                toml::from_str(&fs::read_to_string(config_path).unwrap()).unwrap();
            let entry = config["hooks"]["state"][stale_key].as_table().unwrap();
            assert_eq!(
                entry.get("trusted_hash").and_then(toml::Value::as_str),
                Some(records[0].1.as_str())
            );
            assert_eq!(
                entry.get("enabled").and_then(toml::Value::as_bool),
                Some(true)
            );
        }
    }

    #[test]
    fn coordinated_codex_activity_hook_profile_refresh_creates_missing_hooks_file() {
        let mut coordination = terminal_test_coordination("codex_hook_profile_create");
        let home = terminal_test_directory("codex_hook_profile_create_home");
        let profile = "diffforge-test-profile";
        // Codex only loads hooks from the home-level hooks.json.
        let hooks_path = home.join("hooks.json");
        let profile_path = home.join(format!("{profile}.config.toml"));
        fs::create_dir_all(&home).unwrap();
        fs::write(
            &profile_path,
            "default_permissions = \"diffforge-coordinated\"\n",
        )
        .unwrap();
        coordination.env_vars.push((
            "DIFFFORGE_CODEX_HOME".to_string(),
            home.to_string_lossy().to_string(),
        ));
        coordination
            .env_vars
            .push(("DIFFFORGE_CODEX_PROFILE".to_string(), profile.to_string()));

        let updated = refresh_codex_activity_hook_profile_for_terminal(
            Some(&coordination),
            "codex",
            "workspace-terminal/workspace-1-0-codex",
            42,
            Some("workspace-1"),
            Some(2),
        )
        .unwrap();

        assert!(updated);
        let hooks = fs::read_to_string(&hooks_path).unwrap();
        assert!(hooks.contains("UserPromptSubmit"));
        assert!(hooks.contains("--diff-forge-activity-hook"));
        let profile_config = fs::read_to_string(&profile_path).unwrap();
        assert!(profile_config.contains("default_permissions = \"diffforge-coordinated\""));
        assert!(!profile_config.contains("[[hooks."));
        assert!(!profile_config.contains("--diff-forge-activity-hook"));
    }

